def _parse_path_list(raw_value: str) -> list[Path]:
    raw = (raw_value or "").strip()
    if not raw:
        return []
    parts = [p.strip() for p in raw.split(";") if p.strip()]
    paths = []
    for item in parts:
        try:
            paths.append(Path(os.path.expandvars(item)).expanduser().resolve(strict=False))
        except Exception:
            continue
    return paths


def _parse_csv_list(raw_value: str) -> list[str]:
    raw = (raw_value or "").strip()
    if not raw:
        return []
    return [item.strip() for item in raw.split(",") if item.strip()]


def _normalize_approval_mode(raw_value: str) -> str:
    value = (raw_value or "").strip().lower()
    if value in {"off", "balanced", "strict"}:
        return value
    return "balanced"


def _parse_key_value_pairs(raw_value: str, pair_sep: str = ";", kv_sep: str = "=") -> dict[str, str]:
    pairs: dict[str, str] = {}
    raw = (raw_value or "").strip()
    if not raw:
        return pairs
    for chunk in raw.split(pair_sep):
        item = chunk.strip()
        if not item or kv_sep not in item:
            continue
        key, value = item.split(kv_sep, 1)
        key = key.strip()
        value = value.strip()
        if key and value:
            pairs[key] = value
    return pairs


def _parse_lane_limits(raw_value: str) -> dict[str, int]:
    raw_map = _parse_key_value_pairs(raw_value, pair_sep=";", kv_sep=":")
    limits: dict[str, int] = {}
    for lane, raw_limit in raw_map.items():
        try:
            value = int(raw_limit)
        except Exception:
            continue
        limits[lane.strip().lower()] = max(1, min(32, value))
    return limits

def _default_runtime_dir() -> Path:
    local_appdata = os.getenv("LOCALAPPDATA")
    if local_appdata:
        return Path(local_appdata) / "mind-clone"
    return Path.home() / ".mind-clone"


def _default_temp_runtime_dir() -> Path:
    return Path(tempfile.gettempdir()) / "mind-clone"


def _expand_path_input(raw_value: str) -> Path:
    expanded = os.path.expandvars((raw_value or "").strip())
    return Path(expanded).expanduser()


def _resolve_configured_db_file_path() -> tuple[Path | None, str | None]:
    configured_path = os.getenv("MIND_CLONE_DB_PATH")
    if configured_path and configured_path.strip():
        normalized = _expand_path_input(configured_path).resolve(strict=False)
        return normalized, "env:MIND_CLONE_DB_PATH"
    configured_dir = os.getenv("MIND_CLONE_DB_DIR")
    if configured_dir and configured_dir.strip():
        normalized_dir = _expand_path_input(configured_dir).resolve(strict=False)
        return normalized_dir / "mind_clone.db", "env:MIND_CLONE_DB_DIR"
    return None, None


def _candidate_db_paths() -> tuple[list[Path], str]:
    configured, source = _resolve_configured_db_file_path()
    if configured is not None:
        return [configured], source or "configured"
    return [
        (_default_runtime_dir() / "mind_clone.db").resolve(strict=False),
        (_default_temp_runtime_dir() / "mind_clone.db").resolve(strict=False),
    ], "fallback"


def _sqlite_url_for_path(path: Path) -> str:
    return f"sqlite:///{path.as_posix()}"


