REQUESTS_SESSION = requests.Session()
REQUESTS_SESSION.trust_env = False

# ============================================================================
# VECTOR MEMORY: GloVe Embedding System (AGI Pillar â€” Memory)
# Uses pre-trained GloVe word vectors for semantic similarity.
# Pure Python + numpy â€” no native DLL extensions needed.
# ============================================================================

GLOVE_DIM = 100  # 100-dimensional GloVe vectors
GLOVE_VOCAB_LIMIT = 50000  # Top 50K words covers >99% of typical text
GLOVE_MODEL_NAME = "glove.6B.100d.txt"
GLOVE_ZIP_URL = "https://nlp.stanford.edu/data/glove.6B.zip"

_glove_vectors: dict[str, np.ndarray] | None = None
_glove_lock = threading.Lock()


def _glove_cache_dir() -> Path:
    local_appdata = os.getenv("LOCALAPPDATA")
    if local_appdata:
        return Path(local_appdata) / "mind-clone" / "models"
    return Path.home() / ".mind-clone" / "models"


def _download_glove_if_needed() -> Path:
    """Download GloVe vectors if not cached. Returns path to the text file."""
    cache = _glove_cache_dir()
    cache.mkdir(parents=True, exist_ok=True)
    glove_path = cache / GLOVE_MODEL_NAME
    if glove_path.exists():
        return glove_path

    log.info("GLOVE_DOWNLOAD starting (~330MB one-time download)...")
    resp = REQUESTS_SESSION.get(GLOVE_ZIP_URL, stream=True, timeout=600)
    resp.raise_for_status()
    data = b"".join(resp.iter_content(chunk_size=1024 * 1024))
    log.info("GLOVE_DOWNLOAD extracting %s...", GLOVE_MODEL_NAME)
    with zipfile.ZipFile(BytesIO(data)) as z:
        z.extract(GLOVE_MODEL_NAME, str(cache))
    log.info("GLOVE_DOWNLOAD done: %s", glove_path)
    return glove_path


def _load_glove_vectors() -> dict[str, np.ndarray]:
    """Load GloVe vectors from disk. Called once, cached in memory."""
    global _glove_vectors
    with _glove_lock:
        if _glove_vectors is not None:
            return _glove_vectors
        try:
            glove_path = _download_glove_if_needed()
            vectors = {}
            with open(glove_path, "r", encoding="utf-8") as f:
                for i, line in enumerate(f):
                    if i >= GLOVE_VOCAB_LIMIT:
                        break
                    parts = line.rstrip().split(" ")
                    word = parts[0]
                    vec = np.array([float(x) for x in parts[1:]], dtype=np.float32)
                    vectors[word] = vec
            _glove_vectors = vectors
            log.info("GLOVE_LOADED %d word vectors, dim=%d", len(vectors), GLOVE_DIM)
            return vectors
        except Exception as exc:
            log.error("GLOVE_LOAD_FAILED: %s", exc)
            _glove_vectors = {}
            return {}


def get_embedding(text: str) -> np.ndarray:
    """Generate a normalized embedding for text by averaging GloVe word vectors."""
    vectors = _load_glove_vectors()
    if not vectors:
        return np.zeros(GLOVE_DIM, dtype=np.float32)
    words = re.findall(r"[a-zA-Z]+", text.lower())
    vecs = [vectors[w] for w in words if w in vectors]
    if not vecs:
        return np.zeros(GLOVE_DIM, dtype=np.float32)
    avg = np.mean(vecs, axis=0)
    norm = np.linalg.norm(avg)
    return avg / max(norm, 1e-9)


def get_embeddings_batch(texts: list[str]) -> list[np.ndarray]:
    """Generate embeddings for multiple texts."""
    return [get_embedding(t) for t in texts]


def cosine_similarity(a: np.ndarray, b: np.ndarray) -> float:
    """Compute cosine similarity between two vectors."""
    norm_a = np.linalg.norm(a)
    norm_b = np.linalg.norm(b)
    if norm_a < 1e-9 or norm_b < 1e-9:
        return 0.0
    return float(np.dot(a, b) / (norm_a * norm_b))


def embedding_to_bytes(vec: np.ndarray) -> bytes:
    """Serialize numpy array to bytes for SQLite storage."""
    return vec.astype(np.float32).tobytes()


def bytes_to_embedding(data: bytes) -> np.ndarray:
    """Deserialize bytes back to numpy array."""
    return np.frombuffer(data, dtype=np.float32).copy()


def _coerce_non_negative_int(value, default: int = 0) -> int:
    try:
        return max(0, int(value))
    except Exception:
        return int(default)


def _parse_model_cost_pair(raw_value: str) -> tuple[float, float] | None:
    text = str(raw_value or "").strip()
    if not text:
        return None
    if ":" in text:
        left, right = text.split(":", 1)
    elif "," in text:
        left, right = text.split(",", 1)
    else:
        return None
    try:
        in_cost = max(0.0, float(left.strip()))
        out_cost = max(0.0, float(right.strip()))
        return in_cost, out_cost
    except Exception:
        return None


def model_cost_profile(model_name: str) -> tuple[float, float]:
    key = str(model_name or "").strip().lower()
    override_raw = str(USAGE_MODEL_COST_OVERRIDES.get(key) or "").strip()
    override_pair = _parse_model_cost_pair(override_raw)
    if override_pair:
        return override_pair
    return float(USAGE_DEFAULT_INPUT_COST_PER_1K), float(USAGE_DEFAULT_OUTPUT_COST_PER_1K)


def estimate_llm_cost_usd(model_name: str, prompt_tokens: int, completion_tokens: int) -> float:
    input_cost, output_cost = model_cost_profile(model_name)
    return ((max(0, int(prompt_tokens)) / 1000.0) * input_cost) + (
        (max(0, int(completion_tokens)) / 1000.0) * output_cost
    )


def _extract_task_id_from_source(source_type: str, source_ref: str | None) -> int | None:
    if str(source_type or "").strip().lower() != "task":
        return None
    text = str(source_ref or "").strip().lower()
    if not text:
        return None
    if text.isdigit():
        return int(text)
    if text.startswith("task#"):
        raw = text.split("#", 1)[1].split(":", 1)[0]
        if raw.isdigit():
            return int(raw)
    return None


def _update_usage_rollup_state(
    owner_id: int | None,
    task_id: int | None,
    session_id: str | None,
    prompt_tokens: int,
    completion_tokens: int,
    estimated_cost_usd: float,
):
    def _rollup_update(container: dict, key: str):
        bucket = dict(container.get(key) or {})
        bucket["events"] = int(bucket.get("events", 0)) + 1
        bucket["prompt_tokens"] = int(bucket.get("prompt_tokens", 0)) + int(max(0, prompt_tokens))
        bucket["completion_tokens"] = int(bucket.get("completion_tokens", 0)) + int(max(0, completion_tokens))
        bucket["cost_usd"] = round(float(bucket.get("cost_usd", 0.0) or 0.0) + max(0.0, float(estimated_cost_usd)), 8)
        bucket["updated_at"] = utc_now_iso()
        container[key] = bucket
        if len(container) > 80:
            keys = list(container.keys())[: len(container) - 80]
            for k in keys:
                container.pop(k, None)

    owner_summary = dict(RUNTIME_STATE.get("usage_ledger_last_owner_summary") or {})
    task_summary = dict(RUNTIME_STATE.get("usage_ledger_last_task_summary") or {})
    session_summary = dict(RUNTIME_STATE.get("usage_ledger_last_session_summary") or {})

    if owner_id is not None:
        _rollup_update(owner_summary, str(int(owner_id)))
    if task_id is not None:
        _rollup_update(task_summary, str(int(task_id)))
    if session_id:
        _rollup_update(session_summary, str(session_id))

    RUNTIME_STATE["usage_ledger_last_owner_summary"] = owner_summary
    RUNTIME_STATE["usage_ledger_last_task_summary"] = task_summary
    RUNTIME_STATE["usage_ledger_last_session_summary"] = session_summary


def record_usage_ledger_event(
    owner_id: int | None,
    source_type: str,
    event_type: str,
    model_name: str | None = None,
    tool_name: str | None = None,
    prompt_tokens: int = 0,
    completion_tokens: int = 0,
    estimated_tokens: int = 0,
    estimated_cost_usd: float = 0.0,
    status: str = "ok",
    session_id: str | None = None,
    source_ref: str | None = None,
    detail: dict | None = None,
):
    if not USAGE_LEDGER_ENABLED:
        return
    db = SessionLocal()
    try:
        task_id = _extract_task_id_from_source(source_type, source_ref)
        row = UsageLedger(
            owner_id=int(owner_id) if owner_id is not None else None,
            task_id=int(task_id) if task_id is not None else None,
            session_id=truncate_text(str(session_id or ""), 120) or None,
            source_type=truncate_text(str(source_type or "system"), 40),
            event_type=truncate_text(str(event_type or "event"), 80),
            model_name=truncate_text(str(model_name or ""), 120) or None,
            tool_name=truncate_text(str(tool_name or ""), 120) or None,
            prompt_tokens=_coerce_non_negative_int(prompt_tokens, 0),
            completion_tokens=_coerce_non_negative_int(completion_tokens, 0),
            estimated_tokens=_coerce_non_negative_int(estimated_tokens, 0),
            estimated_cost_usd=f"{float(max(0.0, estimated_cost_usd)):.8f}",
            status=truncate_text(str(status or "ok"), 32),
            detail_json=json.dumps(detail or {}, ensure_ascii=False),
        )
        db.add(row)
        db.commit()
        RUNTIME_STATE["usage_ledger_events"] = int(RUNTIME_STATE.get("usage_ledger_events", 0)) + 1
        running_cost = float(RUNTIME_STATE.get("usage_ledger_cost_usd", 0.0) or 0.0)
        RUNTIME_STATE["usage_ledger_cost_usd"] = round(running_cost + max(0.0, float(estimated_cost_usd)), 8)
        _update_usage_rollup_state(
            owner_id=int(owner_id) if owner_id is not None else None,
            task_id=int(task_id) if task_id is not None else None,
            session_id=str(session_id or "").strip() or None,
            prompt_tokens=_coerce_non_negative_int(prompt_tokens, 0),
            completion_tokens=_coerce_non_negative_int(completion_tokens, 0),
            estimated_cost_usd=max(0.0, float(estimated_cost_usd)),
        )
    except Exception as e:
        db.rollback()
        log.warning("USAGE_LEDGER_WRITE_FAIL error=%s", truncate_text(str(e), 200))
    finally:
        db.close()


