def telegram_token_configured() -> bool:
    token = str(TELEGRAM_BOT_TOKEN or "").strip()
    if not token:
        return False
    lowered = token.lower()
    if lowered in {TOKEN_PLACEHOLDER.lower(), TOKEN_PLACEHOLDER_ALT.lower(), "your-telegram-bot-token-here"}:
        return False
    if "your_telegram_bot_token" in lowered or "your telegram bot token" in lowered:
        return False
    return True


def webhook_base_configured() -> bool:
    base = str(WEBHOOK_BASE_URL or "").strip().rstrip("/")
    if not base:
        return False
    lowered = base.lower()
    if lowered in WEBHOOK_BASE_PLACEHOLDERS:
        return False
    parsed = urlparse(base)
    return parsed.scheme in {"http", "https"} and bool(parsed.netloc)


def telegram_webhook_configured() -> bool:
    return bool(telegram_token_configured() and webhook_base_configured())

