# ============================================================================
# SECTION 1: DATABASE MODELS
# ============================================================================

def _probe_sqlite_file(db_path: Path) -> str | None:
    try:
        with sqlite3.connect(str(db_path), timeout=2) as conn:
            conn.execute("PRAGMA quick_check;").fetchone()
        return None
    except Exception as exc:
        return str(exc)


def _recover_sqlite_files(db_path: Path):
    timestamp = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")
    moved = 0
    for suffix in ("", "-journal", "-wal", "-shm"):
        candidate = Path(f"{db_path}{suffix}")
        if not candidate.exists():
            continue
        backup = candidate.with_name(f"{candidate.name}.corrupt.{timestamp}")
        try:
            candidate.replace(backup)
            moved += 1
            log.warning("DB_RECOVERY_MOVED old=%s new=%s", candidate, backup)
        except Exception as exc:
            log.error("DB_RECOVERY_MOVE_FAIL file=%s error=%s", candidate, exc)
    if moved == 0:
        log.warning("DB_RECOVERY_NO_FILES_MOVED path=%s", db_path)


def _prepare_sqlite_path(db_path: Path) -> tuple[bool, str | None]:
    try:
        db_path.parent.mkdir(parents=True, exist_ok=True)
    except Exception as exc:
        return False, f"mkdir failed: {exc}"

    if db_path.exists():
        probe_error = _probe_sqlite_file(db_path)
        if probe_error:
            if "disk i/o error" in probe_error.lower():
                log.error("DB_DISK_IO_ERROR path=%s error=%s", db_path, probe_error)
                _recover_sqlite_files(db_path)
            else:
                log.warning("DB_PROBE_FAIL path=%s error=%s", db_path, probe_error)

    try:
        with sqlite3.connect(str(db_path), timeout=5) as conn:
            conn.execute("PRAGMA quick_check;").fetchone()
    except Exception as exc:
        return False, str(exc)
    return True, None


def _select_db_file_path() -> tuple[Path, str]:
    candidates, source = _candidate_db_paths()
    if source == "fallback":
        log.warning(
            "DB_PATH_FALLBACK_MODE active; configure MIND_CLONE_DB_PATH for persistent storage."
        )
    failures: list[str] = []
    for candidate in candidates:
        ok, error = _prepare_sqlite_path(candidate)
        if ok:
            log.info("DB_PATH_SELECTED path=%s source=%s", candidate, source)
            return candidate, source
        failures.append(f"{candidate} ({error})")
        log.warning("DB_PATH_REJECTED path=%s error=%s", candidate, error)
    if source.startswith("env:"):
        raise RuntimeError(
            f"Configured DB path from {source} is unusable. "
            f"Fix the path/permissions or unset it. Details: {'; '.join(failures)}"
        )
    raise RuntimeError("No usable SQLite path found: " + "; ".join(failures))


def ensure_db_ready():
    if DB_FILE_PATH is None:
        raise RuntimeError("DB_FILE_PATH is not initialized")
    ok, error = _prepare_sqlite_path(DB_FILE_PATH)
    if not ok:
        raise RuntimeError(f"SQLite path became unusable: {DB_FILE_PATH} ({error})")


DB_FILE_PATH, DB_PATH_SOURCE = _select_db_file_path()
DATABASE_URL = _sqlite_url_for_path(DB_FILE_PATH)
log.info("SQLite DB path: %s (source=%s)", DB_FILE_PATH, DB_PATH_SOURCE)
from sqlalchemy.pool import NullPool as _NullPool
from sqlalchemy import event as _sa_event

engine = create_engine(
    DATABASE_URL,
    connect_args={"check_same_thread": False, "timeout": 30},
    poolclass=_NullPool,
)


@_sa_event.listens_for(engine, "connect")
def _set_sqlite_pragma(dbapi_connection, connection_record):
    cursor = dbapi_connection.cursor()
    cursor.execute("PRAGMA journal_mode=WAL")
    cursor.execute("PRAGMA busy_timeout=30000")
    cursor.execute("PRAGMA synchronous=NORMAL")
    cursor.close()

SessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)
