SCHEMA_MIGRATION_STEPS: list[tuple[int, str, list[str]]] = [
    (
        1,
        "usage_and_checkpoint_indexes",
        [
            "CREATE INDEX IF NOT EXISTS idx_usage_ledger_owner_task ON usage_ledger(owner_id, task_id)",
            "CREATE INDEX IF NOT EXISTS idx_task_checkpoint_task_created ON task_checkpoint_snapshots(task_id, created_at)",
            "CREATE INDEX IF NOT EXISTS idx_node_leases_node_status ON node_leases(node_name, status)",
        ],
    ),
    (
        2,
        "scheduled_jobs_run_at_time",
        [
            "ALTER TABLE scheduled_jobs ADD COLUMN run_at_time TEXT DEFAULT NULL",
        ],
    ),
    (
        3,
        "skills_indexes",
        [
            "CREATE INDEX IF NOT EXISTS idx_skill_profiles_owner_key ON skill_profiles(owner_id, skill_key)",
            "CREATE INDEX IF NOT EXISTS idx_skill_profiles_owner_status ON skill_profiles(owner_id, status)",
            "CREATE INDEX IF NOT EXISTS idx_skill_versions_skill_version ON skill_versions(skill_id, version)",
            "CREATE INDEX IF NOT EXISTS idx_skill_runs_owner_created ON skill_runs(owner_id, created_at)",
        ],
    ),
    (
        4,
        "self_improvement_notes_retrieval_count",
        [
            "ALTER TABLE self_improvement_notes ADD COLUMN retrieval_count INTEGER NOT NULL DEFAULT 0",
        ],
    ),
]


def run_schema_migrations():
    ensure_db_ready()
    with engine.begin() as conn:
        conn.execute(
            sql_text(
                "CREATE TABLE IF NOT EXISTS schema_migrations ("
                "id INTEGER PRIMARY KEY AUTOINCREMENT, "
                "version INTEGER NOT NULL UNIQUE, "
                "name TEXT NOT NULL, "
                "checksum TEXT, "
                "applied_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL)"
            )
        )
        rows = conn.execute(sql_text("SELECT version FROM schema_migrations")).fetchall()
        applied_versions = {int(row[0]) for row in rows}
        latest = max(applied_versions) if applied_versions else 0
        for version, name, statements in SCHEMA_MIGRATION_STEPS:
            if int(version) in applied_versions:
                continue
            for stmt in statements:
                try:
                    conn.execute(sql_text(stmt))
                except OperationalError as exc:
                    err_text = str(exc).lower()
                    stmt_text = str(stmt).lower()
                    # Brownfield-safe migration: skip duplicate add-column statements and continue.
                    if "duplicate column name" in err_text and "alter table" in stmt_text and "add column" in stmt_text:
                        log.warning(
                            "SCHEMA_MIGRATION_STMT_SKIPPED version=%d name=%s reason=duplicate_column",
                            int(version),
                            str(name),
                        )
                        continue
                    raise
            checksum_raw = "\n".join(statements)
            checksum = hashlib.sha256(checksum_raw.encode("utf-8")).hexdigest()
            conn.execute(
                sql_text(
                    "INSERT INTO schema_migrations (version, name, checksum) "
                    "VALUES (:version, :name, :checksum)"
                ),
                {"version": int(version), "name": str(name), "checksum": checksum},
            )
            latest = max(latest, int(version))
            log.info("SCHEMA_MIGRATION_APPLIED version=%d name=%s", int(version), str(name))
    RUNTIME_STATE["schema_version"] = int(latest)


def init_db():
    ensure_db_ready()
    Base.metadata.create_all(bind=engine)
    run_schema_migrations()


# ============================================================================
# SECTION 1B: SESSION INTEGRITY + SSRF + QUEUE MODE HELPERS
# ============================================================================

def get_session_write_lock(owner_id: int) -> threading.Lock:
    key = int(owner_id)
    with SESSION_WRITE_LOCK_GUARD:
        lock = SESSION_WRITE_LOCKS.get(key)
        if lock is None:
            lock = threading.Lock()
            SESSION_WRITE_LOCKS[key] = lock
        return lock


@contextmanager
def session_write_lock(owner_id: int, reason: str = ""):
    lock = get_session_write_lock(int(owner_id))
    waited = False
    acquired = lock.acquire(blocking=False)
    if not acquired:
        waited = True
        lock.acquire()
    try:
        if waited:
            RUNTIME_STATE["session_write_lock_waits"] = int(RUNTIME_STATE.get("session_write_lock_waits", 0)) + 1
        RUNTIME_STATE["session_write_locks_active"] = int(RUNTIME_STATE.get("session_write_locks_active", 0)) + 1
        yield
    finally:
        lock.release()
        RUNTIME_STATE["session_write_locks_active"] = max(
            0,
            int(RUNTIME_STATE.get("session_write_locks_active", 0)) - 1,
        )


def _extract_tool_call_ids_from_payload(tool_calls_payload) -> list[str]:
    ids: list[str] = []
    if not isinstance(tool_calls_payload, list):
        return ids
    for item in tool_calls_payload:
        if not isinstance(item, dict):
            continue
        raw_id = str(item.get("id") or "").strip()
        if not raw_id:
            continue
        ids.append(raw_id[:120])
    return ids


def _safe_load_tool_calls_json(raw_value: str | None):
    if not raw_value:
        return []
    try:
        parsed = json.loads(raw_value)
        return parsed if isinstance(parsed, list) else []
    except Exception:
        return []


def repair_transcript_for_owner(
    db: Session,
    owner_id: int,
    max_rows: int = 1200,
    create_synthetic: bool = True,
) -> dict:
    rows = (
        db.query(ConversationMessage)
        .filter(ConversationMessage.owner_id == int(owner_id))
        .order_by(ConversationMessage.id.asc())
        .limit(clamp_int(max_rows, 50, 10000, 1200))
        .all()
    )
    if not rows:
        return {"ok": True, "orphan_removed": 0, "synthetic_added": 0, "dedup_removed": 0, "invalid_json_fixed": 0}

    assistant_call_ids: set[str] = set()
    invalid_json_rows: list[ConversationMessage] = []
    for row in rows:
        if str(row.role or "").lower() != "assistant":
            continue
        raw_json = str(row.tool_calls_json or "").strip()
        if not raw_json:
            continue
        parsed = _safe_load_tool_calls_json(raw_json)
        if not isinstance(parsed, list) or (parsed == [] and raw_json not in {"[]", ""}):
            invalid_json_rows.append(row)
        for call_id in _extract_tool_call_ids_from_payload(parsed):
            assistant_call_ids.add(call_id)

    tool_rows: list[ConversationMessage] = []
    for row in rows:
        if str(row.role or "").lower() == "tool":
            tool_rows.append(row)

    orphan_rows: list[ConversationMessage] = []
    by_call_id: dict[str, list[ConversationMessage]] = {}
    for row in tool_rows:
        call_id = str(row.tool_call_id or "").strip()
        if not call_id or call_id not in assistant_call_ids:
            orphan_rows.append(row)
            continue
        by_call_id.setdefault(call_id, []).append(row)

    dedup_rows: list[ConversationMessage] = []
    for call_id, grouped in by_call_id.items():
        if len(grouped) <= 1:
            continue
        grouped_sorted = sorted(grouped, key=lambda x: int(x.id))
        dedup_rows.extend(grouped_sorted[:-1])

    synthetic_rows: list[ConversationMessage] = []
    if create_synthetic:
        for call_id in sorted(assistant_call_ids):
            if call_id not in by_call_id:
                synthetic_rows.append(
                    ConversationMessage(
                        owner_id=int(owner_id),
                        role="tool",
                        content=json.dumps(
                            {
                                "ok": False,
                                "error": "MISSING_TOOL_RESULT_REPAIRED",
                                "tool_call_id": call_id,
                            },
                            ensure_ascii=False,
                        ),
                        tool_call_id=call_id,
                        tool_calls_json=None,
                    )
                )

    removed_ids = {int(r.id) for r in orphan_rows + dedup_rows}
    for row in orphan_rows + dedup_rows:
        db.delete(row)

    invalid_fixed = 0
    for row in invalid_json_rows:
        row.tool_calls_json = "[]"
        invalid_fixed += 1

    for row in synthetic_rows:
        db.add(row)

    changed = bool(removed_ids or synthetic_rows or invalid_fixed)
    if changed:
        db.commit()
        RUNTIME_STATE["session_transcript_repairs"] = int(RUNTIME_STATE.get("session_transcript_repairs", 0)) + 1
        RUNTIME_STATE["session_transcript_repair_last_at"] = utc_now_iso()
        log.info(
            "SESSION_TRANSCRIPT_REPAIR owner=%d orphan_removed=%d dedup_removed=%d synthetic_added=%d invalid_json_fixed=%d",
            int(owner_id),
            len(orphan_rows),
            len(dedup_rows),
            len(synthetic_rows),
            int(invalid_fixed),
        )
    return {
        "ok": True,
        "orphan_removed": len(orphan_rows),
        "synthetic_added": len(synthetic_rows),
        "dedup_removed": len(dedup_rows),
        "invalid_json_fixed": int(invalid_fixed),
        "changed": changed,
    }


def repair_recent_transcript_if_needed(db: Session, owner_id: int) -> dict:
    with session_write_lock(int(owner_id), reason="transcript_repair"):
        return repair_transcript_for_owner(db, int(owner_id), max_rows=800, create_synthetic=True)


def run_startup_transcript_repair(limit_owners: int = 200) -> dict:
    db = SessionLocal()
    owners_processed = 0
    owners_changed = 0
    try:
        owner_rows = (
            db.query(ConversationMessage.owner_id)
            .distinct()
            .order_by(ConversationMessage.owner_id.asc())
            .limit(clamp_int(limit_owners, 1, 5000, 200))
            .all()
        )
        for row in owner_rows:
            owner_id = int(row[0])
            owners_processed += 1
            with session_write_lock(owner_id, reason="startup_repair"):
                result = repair_transcript_for_owner(db, owner_id, max_rows=2000, create_synthetic=True)
                if bool(result.get("changed", False)):
                    owners_changed += 1
        return {"ok": True, "owners_processed": owners_processed, "owners_changed": owners_changed}
    except Exception as e:
        db.rollback()
        return {"ok": False, "error": truncate_text(str(e), 220), "owners_processed": owners_processed}
    finally:
        db.close()


def normalize_tool_calls_for_guard(tool_calls) -> tuple[list[dict], list[str]]:
    warnings: list[str] = []
    normalized: list[dict] = []
    seen_ids: set[str] = set()
    if not isinstance(tool_calls, list):
        return normalized, ["tool_calls payload is not a list"]
    for idx, item in enumerate(tool_calls):
        if not isinstance(item, dict):
            warnings.append(f"tool_call[{idx}] skipped: not an object")
            continue
        function_obj = item.get("function")
        if not isinstance(function_obj, dict):
            warnings.append(f"tool_call[{idx}] skipped: missing function object")
            continue
        func_name = str(function_obj.get("name") or "").strip()
        if not func_name:
            warnings.append(f"tool_call[{idx}] skipped: missing function name")
            continue
        call_id = str(item.get("id") or "").strip()
        if not call_id:
            call_id = f"tc_repair_{uuid.uuid4().hex[:10]}"
            warnings.append(f"tool_call[{idx}] missing id; synthetic id assigned")
        call_id = truncate_text(call_id, 120)
        if call_id in seen_ids:
            call_id = f"{call_id}_{idx}"
            warnings.append(f"tool_call[{idx}] duplicate id; suffixed id assigned")
        seen_ids.add(call_id)
        raw_args = function_obj.get("arguments")
        if isinstance(raw_args, str):
            args_text = raw_args
        else:
            try:
                args_text = json.dumps(raw_args if raw_args is not None else {}, ensure_ascii=False)
            except Exception:
                args_text = "{}"
        args_text = _trim_text_for_context(args_text, 12000, "...[TRUNCATED]")
        normalized.append(
            {
                "id": call_id,
                "type": "function",
                "function": {
                    "name": func_name,
                    "arguments": args_text,
                },
            }
        )
    return normalized, warnings


def guarded_tool_result_payload(tool_name: str, call_id: str, result_obj) -> tuple[str, bool]:
    safe_obj: dict
    if isinstance(result_obj, dict):
        safe_obj = dict(result_obj)
    else:
        safe_obj = {"ok": False, "error": "TOOL_RESULT_NON_DICT", "value": truncate_text(str(result_obj), 400)}
        RUNTIME_STATE["session_tool_result_guard_blocks"] = int(RUNTIME_STATE.get("session_tool_result_guard_blocks", 0)) + 1
    if "ok" not in safe_obj:
        safe_obj["ok"] = False
    if str(call_id or "").strip() == "":
        safe_obj["ok"] = False
        safe_obj["error"] = "TOOL_RESULT_MISSING_CALL_ID"
        RUNTIME_STATE["session_tool_result_guard_blocks"] = int(RUNTIME_STATE.get("session_tool_result_guard_blocks", 0)) + 1
    try:
        payload = json.dumps(safe_obj, ensure_ascii=False)
    except Exception:
        payload = json.dumps({"ok": False, "error": "TOOL_RESULT_JSON_ENCODE_FAIL"}, ensure_ascii=False)
        RUNTIME_STATE["session_tool_result_guard_blocks"] = int(RUNTIME_STATE.get("session_tool_result_guard_blocks", 0)) + 1
    truncated = False
    if len(payload) > 10000:
        payload = payload[:10000] + "...[TRUNCATED]"
        truncated = True
    return payload, truncated


def effective_command_queue_mode(owner_id: int | None = None) -> str:
    if owner_id is not None:
        with OWNER_STATE_LOCK:
            override = OWNER_QUEUE_MODE_OVERRIDES.get(int(owner_id))
        if override:
            return _normalize_queue_mode(str(override))
    return _normalize_queue_mode(COMMAND_QUEUE_MODE)


def set_owner_queue_mode(owner_id: int, mode: str) -> str:
    normalized = _normalize_queue_mode(mode)
    with OWNER_STATE_LOCK:
        OWNER_QUEUE_MODE_OVERRIDES[int(owner_id)] = normalized
    RUNTIME_STATE["command_queue_mode_override_count"] = int(RUNTIME_STATE.get("command_queue_mode_override_count", 0)) + 1
    return normalized


def _collect_buffer_append(
    owner_id: int,
    text: str,
    lane: str,
    source: str,
    chat_id: str | None = None,
    username: str | None = None,
) -> tuple[str, bool]:
    now_mono = time.monotonic()
    with OWNER_COLLECT_LOCK:
        row = OWNER_COLLECT_BUFFERS.get(int(owner_id))
        if row is None:
            row = {
                "parts": [],
                "lane": normalize_queue_lane(lane),
                "source": str(source or "telegram"),
                "chat_id": str(chat_id or ""),
                "username": str(username or ""),
                "expires_mono": now_mono + float(COMMAND_QUEUE_COLLECT_WINDOW_SECONDS),
            }
            OWNER_COLLECT_BUFFERS[int(owner_id)] = row
        else:
            if chat_id:
                row["chat_id"] = str(chat_id)
            if username:
                row["username"] = str(username)
        row["parts"].append(str(text or "").strip())
        row["expires_mono"] = now_mono + float(COMMAND_QUEUE_COLLECT_WINDOW_SECONDS)
        merged = "\n".join([part for part in row["parts"] if part]).strip()
        should_flush = len(row["parts"]) >= 3
        return merged, should_flush


def _collect_buffer_pop(owner_id: int) -> dict | None:
    with OWNER_COLLECT_LOCK:
        return OWNER_COLLECT_BUFFERS.pop(int(owner_id), None)


def pop_expired_collect_buffers(now_mono: float | None = None) -> list[dict]:
    now_val = float(now_mono if now_mono is not None else time.monotonic())
    flushed: list[dict] = []
    with OWNER_COLLECT_LOCK:
        owner_ids = list(OWNER_COLLECT_BUFFERS.keys())
        for owner_id in owner_ids:
            row = OWNER_COLLECT_BUFFERS.get(owner_id) or {}
            expires = float(row.get("expires_mono", 0.0) or 0.0)
            parts = [str(part).strip() for part in list(row.get("parts") or []) if str(part).strip()]
            if not parts:
                OWNER_COLLECT_BUFFERS.pop(owner_id, None)
                continue
            if expires > now_val:
                continue
            OWNER_COLLECT_BUFFERS.pop(owner_id, None)
            flushed.append(
                {
                    "owner_id": int(owner_id),
                    "text": "\n".join(parts),
                    "lane": normalize_queue_lane(str(row.get("lane") or "default")),
                    "source": str(row.get("source") or "telegram"),
                    "chat_id": str(row.get("chat_id") or ""),
                    "username": str(row.get("username") or ""),
                }
            )
    return flushed


def _extract_command_prefix(command_text: str) -> str:
    command = str(command_text or "").strip()
    if not command:
        return ""
    try:
        parts = shlex.split(command, posix=False)
    except Exception:
        parts = command.split()
    if not parts:
        return ""
    token = str(parts[0]).strip().lower()
    token = token.replace("\\", "/").split("/")[-1]
    token = token.replace(".exe", "")
    return token


def enforce_node_command_policy(node_name: str, command: str, capability: str | None = None) -> tuple[bool, str]:
    if full_power_system_enabled():
        return True, ""
    prefix = _extract_command_prefix(command)
    if not prefix:
        return False, "Empty command is not allowed."
    if prefix in NODE_COMMAND_DENY_PREFIXES:
        RUNTIME_STATE["node_policy_blocks"] = int(RUNTIME_STATE.get("node_policy_blocks", 0)) + 1
        return False, f"Node command policy blocked prefix '{prefix}'."
    if NODE_COMMAND_ALLOW_PREFIXES and prefix not in NODE_COMMAND_ALLOW_PREFIXES:
        RUNTIME_STATE["node_policy_blocks"] = int(RUNTIME_STATE.get("node_policy_blocks", 0)) + 1
        return False, f"Node command prefix '{prefix}' is not allowlisted."
    cap = str(capability or "").strip().lower()
    if cap == "research" and prefix in {"rm", "del", "format", "diskpart"}:
        RUNTIME_STATE["node_policy_blocks"] = int(RUNTIME_STATE.get("node_policy_blocks", 0)) + 1
        return False, f"Capability '{cap}' cannot execute '{prefix}'."
    return True, ""


def _ssrf_blocked_ip(ip_value: str) -> bool:
    try:
        ip = ipaddress.ip_address(ip_value)
    except Exception:
        return True
    if ip.is_unspecified or ip.is_multicast:
        return True
    if ip.is_loopback and SSRF_BLOCK_LOCALHOST:
        return True
    if not SSRF_ALLOW_PRIVATE_NET and (ip.is_private or ip.is_link_local or ip.is_reserved):
        return True
    return False


def validate_outbound_url(url: str) -> tuple[bool, str]:
    raw = str(url or "").strip()
    if not raw:
        return False, "URL is empty."
    try:
        parsed = urlparse(raw)
    except Exception:
        return False, "URL parsing failed."
    scheme = str(parsed.scheme or "").lower()
    if scheme not in {"http", "https"}:
        return False, "Only http/https URLs are allowed."
    if parsed.username or parsed.password:
        return False, "URL credentials are not allowed."
    host = normalize_domain(str(parsed.netloc or "").split("@")[-1].split(":")[0])
    if not host:
        return False, "URL host is required."
    if SSRF_ALLOW_HOSTS and host not in SSRF_ALLOW_HOSTS and not any(host.endswith("." + x) for x in SSRF_ALLOW_HOSTS):
        return False, f"Host '{host}' is not in SSRF allowlist."
    if host in SSRF_DENY_HOSTS or any(host.endswith("." + x) for x in SSRF_DENY_HOSTS):
        return False, f"Host '{host}' is denylisted."
    if host in {"localhost", "127.0.0.1", "::1"} and SSRF_BLOCK_LOCALHOST:
        return False, "Localhost access is blocked."
    if not SSRF_GUARD_ENABLED:
        return True, ""
    old_timeout = socket.getdefaulttimeout()
    try:
        socket.setdefaulttimeout(float(SSRF_RESOLVE_TIMEOUT_SECONDS))
        records = socket.getaddrinfo(host, None)
    except Exception as e:
        return False, f"DNS resolution failed for host '{host}': {truncate_text(str(e), 160)}"
    finally:
        socket.setdefaulttimeout(old_timeout)
    ips_checked = set()
    for rec in records:
        ip_val = str(rec[4][0])
        if ip_val in ips_checked:
            continue
        ips_checked.add(ip_val)
        if _ssrf_blocked_ip(ip_val):
            return False, f"Host '{host}' resolved to blocked IP '{ip_val}'."
    return True, ""


def apply_url_safety_guard(url: str, source: str = "web_fetch") -> tuple[bool, str]:
    ok, reason = validate_outbound_url(url)
    if not ok:
        RUNTIME_STATE["ssrf_blocked_requests"] = int(RUNTIME_STATE.get("ssrf_blocked_requests", 0)) + 1
        log.warning("SSRF_BLOCK source=%s url=%s reason=%s", source, truncate_text(str(url), 180), truncate_text(reason, 220))
    return ok, reason


def build_protocol_schema_registry() -> dict[str, dict]:
    # Lightweight contracts for payload drift detection on core API surfaces.
    return {
        "chat.request": {"required": ["chat_id", "message"], "types": {"chat_id": str, "message": str}},
        "chat.response": {"required": ["ok"], "types": {"ok": bool}},
        "approval.decision.request": {"required": ["chat_id", "token", "approve"], "types": {"chat_id": str, "token": str, "approve": bool}},
        "approval.decision.response": {"required": ["ok"], "types": {"ok": bool}},
        "queue.mode.request": {"required": ["chat_id", "mode"], "types": {"chat_id": str, "mode": str}},
        "queue.mode.response": {"required": ["ok", "mode"], "types": {"ok": bool, "mode": str}},
        "ui.tasks.create.request": {"required": ["chat_id", "title", "goal"], "types": {"chat_id": str, "title": str, "goal": str}},
        "ui.tasks.create.response": {"required": ["ok"], "types": {"ok": bool}},
        "skills.generate.request": {"required": ["chat_id", "request_text"], "types": {"chat_id": str, "request_text": str}},
        "skills.generate.response": {"required": ["ok"], "types": {"ok": bool}},
        "skills.activate.request": {"required": ["chat_id"], "types": {"chat_id": str}},
        "skills.activate.response": {"required": ["ok"], "types": {"ok": bool}},
        "skills.rollback.request": {"required": ["chat_id", "version"], "types": {"chat_id": str, "version": int}},
        "skills.rollback.response": {"required": ["ok"], "types": {"ok": bool}},
        "session.lanes.response": {"required": ["ok", "count"], "types": {"ok": bool, "count": int}},
        "runtime.metrics.response": {"required": ["worker_alive", "task_queue_size", "tasks_tracked"], "types": {"worker_alive": bool}},
    }


PROTOCOL_SCHEMA_REGISTRY = build_protocol_schema_registry()
RUNTIME_STATE["protocol_schema_count"] = len(PROTOCOL_SCHEMA_REGISTRY)


def protocol_validate_payload(contract_name: str, payload: dict, direction: str = "request") -> tuple[bool, str]:
    contract = PROTOCOL_SCHEMA_REGISTRY.get(contract_name)
    if not contract:
        return True, ""
    if not isinstance(payload, dict):
        RUNTIME_STATE["protocol_schema_failures"] = int(RUNTIME_STATE.get("protocol_schema_failures", 0)) + 1
        return False, f"Contract '{contract_name}' expects object payload."
    required = list(contract.get("required") or [])
    types = dict(contract.get("types") or {})
    for key in required:
        if key not in payload:
            RUNTIME_STATE["protocol_schema_failures"] = int(RUNTIME_STATE.get("protocol_schema_failures", 0)) + 1
            return False, f"Contract '{contract_name}' missing required key '{key}'."
    for key, expected in types.items():
        if key in payload and expected is not None and not isinstance(payload.get(key), expected):
            RUNTIME_STATE["protocol_schema_failures"] = int(RUNTIME_STATE.get("protocol_schema_failures", 0)) + 1
            return False, f"Contract '{contract_name}' key '{key}' has wrong type."
    RUNTIME_STATE["protocol_schema_validations"] = int(RUNTIME_STATE.get("protocol_schema_validations", 0)) + 1
    return True, ""


def protocol_contracts_public_view(registry: dict[str, dict]) -> dict[str, dict]:
    public: dict[str, dict] = {}
    for name, contract in registry.items():
        required = list(_safe_json_list((contract or {}).get("required"), []))
        raw_types = _safe_json_dict((contract or {}).get("types"), {})
        encoded_types: dict[str, str] = {}
        for key, expected in raw_types.items():
            if isinstance(expected, type):
                encoded_types[str(key)] = expected.__name__
            elif isinstance(expected, tuple):
                names: list[str] = []
                for item in expected:
                    if isinstance(item, type):
                        names.append(item.__name__)
                    else:
                        names.append(str(item))
                encoded_types[str(key)] = "|".join(names)
            else:
                encoded_types[str(key)] = str(expected)
        public[str(name)] = {"required": required, "types": encoded_types}
    return public


def normalize_skill_key(raw_value: str, fallback_prefix: str = "skill") -> str:
    text = re.sub(r"[^a-z0-9_]+", "_", str(raw_value or "").strip().lower()).strip("_")
    if not text:
        text = f"{fallback_prefix}_{uuid.uuid4().hex[:8]}"
    return truncate_text(text, 60)


def _skill_intent_hash(intent: str) -> str:
    normalized = re.sub(r"\s+", " ", str(intent or "").strip().lower())
    return hashlib.sha256(normalized.encode("utf-8")).hexdigest()[:40]


def _safe_skill_hints(raw_hints) -> list[str]:
    hints: list[str] = []
    if isinstance(raw_hints, list):
        source = raw_hints
    elif isinstance(raw_hints, str) and raw_hints.strip():
        source = [item.strip() for item in raw_hints.split(",") if item.strip()]
    else:
        source = []
    for item in source:
        hint = truncate_text(str(item or "").strip(), 120)
        if hint and hint not in hints:
            hints.append(hint)
        if len(hints) >= 24:
            break
    return hints


def _skills_owner_root(owner_id: int) -> Path:
    path = (SKILLS_VAULT_ROOT / f"owner_{int(owner_id)}").resolve(strict=False)
    path.mkdir(parents=True, exist_ok=True)
    return path


def _skill_artifact_path(owner_id: int, skill_key: str, version: int) -> Path:
    base = (_skills_owner_root(owner_id) / normalize_skill_key(skill_key)).resolve(strict=False)
    base.mkdir(parents=True, exist_ok=True)
    file_name = f"v{int(version):06d}.json"
    return (base / file_name).resolve(strict=False)


def _skill_status_normalized(raw_status: str) -> str:
    value = str(raw_status or "").strip().lower()
    if value in {"active", "inactive", "archived"}:
        return value
    return "inactive"


def _skill_find_profile(
    db: Session,
    owner_id: int,
    skill_id: int | None = None,
    skill_key: str | None = None,
) -> SkillProfile | None:
    q = db.query(SkillProfile).filter(SkillProfile.owner_id == int(owner_id))
    if skill_id is not None:
        return q.filter(SkillProfile.id == int(skill_id)).first()
    raw_key = str(skill_key or "").strip()
    if not raw_key:
        return None
    key = normalize_skill_key(raw_key)
    return q.filter(SkillProfile.skill_key == key).order_by(SkillProfile.id.desc()).first()


def _skill_version_row(
    db: Session,
    owner_id: int,
    skill_id: int,
    version: int,
) -> SkillVersion | None:
    return (
        db.query(SkillVersion)
        .filter(
            SkillVersion.owner_id == int(owner_id),
            SkillVersion.skill_id == int(skill_id),
            SkillVersion.version == int(version),
        )
        .first()
    )


def _skill_public_payload(db: Session, row: SkillProfile) -> dict:
    active_version = max(1, int(row.active_version or 1))
    version_row = _skill_version_row(db, int(row.owner_id), int(row.id), active_version)
    active_preview = ""
    if version_row and version_row.body_text:
        active_preview = truncate_text(str(version_row.body_text), 240)
    return {
        "id": int(row.id),
        "owner_id": int(row.owner_id),
        "skill_key": str(row.skill_key or ""),
        "title": str(row.title or ""),
        "intent": str(row.intent or ""),
        "trigger_hints": _safe_json_list(row.trigger_hints_json, []),
        "status": _skill_status_normalized(str(row.status or "")),
        "active_version": int(row.active_version or 1),
        "latest_version": int(row.latest_version or 1),
        "source_type": str(row.source_type or "manual"),
        "auto_created": bool(int(row.auto_created or 0)),
        "usage_count": int(row.usage_count or 0),
        "last_used_at": iso_datetime_or_none(row.last_used_at),
        "active_body_preview": active_preview,
        "created_at": iso_datetime_or_none(row.created_at),
        "updated_at": iso_datetime_or_none(row.updated_at),
    }


def _skill_write_artifact(path: Path, payload: dict):
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def _owner_skill_count(db: Session, owner_id: int) -> int:
    return int(
        db.query(func.count(SkillProfile.id))
        .filter(SkillProfile.owner_id == int(owner_id))
        .scalar()
        or 0
    )


def save_skill_profile(
    db: Session,
    *,
    owner_id: int,
    title: str,
    intent: str,
    body_text: str,
    trigger_hints: list[str] | None = None,
    skill_key: str | None = None,
    source_type: str = "manual",
    auto_created: bool = False,
    auto_activate: bool = True,
    metadata: dict | None = None,
) -> dict:
    if not SKILLS_ENABLED:
        return {"ok": False, "error": "Skills are disabled by config."}

    owner = int(owner_id)
    clean_title = truncate_text(str(title or "").strip(), 160)
    clean_intent = truncate_text(str(intent or "").strip(), 1200)
    clean_body = truncate_text(str(body_text or "").strip(), SKILLS_MAX_BODY_CHARS)
    if not clean_title:
        return {"ok": False, "error": "Skill title is required."}
    if not clean_intent:
        return {"ok": False, "error": "Skill intent is required."}
    if not clean_body:
        return {"ok": False, "error": "Skill body is required."}

    hints = _safe_skill_hints(trigger_hints or [])
    key_seed = skill_key or clean_title
    key = normalize_skill_key(key_seed)
    if not key:
        key = normalize_skill_key(clean_title, fallback_prefix="skill")
    intent_hash = _skill_intent_hash(clean_intent)
    meta = _safe_json_dict(metadata, {})

    with SKILL_LOCK:
        existing = _skill_find_profile(db, owner, skill_key=key)
        if existing is None:
            if _owner_skill_count(db, owner) >= SKILLS_MAX_PER_OWNER:
                return {"ok": False, "error": f"Max skills reached ({SKILLS_MAX_PER_OWNER})."}
            existing = SkillProfile(
                owner_id=owner,
                skill_key=key,
                title=clean_title,
                intent=clean_intent,
                intent_hash=intent_hash,
                trigger_hints_json=json.dumps(hints, ensure_ascii=False),
                status="active" if auto_activate else "inactive",
                active_version=1,
                latest_version=0,
                source_type=truncate_text(str(source_type or "manual"), 40),
                auto_created=1 if auto_created else 0,
                usage_count=0,
            )
            db.add(existing)
            db.flush()

        next_version = int(existing.latest_version or 0) + 1
        artifact_payload = {
            "owner_id": owner,
            "skill_id": int(existing.id),
            "skill_key": key,
            "title": clean_title,
            "intent": clean_intent,
            "trigger_hints": hints,
            "version": int(next_version),
            "body_text": clean_body,
            "metadata": meta,
            "source_type": str(source_type or "manual"),
            "auto_created": bool(auto_created),
            "saved_at": utc_now_iso(),
        }
        artifact_path = _skill_artifact_path(owner, key, next_version)
        _skill_write_artifact(artifact_path, artifact_payload)

        version_row = SkillVersion(
            owner_id=owner,
            skill_id=int(existing.id),
            version=int(next_version),
            body_text=clean_body,
            metadata_json=json.dumps(meta, ensure_ascii=False),
            artifact_path=str(artifact_path),
        )
        db.add(version_row)

        existing.title = clean_title
        existing.intent = clean_intent
        existing.intent_hash = intent_hash
        existing.trigger_hints_json = json.dumps(hints, ensure_ascii=False)
        existing.latest_version = int(next_version)
        existing.source_type = truncate_text(str(source_type or "manual"), 40)
        if auto_created:
            existing.auto_created = 1
        if auto_activate:
            existing.status = "active"
            existing.active_version = int(next_version)

        db.commit()
        db.refresh(existing)
        RUNTIME_STATE["skills_total"] = int(RUNTIME_STATE.get("skills_total", 0)) + (1 if next_version == 1 else 0)
        RUNTIME_STATE["skills_versions_total"] = int(RUNTIME_STATE.get("skills_versions_total", 0)) + 1
        RUNTIME_STATE["skills_generated_total"] = int(RUNTIME_STATE.get("skills_generated_total", 0)) + 1
        if auto_created:
            RUNTIME_STATE["skills_autogenerated_total"] = int(RUNTIME_STATE.get("skills_autogenerated_total", 0)) + 1
        if auto_activate:
            RUNTIME_STATE["skills_activated_total"] = int(RUNTIME_STATE.get("skills_activated_total", 0)) + 1
        RUNTIME_STATE["skills_vault_root"] = str(SKILLS_VAULT_ROOT)

        return {
            "ok": True,
            "skill": _skill_public_payload(db, existing),
            "version": int(next_version),
            "artifact_path": str(artifact_path),
        }


def list_skill_profiles(
    db: Session,
    owner_id: int,
    include_inactive: bool = False,
    limit: int = 40,
) -> list[dict]:
    q = db.query(SkillProfile).filter(SkillProfile.owner_id == int(owner_id))
    if not include_inactive:
        q = q.filter(SkillProfile.status == "active")
    rows = q.order_by(SkillProfile.updated_at.desc(), SkillProfile.id.desc()).limit(clamp_int(limit, 1, 200, 40)).all()
    return [_skill_public_payload(db, row) for row in rows]


def skill_profile_detail(db: Session, owner_id: int, skill_id: int) -> dict:
    row = _skill_find_profile(db, int(owner_id), skill_id=int(skill_id))
    if row is None:
        return {"ok": False, "error": "Skill not found."}
    versions = (
        db.query(SkillVersion)
        .filter(SkillVersion.owner_id == int(owner_id), SkillVersion.skill_id == int(row.id))
        .order_by(SkillVersion.version.desc())
        .limit(120)
        .all()
    )
    return {
        "ok": True,
        "skill": _skill_public_payload(db, row),
        "versions": [
            {
                "version": int(v.version or 0),
                "artifact_path": str(v.artifact_path or ""),
                "metadata": _safe_json_dict(v.metadata_json, {}),
                "body_preview": truncate_text(str(v.body_text or ""), 320),
                "created_at": iso_datetime_or_none(v.created_at),
            }
            for v in versions
        ],
    }


def set_skill_status(
    db: Session,
    owner_id: int,
    *,
    skill_id: int | None = None,
    skill_key: str | None = None,
    active: bool = True,
    version: int | None = None,
) -> dict:
    row = _skill_find_profile(db, int(owner_id), skill_id=skill_id, skill_key=skill_key)
    if row is None:
        return {"ok": False, "error": "Skill not found."}

    if active:
        target_version = int(version or row.latest_version or 1)
        vrow = _skill_version_row(db, int(owner_id), int(row.id), target_version)
        if vrow is None:
            return {"ok": False, "error": f"Version {target_version} not found for skill '{row.skill_key}'."}
        row.status = "active"
        row.active_version = int(target_version)
        RUNTIME_STATE["skills_activated_total"] = int(RUNTIME_STATE.get("skills_activated_total", 0)) + 1
    else:
        row.status = "inactive"
        RUNTIME_STATE["skills_deactivated_total"] = int(RUNTIME_STATE.get("skills_deactivated_total", 0)) + 1

    db.commit()
    db.refresh(row)
    return {"ok": True, "skill": _skill_public_payload(db, row)}


def rollback_skill_version(
    db: Session,
    owner_id: int,
    *,
    skill_id: int | None = None,
    skill_key: str | None = None,
    version: int,
) -> dict:
    row = _skill_find_profile(db, int(owner_id), skill_id=skill_id, skill_key=skill_key)
    if row is None:
        return {"ok": False, "error": "Skill not found."}
    target_version = int(version or 0)
    if target_version <= 0:
        return {"ok": False, "error": "version must be > 0"}
    vrow = _skill_version_row(db, int(owner_id), int(row.id), target_version)
    if vrow is None:
        return {"ok": False, "error": f"Version {target_version} not found for skill '{row.skill_key}'."}
    row.active_version = int(target_version)
    row.status = "active"
    db.commit()
    db.refresh(row)
    RUNTIME_STATE["skills_rollbacks_total"] = int(RUNTIME_STATE.get("skills_rollbacks_total", 0)) + 1
    return {"ok": True, "skill": _skill_public_payload(db, row)}


def _skill_keyword_set(text: str) -> set[str]:
    return {
        token
        for token in re.findall(r"[a-z0-9_]{3,}", str(text or "").lower())
        if token
    }


def _score_skill_for_message(message: str, row: SkillProfile) -> int:
    msg = str(message or "").lower()
    msg_words = _skill_keyword_set(msg)
    score = 0
    for hint in _safe_json_list(row.trigger_hints_json, []):
        hint_text = str(hint or "").strip().lower()
        if not hint_text:
            continue
        if hint_text in msg:
            score += 4
        hint_words = _skill_keyword_set(hint_text)
        if hint_words and (hint_words & msg_words):
            score += 1
    title_words = _skill_keyword_set(str(row.title or ""))
    if title_words and (title_words & msg_words):
        score += 1
    return score


def select_active_skills_for_prompt(
    db: Session,
    owner_id: int,
    user_message: str,
    top_k: int | None = None,
    session_id: str | None = None,
) -> list[str]:
    if not SKILLS_ENABLED:
        return []
    rows = (
        db.query(SkillProfile)
        .filter(
            SkillProfile.owner_id == int(owner_id),
            SkillProfile.status == "active",
        )
        .order_by(SkillProfile.updated_at.desc())
        .limit(200)
        .all()
    )
    if not rows:
        return []

    ranked: list[tuple[int, SkillProfile, SkillVersion | None]] = []
    for row in rows:
        score = _score_skill_for_message(user_message, row)
        vrow = _skill_version_row(db, int(owner_id), int(row.id), int(row.active_version or 1))
        ranked.append((score, row, vrow))

    ranked.sort(key=lambda item: (item[0], int(item[1].usage_count or 0)), reverse=True)
    cap = clamp_int(top_k if top_k is not None else SKILLS_ACTIVE_TOP_K, 1, 10, SKILLS_ACTIVE_TOP_K)
    selected = [item for item in ranked if item[0] > 0][:cap]
    if not selected and ranked:
        selected = ranked[:1]

    prompt_blocks: list[str] = []
    for score, row, vrow in selected:
        body = truncate_text(str((vrow.body_text if vrow else "") or ""), 600)
        hints = ", ".join(_safe_json_list(row.trigger_hints_json, [])[:6])
        prompt_blocks.append(
            f"{row.title} (key={row.skill_key}, v={int(row.active_version or 1)}, score={int(score)}): "
            f"{body} Trigger hints: {hints or 'none'}."
        )
        row.usage_count = int(row.usage_count or 0) + 1
        row.last_used_at = datetime.utcnow()
        db.add(
            SkillRun(
                owner_id=int(owner_id),
                skill_id=int(row.id),
                skill_version=int(row.active_version or 1),
                session_id=str(session_id or ""),
                source_type="chat",
                source_ref=str(owner_id),
                status="invoked",
                message_preview=truncate_text(user_message, 220),
                output_preview="",
            )
        )

    db.commit()
    RUNTIME_STATE["skills_prompt_injections"] = int(RUNTIME_STATE.get("skills_prompt_injections", 0)) + len(prompt_blocks)
    return prompt_blocks


def synthesize_skill_blueprint(request_text: str, preferred_name: str | None = None) -> dict:
    text = str(request_text or "").strip()
    lowered = text.lower()
    raw_pref = str(preferred_name or "").strip()
    key = normalize_skill_key(raw_pref) if raw_pref else ""
    hints: list[str] = []
    title = "Autonomous Research Skill"
    body = (
        "When triggered, run a structured research pass:\n"
        "1) Identify key unknowns.\n"
        "2) Use search_web for recent high-trust sources.\n"
        "3) Use read_webpage/deep_research for synthesis.\n"
        "4) Produce concise output with assumptions, risks, and next steps."
    )
    intent = text or "Autonomous multi-step research and synthesis."

    if "crypto" in lowered or "bitcoin" in lowered or "ethereum" in lowered:
        title = "Daily Crypto Intelligence Brief"
        if not key:
            key = "daily_crypto_brief"
        hints = ["crypto", "bitcoin", "ethereum", "market update", "signal", "every morning"]
        body = (
            "Run a daily crypto market briefing:\n"
            "1) Gather latest price/action context from trusted market sources.\n"
            "2) Gather top macro/regulatory/news drivers.\n"
            "3) Build a directional bias with confidence and invalidation levels.\n"
            "4) If requested, include simple regression/game-theory framing and clearly state uncertainty."
        )
    elif "news" in lowered:
        title = "Daily News Digest Skill"
        if not key:
            key = "daily_news_digest"
        hints = ["news", "morning brief", "daily update"]
        body = (
            "Build a daily briefing:\n"
            "1) Collect top global and domain-specific updates from trusted outlets.\n"
            "2) Cluster related stories and remove duplicates.\n"
            "3) Summarize key developments, why they matter, and potential next impacts."
        )

    if "regression" in lowered and "regression" not in body.lower():
        body += "\n5) Apply a lightweight regression sanity-check when numeric time-series data is available."
    if "game theory" in lowered and "game-theory" not in body.lower():
        body += "\n6) Add game-theory framing for strategic actor behavior when relevant."

    if not hints:
        hints = [token for token in sorted(_skill_keyword_set(lowered))[:8]]
    if not key:
        key = normalize_skill_key(title, fallback_prefix="skill")
    return {
        "skill_key": key,
        "title": title,
        "intent": intent,
        "trigger_hints": hints,
        "body_text": body,
    }


def maybe_autocreate_skill_from_gap(
    db: Session,
    owner_id: int,
    user_message: str,
    assistant_text: str,
    session_id: str | None = None,
) -> dict | None:
    if not (SKILLS_ENABLED and SKILLS_AUTO_CREATE_ENABLED):
        return None
    gap_phrases = {"i don't have a tool", "no tool available", "i cannot", "i lack the capability", "not currently able to"}
    response_text = str(assistant_text or "").lower()
    if not any(phrase in response_text for phrase in gap_phrases):
        return None

    now = time.monotonic()
    with SKILL_LOCK:
        last = float(SKILL_AUTOCREATE_LAST_AT.get(int(owner_id), 0.0) or 0.0)
        if now - last < float(SKILLS_AUTO_CREATE_COOLDOWN_SECONDS):
            return None
        SKILL_AUTOCREATE_LAST_AT[int(owner_id)] = now

    blueprint = synthesize_skill_blueprint(user_message)
    result = save_skill_profile(
        db,
        owner_id=int(owner_id),
        title=str(blueprint.get("title") or "Auto Skill"),
        intent=str(blueprint.get("intent") or user_message),
        body_text=str(blueprint.get("body_text") or ""),
        trigger_hints=_safe_skill_hints(blueprint.get("trigger_hints") or []),
        skill_key=str(blueprint.get("skill_key") or ""),
        source_type="auto",
        auto_created=True,
        auto_activate=bool(SKILLS_AUTO_ACTIVATE_ENABLED),
        metadata={"reason": "capability_gap", "session_id": str(session_id or "")},
    )
    if result.get("ok"):
        log.info(
            "SKILL_AUTOCREATED owner=%d key=%s version=%s",
            int(owner_id),
            str((result.get("skill") or {}).get("skill_key") or ""),
            str(result.get("version") or ""),
        )
    return result


def _session_lane_key(owner_id: int, chat_id: str) -> str:
    chat = truncate_text(str(chat_id or "").strip() or "owner", 120)
    return f"{int(owner_id)}::{chat}"


def session_lane_mark(
    *,
    owner_id: int,
    chat_id: str,
    lane: str,
    run_id: str,
    event: str,
    status: str,
    source: str,
    error: str | None = None,
):
    now_iso = utc_now_iso()
    now_mono = time.monotonic()
    key = _session_lane_key(owner_id, chat_id)
    lane_name = normalize_queue_lane(lane)
    event_name = truncate_text(str(event or "event"), 80)
    status_name = truncate_text(str(status or "unknown"), 40)
    source_name = truncate_text(str(source or "api"), 40)
    run = truncate_text(str(run_id or uuid.uuid4().hex), 80)
    with SESSION_LANE_LOCK:
        row = SESSION_LANES.get(key)
        if row is None:
            row = {
                "session_key": key,
                "owner_id": int(owner_id),
                "chat_id": str(chat_id or ""),
                "lane": lane_name,
                "run_id": run,
                "last_event": event_name,
                "status": status_name,
                "source": source_name,
                "events": 0,
                "accepted_at": now_iso,
                "started_at": None,
                "completed_at": None,
                "updated_at": now_iso,
                "_updated_mono": now_mono,
                "queue_depth": 0,
                "owner_active": False,
                "last_error": None,
            }
            SESSION_LANES[key] = row
        row["lane"] = lane_name
        row["run_id"] = run
        row["last_event"] = event_name
        row["status"] = status_name
        row["source"] = source_name
        row["events"] = int(row.get("events", 0)) + 1
        row["updated_at"] = now_iso
        row["_updated_mono"] = now_mono
        if event_name == "accepted" and not row.get("accepted_at"):
            row["accepted_at"] = now_iso
        if event_name == "running":
            row["started_at"] = now_iso
        if status_name in {"completed", "failed", "timeout"}:
            row["completed_at"] = now_iso
        row["last_error"] = truncate_text(str(error or ""), 220) if error else None
        SESSION_RUN_INDEX[run] = key

        row["queue_depth"] = int(owner_queue_count(int(owner_id)))
        row["owner_active"] = bool(is_owner_busy_or_backlogged(int(owner_id)))
        RUNTIME_STATE["session_lanes_tracked"] = len(SESSION_LANES)
        RUNTIME_STATE["session_lane_events_total"] = int(RUNTIME_STATE.get("session_lane_events_total", 0)) + 1


def session_lanes_snapshot(
    owner_id: int | None = None,
    include_stale: bool = False,
    limit: int = 100,
) -> dict:
    now = time.monotonic()
    stale_cutoff = float(SESSION_LANE_STALE_SECONDS)
    rows: list[dict] = []
    with SESSION_LANE_LOCK:
        for row in SESSION_LANES.values():
            if owner_id is not None and int(row.get("owner_id", 0)) != int(owner_id):
                continue
            age = max(0.0, now - float(row.get("_updated_mono", now)))
            if not include_stale and age > stale_cutoff:
                continue
            item = dict(row)
            item.pop("_updated_mono", None)
            item["age_seconds"] = round(age, 3)
            rows.append(item)
    rows.sort(key=lambda item: float(item.get("age_seconds", 0.0)), reverse=False)
    cap = clamp_int(limit, 1, 500, 100)
    rows = rows[:cap]
    return {
        "ok": True,
        "count": len(rows),
        "limit": cap,
        "stale_cutoff_seconds": int(stale_cutoff),
        "items": rows,
    }


# ============================================================================
# SECTION 2: TOOL IMPLEMENTATIONS
# ============================================================================

# --- File Operations ---

def tool_read_file(file_path: str) -> dict:
    try:
        if not os.path.exists(file_path):
            return {"ok": False, "error": "File not found", "path": file_path}
        with open(file_path, "r", encoding="utf-8") as f:
            content = f.read()
        return {"ok": True, "content": content, "path": file_path}
    except Exception as e:
        return {"ok": False, "error": str(e), "path": file_path}


def tool_write_file(file_path: str, content: str) -> dict:
    try:
        parent_dir = os.path.dirname(file_path)
        if parent_dir and not os.path.exists(parent_dir):
            os.makedirs(parent_dir)
        with open(file_path, "w", encoding="utf-8") as f:
            f.write(content)
        return {"ok": True, "path": file_path, "bytes_written": len(content)}
    except Exception as e:
        return {"ok": False, "error": str(e), "path": file_path}


def tool_list_directory(dir_path: str) -> dict:
    try:
        if not os.path.exists(dir_path):
            return {"ok": False, "error": "Directory not found", "path": dir_path}
        if not os.path.isdir(dir_path):
            return {"ok": False, "error": "Path is not a directory", "path": dir_path}
        items = []
        for name in os.listdir(dir_path):
            full_path = os.path.join(dir_path, name)
            items.append({
                "name": name,
                "is_dir": os.path.isdir(full_path),
                "size": os.path.getsize(full_path) if os.path.isfile(full_path) else None
            })
        return {"ok": True, "path": dir_path, "items": items}
    except Exception as e:
        return {"ok": False, "error": str(e), "path": dir_path}


# --- Terminal Operations ---

def tool_run_command(command: str, timeout: int = 30, cwd: str | None = None) -> dict:
    policy_ok, policy_reason = enforce_node_command_policy("local", command, capability="general")
    if not policy_ok:
        return {"ok": False, "error": policy_reason, "command": command, "cwd": str(cwd or "")}
    try:
        run_cwd = str(cwd or "").strip() or None
        result = subprocess.run(
            command,
            shell=True,
            capture_output=True,
            text=True,
            timeout=timeout,
            cwd=run_cwd,
        )
        return {
            "ok": True,
            "stdout": result.stdout,
            "stderr": result.stderr,
            "return_code": result.returncode,
            "cwd": run_cwd,
        }
    except subprocess.TimeoutExpired:
        return {"ok": False, "error": "Command timed out", "command": command, "cwd": str(cwd or "")}
    except Exception as e:
        return {"ok": False, "error": str(e), "command": command, "cwd": str(cwd or "")}


# --- Code Execution ---

def tool_execute_python(code: str, timeout: int = 15, cwd: str | None = None) -> dict:
    """Execute Python code in a subprocess and return stdout/stderr."""
    try:
        run_cwd = str(cwd or "").strip() or None
        result = subprocess.run(
            ["python", "-c", code],
            capture_output=True, text=True, timeout=timeout,
            env={**os.environ, "PYTHONDONTWRITEBYTECODE": "1"},
            cwd=run_cwd,
        )
        output = result.stdout
        if result.stderr:
            output += "\n[STDERR]\n" + result.stderr
        if len(output) > 8000:
            output = output[:8000] + "\n...[TRUNCATED]"
        return {
            "ok": True,
            "output": output,
            "return_code": result.returncode,
            "cwd": run_cwd,
        }
    except subprocess.TimeoutExpired:
        return {"ok": False, "error": f"Code execution timed out after {timeout}s", "cwd": str(cwd or "")}
    except Exception as e:
        return {"ok": False, "error": str(e), "cwd": str(cwd or "")}


# --- Desktop Automation Operations ---

def _desktop_import_modules() -> tuple[object | None, object | None, object | None, str | None]:
    if not DESKTOP_CONTROL_ENABLED:
        return None, None, None, "Desktop control is disabled by configuration."
    try:
        import pyautogui  # type: ignore
    except Exception as e:
        return None, None, None, f"pyautogui is not available: {e}"
    try:
        import pygetwindow as gw  # type: ignore
    except Exception:
        gw = None
    try:
        import pyperclip  # type: ignore
    except Exception:
        pyperclip = None

    try:
        pyautogui.FAILSAFE = bool(DESKTOP_FAILSAFE_ENABLED)
        pyautogui.PAUSE = float(DESKTOP_ACTION_PAUSE_SECONDS)
    except Exception:
        pass
    return pyautogui, gw, pyperclip, None


def _desktop_mark_action(action: str, error: str | None = None):
    RUNTIME_STATE["desktop_actions_total"] = int(RUNTIME_STATE.get("desktop_actions_total", 0)) + 1
    RUNTIME_STATE["desktop_last_action"] = str(action or "")
    RUNTIME_STATE["desktop_last_error"] = truncate_text(str(error or ""), 240) if error else None


def _desktop_screen_size(pyautogui_mod) -> tuple[int, int]:
    width, height = pyautogui_mod.size()
    return int(width), int(height)


def _desktop_mouse_position(pyautogui_mod) -> tuple[int, int]:
    x, y = pyautogui_mod.position()
    return int(x), int(y)


def _desktop_clip_point(x: int, y: int, width: int, height: int) -> tuple[int, int]:
    safe_x = max(0, min(int(width) - 1, int(x)))
    safe_y = max(0, min(int(height) - 1, int(y)))
    return safe_x, safe_y


def _desktop_workspace_root(owner_id: int | None, workspace_root: str | None = None) -> Path:
    candidate = str(workspace_root or "").strip()
    if candidate:
        try:
            return Path(candidate).expanduser().resolve(strict=False)
        except Exception:
            pass
    if owner_id:
        try:
            return owner_workspace_root(int(owner_id))
        except Exception:
            pass
    return DESKTOP_SCREENSHOT_DIR


def _desktop_resolve_screenshot_path(owner_id: int | None, file_path: str | None, workspace_root: str | None = None) -> Path:
    root = _desktop_workspace_root(owner_id, workspace_root=workspace_root)
    root.mkdir(parents=True, exist_ok=True)
    raw_path = str(file_path or "").strip()
    if not raw_path:
        stamp = datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")
        return (root / f"desktop_{stamp}_{uuid.uuid4().hex[:6]}.png").resolve(strict=False)
    target = Path(os.path.expandvars(raw_path)).expanduser()
    if not target.suffix:
        target = target.with_suffix(".png")
    if not target.is_absolute():
        target = (root / target).resolve(strict=False)
    else:
        target = target.resolve(strict=False)
    target.parent.mkdir(parents=True, exist_ok=True)
    return target


def _desktop_resolve_asset_path(owner_id: int | None, asset_path: str, workspace_root: str | None = None) -> Path:
    raw = str(asset_path or "").strip()
    if not raw:
        raise ValueError("image_path is required.")
    candidate = Path(os.path.expandvars(raw)).expanduser()
    if not candidate.is_absolute():
        root = _desktop_workspace_root(owner_id, workspace_root=workspace_root)
        candidate = (root / candidate).resolve(strict=False)
    else:
        candidate = candidate.resolve(strict=False)
    if not candidate.exists():
        raise FileNotFoundError(f"Asset file not found: {candidate}")
    return candidate


def _desktop_normalize_region(region: dict | None, screen_w: int, screen_h: int) -> tuple[int, int, int, int] | None:
    if not isinstance(region, dict) or not region:
        return None
    x = int(region.get("x", 0))
    y = int(region.get("y", 0))
    width = max(1, int(region.get("width", 1)))
    height = max(1, int(region.get("height", 1)))
    x, y = _desktop_clip_point(x, y, screen_w, screen_h)
    width = max(1, min(width, screen_w - x))
    height = max(1, min(height, screen_h - y))
    return (x, y, width, height)


def _desktop_box_to_dict(box) -> dict | None:
    if box is None:
        return None
    left = top = width = height = None
    try:
        left = int(getattr(box, "left"))
        top = int(getattr(box, "top"))
        width = int(getattr(box, "width"))
        height = int(getattr(box, "height"))
    except Exception:
        try:
            left = int(box[0])
            top = int(box[1])
            width = int(box[2])
            height = int(box[3])
        except Exception:
            return None
    center_x = int(left + (width / 2))
    center_y = int(top + (height / 2))
    return {
        "left": int(left),
        "top": int(top),
        "width": int(width),
        "height": int(height),
        "center_x": int(center_x),
        "center_y": int(center_y),
    }


def _desktop_owner_key(owner_id: int | None) -> int:
    try:
        return int(owner_id or 0)
    except Exception:
        return 0


def _desktop_sessions_root(owner_id: int | None) -> Path:
    if owner_id:
        try:
            base = owner_workspace_root(int(owner_id))
            return (base / ".desktop_sessions").resolve(strict=False)
        except Exception:
            pass
    return DESKTOP_SESSION_DIR


def _desktop_session_log_path(owner_id: int | None, session_id: str) -> Path:
    root = _desktop_sessions_root(owner_id)
    root.mkdir(parents=True, exist_ok=True)
    safe_id = re.sub(r"[^a-zA-Z0-9_-]", "", str(session_id or ""))[:80] or uuid.uuid4().hex[:12]
    return (root / f"{safe_id}.jsonl").resolve(strict=False)


def _desktop_get_active_session(owner_id: int | None) -> dict | None:
    key = _desktop_owner_key(owner_id)
    with DESKTOP_SESSION_LOCK:
        row = DESKTOP_ACTIVE_SESSIONS.get(key)
        if not row:
            return None
        return dict(row)


def _desktop_set_active_session(owner_id: int | None, state: dict | None):
    key = _desktop_owner_key(owner_id)
    with DESKTOP_SESSION_LOCK:
        if state is None:
            DESKTOP_ACTIVE_SESSIONS.pop(key, None)
        else:
            DESKTOP_ACTIVE_SESSIONS[key] = dict(state)
    active = _desktop_get_active_session(owner_id)
    RUNTIME_STATE["desktop_session_active"] = bool(active)
    RUNTIME_STATE["desktop_session_id"] = str(active.get("session_id")) if active else None
    RUNTIME_STATE["desktop_last_session_path"] = str(active.get("log_path")) if active else RUNTIME_STATE.get("desktop_last_session_path")


def _desktop_start_session(owner_id: int | None, label: str | None = None) -> dict:
    owner_key = _desktop_owner_key(owner_id)
    now_iso = datetime.now(timezone.utc).isoformat()
    session_id = f"ds_{datetime.now(timezone.utc).strftime('%Y%m%d_%H%M%S')}_{uuid.uuid4().hex[:8]}"
    log_path = _desktop_session_log_path(owner_id, session_id)
    state = {
        "owner_id": owner_key,
        "session_id": session_id,
        "label": truncate_text(str(label or ""), 120),
        "started_at": now_iso,
        "updated_at": now_iso,
        "actions_count": 0,
        "log_path": str(log_path),
        "active": True,
    }
    log_path.parent.mkdir(parents=True, exist_ok=True)
    header = {
        "event": "session_started",
        "session_id": session_id,
        "owner_id": owner_key,
        "label": state["label"],
        "timestamp": now_iso,
    }
    with open(log_path, "w", encoding="utf-8") as f:
        f.write(json.dumps(header, ensure_ascii=False) + "\n")
    _desktop_set_active_session(owner_id, state)
    RUNTIME_STATE["desktop_sessions_started"] = int(RUNTIME_STATE.get("desktop_sessions_started", 0)) + 1
    return {"ok": True, "session_id": session_id, "log_path": str(log_path), "started_at": now_iso, "label": state["label"]}


def _desktop_stop_session(owner_id: int | None, reason: str = "manual") -> dict:
    current = _desktop_get_active_session(owner_id)
    if not current:
        return {"ok": False, "error": "No active desktop session."}
    now_iso = datetime.now(timezone.utc).isoformat()
    log_path = Path(str(current.get("log_path") or "")).expanduser().resolve(strict=False)
    trailer = {
        "event": "session_stopped",
        "session_id": current.get("session_id"),
        "owner_id": _desktop_owner_key(owner_id),
        "timestamp": now_iso,
        "reason": truncate_text(str(reason or "manual"), 120),
        "actions_count": int(current.get("actions_count", 0)),
    }
    try:
        with open(log_path, "a", encoding="utf-8") as f:
            f.write(json.dumps(trailer, ensure_ascii=False) + "\n")
    except Exception:
        pass
    _desktop_set_active_session(owner_id, None)
    RUNTIME_STATE["desktop_sessions_completed"] = int(RUNTIME_STATE.get("desktop_sessions_completed", 0)) + 1
    RUNTIME_STATE["desktop_last_session_path"] = str(log_path)
    return {
        "ok": True,
        "session_id": str(current.get("session_id") or ""),
        "log_path": str(log_path),
        "actions_count": int(current.get("actions_count", 0)),
        "stopped_at": now_iso,
        "reason": trailer["reason"],
    }


def _desktop_session_status(owner_id: int | None) -> dict:
    current = _desktop_get_active_session(owner_id)
    if not current:
        return {"ok": True, "active": False, "session": None}
    return {
        "ok": True,
        "active": True,
        "session": {
            "session_id": str(current.get("session_id") or ""),
            "label": str(current.get("label") or ""),
            "started_at": current.get("started_at"),
            "updated_at": current.get("updated_at"),
            "actions_count": int(current.get("actions_count", 0)),
            "log_path": str(current.get("log_path") or ""),
        },
    }


def _desktop_action_args_for_log(args: dict | None) -> dict:
    data = {}
    for key, value in dict(args or {}).items():
        k = str(key or "")
        if k.startswith("_"):
            continue
        data[k] = value
    return _blackbox_sanitize(data)


def _desktop_record_action(owner_id: int | None, tool_name: str, args: dict | None, result: dict | None):
    if str(tool_name or "") in DESKTOP_SESSION_CONTROL_TOOL_NAMES:
        return
    current = _desktop_get_active_session(owner_id)
    if not current:
        return
    log_path = Path(str(current.get("log_path") or "")).expanduser().resolve(strict=False)
    now_iso = datetime.now(timezone.utc).isoformat()
    event = {
        "event": "action",
        "timestamp": now_iso,
        "session_id": str(current.get("session_id") or ""),
        "tool_name": str(tool_name or ""),
        "args": _desktop_action_args_for_log(args),
        "result": _blackbox_sanitize(result or {}),
    }
    try:
        log_path.parent.mkdir(parents=True, exist_ok=True)
        with open(log_path, "a", encoding="utf-8") as f:
            f.write(json.dumps(event, ensure_ascii=False) + "\n")
        current["actions_count"] = int(current.get("actions_count", 0)) + 1
        current["updated_at"] = now_iso
        _desktop_set_active_session(owner_id, current)
    except Exception:
        pass


def _desktop_load_session_actions(owner_id: int | None, session_id: str, start_index: int = 0, max_steps: int = 200) -> tuple[bool, str, list[dict], str]:
    log_path = _desktop_session_log_path(owner_id, session_id)
    if not log_path.exists():
        return False, f"Session log not found: {log_path}", [], str(log_path)
    items: list[dict] = []
    try:
        with open(log_path, "r", encoding="utf-8") as f:
            for line in f:
                row = str(line or "").strip()
                if not row:
                    continue
                try:
                    parsed = json.loads(row)
                except Exception:
                    continue
                if str(parsed.get("event") or "") != "action":
                    continue
                items.append(parsed)
    except Exception as e:
        return False, f"Failed reading session log: {e}", [], str(log_path)

    safe_start = max(0, int(start_index))
    safe_max = max(1, min(DESKTOP_REPLAY_MAX_STEPS, int(max_steps)))
    sliced = items[safe_start : safe_start + safe_max]
    return True, "", sliced, str(log_path)


def _desktop_tool_requires_active_session(tool_name: str) -> bool:
    if not DESKTOP_REQUIRE_ACTIVE_SESSION:
        return False
    return str(tool_name or "").strip().lower() in DESKTOP_MUTATING_TOOL_NAMES


def _desktop_replay_step(owner_id: int | None, tool_name: str, args: dict) -> dict:
    name = str(tool_name or "").strip().lower()
    if name not in TOOL_DISPATCH:
        return {"ok": False, "error": f"Replay tool not found: {name}"}
    replay_args = dict(args or {})
    replay_args["_owner_id"] = owner_id
    if name == "desktop_screenshot" and "_workspace_root" not in replay_args and owner_id:
        replay_args["_workspace_root"] = str(owner_workspace_root(int(owner_id)))
    return TOOL_DISPATCH[name](replay_args)


def tool_desktop_session_start(owner_id: int | None = None, label: str | None = None) -> dict:
    if not DESKTOP_CONTROL_ENABLED:
        return {"ok": False, "error": "Desktop control is disabled by configuration."}
    current = _desktop_get_active_session(owner_id)
    if current:
        return {
            "ok": True,
            "already_active": True,
            "session_id": str(current.get("session_id") or ""),
            "log_path": str(current.get("log_path") or ""),
            "actions_count": int(current.get("actions_count", 0)),
        }
    return _desktop_start_session(owner_id, label=label)


def tool_desktop_session_status(owner_id: int | None = None) -> dict:
    return _desktop_session_status(owner_id)


def tool_desktop_session_stop(owner_id: int | None = None, reason: str = "manual") -> dict:
    return _desktop_stop_session(owner_id, reason=reason)


def tool_desktop_session_replay(
    owner_id: int | None = None,
    session_id: str | None = None,
    start_index: int = 0,
    max_steps: int = 120,
    dry_run: bool = False,
    speed: float = 1.0,
) -> dict:
    sid = str(session_id or "").strip()
    if not sid:
        active = _desktop_get_active_session(owner_id)
        if active:
            sid = str(active.get("session_id") or "")
    if not sid:
        return {"ok": False, "error": "session_id is required (or start a session first)."}

    ok, err, actions, log_path = _desktop_load_session_actions(owner_id, sid, start_index=start_index, max_steps=max_steps)
    if not ok:
        return {"ok": False, "error": err, "log_path": log_path}

    if not actions:
        return {"ok": True, "session_id": sid, "log_path": log_path, "executed": 0, "dry_run": bool(dry_run), "results": []}

    replay_speed = max(0.1, min(5.0, float(speed)))
    results: list[dict] = []
    for idx, row in enumerate(actions, 1):
        name = str(row.get("tool_name") or "").strip().lower()
        args = dict(row.get("args") or {})
        if dry_run:
            results.append({"step": idx, "tool_name": name, "ok": True, "dry_run": True})
            continue
        step_result = _desktop_replay_step(owner_id, name, args)
        results.append(
            {
                "step": idx,
                "tool_name": name,
                "ok": bool(step_result.get("ok", False)) if isinstance(step_result, dict) else False,
                "error": None if not isinstance(step_result, dict) else step_result.get("error"),
            }
        )
        if not (isinstance(step_result, dict) and bool(step_result.get("ok", False))):
            break
        if replay_speed != 1.0:
            time.sleep(max(0.0, 0.12 / replay_speed))

    RUNTIME_STATE["desktop_sessions_replayed"] = int(RUNTIME_STATE.get("desktop_sessions_replayed", 0)) + 1
    return {
        "ok": True,
        "session_id": sid,
        "log_path": log_path,
        "executed": len(results),
        "dry_run": bool(dry_run),
        "results": results,
    }


def tool_desktop_screen_state() -> dict:
    action = "desktop_screen_state"
    pyautogui_mod, _, _, err = _desktop_import_modules()
    if err:
        _desktop_mark_action(action, err)
        return {"ok": False, "error": err}
    try:
        with DESKTOP_TOOL_LOCK:
            width, height = _desktop_screen_size(pyautogui_mod)
            mouse_x, mouse_y = _desktop_mouse_position(pyautogui_mod)
        _desktop_mark_action(action)
        return {
            "ok": True,
            "screen": {"width": width, "height": height},
            "mouse": {"x": mouse_x, "y": mouse_y},
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }
    except Exception as e:
        _desktop_mark_action(action, str(e))
        return {"ok": False, "error": str(e)}


def tool_desktop_screenshot(
    owner_id: int | None = None,
    file_path: str | None = None,
    region: dict | None = None,
    workspace_root: str | None = None,
) -> dict:
    action = "desktop_screenshot"
    pyautogui_mod, _, _, err = _desktop_import_modules()
    if err:
        _desktop_mark_action(action, err)
        return {"ok": False, "error": err}
    try:
        region_tuple = None
        with DESKTOP_TOOL_LOCK:
            screen_w, screen_h = _desktop_screen_size(pyautogui_mod)
            if isinstance(region, dict) and region:
                x = int(region.get("x", 0))
                y = int(region.get("y", 0))
                width = max(1, int(region.get("width", 1)))
                height = max(1, int(region.get("height", 1)))
                x, y = _desktop_clip_point(x, y, screen_w, screen_h)
                width = max(1, min(width, screen_w - x))
                height = max(1, min(height, screen_h - y))
                region_tuple = (x, y, width, height)
        target_path = _desktop_resolve_screenshot_path(owner_id, file_path, workspace_root=workspace_root)

        shot_w = 0
        shot_h = 0
        pyautogui_error = None
        try:
            shot = pyautogui_mod.screenshot(region=region_tuple)
            shot.save(str(target_path))
            shot_w, shot_h = shot.size
        except Exception as inner_exc:
            pyautogui_error = str(inner_exc)
            try:
                import mss  # type: ignore
                import mss.tools  # type: ignore

                with mss.mss() as sct:
                    monitor = (
                        {"left": int(region_tuple[0]), "top": int(region_tuple[1]), "width": int(region_tuple[2]), "height": int(region_tuple[3])}
                        if region_tuple
                        else dict(sct.monitors[1])
                    )
                    frame = sct.grab(monitor)
                    mss.tools.to_png(frame.rgb, frame.size, output=str(target_path))
                    shot_w, shot_h = int(frame.size.width), int(frame.size.height)
            except Exception as mss_exc:
                raise RuntimeError(
                    f"screenshot failed via pyautogui ({pyautogui_error}); mss fallback failed ({mss_exc})"
                )
        _desktop_mark_action(action)
        # Read screenshot file and encode as base64 for vision LLM
        screenshot_b64 = ""
        try:
            with open(str(target_path), "rb") as f:
                screenshot_b64 = base64.b64encode(f.read()).decode("utf-8")
        except Exception:
            pass
        return {
            "ok": True,
            "path": str(target_path),
            "width": int(shot_w),
            "height": int(shot_h),
            "region": {"x": int(region_tuple[0]), "y": int(region_tuple[1]), "width": int(region_tuple[2]), "height": int(region_tuple[3])} if region_tuple else None,
            "_screenshot_base64": screenshot_b64,
        }
    except Exception as e:
        _desktop_mark_action(action, str(e))
        return {"ok": False, "error": str(e)}


def tool_desktop_list_windows(limit: int = 30) -> dict:
    action = "desktop_list_windows"
    _, gw_mod, _, err = _desktop_import_modules()
    if err:
        _desktop_mark_action(action, err)
        return {"ok": False, "error": err}
    if gw_mod is None:
        msg = "pygetwindow is not available; install PyGetWindow for window introspection."
        _desktop_mark_action(action, msg)
        return {"ok": False, "error": msg}
    try:
        rows = []
        for win in gw_mod.getAllWindows():
            title = str(getattr(win, "title", "") or "").strip()
            if not title:
                continue
            rows.append(
                {
                    "title": title,
                    "left": int(getattr(win, "left", 0) or 0),
                    "top": int(getattr(win, "top", 0) or 0),
                    "width": int(getattr(win, "width", 0) or 0),
                    "height": int(getattr(win, "height", 0) or 0),
                    "is_active": bool(getattr(win, "isActive", False)),
                }
            )
        rows = rows[:max(1, min(200, int(limit)))]
        _desktop_mark_action(action)
        return {"ok": True, "windows": rows, "count": len(rows)}
    except Exception as e:
        _desktop_mark_action(action, str(e))
        return {"ok": False, "error": str(e)}


def _desktop_locate_image(pyautogui_mod, image_path: Path, confidence: float | None, grayscale: bool, region_tuple: tuple[int, int, int, int] | None) -> tuple[object | None, str | None, bool]:
    kwargs: dict = {"grayscale": bool(grayscale)}
    if region_tuple is not None:
        kwargs["region"] = region_tuple
    conf_value = None
    if confidence is not None:
        conf_value = max(0.5, min(0.99, float(confidence)))
        kwargs["confidence"] = conf_value
    try:
        box = pyautogui_mod.locateOnScreen(str(image_path), **kwargs)
        return box, None, False
    except TypeError as e:
        text = str(e)
        # pyautogui confidence requires OpenCV; retry without confidence as fallback.
        if "confidence" in text.lower() and conf_value is not None:
            kwargs.pop("confidence", None)
            try:
                box = pyautogui_mod.locateOnScreen(str(image_path), **kwargs)
                return box, None, True
            except Exception as inner:
                return None, str(inner), True
        return None, text, False
    except Exception as e:
        return None, str(e), False


def tool_desktop_uia_tree(title: str | None = None, exact: bool = False, limit: int = DESKTOP_UITREE_DEFAULT_LIMIT) -> dict:
    action = "desktop_uia_tree"
    _, gw_mod, _, err = _desktop_import_modules()
    if err:
        _desktop_mark_action(action, err)
        return {"ok": False, "error": err}
    safe_limit = max(5, min(500, int(limit)))
    needle = str(title or "").strip()
    try:
        from pywinauto import Desktop as UIADesktop  # type: ignore

        desktop = UIADesktop(backend="uia")
        top_windows = list(desktop.windows())
        target = None
        if needle:
            if exact:
                target = next((w for w in top_windows if str(w.window_text() or "").strip() == needle), None)
            else:
                low = needle.lower()
                target = next((w for w in top_windows if low in str(w.window_text() or "").lower()), None)
        if target is None and top_windows:
            target = top_windows[0]
        if target is None:
            _desktop_mark_action(action, "No UIA windows available.")
            return {"ok": False, "error": "No UIA windows available."}

        nodes: list[dict] = []
        queue_items: list[tuple[object, int]] = [(target, 0)]
        while queue_items and len(nodes) < safe_limit:
            ctrl, depth = queue_items.pop(0)
            try:
                elem = getattr(ctrl, "element_info", None)
                rect = getattr(elem, "rectangle", None)
                node = {
                    "depth": int(depth),
                    "name": truncate_text(str(ctrl.window_text() or ""), 240),
                    "control_type": str(getattr(elem, "control_type", "") or ""),
                    "automation_id": str(getattr(elem, "automation_id", "") or ""),
                    "class_name": str(getattr(elem, "class_name", "") or ""),
                    "rectangle": {
                        "left": int(getattr(rect, "left", 0) or 0),
                        "top": int(getattr(rect, "top", 0) or 0),
                        "right": int(getattr(rect, "right", 0) or 0),
                        "bottom": int(getattr(rect, "bottom", 0) or 0),
                    },
                }
                nodes.append(node)
            except Exception:
                continue
            if depth >= 6:
                continue
            try:
                for child in list(ctrl.children()):
                    if len(nodes) + len(queue_items) >= safe_limit * 2:
                        break
                    queue_items.append((child, depth + 1))
            except Exception:
                continue
        _desktop_mark_action(action)
        return {
            "ok": True,
            "backend": "pywinauto",
            "target_title": truncate_text(str(target.window_text() or ""), 240),
            "count": len(nodes),
            "nodes": nodes,
        }
    except Exception:
        if gw_mod is None:
            msg = "pywinauto is not available; install pywinauto for UI tree inspection."
            _desktop_mark_action(action, msg)
            return {"ok": False, "error": msg}
        try:
            windows = []
            for win in gw_mod.getAllWindows():
                title_text = str(getattr(win, "title", "") or "").strip()
                if not title_text:
                    continue
                if needle:
                    if exact and title_text != needle:
                        continue
                    if (not exact) and (needle.lower() not in title_text.lower()):
                        continue
                windows.append(
                    {
                        "depth": 0,
                        "name": truncate_text(title_text, 240),
                        "control_type": "Window",
                        "automation_id": "",
                        "class_name": "",
                        "rectangle": {
                            "left": int(getattr(win, "left", 0) or 0),
                            "top": int(getattr(win, "top", 0) or 0),
                            "right": int((getattr(win, "left", 0) or 0) + (getattr(win, "width", 0) or 0)),
                            "bottom": int((getattr(win, "top", 0) or 0) + (getattr(win, "height", 0) or 0)),
                        },
                    }
                )
                if len(windows) >= safe_limit:
                    break
            _desktop_mark_action(action)
            return {
                "ok": True,
                "backend": "pygetwindow_fallback",
                "warning": "pywinauto not available; returning top-level windows only.",
                "count": len(windows),
                "nodes": windows,
            }
        except Exception as e:
            _desktop_mark_action(action, str(e))
            return {"ok": False, "error": str(e)}


def tool_desktop_locate_on_screen(
    owner_id: int | None = None,
    image_path: str = "",
    confidence: float | None = DESKTOP_IMAGE_MATCH_THRESHOLD,
    grayscale: bool = True,
    region: dict | None = None,
    workspace_root: str | None = None,
) -> dict:
    action = "desktop_locate_on_screen"
    pyautogui_mod, _, _, err = _desktop_import_modules()
    if err:
        _desktop_mark_action(action, err)
        return {"ok": False, "error": err}
    try:
        template_path = _desktop_resolve_asset_path(owner_id, image_path, workspace_root=workspace_root)
        with DESKTOP_TOOL_LOCK:
            screen_w, screen_h = _desktop_screen_size(pyautogui_mod)
            region_tuple = _desktop_normalize_region(region, screen_w, screen_h)
            box, locate_err, confidence_fallback = _desktop_locate_image(
                pyautogui_mod,
                template_path,
                confidence=confidence,
                grayscale=bool(grayscale),
                region_tuple=region_tuple,
            )
        if locate_err:
            _desktop_mark_action(action, locate_err)
            return {"ok": False, "error": locate_err}
        box_payload = _desktop_box_to_dict(box)
        _desktop_mark_action(action)
        if box_payload is None:
            return {
                "ok": True,
                "found": False,
                "image_path": str(template_path),
                "confidence_fallback": bool(confidence_fallback),
            }
        return {
            "ok": True,
            "found": True,
            "image_path": str(template_path),
            "match": box_payload,
            "confidence_fallback": bool(confidence_fallback),
        }
    except Exception as e:
        _desktop_mark_action(action, str(e))
        return {"ok": False, "error": str(e)}


def tool_desktop_click_image(
    owner_id: int | None = None,
    image_path: str = "",
    confidence: float | None = DESKTOP_IMAGE_MATCH_THRESHOLD,
    grayscale: bool = True,
    region: dict | None = None,
    button: str = "left",
    clicks: int = 1,
    interval: float = 0.0,
    move_duration: float | None = None,
    offset_x: int = 0,
    offset_y: int = 0,
    workspace_root: str | None = None,
) -> dict:
    action = "desktop_click_image"
    pyautogui_mod, _, _, err = _desktop_import_modules()
    if err:
        _desktop_mark_action(action, err)
        return {"ok": False, "error": err}
    button_name = str(button or "left").strip().lower()
    if button_name not in {"left", "right", "middle"}:
        button_name = "left"
    try:
        template_path = _desktop_resolve_asset_path(owner_id, image_path, workspace_root=workspace_root)
        with DESKTOP_TOOL_LOCK:
            screen_w, screen_h = _desktop_screen_size(pyautogui_mod)
            region_tuple = _desktop_normalize_region(region, screen_w, screen_h)
            box, locate_err, confidence_fallback = _desktop_locate_image(
                pyautogui_mod,
                template_path,
                confidence=confidence,
                grayscale=bool(grayscale),
                region_tuple=region_tuple,
            )
            if locate_err:
                raise RuntimeError(locate_err)
            match = _desktop_box_to_dict(box)
            if match is None:
                _desktop_mark_action(action, "Image not found on screen.")
                return {
                    "ok": False,
                    "found": False,
                    "error": "Image not found on screen.",
                    "image_path": str(template_path),
                    "confidence_fallback": bool(confidence_fallback),
                }
            target_x, target_y = _desktop_clip_point(
                int(match["center_x"]) + int(offset_x),
                int(match["center_y"]) + int(offset_y),
                screen_w,
                screen_h,
            )
            move_secs = float(DESKTOP_DEFAULT_MOVE_DURATION if move_duration is None else move_duration)
            move_secs = max(0.0, min(5.0, move_secs))
            pyautogui_mod.moveTo(target_x, target_y, duration=move_secs)
            pyautogui_mod.click(
                x=target_x,
                y=target_y,
                clicks=max(1, min(10, int(clicks))),
                interval=max(0.0, min(1.0, float(interval))),
                button=button_name,
            )
        _desktop_mark_action(action)
        return {
            "ok": True,
            "found": True,
            "image_path": str(template_path),
            "match": match,
            "clicked_x": int(target_x),
            "clicked_y": int(target_y),
            "button": button_name,
            "clicks": max(1, min(10, int(clicks))),
            "confidence_fallback": bool(confidence_fallback),
        }
    except Exception as e:
        _desktop_mark_action(action, str(e))
        return {"ok": False, "error": str(e)}


def tool_desktop_focus_window(title: str, exact: bool = False) -> dict:
    action = "desktop_focus_window"
    _, gw_mod, _, err = _desktop_import_modules()
    if err:
        _desktop_mark_action(action, err)
        return {"ok": False, "error": err}
    if gw_mod is None:
        msg = "pygetwindow is not available; install PyGetWindow for window focus control."
        _desktop_mark_action(action, msg)
        return {"ok": False, "error": msg}

    needle = str(title or "").strip()
    if not needle:
        msg = "title is required."
        _desktop_mark_action(action, msg)
        return {"ok": False, "error": msg}
    try:
        if exact:
            candidates = [w for w in gw_mod.getAllWindows() if str(getattr(w, "title", "") or "").strip() == needle]
        else:
            low = needle.lower()
            candidates = [w for w in gw_mod.getAllWindows() if low in str(getattr(w, "title", "") or "").lower()]
        if not candidates:
            msg = f"No window matched '{needle}'."
            _desktop_mark_action(action, msg)
            return {"ok": False, "error": msg}
        win = candidates[0]
        try:
            if bool(getattr(win, "isMinimized", False)):
                win.restore()
        except Exception:
            pass
        win.activate()
        _desktop_mark_action(action)
        return {"ok": True, "matched_title": str(getattr(win, "title", "") or ""), "matches": len(candidates)}
    except Exception as e:
        _desktop_mark_action(action, str(e))
        return {"ok": False, "error": str(e)}


