_TYPE_BLOCK_PATTERNS: list[str] = [
    "taskkill",
    "stop-process",
    "kill -",
    "shutdown /s",
    "shutdown /r",
]


def tool_desktop_type_text(text: str, interval: float | None = None, press_enter: bool = False) -> dict:
    action = "desktop_type_text"
    pyautogui_mod, _, _, err = _desktop_import_modules()
    if err:
        _desktop_mark_action(action, err)
        return {"ok": False, "error": err}
    blob = str(text or "")
    if not blob:
        msg = "text is required."
        _desktop_mark_action(action, msg)
        return {"ok": False, "error": msg}
    if len(blob) > 5000:
        blob = blob[:5000]
    if bool(press_enter):
        blob_lower = blob.strip().lower()
        for pattern in _TYPE_BLOCK_PATTERNS:
            if pattern in blob_lower:
                msg = f"Blocked: typing '{blob.strip()[:40]}' with enter could kill the agent. Use a safer approach."
                log.warning("DESKTOP_TYPE_BLOCKED text=%s", blob.strip()[:60])
                _desktop_mark_action(action, msg)
                return {"ok": False, "error": msg}
    try:
        with DESKTOP_TOOL_LOCK:
            key_interval = float(DESKTOP_DEFAULT_TYPE_INTERVAL if interval is None else interval)
            key_interval = max(0.0, min(0.5, key_interval))
            pyautogui_mod.write(blob, interval=key_interval)
            if bool(press_enter):
                pyautogui_mod.press("enter")
        _desktop_mark_action(action)
        return {"ok": True, "typed_chars": len(blob), "press_enter": bool(press_enter)}
    except Exception as e:
        _desktop_mark_action(action, str(e))
        return {"ok": False, "error": str(e)}


