_HOTKEY_BLOCK_LIST: list[tuple[str, ...]] = [
    ("ctrl", "c"),
    ("ctrl", "break"),
    ("ctrl", "z"),
    ("alt", "f4"),
    ("ctrl", "shift", "q"),
    ("ctrl", "w"),
]


def tool_desktop_hotkey(keys: list[str]) -> dict:
    action = "desktop_hotkey"
    pyautogui_mod, _, _, err = _desktop_import_modules()
    if err:
        _desktop_mark_action(action, err)
        return {"ok": False, "error": err}
    combo = [str(k or "").strip().lower() for k in (keys or []) if str(k or "").strip()]
    if not combo:
        msg = "keys list is required."
        _desktop_mark_action(action, msg)
        return {"ok": False, "error": msg}
    combo = combo[:5]
    combo_set = set(combo)
    for blocked in _HOTKEY_BLOCK_LIST:
        if set(blocked) == combo_set:
            msg = f"Blocked: hotkey {'+'.join(combo)} could kill the agent process. Use a safer approach."
            log.warning("DESKTOP_HOTKEY_BLOCKED combo=%s", combo)
            _desktop_mark_action(action, msg)
            return {"ok": False, "error": msg}
    try:
        with DESKTOP_TOOL_LOCK:
            pyautogui_mod.hotkey(*combo)
        _desktop_mark_action(action)
        return {"ok": True, "keys": combo}
    except Exception as e:
        _desktop_mark_action(action, str(e))
        return {"ok": False, "error": str(e)}


