# --- Web Operations ---

def tool_search_web(query: str, num_results: int = 5) -> dict:
    allowed, reason = circuit_allow_call("web_search")
    if not allowed:
        return {"ok": False, "error": reason}
    try:
        results = []
        with without_proxy_env():
            with DDGS() as ddgs:
                for r in ddgs.text(query, max_results=num_results):
                    results.append({
                        "title": r.get("title", ""),
                        "url": r.get("href", ""),
                        "snippet": r.get("body", "")
                    })
        circuit_record_success("web_search")
        return {"ok": True, "results": results}
    except Exception as e:
        circuit_record_failure("web_search", str(e))
        return {"ok": False, "error": str(e)}


def tool_read_webpage(url: str) -> dict:
    allowed, reason = circuit_allow_call("web_fetch")
    if not allowed:
        return {"ok": False, "error": reason, "url": url}
    safe_ok, safe_reason = apply_url_safety_guard(url, source="read_webpage")
    if not safe_ok:
        return {"ok": False, "error": safe_reason, "url": url}
    try:
        response = REQUESTS_SESSION.get(url, timeout=10)
        response.raise_for_status()
        soup = BeautifulSoup(response.text, "html.parser")
        for tag in soup(["script", "style", "nav", "footer", "aside"]):
            tag.decompose()
        text = soup.get_text(separator="\n", strip=True)
        # Truncate to avoid blowing up context
        if len(text) > 8000:
            text = text[:8000] + "\n...[TRUNCATED]"
        circuit_record_success("web_fetch")
        return {"ok": True, "text": text, "url": url}
    except Exception as e:
        circuit_record_failure("web_fetch", str(e))
        return {"ok": False, "error": str(e), "url": url}


def clamp_int(value, min_value: int, max_value: int, default: int) -> int:
    try:
        parsed = int(value)
    except Exception:
        parsed = default
    return max(min_value, min(max_value, parsed))


def _default_circuit_state() -> dict:
    return {
        "state": "closed",  # closed | open | half_open
        "failures": 0,
        "opened_until": 0.0,
        "last_error": None,
        "last_opened_at": None,
    }


def _ensure_circuit_state(provider: str) -> dict:
    state = PROVIDER_CIRCUITS.get(provider)
    if not isinstance(state, dict):
        state = _default_circuit_state()
        PROVIDER_CIRCUITS[provider] = state
    for key, value in _default_circuit_state().items():
        state.setdefault(key, value)
    return state


def circuit_allow_call(provider: str) -> tuple[bool, str]:
    now = time.monotonic()
    with CIRCUIT_LOCK:
        state = _ensure_circuit_state(provider)
        if state["state"] == "open":
            opened_until = float(state.get("opened_until", 0.0))
            if now < opened_until:
                remaining = max(0.0, opened_until - now)
                RUNTIME_STATE["circuit_blocked_calls"] = int(RUNTIME_STATE.get("circuit_blocked_calls", 0)) + 1
                return False, f"Circuit open for {provider}. Retry in {remaining:.1f}s."
            state["state"] = "half_open"
        return True, ""


def circuit_record_success(provider: str):
    with CIRCUIT_LOCK:
        state = _ensure_circuit_state(provider)
        state["state"] = "closed"
        state["failures"] = 0
        state["opened_until"] = 0.0
        state["last_error"] = None


def circuit_record_failure(provider: str, error_message: str):
    now = time.monotonic()
    with CIRCUIT_LOCK:
        state = _ensure_circuit_state(provider)
        state["last_error"] = truncate_text(error_message, 220)

        if state["state"] == "half_open":
            state["failures"] = CIRCUIT_BREAKER_FAILURE_THRESHOLD
        else:
            state["failures"] = int(state.get("failures", 0)) + 1

        if int(state["failures"]) < CIRCUIT_BREAKER_FAILURE_THRESHOLD:
            return

        state["state"] = "open"
        state["opened_until"] = now + float(CIRCUIT_BREAKER_COOLDOWN_SECONDS)
        state["last_opened_at"] = utc_now_iso() if "utc_now_iso" in globals() else None
        RUNTIME_STATE["circuit_open_events"] = int(RUNTIME_STATE.get("circuit_open_events", 0)) + 1
        log.warning(
            "CIRCUIT_OPEN provider=%s cooldown=%ss reason=%s",
            provider,
            CIRCUIT_BREAKER_COOLDOWN_SECONDS,
            truncate_text(error_message, 180),
        )


def circuit_snapshot() -> dict:
    snapshot = {}
    now = time.monotonic()
    with CIRCUIT_LOCK:
        for provider in list(PROVIDER_CIRCUITS.keys()):
            state = _ensure_circuit_state(provider)
            opened_until = float(state.get("opened_until", 0.0))
            snapshot[provider] = {
                "state": state.get("state", "closed"),
                "failures": int(state.get("failures", 0)),
                "cooldown_remaining_sec": round(max(0.0, opened_until - now), 1),
                "last_error": state.get("last_error"),
            }
    return snapshot


@contextmanager
def without_proxy_env():
    with PROXY_ENV_LOCK:
        saved = {k: os.environ.get(k) for k in PROXY_ENV_KEYS}
        saved_no_proxy = os.environ.get("NO_PROXY")
        try:
            for key in PROXY_ENV_KEYS:
                os.environ.pop(key, None)
            os.environ["NO_PROXY"] = "*"
            yield
        finally:
            for key, value in saved.items():
                if value is None:
                    os.environ.pop(key, None)
                else:
                    os.environ[key] = value
            if saved_no_proxy is None:
                os.environ.pop("NO_PROXY", None)
            else:
                os.environ["NO_PROXY"] = saved_no_proxy


def normalize_domain(value: str) -> str:
    d = (value or "").strip().lower()
    if d.startswith("http://") or d.startswith("https://"):
        d = urlparse(d).netloc
    if d.startswith("www."):
        d = d[4:]
    return d


def get_domain_from_url(url: str) -> str:
    try:
        return normalize_domain(urlparse(url).netloc)
    except Exception:
        return ""


def canonicalize_url(url: str) -> str:
    try:
        parsed = urlparse(url.strip())
        netloc = normalize_domain(parsed.netloc)
        path = parsed.path or "/"
        while "//" in path:
            path = path.replace("//", "/")
        if path != "/" and path.endswith("/"):
            path = path[:-1]
        return urlunparse((parsed.scheme.lower(), netloc, path, "", "", ""))
    except Exception:
        return (url or "").strip()


def domain_matches(domain: str, pattern: str) -> bool:
    if not domain or not pattern:
        return False
    return domain == pattern or domain.endswith("." + pattern)


def filter_url_by_domain(url: str, domains_allow: list[str], domains_deny: list[str]) -> bool:
    domain = get_domain_from_url(url)
    if not domain:
        return False

    if domains_allow:
        if not any(domain_matches(domain, allowed) for allowed in domains_allow):
            return False

    if domains_deny:
        if any(domain_matches(domain, blocked) for blocked in domains_deny):
            return False

    return True


def _domain_matches_any(domain: str, patterns: set[str]) -> bool:
    return any(domain_matches(domain, pattern) for pattern in patterns)


def classify_trust_tier(url: str, title: str = "") -> str:
    parsed = urlparse(url or "")
    domain = normalize_domain(parsed.netloc)
    path_l = (parsed.path or "").lower()
    title_l = (title or "").lower()

    if not domain:
        return "community"

    if domain.endswith(".gov") or domain.endswith(".edu") or domain.endswith(".mil"):
        return "official"

    if _domain_matches_any(domain, OFFICIAL_DOMAIN_HINTS):
        return "official"

    if (
        "docs." in domain
        or "developer." in domain
        or "developers." in domain
        or "/docs" in path_l
        or "/documentation" in path_l
        or "documentation" in title_l
        or _domain_matches_any(domain, DOCS_DOMAIN_HINTS)
    ):
        return "docs"

    if _domain_matches_any(domain, NEWS_DOMAIN_HINTS):
        return "news"

    if domain.endswith(".org"):
        return "org"

    return "community"


def parse_date_for_recency(value) -> datetime | None:
    if not value:
        return None
    if date_parser is None:
        return None
    try:
        dt = date_parser.parse(str(value))
        if dt.tzinfo is None:
            return dt.replace(tzinfo=timezone.utc)
        return dt.astimezone(timezone.utc)
    except Exception:
        return None


def score_search_hit(hit: dict, query: str, recency_days: int | None = None) -> float:
    title = (hit.get("title") or "").lower()
    snippet = (hit.get("snippet") or "").lower()
    query_tokens = [t for t in re.findall(r"[a-zA-Z0-9]+", (query or "").lower()) if len(t) > 2]
    query_tokens = query_tokens[:10]

    trust_tier = hit.get("trust_tier", "community")
    score = TRUST_WEIGHTS.get(trust_tier, TRUST_WEIGHTS["community"])
    title_hits = 0
    snippet_hits = 0

    if query_tokens:
        title_hits = sum(1 for token in query_tokens if token in title)
        snippet_hits = sum(1 for token in query_tokens if token in snippet)
        score += min(0.24, title_hits * 0.06)
        score += min(0.15, snippet_hits * 0.03)

    if recency_days is not None:
        parsed_dt = parse_date_for_recency(hit.get("date"))
        if parsed_dt is not None:
            age_days = (datetime.now(timezone.utc) - parsed_dt).total_seconds() / 86400.0
            if age_days <= max(1, recency_days):
                score += 0.16
            elif age_days <= max(7, recency_days * 2):
                score += 0.06
            else:
                score -= 0.08

    penalty = low_trust_penalty(
        url=hit.get("url", ""),
        title=hit.get("title", ""),
        snippet=hit.get("snippet", ""),
    )
    score -= penalty

    if trust_tier in HIGH_TRUST_TIERS and title_hits > 0:
        score += 0.04

    return round(score, 4)


def low_trust_penalty(url: str, title: str = "", snippet: str = "") -> float:
    domain = get_domain_from_url(url)
    title_l = (title or "").lower()
    snippet_l = (snippet or "").lower()
    combined = f"{title_l} {snippet_l}"

    penalty = 0.0
    if domain and _domain_matches_any(domain, LOW_TRUST_DOMAIN_MARKERS):
        penalty += 0.14
    if domain.startswith("blog.") or ".blog." in domain:
        penalty += 0.08

    if any(pattern.search(title_l) for pattern in LOW_TRUST_TITLE_PATTERNS):
        penalty += 0.08

    if any(
        marker in combined
        for marker in ("sponsored", "affiliate", "promo code", "coupon", "casino", "betting")
    ):
        penalty += 0.22

    return min(0.36, round(penalty, 4))


def _trust_tier_rank(tier: str) -> int:
    return TRUST_TIER_ORDER.get(tier or "community", TRUST_TIER_ORDER["community"])


def select_diverse_sources(
    candidates: list[dict],
    max_sources: int,
    per_domain_cap: int = 2,
) -> tuple[list[dict], bool]:
    ordered = sorted(
        candidates,
        key=lambda hit: (_trust_tier_rank(hit.get("trust_tier", "community")), -hit.get("score", 0.0)),
    )

    selected: list[dict] = []
    selected_keys: set[str] = set()
    domain_counts: dict[str, int] = {}

    for hit in ordered:
        url = hit.get("url", "")
        key = canonicalize_url(url)
        if not key or key in selected_keys:
            continue
        domain = get_domain_from_url(url)
        if domain and domain_counts.get(domain, 0) >= per_domain_cap:
            continue

        selected.append(hit)
        selected_keys.add(key)
        if domain:
            domain_counts[domain] = domain_counts.get(domain, 0) + 1
        if len(selected) >= max_sources:
            return selected, False

    cap_relaxed = False
    if len(selected) < max_sources:
        for hit in ordered:
            url = hit.get("url", "")
            key = canonicalize_url(url)
            if not key or key in selected_keys:
                continue
            selected.append(hit)
            selected_keys.add(key)
            cap_relaxed = True
            if len(selected) >= max_sources:
                break

    return selected, cap_relaxed


def extract_primary_text_from_html(html: str, url: str) -> str:
    extracted = None
    if trafilatura is not None:
        try:
            extracted = trafilatura.extract(
                html,
                include_comments=False,
                include_tables=False,
                url=url,
            )
        except Exception:
            extracted = None

    if extracted:
        text = extracted.strip()
    else:
        soup = BeautifulSoup(html, "html.parser")
        for tag in soup(["script", "style", "nav", "footer", "aside"]):
            tag.decompose()
        text = soup.get_text(separator="\n", strip=True)

    if len(text) > 10000:
        text = text[:10000] + "\n...[TRUNCATED]"
    return text


def make_citation_snippet(text: str, query: str, max_chars: int = 260) -> str:
    clean = (text or "").replace("\r", "\n").strip()
    if not clean:
        return ""

    keywords = [t for t in re.findall(r"[a-zA-Z0-9]+", query.lower()) if len(t) > 3][:8]
    lines = [line.strip() for line in clean.split("\n") if line.strip()]

    for line in lines[:60]:
        ll = line.lower()
        if keywords and any(k in ll for k in keywords):
            return line[:max_chars]

    return clean[:max_chars]


def parse_json_flexible(raw_text: str):
    if not raw_text:
        return None
    candidates = [raw_text.strip()]
    code_blocks = re.findall(r"```(?:json)?\s*([\s\S]*?)```", raw_text, flags=re.IGNORECASE)
    candidates.extend(block.strip() for block in code_blocks if block.strip())
    for candidate in candidates:
        try:
            return json.loads(candidate)
        except Exception:
            continue
    return None


def generate_research_subqueries(query: str) -> list[str]:
    system = (
        "Generate 3 to 5 focused web research subqueries. "
        "Return JSON only as: {\"subqueries\": [\"...\"]}"
    )
    user = f"Primary query: {query}"
    response = call_llm(
        [
            {"role": "system", "content": system},
            {"role": "user", "content": user},
        ],
        source_type="research",
        source_ref="subquery_gen",
    )

    if "error" not in response:
        content = response["choices"][0]["message"].get("content", "")
        parsed = parse_json_flexible(content)
        if isinstance(parsed, dict):
            raw = parsed.get("subqueries", [])
            if isinstance(raw, list):
                cleaned = []
                for item in raw:
                    if isinstance(item, str):
                        q = item.strip()
                        if q:
                            cleaned.append(q)
                if cleaned:
                    return cleaned[:5]

    fallback = [
        query,
        f"{query} official documentation",
        f"{query} latest updates",
        f"{query} best practices",
    ]
    dedup = []
    seen = set()
    for q in fallback:
        k = q.lower().strip()
        if k and k not in seen:
            seen.add(k)
            dedup.append(q)
    return dedup[:5]


def synthesize_research(query: str, source_docs: list[dict], remaining_seconds: float) -> dict:
    if remaining_seconds < 8:
        return {"ok": False, "error": "Not enough time left for synthesis."}

    packed = []
    for src in source_docs[:10]:
        packed.append({
            "title": src.get("title", ""),
            "url": src.get("url", ""),
            "trust_tier": src.get("trust_tier", "community"),
            "snippet": src.get("snippet", ""),
        })

    system = (
        "You are a research synthesis engine. "
        "Return strict JSON with keys: answer_brief, evidence, conflicts. "
        "evidence is a list of objects with keys: claim, source_url, source_title, snippet, trust_tier. "
        "Keep answer_brief concise and citation-first."
    )
    user = (
        f"Query: {query}\n"
        f"Sources JSON: {json.dumps(packed, ensure_ascii=False)}\n"
        "Return JSON only."
    )
    response = call_llm(
        [
            {"role": "system", "content": system},
            {"role": "user", "content": user},
        ],
        source_type="research",
        source_ref="synthesis",
    )
    if "error" in response:
        return {"ok": False, "error": response["error"]}

    content = response["choices"][0]["message"].get("content", "")
    parsed = parse_json_flexible(content)
    if not isinstance(parsed, dict):
        return {"ok": False, "error": "Failed to parse synthesis JSON."}

    return {"ok": True, "data": parsed}


def tool_deep_research(
    query: str,
    max_sources: int = 10,
    max_runtime_sec: int = 120,
    recency_days: int | None = None,
    domains_allow: list[str] | None = None,
    domains_deny: list[str] | None = None,
) -> dict:
    started = time.monotonic()
    warnings = []
    conflicts = []

    query = (query or "").strip()
    if not query:
        return {"ok": False, "error": "Query is required."}

    max_sources = clamp_int(max_sources, 3, 12, 10)
    max_runtime_sec = clamp_int(max_runtime_sec, 30, 120, 120)
    recency_days = clamp_int(recency_days, 1, 3650, 30) if recency_days is not None else None

    allow = [normalize_domain(x) for x in (domains_allow or []) if normalize_domain(x)]
    deny = [normalize_domain(x) for x in (domains_deny or []) if normalize_domain(x)]

    subqueries = generate_research_subqueries(query)

    raw_hits = []
    for sq in subqueries:
        if time.monotonic() - started > max_runtime_sec * 0.45:
            warnings.append("Stopped adding new subqueries due to runtime budget.")
            break
        try:
            with without_proxy_env():
                with DDGS() as ddgs:
                    for r in ddgs.text(sq, max_results=8):
                        url = r.get("href", "")
                        if not url:
                            continue
                        safe_ok, safe_reason = apply_url_safety_guard(url, source="deep_research.search_hit")
                        if not safe_ok:
                            warnings.append(f"Blocked URL during search merge: {truncate_text(safe_reason, 120)}")
                            continue
                        if not filter_url_by_domain(url, allow, deny):
                            continue
                        raw_hits.append({
                            "query": sq,
                            "title": r.get("title", ""),
                            "url": url,
                            "snippet": r.get("body", ""),
                            "date": r.get("date"),
                        })
        except Exception as e:
            warnings.append(f"Search subquery failed: {truncate_text(str(e), 120)}")

    if not raw_hits:
        return {
            "ok": False,
            "error": "No search results found for query and domain filters.",
            "warnings": warnings,
        }

    deduped = {}
    for hit in raw_hits:
        canonical = canonicalize_url(hit["url"])
        trust_tier = classify_trust_tier(hit["url"], hit.get("title", ""))
        hit["trust_tier"] = trust_tier
        hit["score"] = score_search_hit(hit, query, recency_days=recency_days)
        existing = deduped.get(canonical)
        if existing is None or hit["score"] > existing["score"]:
            deduped[canonical] = hit

    selected, cap_relaxed = select_diverse_sources(
        candidates=list(deduped.values()),
        max_sources=max_sources,
        per_domain_cap=2,
    )
    if cap_relaxed:
        warnings.append("Source diversity cap relaxed due sparse candidates.")
    if len(selected) < 5:
        warnings.append("Low source count; confidence may be lower.")
    high_trust_count = sum(1 for item in selected if item.get("trust_tier") in HIGH_TRUST_TIERS)
    min_high_trust = min(4, max(2, len(selected) // 2))
    if selected and high_trust_count < min_high_trust:
        warnings.append("Limited high-trust source coverage; verify important claims.")

    source_docs = []
    for src in selected:
        elapsed = time.monotonic() - started
        if elapsed > max_runtime_sec * 0.9:
            warnings.append("Stopped page reading due to runtime budget.")
            break

        try:
            safe_ok, safe_reason = apply_url_safety_guard(src["url"], source="deep_research.read")
            if not safe_ok:
                warnings.append(f"Blocked source URL: {truncate_text(safe_reason, 120)}")
                continue
            response = REQUESTS_SESSION.get(src["url"], timeout=10)
            response.raise_for_status()
            text = extract_primary_text_from_html(response.text, src["url"])
            if len(text.strip()) < 80:
                warnings.append(f"Low-content page skipped: {src['url']}")
                continue
            snippet = make_citation_snippet(text, query)
            source_docs.append({
                "url": src["url"],
                "title": src.get("title", ""),
                "score": src["score"],
                "trust_tier": src.get("trust_tier", "community"),
                "text": text[:3000],
                "snippet": snippet,
            })
        except Exception as e:
            warnings.append(f"Read failed for {src['url']}: {truncate_text(str(e), 120)}")

    if not source_docs:
        # Fall back to search snippets if full-page reading fails.
        for src in selected[:6]:
            source_docs.append({
                "url": src["url"],
                "title": src.get("title", ""),
                "score": src["score"],
                "trust_tier": src.get("trust_tier", "community"),
                "text": src.get("snippet", ""),
                "snippet": truncate_text(src.get("snippet", ""), 260),
            })
        warnings.append("Using search snippets only; page extraction unavailable.")

    remaining = max_runtime_sec - (time.monotonic() - started)
    synthesized = synthesize_research(query, source_docs, remaining)

    if synthesized.get("ok"):
        payload = synthesized["data"]
        answer_brief = str(payload.get("answer_brief", "")).strip()
        raw_evidence = payload.get("evidence", [])
        if not isinstance(raw_evidence, list):
            raw_evidence = []
        evidence = []
        for item in raw_evidence[:10]:
            if not isinstance(item, dict):
                continue
            evidence.append({
                "claim": truncate_text(str(item.get("claim", "")), 220),
                "source_url": str(item.get("source_url", "")),
                "source_title": truncate_text(str(item.get("source_title", "")), 160),
                "snippet": truncate_text(str(item.get("snippet", "")), 260),
                "trust_tier": str(item.get("trust_tier", "community")),
            })
        raw_conflicts = payload.get("conflicts", [])
        if isinstance(raw_conflicts, list):
            conflicts = [truncate_text(str(x), 220) for x in raw_conflicts[:8]]
    else:
        answer_brief = (
            "Research completed with partial synthesis. "
            "Review evidence and sources for the strongest findings."
        )
        evidence = []
        for src in source_docs[:8]:
            evidence.append({
                "claim": truncate_text(src.get("snippet", "Source finding"), 220),
                "source_url": src.get("url", ""),
                "source_title": truncate_text(src.get("title", ""), 160),
                "snippet": truncate_text(src.get("snippet", ""), 260),
                "trust_tier": src.get("trust_tier", "community"),
            })
        conflicts = []
        warnings.append(f"Synthesis fallback used: {truncate_text(synthesized.get('error', ''), 140)}")

    sources = []
    for src in selected:
        sources.append({
            "url": src["url"],
            "title": src.get("title", ""),
            "score": src["score"],
            "trust_tier": src.get("trust_tier", "community"),
        })

    return {
        "ok": True,
        "answer_brief": truncate_text(answer_brief, 1800),
        "evidence": evidence,
        "sources": sources,
        "conflicts": conflicts,
        "warnings": warnings,
    }


def tool_read_pdf_url(url: str, max_pages: int = 20) -> dict:
    if PdfReader is None:
        return {"ok": False, "error": "pypdf is not installed.", "url": url}

    max_pages = clamp_int(max_pages, 1, 200, 20)
    allowed, reason = circuit_allow_call("web_fetch")
    if not allowed:
        return {"ok": False, "error": reason, "url": url}
    safe_ok, safe_reason = apply_url_safety_guard(url, source="read_pdf_url")
    if not safe_ok:
        return {"ok": False, "error": safe_reason, "url": url}

    try:
        response = REQUESTS_SESSION.get(url, timeout=20)
        response.raise_for_status()
        raw_bytes = BytesIO(response.content)
        reader = PdfReader(raw_bytes)

        total_pages = len(reader.pages)
        limit = min(total_pages, max_pages)
        chunks = []
        for idx in range(limit):
            page_text = reader.pages[idx].extract_text() or ""
            chunks.append(page_text)

        text = "\n".join(chunks).strip()
        if len(text) > 25000:
            text = text[:25000] + "\n...[TRUNCATED]"

        metadata_title = None
        try:
            metadata_title = getattr(reader.metadata, "title", None) if reader.metadata else None
        except Exception:
            metadata_title = None

        circuit_record_success("web_fetch")
        return {
            "ok": True,
            "text": text,
            "metadata": {"title": metadata_title, "pages": total_pages},
            "url": url,
        }
    except Exception as e:
        circuit_record_failure("web_fetch", str(e))
        return {"ok": False, "error": str(e), "url": url}


def tool_save_research_note(
    owner_id: int | None,
    topic: str,
    summary: str,
    sources: list[str],
    tags: list[str] | None = None,
) -> dict:
    if not owner_id or int(owner_id) <= 0:
        return {"ok": False, "error": "Owner context missing for research note."}

    topic = (topic or "").strip()
    summary = (summary or "").strip()
    if not topic or not summary:
        return {"ok": False, "error": "Both topic and summary are required."}

    sources = [str(s).strip() for s in (sources or []) if str(s).strip()]
    tags = [str(t).strip() for t in (tags or []) if str(t).strip()]

    db = SessionLocal()
    try:
        note = ResearchNote(
            owner_id=int(owner_id),
            topic=topic[:200],
            summary=summary[:6000],
            sources_json=json.dumps(sources),
            tags_json=json.dumps(tags),
        )
        db.add(note)
        db.commit()
        db.refresh(note)

        # Generate and store vector embedding for semantic search
        try:
            embed_text = f"{topic} {summary}"
            vec = get_embedding(embed_text)
            if np.linalg.norm(vec) > 1e-9:
                mv = MemoryVector(
                    owner_id=int(owner_id),
                    memory_type="research_note",
                    ref_id=note.id,
                    text_preview=embed_text[:200],
                    embedding=embedding_to_bytes(vec),
                )
                db.add(mv)
                db.commit()
        except Exception as emb_err:
            log.warning("EMBEDDING_STORE_FAILED note_id=%d: %s", note.id, emb_err)

        return {"ok": True, "note_id": note.id}
    except Exception as e:
        db.rollback()
        return {"ok": False, "error": str(e)}
    finally:
        db.close()


def tool_send_email(owner_id: int | None, to: str, subject: str, body: str, cc: str | None = None, bcc: str | None = None) -> dict:
    """Send an email via Gmail SMTP."""
    if not SMTP_USERNAME or not SMTP_PASSWORD:
        return {"ok": False, "error": "SMTP_USERNAME and SMTP_PASSWORD not configured in .env"}
    to = (to or "").strip()
    subject = (subject or "").strip()
    body = (body or "").strip()
    if not to or not subject or not body:
        return {"ok": False, "error": "to, subject, and body are all required"}
    try:
        msg = MIMEMultipart("alternative")
        msg["From"] = f"{SMTP_FROM_NAME} <{SMTP_USERNAME}>"
        msg["To"] = to
        msg["Subject"] = subject
        if cc:
            msg["Cc"] = cc.strip()
        if bcc:
            msg["Bcc"] = bcc.strip()
        msg.attach(MIMEText(body, "plain"))
        all_recipients = [r.strip() for r in to.split(",")]
        if cc:
            all_recipients += [r.strip() for r in cc.split(",")]
        if bcc:
            all_recipients += [r.strip() for r in bcc.split(",")]
        with smtplib.SMTP(SMTP_HOST, SMTP_PORT, timeout=30) as server:
            server.starttls()
            server.login(SMTP_USERNAME, SMTP_PASSWORD)
            server.sendmail(SMTP_USERNAME, all_recipients, msg.as_string())
        log.info("EMAIL_SENT to=%s subject=%s", to, subject[:50])
        return {"ok": True, "to": to, "subject": subject, "message": "Email sent successfully"}
    except Exception as e:
        log.error("EMAIL_SEND_FAILED to=%s error=%s", to, e)
        return {"ok": False, "error": str(e)}


def tool_research_memory_search(owner_id: int | None, query: str, top_k: int = 5) -> dict:
    """Semantic vector search over saved research notes (with keyword fallback)."""
    if not owner_id or int(owner_id) <= 0:
        return {"ok": False, "error": "Owner context missing for research memory search."}

    query = (query or "").strip()
    if not query:
        return {"ok": False, "error": "Query is required."}

    top_k = clamp_int(top_k, 1, 20, 5)

    db = SessionLocal()
    try:
        # --- Try vector search first ---
        mem_vectors = (
            db.query(MemoryVector)
            .filter(
                MemoryVector.owner_id == int(owner_id),
                MemoryVector.memory_type == "research_note",
            )
            .limit(1000)
            .all()
        )

        if mem_vectors:
            query_vec = get_embedding(query)
            if np.linalg.norm(query_vec) > 1e-9:
                scored = []
                for mv in mem_vectors:
                    stored_vec = bytes_to_embedding(mv.embedding)
                    sim = cosine_similarity(query_vec, stored_vec)
                    if sim > 0.15:  # Minimum similarity threshold
                        scored.append((mv.ref_id, sim))
                scored.sort(key=lambda x: x[1], reverse=True)
                top_ids = scored[:top_k]

                if top_ids:
                    results = []
                    for ref_id, sim in top_ids:
                        note = db.query(ResearchNote).filter(ResearchNote.id == ref_id).first()
                        if note:
                            sources = []
                            try:
                                sources = json.loads(note.sources_json or "[]")
                            except Exception:
                                pass
                            results.append({
                                "note_id": note.id,
                                "topic": note.topic,
                                "summary": truncate_text(note.summary, 700),
                                "score": round(sim, 4),
                                "search_method": "vector",
                                "sources": sources[:10],
                            })
                    if results:
                        return {"ok": True, "matches": results, "method": "vector_similarity"}

        # --- Fallback: keyword search (for notes without embeddings) ---
        q_tokens = set(re.findall(r"[a-zA-Z0-9]+", query.lower()))
        rows = (
            db.query(ResearchNote)
            .filter(ResearchNote.owner_id == int(owner_id))
            .order_by(ResearchNote.id.desc())
            .limit(300)
            .all()
        )

        scored = []
        for row in rows:
            sources = []
            tags = []
            try:
                sources = json.loads(row.sources_json or "[]")
            except Exception:
                pass
            try:
                tags = json.loads(row.tags_json or "[]")
            except Exception:
                pass

            text_blob = " ".join([
                (row.topic or ""),
                (row.summary or ""),
                " ".join(str(x) for x in sources),
                " ".join(str(x) for x in tags),
            ]).lower()

            if q_tokens:
                hits = sum(1 for token in q_tokens if token in text_blob)
                score = hits / max(len(q_tokens), 1)
            else:
                score = 0.0

            if score > 0:
                scored.append({
                    "note_id": row.id,
                    "topic": row.topic,
                    "summary": truncate_text(row.summary, 700),
                    "score": round(score, 4),
                    "search_method": "keyword",
                    "sources": sources[:10],
                })

        scored.sort(key=lambda x: x["score"], reverse=True)
        return {"ok": True, "matches": scored[:top_k], "method": "keyword_fallback"}
    except Exception as e:
        return {"ok": False, "error": str(e)}
    finally:
        db.close()


def tool_semantic_memory_search(
    owner_id: int | None,
    query: str,
    memory_types: list[str] | None = None,
    top_k: int = 5,
) -> dict:
    """Semantic search across ALL memory types using vector similarity."""
    if not owner_id or int(owner_id) <= 0:
        return {"ok": False, "error": "Owner context missing."}

    query = (query or "").strip()
    if not query:
        return {"ok": False, "error": "Query is required."}

    top_k = clamp_int(top_k, 1, 20, 5)

    db = SessionLocal()
    try:
        q = db.query(MemoryVector).filter(MemoryVector.owner_id == int(owner_id))
        if memory_types:
            q = q.filter(MemoryVector.memory_type.in_(memory_types))
        mem_vectors = q.limit(1000).all()

        if not mem_vectors:
            return {"ok": True, "matches": [], "message": "No memories stored yet."}

        query_vec = get_embedding(query)
        if np.linalg.norm(query_vec) < 1e-9:
            return {"ok": True, "matches": [], "message": "Could not embed query."}

        scored = []
        for mv in mem_vectors:
            stored_vec = bytes_to_embedding(mv.embedding)
            sim = cosine_similarity(query_vec, stored_vec)
            if sim > 0.15:
                entry = {
                    "memory_type": mv.memory_type,
                    "ref_id": mv.ref_id,
                    "text_preview": mv.text_preview,
                    "similarity": round(sim, 4),
                }
                # Enrich with source data if it's a research note
                if mv.memory_type == "research_note" and mv.ref_id:
                    note = db.query(ResearchNote).filter(ResearchNote.id == mv.ref_id).first()
                    if note:
                        entry["topic"] = note.topic
                        entry["summary"] = truncate_text(note.summary, 500)
                        try:
                            entry["sources"] = json.loads(note.sources_json or "[]")[:5]
                        except Exception:
                            pass
                elif mv.memory_type == "task_artifact" and mv.ref_id:
                    artifact = db.query(TaskArtifact).filter(TaskArtifact.id == mv.ref_id).first()
                    if artifact:
                        entry["task_id"] = artifact.task_id
                        entry["step_id"] = artifact.step_id
                        entry["status"] = artifact.status
                        entry["node_title"] = artifact.node_title
                        entry["outcome_summary"] = truncate_text(artifact.outcome_summary, 500)
                elif mv.memory_type in {"world_model_forecast", "world_model_outcome"} and mv.ref_id:
                    forecast = db.query(ActionForecast).filter(ActionForecast.id == mv.ref_id).first()
                    if forecast:
                        entry["context_type"] = forecast.context_type
                        entry["context_ref"] = forecast.context_ref
                        entry["pattern_tag"] = forecast.pattern_tag
                        entry["status"] = forecast.status
                        entry["predicted_outcome"] = truncate_text(forecast.predicted_outcome or "", 260)
                        entry["observed_outcome"] = truncate_text(forecast.observed_outcome or forecast.observed_error or "", 260)
                elif mv.memory_type == "self_improvement_note" and mv.ref_id:
                    note = db.query(SelfImprovementNote).filter(SelfImprovementNote.id == mv.ref_id).first()
                    if note:
                        entry["title"] = note.title
                        entry["summary"] = truncate_text(note.summary, 300)
                        entry["priority"] = note.priority
                scored.append(entry)

        scored.sort(key=lambda x: x["similarity"], reverse=True)
        return {"ok": True, "matches": scored[:top_k]}
    except Exception as e:
        return {"ok": False, "error": str(e)}
    finally:
        db.close()


SECRET_VALUE_PATTERNS = [
    re.compile(r"(?i)\b(sk-[a-z0-9]{16,})\b"),
    re.compile(r"(?i)\b(ghp_[a-z0-9]{20,})\b"),
    re.compile(r"(?i)\b(xox[baprs]-[a-z0-9-]{12,})\b"),
    re.compile(r"(?i)\b(bearer\s+)[a-z0-9._~+/=-]{12,}"),
    re.compile(r"(?i)\b(authorization\s*:\s*)(?:bearer\s+)?[a-z0-9._~+/=-]{10,}"),
    re.compile(r"(?i)\b(api[_-]?key|token|secret|password|passwd)\b\s*[:=]\s*([\"'])?[^\s\"']{6,}"),
]


def _estimate_text_tokens(value: str) -> int:
    text = str(value or "")
    if not text:
        return 0
    return max(1, int((len(text) + 3) / 4))


def _estimate_messages_tokens(messages: list[dict]) -> int:
    total = 0
    for msg in messages or []:
        if not isinstance(msg, dict):
            total += _estimate_text_tokens(str(msg))
            continue
        content = msg.get("content")
        if isinstance(content, str):
            total += _estimate_text_tokens(content)
        elif content is not None:
            total += _estimate_text_tokens(str(content))
        tool_calls = msg.get("tool_calls")
        if isinstance(tool_calls, list):
            for tc in tool_calls:
                if not isinstance(tc, dict):
                    total += _estimate_text_tokens(str(tc))
                    continue
                fn = tc.get("function")
                if isinstance(fn, dict):
                    total += _estimate_text_tokens(str(fn.get("name") or ""))
                    total += _estimate_text_tokens(str(fn.get("arguments") or ""))
                else:
                    total += _estimate_text_tokens(str(tc))
        tool_call_id = msg.get("tool_call_id")
        if tool_call_id:
            total += _estimate_text_tokens(str(tool_call_id))
    return int(total)


def _redact_secret_text(value: str) -> tuple[str, int]:
    text = str(value or "")
    if not text or not SECRET_GUARDRAIL_ENABLED:
        return text, 0

    redacted = text
    hits = 0
    for pattern in SECRET_VALUE_PATTERNS:
        if hits >= SECRET_REDACTION_MAX_HITS:
            break

        def repl(match: re.Match) -> str:
            nonlocal hits
            if hits >= SECRET_REDACTION_MAX_HITS:
                return match.group(0)
            hits += 1
            groups = match.groups()
            if not groups:
                return SECRET_REDACTION_TOKEN
            if len(groups) == 1:
                prefix = groups[0] or ""
                if len(prefix) > 30:
                    return SECRET_REDACTION_TOKEN
                return f"{prefix}{SECRET_REDACTION_TOKEN}"
            prefix = groups[0] or ""
            return f"{prefix}{SECRET_REDACTION_TOKEN}"

        redacted = pattern.sub(repl, redacted)
    return redacted, hits


def redact_secret_data(value):
    """Recursively redact likely secrets. Returns (redacted_value, hits)."""
    if not SECRET_GUARDRAIL_ENABLED:
        return value, 0
    if value is None:
        return None, 0
    if isinstance(value, str):
        return _redact_secret_text(value)
    if isinstance(value, (bool, int, float)):
        return value, 0
    if isinstance(value, dict):
        out = {}
        total = 0
        for key, item in value.items():
            safe_key, key_hits = _redact_secret_text(str(key))
            safe_item, item_hits = redact_secret_data(item)
            out[safe_key] = safe_item
            total += key_hits + item_hits
            if total >= SECRET_REDACTION_MAX_HITS:
                break
        return out, min(total, SECRET_REDACTION_MAX_HITS)
    if isinstance(value, (list, tuple, set)):
        out = []
        total = 0
        for item in list(value):
            safe_item, item_hits = redact_secret_data(item)
            out.append(safe_item)
            total += item_hits
            if total >= SECRET_REDACTION_MAX_HITS:
                break
        return out, min(total, SECRET_REDACTION_MAX_HITS)
    safe_text, hits = _redact_secret_text(str(value))
    return safe_text, hits


def _budget_elapsed_seconds(run_budget: dict | None) -> float:
    if not run_budget:
        return 0.0
    start = float(run_budget.get("started_monotonic") or 0.0)
    if start <= 0:
        return 0.0
    return max(0.0, time.monotonic() - start)


def _budget_usage(run_budget: dict | None) -> dict:
    if not run_budget:
        return {}
    elapsed = _budget_elapsed_seconds(run_budget)
    return {
        "seconds": round(elapsed, 3),
        "llm_calls": int(run_budget.get("llm_calls", 0)),
        "tool_calls": int(run_budget.get("tool_calls", 0)),
        "est_tokens": int(run_budget.get("est_tokens", 0)),
    }


def _budget_ratio(numerator: float, denominator: float) -> float:
    if denominator <= 0:
        return 0.0
    return max(0.0, float(numerator) / float(denominator))


def _budget_peak_ratio(run_budget: dict | None) -> float:
    usage = _budget_usage(run_budget)
    if not usage:
        return 0.0
    return max(
        _budget_ratio(usage.get("seconds", 0.0), float(BUDGET_MAX_SECONDS)),
        _budget_ratio(usage.get("llm_calls", 0), float(BUDGET_MAX_LLM_CALLS)),
        _budget_ratio(usage.get("tool_calls", 0), float(BUDGET_MAX_TOOL_CALLS)),
        _budget_ratio(usage.get("est_tokens", 0), float(BUDGET_MAX_EST_TOKENS)),
    )


def _budget_limit_reason(run_budget: dict | None) -> str | None:
    if not run_budget:
        return None
    usage = _budget_usage(run_budget)
    if usage.get("seconds", 0.0) > float(BUDGET_MAX_SECONDS):
        return f"runtime seconds>{BUDGET_MAX_SECONDS}"
    if usage.get("llm_calls", 0) > int(BUDGET_MAX_LLM_CALLS):
        return f"llm calls>{BUDGET_MAX_LLM_CALLS}"
    if usage.get("tool_calls", 0) > int(BUDGET_MAX_TOOL_CALLS):
        return f"tool calls>{BUDGET_MAX_TOOL_CALLS}"
    if usage.get("est_tokens", 0) > int(BUDGET_MAX_EST_TOKENS):
        return f"estimated tokens>{BUDGET_MAX_EST_TOKENS}"
    return None


def create_run_budget(scope: str, owner_id: int | None, source_ref: str | None = None) -> dict | None:
    if not BUDGET_GOVERNOR_ENABLED:
        return None
    budget = {
        "scope": str(scope or "chat"),
        "owner_id": int(owner_id) if owner_id is not None else None,
        "source_ref": str(source_ref or "") or None,
        "started_monotonic": time.monotonic(),
        "llm_calls": 0,
        "tool_calls": 0,
        "est_tokens": 0,
        "degraded": False,
    }
    RUNTIME_STATE["budget_runs_started"] = int(RUNTIME_STATE.get("budget_runs_started", 0)) + 1
    RUNTIME_STATE["budget_last_scope"] = budget["scope"]
    RUNTIME_STATE["budget_last_reason"] = None
    RUNTIME_STATE["budget_last_usage"] = _budget_usage(budget)
    return budget


def budget_record_llm_call(run_budget: dict | None, messages: list[dict], response: dict | None = None):
    if not run_budget:
        return
    run_budget["llm_calls"] = int(run_budget.get("llm_calls", 0)) + 1
    delta = _estimate_messages_tokens(messages)
    if isinstance(response, dict):
        try:
            choice = (response.get("choices") or [{}])[0]
            assistant = choice.get("message") if isinstance(choice, dict) else {}
            if isinstance(assistant, dict):
                delta += _estimate_messages_tokens([assistant])
        except Exception:
            pass
    run_budget["est_tokens"] = int(run_budget.get("est_tokens", 0)) + int(max(0, delta))
    RUNTIME_STATE["budget_last_usage"] = _budget_usage(run_budget)


def budget_record_tool_call(run_budget: dict | None, tool_name: str, args: dict | None = None, result: dict | None = None):
    if not run_budget:
        return
    run_budget["tool_calls"] = int(run_budget.get("tool_calls", 0)) + 1
    run_budget["est_tokens"] = int(run_budget.get("est_tokens", 0)) + _estimate_text_tokens(
        json.dumps({"tool": tool_name, "args": args or {}, "result": result or {}}, ensure_ascii=False)
    )
    RUNTIME_STATE["budget_last_usage"] = _budget_usage(run_budget)


def budget_should_stop(run_budget: dict | None) -> tuple[bool, str | None]:
    if not run_budget or BUDGET_GOVERNOR_MODE != "stop":
        return False, None
    reason = _budget_limit_reason(run_budget)
    if reason:
        RUNTIME_STATE["budget_runs_stopped"] = int(RUNTIME_STATE.get("budget_runs_stopped", 0)) + 1
        RUNTIME_STATE["budget_last_reason"] = reason
        RUNTIME_STATE["budget_last_usage"] = _budget_usage(run_budget)
        return True, reason
    return False, None


def budget_should_degrade(run_budget: dict | None) -> bool:
    if not run_budget or BUDGET_GOVERNOR_MODE != "degrade":
        return False
    ratio = _budget_peak_ratio(run_budget) * 100.0
    if ratio < float(BUDGET_DEGRADE_AT_PERCENT):
        return False
    if not bool(run_budget.get("degraded", False)):
        run_budget["degraded"] = True
        RUNTIME_STATE["budget_runs_degraded"] = int(RUNTIME_STATE.get("budget_runs_degraded", 0)) + 1
        RUNTIME_STATE["budget_last_reason"] = f"degraded_at_{int(ratio)}pct"
    return True


def budget_apply_degrade_to_tool_args(tool_name: str, args: dict, run_budget: dict | None) -> dict:
    runtime_args = dict(args or {})
    if not budget_should_degrade(run_budget):
        return runtime_args
    name = str(tool_name or "").strip().lower()
    if name == "search_web":
        runtime_args["num_results"] = min(3, clamp_int(runtime_args.get("num_results", 3), 1, 10, 3))
    elif name == "deep_research":
        runtime_args["max_sources"] = min(5, clamp_int(runtime_args.get("max_sources", 5), 3, 12, 5))
        runtime_args["max_runtime_sec"] = min(45, clamp_int(runtime_args.get("max_runtime_sec", 45), 15, 120, 45))
    elif name in {"run_command", "run_command_node"}:
        runtime_args["timeout"] = min(10, clamp_int(runtime_args.get("timeout", 10), 1, 120, 10))
    elif name == "execute_python":
        runtime_args["timeout"] = min(8, clamp_int(runtime_args.get("timeout", 8), 1, 60, 8))
    return runtime_args


def _diff_changed_lines(before_text: str, after_text: str) -> int:
    before_lines = str(before_text or "").splitlines()
    after_lines = str(after_text or "").splitlines()
    changed = 0
    for line in difflib.unified_diff(before_lines, after_lines, lineterm=""):
        if line.startswith(("+++", "---", "@@")):
            continue
        if line.startswith("+") or line.startswith("-"):
            changed += 1
    return int(changed)


def _read_text_file_safe(path: Path) -> str:
    try:
        return path.read_text(encoding="utf-8", errors="ignore")
    except Exception:
        return ""


def evaluate_workspace_diff_gate(tool_name: str, args: dict) -> dict:
    if full_power_system_enabled():
        return {"blocked": False, "require_approval": False, "warned": False, "reason": "", "path": "", "changed_lines": 0}
    if not WORKSPACE_DIFF_GATE_ENABLED or str(tool_name or "").strip().lower() != "write_file":
        return {"blocked": False, "require_approval": False, "warned": False, "reason": "", "path": "", "changed_lines": 0}

    file_path = str((args or {}).get("file_path") or "").strip()
    if not file_path:
        return {"blocked": False, "require_approval": False, "warned": False, "reason": "", "path": "", "changed_lines": 0}

    try:
        target = _resolve_write_target(file_path)
    except Exception:
        target = Path(file_path).expanduser().resolve(strict=False)

    ext = str(target.suffix or "").strip().lower()
    if WORKSPACE_DIFF_MONITORED_EXTENSIONS and ext and ext not in WORKSPACE_DIFF_MONITORED_EXTENSIONS:
        return {"blocked": False, "require_approval": False, "warned": False, "reason": "", "path": str(target), "changed_lines": 0}

    content = str((args or {}).get("content") or "")
    old_text = _read_text_file_safe(target) if target.exists() else ""
    changed_lines = _diff_changed_lines(old_text, content)
    new_bytes = len(content.encode("utf-8", errors="ignore"))

    reasons: list[str] = []
    if changed_lines > int(WORKSPACE_DIFF_MAX_CHANGED_LINES):
        reasons.append(f"changed_lines>{WORKSPACE_DIFF_MAX_CHANGED_LINES}")
    if new_bytes > int(WORKSPACE_DIFF_MAX_FILE_BYTES):
        reasons.append(f"bytes>{WORKSPACE_DIFF_MAX_FILE_BYTES}")

    if not reasons:
        return {
            "blocked": False,
            "require_approval": False,
            "warned": False,
            "reason": "",
            "path": str(target),
            "changed_lines": int(changed_lines),
        }

    reason = ", ".join(reasons)
    RUNTIME_STATE["workspace_diff_gate_last_path"] = str(target)
    RUNTIME_STATE["workspace_diff_gate_last_reason"] = reason
    RUNTIME_STATE["workspace_diff_gate_last_changed_lines"] = int(changed_lines)

    mode = WORKSPACE_DIFF_GATE_MODE
    if mode == "warn":
        RUNTIME_STATE["workspace_diff_gate_warns"] = int(RUNTIME_STATE.get("workspace_diff_gate_warns", 0)) + 1
        log.warning("WORKSPACE_DIFF_GATE_WARN path=%s changed_lines=%d reason=%s", target, changed_lines, reason)
        return {"blocked": False, "require_approval": False, "warned": True, "reason": reason, "path": str(target), "changed_lines": int(changed_lines)}
    if mode == "block":
        RUNTIME_STATE["workspace_diff_gate_blocks"] = int(RUNTIME_STATE.get("workspace_diff_gate_blocks", 0)) + 1
        log.warning("WORKSPACE_DIFF_GATE_BLOCK path=%s changed_lines=%d reason=%s", target, changed_lines, reason)
        return {"blocked": True, "require_approval": False, "warned": False, "reason": reason, "path": str(target), "changed_lines": int(changed_lines)}

    RUNTIME_STATE["workspace_diff_gate_approvals"] = int(RUNTIME_STATE.get("workspace_diff_gate_approvals", 0)) + 1
    log.info("WORKSPACE_DIFF_GATE_APPROVAL path=%s changed_lines=%d reason=%s", target, changed_lines, reason)
    return {"blocked": False, "require_approval": True, "warned": False, "reason": reason, "path": str(target), "changed_lines": int(changed_lines)}


ROLE_PROMPT_SUFFIX = {
    "planner": "Role=Planner. Keep a short execution plan and choose the next best action/tool.",
    "executor": "Role=Executor. Perform concrete actions and collect evidence/output.",
    "critic": "Role=Critic. Verify results, catch mistakes, and ensure the step is truly complete.",
}


def task_role_for_iteration(iteration_index: int) -> str:
    if not TASK_ROLE_LOOP_ENABLED or TASK_ROLE_LOOP_MODE == "off":
        return "executor"
    roles = ["planner", "executor", "critic"]
    if TASK_ROLE_LOOP_MODE == "cycle":
        return roles[int(iteration_index) % len(roles)]
    idx = min(max(0, int(iteration_index)), len(roles) - 1)
    return roles[idx]


def _blackbox_session_id(prefix: str, owner_id: int, seed: str = "") -> str:
    token = uuid.uuid4().hex[:10]
    root = f"{prefix}:{int(owner_id)}:{token}"
    if seed:
        root = f"{root}:{truncate_text(seed, 40)}"
    return root


def _blackbox_sanitize(value, depth: int = 0):
    if depth >= 3:
        redacted, hits = redact_secret_data(str(value))
        if hits > 0:
            RUNTIME_STATE["secret_redactions_total"] = int(RUNTIME_STATE.get("secret_redactions_total", 0)) + int(hits)
        return truncate_text(str(redacted), 220)
    if value is None:
        return None
    if isinstance(value, (bool, int, float)):
        return value
    if isinstance(value, str):
        redacted, hits = redact_secret_data(value)
        if hits > 0:
            RUNTIME_STATE["secret_redactions_total"] = int(RUNTIME_STATE.get("secret_redactions_total", 0)) + int(hits)
        return truncate_text(str(redacted), 420)
    if isinstance(value, dict):
        out = {}
        count = 0
        for key, item in value.items():
            out[truncate_text(str(key), 120)] = _blackbox_sanitize(item, depth + 1)
            count += 1
            if count >= 30:
                out["_truncated"] = True
                break
        return out
    if isinstance(value, (list, tuple, set)):
        out = []
        for idx, item in enumerate(list(value)):
            if idx >= 30:
                out.append("...[TRUNCATED]")
                break
            out.append(_blackbox_sanitize(item, depth + 1))
        return out
    redacted, hits = redact_secret_data(str(value))
    if hits > 0:
        RUNTIME_STATE["secret_redactions_total"] = int(RUNTIME_STATE.get("secret_redactions_total", 0)) + int(hits)
    return truncate_text(str(redacted), 220)


def _blackbox_payload_json(payload: dict | None) -> str:
    safe_payload = _blackbox_sanitize(payload or {})
    try:
        raw = json.dumps(safe_payload, ensure_ascii=False)
    except Exception:
        raw = json.dumps({"_raw": truncate_text(str(payload), 420)}, ensure_ascii=False)
    if len(raw) > BLACKBOX_PAYLOAD_MAX_CHARS:
        raw = raw[:BLACKBOX_PAYLOAD_MAX_CHARS] + "...[TRUNCATED]"
    return raw


def record_blackbox_event(
    db: Session,
    owner_id: int,
    session_id: str,
    source_type: str,
    event_type: str,
    payload: dict | None = None,
    source_ref: str | None = None,
) -> bool:
    if not BLACKBOX_ENABLED:
        return False
    if not session_id:
        return False
    try:
        row = ExecutionEvent(
            owner_id=int(owner_id),
            session_id=truncate_text(session_id, 120),
            source_type=truncate_text(source_type or "system", 32),
            source_ref=truncate_text(str(source_ref or ""), 120) or None,
            event_type=truncate_text(event_type, 80),
            payload_json=_blackbox_payload_json(payload),
        )
        db.add(row)
        RUNTIME_STATE["blackbox_events_total"] = int(RUNTIME_STATE.get("blackbox_events_total", 0)) + 1
        RUNTIME_STATE["blackbox_last_event_at"] = utc_now_iso()
        return True
    except Exception as exc:
        log.warning("BLACKBOX_EVENT_FAIL owner=%s event=%s error=%s", owner_id, event_type, truncate_text(str(exc), 200))
        return False


def record_blackbox_event_with_new_session(
    owner_id: int,
    session_id: str,
    source_type: str,
    event_type: str,
    payload: dict | None = None,
    source_ref: str | None = None,
):
    if not BLACKBOX_ENABLED:
        return
    db = SessionLocal()
    try:
        ok = record_blackbox_event(
            db=db,
            owner_id=int(owner_id),
            session_id=session_id,
            source_type=source_type,
            event_type=event_type,
            payload=payload,
            source_ref=source_ref,
        )
        if ok:
            db.commit()
        else:
            db.rollback()
    except Exception:
        db.rollback()
    finally:
        db.close()


def fetch_blackbox_events(
    owner_id: int,
    session_id: str | None = None,
    source_type: str | None = None,
    limit: int = 100,
) -> list[dict]:
    read_limit = clamp_int(limit, 1, BLACKBOX_READ_MAX_LIMIT, 100)
    db = SessionLocal()
    try:
        q = db.query(ExecutionEvent).filter(ExecutionEvent.owner_id == int(owner_id))
        if session_id:
            q = q.filter(ExecutionEvent.session_id == str(session_id).strip())
        if source_type:
            q = q.filter(ExecutionEvent.source_type == str(source_type).strip().lower())
        rows = (
            q.order_by(ExecutionEvent.id.desc())
            .limit(read_limit)
            .all()
        )
        events: list[dict] = []
        for row in rows:
            events.append(_blackbox_row_to_event_dict(row))
        return events
    finally:
        db.close()


def fetch_blackbox_events_after(
    owner_id: int,
    after_event_id: int = 0,
    session_id: str | None = None,
    source_type: str | None = None,
    limit: int = 100,
) -> list[dict]:
    read_limit = clamp_int(limit, 1, BLACKBOX_READ_MAX_LIMIT, 100)
    db = SessionLocal()
    try:
        q = db.query(ExecutionEvent).filter(ExecutionEvent.owner_id == int(owner_id))
        if int(after_event_id) > 0:
            q = q.filter(ExecutionEvent.id > int(after_event_id))
        if session_id:
            q = q.filter(ExecutionEvent.session_id == str(session_id).strip())
        if source_type:
            q = q.filter(ExecutionEvent.source_type == str(source_type).strip().lower())
        rows = (
            q.order_by(ExecutionEvent.id.asc())
            .limit(read_limit)
            .all()
        )
        return [_blackbox_row_to_event_dict(row) for row in rows]
    finally:
        db.close()


def _blackbox_row_to_event_dict(row: ExecutionEvent) -> dict:
    payload: dict = {}
    try:
        payload = json.loads(row.payload_json or "{}")
        if not isinstance(payload, dict):
            payload = {"value": payload}
    except Exception:
        payload = {"_raw": truncate_text(row.payload_json or "", 320)}

    created = _coerce_utc(row.created_at)
    return {
        "id": int(row.id),
        "owner_id": int(row.owner_id),
        "session_id": row.session_id,
        "source_type": row.source_type,
        "source_ref": row.source_ref,
        "event_type": row.event_type,
        "payload": payload,
        "created_at": created.isoformat() if created else None,
    }


def _blackbox_payload_preview(payload: dict, max_len: int = 220) -> str:
    if not isinstance(payload, dict) or not payload:
        return ""
    for key in ("error", "message", "result_preview", "detail", "status"):
        value = payload.get(key)
        if value:
            return truncate_text(str(value), max_len)
    tool = str(payload.get("tool") or payload.get("tool_name") or "").strip()
    if tool:
        return truncate_text(f"tool={tool}", max_len)
    try:
        return truncate_text(json.dumps(payload, ensure_ascii=False), max_len)
    except Exception:
        return truncate_text(str(payload), max_len)


def _blackbox_event_is_failure(event_type: str, payload: dict) -> bool:
    et = str(event_type or "").strip().lower()
    if any(token in et for token in ("fail", "error", "exception", "dead_letter")):
        return True
    if "blocked" in et and "approval" not in et:
        return True
    if isinstance(payload, dict):
        if payload.get("ok") is False:
            return True
        status = str(payload.get("status") or "").strip().lower()
        if status in {"failed", "error", "timeout", "blocked", "cancelled"}:
            return True
        err_blob = " ".join(
            str(payload.get(k) or "")
            for k in ("error", "message", "detail")
        ).strip()
        if err_blob and re.search(r"(fail|error|exception|timeout|denied|invalid)", err_blob, re.IGNORECASE):
            return True
    return False


def _blackbox_event_is_warning(event_type: str, payload: dict) -> bool:
    et = str(event_type or "").strip().lower()
    if any(token in et for token in ("retry", "warning", "degraded", "fallback")):
        return True
    if isinstance(payload, dict):
        msg = str(payload.get("warning") or payload.get("message") or "")
        if msg and re.search(r"(retry|warning|degraded|fallback|partial)", msg, re.IGNORECASE):
            return True
    return False


def _blackbox_latest_session_id(db: Session, owner_id: int, source_type: str | None = None) -> str | None:
    q = db.query(ExecutionEvent).filter(ExecutionEvent.owner_id == int(owner_id))
    if source_type:
        q = q.filter(ExecutionEvent.source_type == str(source_type).strip().lower())
    row = q.order_by(ExecutionEvent.id.desc()).first()
    if not row:
        return None
    return str(row.session_id or "").strip() or None


def list_blackbox_sessions(
    owner_id: int,
    limit: int = 20,
    source_type: str | None = None,
) -> list[dict]:
    read_limit = clamp_int(limit, 1, BLACKBOX_SESSION_LIST_MAX_LIMIT, 20)
    db = SessionLocal()
    try:
        q = db.query(
            ExecutionEvent.session_id.label("session_id"),
            ExecutionEvent.source_type.label("source_type"),
            func.count(ExecutionEvent.id).label("event_count"),
            func.min(ExecutionEvent.created_at).label("first_event_at"),
            func.max(ExecutionEvent.created_at).label("last_event_at"),
            func.max(ExecutionEvent.id).label("last_event_id"),
        ).filter(ExecutionEvent.owner_id == int(owner_id))

        if source_type:
            q = q.filter(ExecutionEvent.source_type == str(source_type).strip().lower())

        rows = (
            q.group_by(ExecutionEvent.session_id, ExecutionEvent.source_type)
            .order_by(func.max(ExecutionEvent.id).desc())
            .limit(read_limit)
            .all()
        )

        sessions: list[dict] = []
        for row in rows:
            first_dt = _coerce_utc(row.first_event_at)
            last_dt = _coerce_utc(row.last_event_at)
            duration = None
            if first_dt and last_dt:
                duration = round(max(0.0, (last_dt - first_dt).total_seconds()), 3)
            sessions.append({
                "session_id": str(row.session_id or ""),
                "source_type": str(row.source_type or ""),
                "event_count": int(row.event_count or 0),
                "first_event_at": first_dt.isoformat() if first_dt else None,
                "last_event_at": last_dt.isoformat() if last_dt else None,
                "duration_seconds": duration,
            })
        return sessions
    except Exception as exc:
        log.warning("BLACKBOX_LIST_SESSIONS_FAIL owner=%s error=%s", owner_id, truncate_text(str(exc), 200))
        return []
    finally:
        db.close()


def build_blackbox_session_report(
    owner_id: int,
    session_id: str | None = None,
    source_type: str | None = None,
    limit: int = 300,
    include_timeline: bool = False,
) -> dict:
    read_limit = clamp_int(limit, 1, BLACKBOX_SESSION_REPORT_MAX_EVENTS, 300)
    db = SessionLocal()
    try:
        chosen_session = str(session_id or "").strip()
        if not chosen_session:
            chosen_session = _blackbox_latest_session_id(db, owner_id, source_type=source_type) or ""
        if not chosen_session:
            return {"ok": False, "error": "No blackbox session found for owner."}

        q = db.query(ExecutionEvent).filter(
            ExecutionEvent.owner_id == int(owner_id),
            ExecutionEvent.session_id == chosen_session,
        )
        if source_type:
            q = q.filter(ExecutionEvent.source_type == str(source_type).strip().lower())

        total_events = int(q.count())
        raw_rows = (
            q.order_by(ExecutionEvent.id.desc())
            .limit(read_limit)
            .all()
        )
        rows = list(reversed(raw_rows))
        events = [_blackbox_row_to_event_dict(row) for row in rows]

        event_type_counts: dict[str, int] = {}
        source_counts: dict[str, int] = {}
        tool_counts: dict[str, int] = {}
        failures: list[dict] = []
        warning_count = 0
        failure_count = 0
        tool_requested = 0
        tool_completed = 0
        tool_failed = 0
        tool_blocked = 0
        approval_required = 0

        for event in events:
            et = str(event.get("event_type") or "")
            payload = event.get("payload") if isinstance(event.get("payload"), dict) else {}
            source = str(event.get("source_type") or "")

            event_type_counts[et] = int(event_type_counts.get(et, 0)) + 1
            source_counts[source] = int(source_counts.get(source, 0)) + 1

            et_lower = et.lower()
            tool_name = str(payload.get("tool") or payload.get("tool_name") or "").strip()
            if "tool_requested" in et_lower:
                tool_requested += 1
                if tool_name:
                    tool_counts[tool_name] = int(tool_counts.get(tool_name, 0)) + 1
            if "tool_completed" in et_lower:
                tool_completed += 1
            if any(token in et_lower for token in ("tool_exception", "tool_unknown")):
                tool_failed += 1
            if "tool_blocked" in et_lower:
                tool_blocked += 1
            if "approval_required" in et_lower:
                approval_required += 1

            if _blackbox_event_is_warning(et, payload):
                warning_count += 1

            if _blackbox_event_is_failure(et, payload):
                failure_count += 1
                if len(failures) < BLACKBOX_SESSION_FAILURE_SAMPLE_LIMIT:
                    failures.append({
                        "event_type": et,
                        "created_at": event.get("created_at"),
                        "source_ref": event.get("source_ref"),
                        "message": _blackbox_payload_preview(payload, max_len=260),
                    })

        first_dt = _coerce_utc(rows[0].created_at) if rows else None
        last_dt = _coerce_utc(rows[-1].created_at) if rows else None
        duration = None
        if first_dt and last_dt:
            duration = round(max(0.0, (last_dt - first_dt).total_seconds()), 3)

        status = "healthy"
        if failure_count > 0:
            status = "degraded"
        if failure_count >= 3 and failure_count >= max(2, tool_completed):
            status = "failed"

        top_tools = [
            {"tool": name, "count": int(count)}
            for name, count in sorted(tool_counts.items(), key=lambda kv: kv[1], reverse=True)[:10]
        ]

        timeline: list[dict] = []
        if include_timeline:
            for event in events:
                payload = event.get("payload") if isinstance(event.get("payload"), dict) else {}
                raw_task_id = payload.get("task_id")
                task_id = None
                try:
                    if raw_task_id is not None:
                        task_id = int(raw_task_id)
                except Exception:
                    task_id = None
                timeline.append({
                    "id": event.get("id"),
                    "created_at": event.get("created_at"),
                    "event_type": event.get("event_type"),
                    "source_type": event.get("source_type"),
                    "source_ref": event.get("source_ref"),
                    "tool_name": truncate_text(str(payload.get("tool") or payload.get("tool_name") or ""), 120) or None,
                    "step_id": truncate_text(str(payload.get("step_id") or ""), 120) or None,
                    "token": truncate_text(str(payload.get("token") or ""), 120) or None,
                    "task_id": task_id,
                    "payload_preview": _blackbox_payload_preview(payload, max_len=220),
                })

        RUNTIME_STATE["blackbox_reports_built"] = int(RUNTIME_STATE.get("blackbox_reports_built", 0)) + 1
        return {
            "ok": True,
            "owner_id": int(owner_id),
            "session_id": chosen_session,
            "status": status,
            "first_event_at": first_dt.isoformat() if first_dt else None,
            "last_event_at": last_dt.isoformat() if last_dt else None,
            "duration_seconds": duration,
            "total_events_in_session": total_events,
            "events_loaded": len(events),
            "truncated": bool(total_events > len(events)),
            "source_counts": source_counts,
            "event_type_counts": event_type_counts,
            "tool_requested": tool_requested,
            "tool_completed": tool_completed,
            "tool_failed": tool_failed,
            "tool_blocked": tool_blocked,
            "approval_required": approval_required,
            "warning_count": warning_count,
            "failure_count": failure_count,
            "top_tools": top_tools,
            "failure_samples": failures,
            "timeline": timeline,
            "generated_at": utc_now_iso(),
        }
    except Exception as exc:
        log.warning(
            "BLACKBOX_SESSION_REPORT_FAIL owner=%s session=%s error=%s",
            owner_id,
            truncate_text(str(session_id or ""), 80),
            truncate_text(str(exc), 220),
        )
        return {"ok": False, "error": "Failed to build blackbox session report."}
    finally:
        db.close()


def _safe_int(value, default: int | None = None) -> int | None:
    try:
        if value is None:
            return default
        return int(value)
    except Exception:
        return default


def build_blackbox_recovery_plan(
    owner_id: int,
    session_id: str | None = None,
    source_type: str | None = None,
    limit: int = 300,
) -> dict:
    report = build_blackbox_session_report(
        owner_id=owner_id,
        session_id=session_id,
        source_type=source_type,
        limit=limit,
        include_timeline=True,
    )
    if not report.get("ok"):
        return report

    timeline = report.get("timeline") if isinstance(report.get("timeline"), list) else []
    latest_event_type = str(timeline[-1].get("event_type")) if timeline else None

    token_order: list[str] = []
    token_seen: set[str] = set()
    task_ids: set[int] = set()
    for item in timeline:
        if not isinstance(item, dict):
            continue

        token = str(item.get("token") or "").strip()
        if token and token not in token_seen:
            token_seen.add(token)
            token_order.append(token)

        task_id = _safe_int(item.get("task_id"), None)
        if task_id and task_id > 0:
            task_ids.add(task_id)
            continue

        source_type_item = str(item.get("source_type") or "").strip().lower()
        source_ref_item = str(item.get("source_ref") or "").strip()
        if source_type_item == "task":
            parsed_task = _safe_int(source_ref_item, None)
            if parsed_task and parsed_task > 0:
                task_ids.add(parsed_task)

    token_order = token_order[:BLACKBOX_RECOVERY_MAX_APPROVALS]
    approvals_by_token: dict[str, dict] = {}
    tasks_by_id: dict[int, dict] = {}

    db = SessionLocal()
    try:
        if token_order:
            rows = (
                db.query(ApprovalRequest)
                .filter(
                    ApprovalRequest.owner_id == int(owner_id),
                    ApprovalRequest.token.in_(token_order),
                )
                .order_by(ApprovalRequest.id.desc())
                .all()
            )
            for row in rows:
                token = str(row.token or "").strip()
                if not token or token in approvals_by_token:
                    continue
                expires_dt = _coerce_utc(row.expires_at)
                created_dt = _coerce_utc(row.created_at)
                decided_dt = _coerce_utc(row.decided_at)
                now_dt = datetime.now(timezone.utc)
                is_expired = bool(expires_dt and expires_dt <= now_dt)
                approvals_by_token[token] = {
                    "token": token,
                    "status": str(row.status or "pending"),
                    "tool_name": str(row.tool_name or ""),
                    "source_type": str(row.source_type or ""),
                    "source_ref": str(row.source_ref or ""),
                    "step_id": str(row.step_id or "") or None,
                    "created_at": created_dt.isoformat() if created_dt else None,
                    "expires_at": expires_dt.isoformat() if expires_dt else None,
                    "decided_at": decided_dt.isoformat() if decided_dt else None,
                    "is_expired": is_expired,
                }

        if task_ids:
            rows = (
                db.query(Task)
                .filter(
                    Task.owner_id == int(owner_id),
                    Task.id.in_(list(task_ids)),
                )
                .all()
            )
            for row in rows:
                tasks_by_id[int(row.id)] = {
                    "task_id": int(row.id),
                    "title": truncate_text(str(row.title or ""), 180),
                    "status": str(row.status or ""),
                    "created_at": _coerce_utc(row.created_at).isoformat() if _coerce_utc(row.created_at) else None,
                }
    finally:
        db.close()

    approvals: list[dict] = []
    pending_approval_count = 0
    rejected_approval_count = 0
    expired_approval_count = 0
    consumed_approval_count = 0

    for token in token_order:
        entry = approvals_by_token.get(token) or {
            "token": token,
            "status": "unknown",
            "tool_name": "",
            "source_type": "",
            "source_ref": "",
            "step_id": None,
            "created_at": None,
            "expires_at": None,
            "decided_at": None,
            "is_expired": False,
        }
        status = str(entry.get("status") or "unknown").strip().lower()
        if status == "pending":
            pending_approval_count += 1
        elif status == "rejected":
            rejected_approval_count += 1
        elif status == "expired":
            expired_approval_count += 1
        elif status == "consumed":
            consumed_approval_count += 1
        approvals.append(entry)

    task_refs = [tasks_by_id[k] for k in sorted(tasks_by_id.keys())]
    failed_task_count = sum(1 for t in task_refs if str(t.get("status", "")).lower() == TASK_STATUS_FAILED)
    blocked_task_count = sum(1 for t in task_refs if str(t.get("status", "")).lower() == TASK_STATUS_BLOCKED)

    recommendations: list[dict] = []
    for approval in approvals:
        status = str(approval.get("status") or "").strip().lower()
        token = str(approval.get("token") or "").strip()
        tool_name = str(approval.get("tool_name") or "tool").strip() or "tool"
        if status == "pending":
            recommendations.append({
                "priority": "high",
                "kind": "approval",
                "message": f"Pending approval for {tool_name}.",
                "command": f"/approve {token}",
            })
        elif status in {"rejected", "expired"}:
            recommendations.append({
                "priority": "medium",
                "kind": "approval",
                "message": f"Approval token {token} is {status}; rerun task/message if still needed.",
                "command": None,
            })

    for task_info in task_refs:
        task_id = int(task_info.get("task_id") or 0)
        status = str(task_info.get("status") or "").strip().lower()
        if task_id <= 0:
            continue
        if status in {TASK_STATUS_FAILED, TASK_STATUS_BLOCKED}:
            recommendations.append({
                "priority": "high",
                "kind": "task",
                "message": f"Task #{task_id} is {status}. Inspect and decide next action.",
                "command": f"/task_status {task_id}",
            })

    if str(latest_event_type or "").lower() == "chat_loop_exhausted":
        recommendations.append({
            "priority": "medium",
            "kind": "chat",
            "message": "Chat run exhausted tool-loop budget; retry with narrower scope.",
            "command": None,
        })

    if str(latest_event_type or "").lower() == "llm_error":
        recommendations.append({
            "priority": "high",
            "kind": "llm",
            "message": "Latest session ended with LLM error; verify provider/runtime health.",
            "command": None,
        })

    # Dedupe recommendations by (kind, command, message) and cap size.
    deduped: list[dict] = []
    seen_rec: set[str] = set()
    for rec in recommendations:
        key = f"{rec.get('kind')}|{rec.get('command')}|{rec.get('message')}"
        if key in seen_rec:
            continue
        seen_rec.add(key)
        deduped.append(rec)
        if len(deduped) >= BLACKBOX_RECOVERY_MAX_ACTIONS:
            break

    RUNTIME_STATE["blackbox_recovery_plans_built"] = int(RUNTIME_STATE.get("blackbox_recovery_plans_built", 0)) + 1
    RUNTIME_STATE["blackbox_last_recovery_plan_at"] = utc_now_iso()

    return {
        "ok": True,
        "owner_id": int(owner_id),
        "session_id": str(report.get("session_id") or ""),
        "status": report.get("status"),
        "latest_event_type": latest_event_type,
        "pending_approval_count": pending_approval_count,
        "rejected_approval_count": rejected_approval_count,
        "expired_approval_count": expired_approval_count,
        "consumed_approval_count": consumed_approval_count,
        "blocked_task_count": blocked_task_count,
        "failed_task_count": failed_task_count,
        "approvals": approvals,
        "task_refs": task_refs,
        "recommended_actions": deduped,
        "session_report_excerpt": {
            "failure_count": int(report.get("failure_count") or 0),
            "warning_count": int(report.get("warning_count") or 0),
            "tool_requested": int(report.get("tool_requested") or 0),
            "tool_completed": int(report.get("tool_completed") or 0),
            "tool_failed": int(report.get("tool_failed") or 0),
        },
        "generated_at": utc_now_iso(),
    }


def build_blackbox_replay(
    owner_id: int,
    session_id: str | None = None,
    source_type: str | None = None,
    limit: int = 600,
) -> dict:
    if not BLACKBOX_ENABLED:
        return {"ok": False, "error": "blackbox disabled", "enabled": False}

    read_limit = clamp_int(limit, 1, BLACKBOX_EXPORT_MAX_EVENTS, 600)
    report = build_blackbox_session_report(
        owner_id=owner_id,
        session_id=session_id,
        source_type=source_type,
        limit=read_limit,
        include_timeline=True,
    )
    if not report.get("ok"):
        return report

    resolved_session = str(report.get("session_id") or "").strip()
    timeline = list(report.get("timeline") or [])
    checkpoints: list[dict] = []
    for idx, item in enumerate(timeline, 1):
        if not isinstance(item, dict):
            continue
        event_type = str(item.get("event_type") or "").strip()
        payload_preview = str(item.get("payload_preview") or "").strip()
        state = "progress"
        lower = event_type.lower()
        if any(token in lower for token in ("fail", "error", "exception")):
            state = "failure"
        elif "approval" in lower:
            state = "approval_gate"
        elif any(token in lower for token in ("done", "completed", "final_response")):
            state = "success"
        checkpoints.append({
            "index": idx,
            "event_id": item.get("id"),
            "event_type": event_type,
            "state": state,
            "created_at": item.get("created_at"),
            "step_id": item.get("step_id"),
            "tool_name": item.get("tool_name"),
            "summary": truncate_text(payload_preview, 220),
        })

    recovery = build_blackbox_recovery_plan(
        owner_id=owner_id,
        session_id=resolved_session,
        source_type=source_type,
        limit=read_limit,
    )
    if not recovery.get("ok"):
        recovery = {"ok": False, "error": recovery.get("error", "Recovery plan unavailable.")}

    latest_event_type = str((timeline[-1] or {}).get("event_type") if timeline else "").lower()
    resumable = bool(
        latest_event_type
        and any(
            token in latest_event_type
            for token in ("approval", "blocked", "retry", "paused")
        )
    )

    return {
        "ok": True,
        "owner_id": int(owner_id),
        "session_id": resolved_session,
        "status": report.get("status"),
        "events_loaded": len(timeline),
        "checkpoints": checkpoints,
        "resumable": resumable,
        "latest_event_type": latest_event_type or None,
        "recovery_plan": recovery,
        "generated_at": utc_now_iso(),
    }


def prune_blackbox_events(owner_id: int | None = None, reason: str = "manual") -> dict:
    if not BLACKBOX_ENABLED:
        return {"ok": False, "error": "blackbox disabled", "enabled": False}
    if not BLACKBOX_PRUNE_ENABLED:
        return {
            "ok": True,
            "enabled": True,
            "prune_enabled": False,
            "owner_id": int(owner_id) if owner_id else None,
            "deleted_total": 0,
            "deleted_age": 0,
            "deleted_overflow": 0,
            "timestamp": utc_now_iso(),
        }

    owner_filter = int(owner_id) if owner_id and int(owner_id) > 0 else None
    deleted_age = 0
    deleted_overflow = 0
    db = SessionLocal()
    try:
        if BLACKBOX_MAX_EVENT_AGE_DAYS > 0:
            cutoff_dt = datetime.utcnow() - timedelta(days=float(BLACKBOX_MAX_EVENT_AGE_DAYS))
            while True:
                q = db.query(ExecutionEvent.id).filter(ExecutionEvent.created_at < cutoff_dt)
                if owner_filter is not None:
                    q = q.filter(ExecutionEvent.owner_id == owner_filter)
                id_rows = q.order_by(ExecutionEvent.id.asc()).limit(BLACKBOX_PRUNE_BATCH_SIZE).all()
                ids = [int(row[0]) for row in id_rows if row and row[0] is not None]
                if not ids:
                    break
                deleted = (
                    db.query(ExecutionEvent)
                    .filter(ExecutionEvent.id.in_(ids))
                    .delete(synchronize_session=False)
                )
                db.commit()
                deleted_age += int(max(0, deleted))
                if deleted <= 0:
                    break

        if owner_filter is not None:
            owner_ids = [owner_filter]
        else:
            owner_ids = [
                int(row[0])
                for row in db.query(ExecutionEvent.owner_id).distinct().all()
                if row and row[0] is not None
            ]

        for oid in owner_ids:
            while True:
                total = int(
                    db.query(func.count(ExecutionEvent.id))
                    .filter(ExecutionEvent.owner_id == int(oid))
                    .scalar()
                    or 0
                )
                overflow = total - int(BLACKBOX_MAX_EVENTS_PER_OWNER)
                if overflow <= 0:
                    break
                batch = min(int(overflow), int(BLACKBOX_PRUNE_BATCH_SIZE))
                id_rows = (
                    db.query(ExecutionEvent.id)
                    .filter(ExecutionEvent.owner_id == int(oid))
                    .order_by(ExecutionEvent.id.asc())
                    .limit(batch)
                    .all()
                )
                ids = [int(row[0]) for row in id_rows if row and row[0] is not None]
                if not ids:
                    break
                deleted = (
                    db.query(ExecutionEvent)
                    .filter(ExecutionEvent.id.in_(ids))
                    .delete(synchronize_session=False)
                )
                db.commit()
                deleted_overflow += int(max(0, deleted))
                if deleted <= 0:
                    break

        deleted_total = int(deleted_age + deleted_overflow)
        RUNTIME_STATE["blackbox_events_pruned"] = int(RUNTIME_STATE.get("blackbox_events_pruned", 0)) + deleted_total
        RUNTIME_STATE["blackbox_last_prune_at"] = utc_now_iso()
        RUNTIME_STATE["blackbox_last_prune_reason"] = truncate_text(str(reason or "manual"), 120)
        RUNTIME_STATE["blackbox_last_prune_count"] = deleted_total

        if deleted_total > 0:
            log.info(
                "BLACKBOX_PRUNE_OK owner=%s deleted_total=%d deleted_age=%d deleted_overflow=%d reason=%s",
                owner_filter,
                deleted_total,
                int(deleted_age),
                int(deleted_overflow),
                truncate_text(str(reason or ""), 120),
            )

        return {
            "ok": True,
            "enabled": True,
            "prune_enabled": True,
            "owner_id": owner_filter,
            "deleted_total": deleted_total,
            "deleted_age": int(deleted_age),
            "deleted_overflow": int(deleted_overflow),
            "reason": truncate_text(str(reason or "manual"), 120),
            "timestamp": utc_now_iso(),
        }
    except Exception as exc:
        db.rollback()
        log.warning(
            "BLACKBOX_PRUNE_FAIL owner=%s reason=%s error=%s",
            owner_filter,
            truncate_text(str(reason or "manual"), 120),
            truncate_text(str(exc), 220),
        )
        return {"ok": False, "error": "Failed to prune blackbox events."}
    finally:
        db.close()


def build_blackbox_export_bundle(
    owner_id: int,
    session_id: str | None = None,
    source_type: str | None = None,
    limit: int = 600,
    include_timeline: bool = True,
    include_raw_events: bool = False,
) -> dict:
    if not BLACKBOX_ENABLED:
        return {"ok": False, "error": "blackbox disabled", "enabled": False}

    read_limit = clamp_int(limit, 1, BLACKBOX_EXPORT_MAX_EVENTS, 600)
    report = build_blackbox_session_report(
        owner_id=owner_id,
        session_id=session_id,
        source_type=source_type,
        limit=read_limit,
        include_timeline=bool(include_timeline),
    )
    if not report.get("ok"):
        return report

    resolved_session = str(report.get("session_id") or "").strip()
    recovery = build_blackbox_recovery_plan(
        owner_id=owner_id,
        session_id=resolved_session,
        source_type=source_type,
        limit=read_limit,
    )
    if not recovery.get("ok"):
        recovery = {"ok": False, "error": recovery.get("error", "Recovery plan unavailable.")}

    raw_events: list[dict] = []
    if include_raw_events and resolved_session:
        raw_events = list(
            reversed(
                fetch_blackbox_events(
                    owner_id=owner_id,
                    session_id=resolved_session,
                    source_type=source_type,
                    limit=read_limit,
                )
            )
        )

    recent_sessions = list_blackbox_sessions(
        owner_id=owner_id,
        limit=min(20, BLACKBOX_SESSION_LIST_MAX_LIMIT),
        source_type=source_type,
    )

    RUNTIME_STATE["blackbox_exports_built"] = int(RUNTIME_STATE.get("blackbox_exports_built", 0)) + 1
    RUNTIME_STATE["blackbox_last_export_at"] = utc_now_iso()

    return {
        "ok": True,
        "enabled": True,
        "owner_id": int(owner_id),
        "session_id": resolved_session,
        "manifest": {
            "schema_version": "blackbox_bundle_v1",
            "generated_at": utc_now_iso(),
            "source_type_filter": source_type,
            "max_events": int(read_limit),
            "includes_timeline": bool(include_timeline),
            "includes_raw_events": bool(include_raw_events),
        },
        "session_report": report,
        "recovery_plan": recovery,
        "recent_sessions": recent_sessions,
        "raw_events": raw_events,
    }


def _safe_json_dict(raw_value, fallback: dict | None = None) -> dict:
    if isinstance(raw_value, dict):
        return raw_value
    if isinstance(raw_value, str):
        try:
            parsed = json.loads(raw_value)
            if isinstance(parsed, dict):
                return parsed
        except Exception:
            pass
    return dict(fallback or {})


def _safe_json_list(raw_value, fallback: list | None = None) -> list:
    if isinstance(raw_value, list):
        return raw_value
    if isinstance(raw_value, str):
        try:
            parsed = json.loads(raw_value)
            if isinstance(parsed, list):
                return parsed
        except Exception:
            pass
    return list(fallback or [])


def _normalize_capability_list(raw_value) -> list[str]:
    items: list[str] = []
    if isinstance(raw_value, list):
        items = [str(x).strip().lower() for x in raw_value if str(x).strip()]
    elif isinstance(raw_value, str):
        text = raw_value.strip()
        if text:
            try:
                parsed = json.loads(text)
                if isinstance(parsed, list):
                    items = [str(x).strip().lower() for x in parsed if str(x).strip()]
                else:
                    items = [part.strip().lower() for part in text.split(",") if part.strip()]
            except Exception:
                items = [part.strip().lower() for part in text.split(",") if part.strip()]
    deduped: list[str] = []
    seen = set()
    for item in items:
        if not re.fullmatch(r"[a-z0-9_-]{1,40}", item):
            continue
        if item in seen:
            continue
        seen.add(item)
        deduped.append(item)
    if not deduped:
        deduped = [NODE_AUTO_CAPABILITY_DEFAULT]
    return deduped[:16]


def _node_last_heartbeat_iso(node_name: str, fallback_value: str | None = None) -> str | None:
    with NODE_CONTROL_LOCK:
        meta = NODE_HEARTBEAT_MAP.get(str(node_name or "").strip().lower())
        if isinstance(meta, dict):
            value = str(meta.get("last_heartbeat_at") or "").strip()
            if value:
                return value
    value = str(fallback_value or "").strip()
    return value or None


def _node_is_healthy(node_name: str, fallback_value: str | None = None) -> bool:
    heartbeat_iso = _node_last_heartbeat_iso(node_name, fallback_value=fallback_value)
    if not heartbeat_iso:
        return False
    dt = parse_iso_utc(heartbeat_iso)
    if dt is None:
        return False
    age = (datetime.now(timezone.utc) - dt).total_seconds()
    return age <= float(NODE_HEARTBEAT_STALE_SECONDS)


def _default_node_scheduler_state() -> dict:
    return {
        "dispatches_total": 0,
        "failures_total": 0,
        "consecutive_failures": 0,
        "last_dispatch_at": None,
        "last_success_at": None,
        "last_failure_at": None,
        "last_error": None,
        "last_latency_ms": None,
        "avg_latency_ms": None,
        "last_score": None,
    }


def _get_node_scheduler_state(node_name: str) -> dict:
    key = str(node_name or "").strip().lower()
    with NODE_CONTROL_LOCK:
        row = NODE_SCHEDULER_STATS.get(key)
        if not isinstance(row, dict):
            row = _default_node_scheduler_state()
            NODE_SCHEDULER_STATS[key] = row
        return row


def _node_scheduler_snapshot(node_name: str) -> dict:
    key = str(node_name or "").strip().lower()
    with NODE_CONTROL_LOCK:
        row = dict(NODE_SCHEDULER_STATS.get(key) or _default_node_scheduler_state())
    return row


def _record_node_dispatch(
    node_name: str,
    *,
    success: bool,
    latency_ms: float | None = None,
    error: str | None = None,
):
    key = str(node_name or "").strip().lower()
    if not key:
        return
    now_iso = utc_now_iso()
    with NODE_CONTROL_LOCK:
        row = NODE_SCHEDULER_STATS.get(key)
        if not isinstance(row, dict):
            row = _default_node_scheduler_state()
            NODE_SCHEDULER_STATS[key] = row
        row["dispatches_total"] = int(row.get("dispatches_total", 0)) + 1
        row["last_dispatch_at"] = now_iso
        if latency_ms is not None:
            lat = max(0.0, float(latency_ms))
            row["last_latency_ms"] = round(lat, 3)
            prev_avg = row.get("avg_latency_ms")
            if isinstance(prev_avg, (int, float)):
                row["avg_latency_ms"] = round((float(prev_avg) * 0.7) + (lat * 0.3), 3)
            else:
                row["avg_latency_ms"] = round(lat, 3)
        if success:
            row["consecutive_failures"] = 0
            row["last_success_at"] = now_iso
            row["last_error"] = None
        else:
            row["failures_total"] = int(row.get("failures_total", 0)) + 1
            row["consecutive_failures"] = int(row.get("consecutive_failures", 0)) + 1
            row["last_failure_at"] = now_iso
            row["last_error"] = truncate_text(str(error or "dispatch failure"), 240)

    RUNTIME_STATE["node_scheduler_dispatches"] = int(RUNTIME_STATE.get("node_scheduler_dispatches", 0)) + 1
    RUNTIME_STATE["node_scheduler_last_node"] = key
    if not success:
        RUNTIME_STATE["node_scheduler_failures"] = int(RUNTIME_STATE.get("node_scheduler_failures", 0)) + 1


def _active_lease_counts(db: Session) -> dict[str, int]:
    counts: dict[str, int] = {}
    try:
        rows = (
            db.query(NodeLease.node_name, func.count(NodeLease.id))
            .filter(
                NodeLease.status == "active",
                NodeLease.expires_at > datetime.utcnow(),
            )
            .group_by(NodeLease.node_name)
            .all()
        )
        for node_name, count_value in rows:
            key = str(node_name or "").strip().lower()
            if not key:
                continue
            counts[key] = int(count_value or 0)
    except Exception:
        pass
    return counts


def _candidate_node_scores(capability: str, preferred_node: str | None = None) -> list[dict]:
    required = str(capability or NODE_AUTO_CAPABILITY_DEFAULT).strip().lower() or NODE_AUTO_CAPABILITY_DEFAULT
    preferred = str(preferred_node or "").strip().lower()
    db = SessionLocal()
    try:
        cleanup_expired_node_leases(db)
        db.commit()
        lease_counts = _active_lease_counts(db)
    except Exception:
        db.rollback()
        lease_counts = {}
    finally:
        db.close()

    candidates: list[dict] = []
    now = datetime.now(timezone.utc)
    for entry in REMOTE_NODE_REGISTRY.values():
        name = str(entry.get("name") or "").strip().lower()
        if not name or not bool(entry.get("enabled", True)):
            continue
        caps = _normalize_capability_list(entry.get("capabilities", []))
        exact_capability = required in caps
        if not exact_capability and "general" not in caps:
            continue

        score = 0.0
        healthy = _node_is_healthy(name, fallback_value=entry.get("last_heartbeat_at"))
        if healthy:
            score += 120.0
        else:
            score -= 160.0

        score += 35.0 if exact_capability else 12.0
        if preferred and name == preferred:
            score += 25.0

        lease_count = int(lease_counts.get(name, 0))
        score -= float(lease_count) * float(NODE_SCHEDULER_LEASE_PENALTY)

        stats = _node_scheduler_snapshot(name)
        consecutive_failures = int(stats.get("consecutive_failures", 0))
        score -= float(consecutive_failures) * float(NODE_SCHEDULER_FAILURE_PENALTY)

        avg_latency = stats.get("avg_latency_ms")
        if isinstance(avg_latency, (int, float)):
            score -= float(avg_latency) * float(NODE_SCHEDULER_LATENCY_PENALTY)

        last_failure_iso = normalize_optional_text(stats.get("last_failure_at"), 80)
        if last_failure_iso:
            failure_dt = parse_iso_utc(last_failure_iso)
            if failure_dt is not None:
                age = (now - failure_dt).total_seconds()
                if age < float(NODE_SCHEDULER_FAILURE_WINDOW_SECONDS):
                    score -= float(NODE_SCHEDULER_FAILURE_PENALTY)

        if int(stats.get("failures_total", 0)) > 0 and consecutive_failures == 0:
            score += float(NODE_SCHEDULER_RECOVERY_BONUS)

        score -= min(20.0, float(int(stats.get("dispatches_total", 0)) * 0.08))

        candidates.append({
            "node_name": name,
            "score": round(score, 3),
            "healthy": healthy,
            "exact_capability": bool(exact_capability),
            "lease_count": lease_count,
            "stats": stats,
        })

    candidates.sort(key=lambda item: (-float(item["score"]), item["node_name"]))
    return candidates


def _refresh_node_runtime_metrics():
    db = SessionLocal()
    try:
        active_leases = int(sum(_active_lease_counts(db).values()))
    except Exception:
        active_leases = 0
    finally:
        db.close()
    RUNTIME_STATE["node_control_plane_nodes"] = int(len(REMOTE_NODE_REGISTRY))
    RUNTIME_STATE["node_control_plane_leases_active"] = int(active_leases)


def cleanup_expired_node_leases(db: Session):
    try:
        now_dt = datetime.utcnow()
        db.query(NodeLease).filter(
            NodeLease.status == "active",
            NodeLease.expires_at <= now_dt,
        ).update({"status": "expired"}, synchronize_session=False)
        db.flush()
    except Exception:
        pass


def select_remote_node_for_capability(capability: str, preferred_node: str | None = None) -> str | None:
    candidates = _candidate_node_scores(capability, preferred_node=preferred_node)
    if not candidates:
        return None
    selected = candidates[0]
    node_name = str(selected["node_name"])
    score = float(selected.get("score", 0.0))
    RUNTIME_STATE["node_scheduler_last_node"] = node_name
    RUNTIME_STATE["node_scheduler_last_score"] = round(score, 3)
    with NODE_CONTROL_LOCK:
        stats = NODE_SCHEDULER_STATS.get(node_name)
        if not isinstance(stats, dict):
            stats = _default_node_scheduler_state()
            NODE_SCHEDULER_STATS[node_name] = stats
        stats["last_score"] = round(score, 3)
    return node_name


def claim_node_lease(owner_id: int | None, capability: str, node_name: str | None = None, ttl_seconds: int | None = None) -> dict:
    if not NODE_CONTROL_PLANE_ENABLED:
        return {"ok": False, "error": "Node control-plane is disabled."}
    db = SessionLocal()
    try:
        cleanup_expired_node_leases(db)
        selected = str(node_name or "").strip().lower()
        if selected in {"", "auto"}:
            selected = select_remote_node_for_capability(capability)
        if not selected:
            return {"ok": False, "error": f"No node available for capability '{capability}'."}
        if selected not in REMOTE_NODE_REGISTRY:
            return {"ok": False, "error": f"Node '{selected}' is not registered/enabled."}
        selected_caps = _normalize_capability_list(REMOTE_NODE_REGISTRY.get(selected, {}).get("capabilities", []))
        required_capability = str(capability or NODE_AUTO_CAPABILITY_DEFAULT).strip().lower() or NODE_AUTO_CAPABILITY_DEFAULT
        if required_capability not in selected_caps and "general" not in selected_caps:
            return {
                "ok": False,
                "error": f"Node '{selected}' does not expose capability '{required_capability}'.",
                "available_capabilities": selected_caps,
            }
        lease_ttl = clamp_int(ttl_seconds, 15, 3600, NODE_LEASE_TTL_SECONDS)
        token = f"nls_{uuid.uuid4().hex[:14]}"
        row = NodeLease(
            lease_token=token,
            node_name=selected,
            owner_id=int(owner_id) if owner_id is not None else None,
            capability=truncate_text(str(capability or NODE_AUTO_CAPABILITY_DEFAULT), 40),
            status="active",
            expires_at=datetime.utcnow() + timedelta(seconds=lease_ttl),
        )
        db.add(row)
        db.commit()
        _refresh_node_runtime_metrics()
        return {
            "ok": True,
            "lease_token": token,
            "node_name": selected,
            "capability": row.capability,
            "expires_at": iso_datetime_or_none(row.expires_at),
            "scheduler_score": RUNTIME_STATE.get("node_scheduler_last_score"),
        }
    except Exception as e:
        db.rollback()
        return {"ok": False, "error": truncate_text(str(e), 260)}
    finally:
        db.close()


def release_node_lease(lease_token: str) -> dict:
    token = str(lease_token or "").strip()
    if not token:
        return {"ok": False, "error": "lease_token is required."}
    db = SessionLocal()
    try:
        row = db.query(NodeLease).filter(NodeLease.lease_token == token).first()
        if not row:
            return {"ok": False, "error": "Lease not found."}
        if row.status != "active":
            return {"ok": True, "status": row.status}
        row.status = "released"
        row.released_at = datetime.utcnow()
        db.commit()
        _refresh_node_runtime_metrics()
        return {"ok": True, "status": row.status, "node_name": row.node_name}
    except Exception as e:
        db.rollback()
        return {"ok": False, "error": truncate_text(str(e), 260)}
    finally:
        db.close()


def load_remote_node_registry() -> dict[str, dict]:
    global REMOTE_NODE_REGISTRY
    loaded: dict[str, dict] = {}
    try:
        parsed = json.loads(REMOTE_NODES_JSON or "[]")
        if not isinstance(parsed, list):
            parsed = []
        for item in parsed:
            if not isinstance(item, dict):
                continue
            name = (item.get("name") or "").strip().lower()
            base_url = (item.get("base_url") or "").strip().rstrip("/")
            if not name or not base_url:
                continue
            if not re.fullmatch(r"[a-z0-9][a-z0-9_-]{1,40}", name):
                continue
            loaded[name] = {
                "name": name,
                "base_url": base_url,
                "command_path": str(item.get("command_path") or "/run_command"),
                "token": str(item.get("token") or "").strip(),
                "enabled": bool(item.get("enabled", True)),
                "capabilities": _normalize_capability_list(item.get("capabilities", [])),
                "source": "env",
                "last_heartbeat_at": None,
            }
    except Exception as e:
        log.warning("REMOTE_NODE_REGISTRY_LOAD_FAIL error=%s", str(e)[:220])
        loaded = {}

    if NODE_CONTROL_PLANE_ENABLED:
        db = SessionLocal()
        try:
            rows = db.query(NodeRegistration).all()
            for row in rows:
                name = str(row.node_name or "").strip().lower()
                if not name:
                    continue
                loaded[name] = {
                    "name": name,
                    "base_url": str(row.base_url or "").strip().rstrip("/"),
                    "command_path": "/run_command",
                    "token": str(row.auth_token or "").strip(),
                    "enabled": bool(int(row.enabled or 0) == 1),
                    "capabilities": _normalize_capability_list(row.capabilities_json),
                    "source": "control_plane",
                    "last_heartbeat_at": iso_datetime_or_none(row.last_heartbeat_at),
                }
        except Exception as e:
            log.warning("NODE_CONTROL_LOAD_FAIL error=%s", truncate_text(str(e), 220))
        finally:
            db.close()

    REMOTE_NODE_REGISTRY = loaded
    with NODE_CONTROL_LOCK:
        stale = [name for name in NODE_SCHEDULER_STATS.keys() if name not in loaded]
        for name in stale:
            NODE_SCHEDULER_STATS.pop(name, None)
    RUNTIME_STATE["remote_nodes_loaded"] = len(loaded)
    _refresh_node_runtime_metrics()
    return loaded


def tool_list_execution_nodes() -> dict:
    db = SessionLocal()
    try:
        lease_counts = _active_lease_counts(db)
    finally:
        db.close()

    local_caps = ["general"]
    local_hash = hashlib.sha256(",".join(sorted(local_caps)).encode("utf-8")).hexdigest()[:12]
    nodes = [{
        "name": "local",
        "kind": "local",
        "enabled": True,
        "healthy": True,
        "capabilities": local_caps,
        "capability_hash": local_hash,
        "max_parallel_leases": int(NODE_MAX_LEASES_PER_NODE),
        "active_leases": 0,
    }]
    for entry in sorted(REMOTE_NODE_REGISTRY.values(), key=lambda x: x["name"]):
        node_name = str(entry["name"])
        stats = _node_scheduler_snapshot(node_name)
        caps = _normalize_capability_list(entry.get("capabilities", []))
        cap_hash = hashlib.sha256(",".join(sorted(caps)).encode("utf-8")).hexdigest()[:12] if caps else ""
        nodes.append({
            "name": node_name,
            "kind": "remote",
            "enabled": bool(entry.get("enabled", True)),
            "base_url": entry.get("base_url", ""),
            "healthy": _node_is_healthy(node_name, fallback_value=entry.get("last_heartbeat_at")),
            "last_heartbeat_at": _node_last_heartbeat_iso(node_name, fallback_value=entry.get("last_heartbeat_at")),
            "capabilities": caps,
            "capability_hash": cap_hash,
            "source": str(entry.get("source") or "env"),
            "max_parallel_leases": int(NODE_MAX_LEASES_PER_NODE),
            "active_leases": int(lease_counts.get(node_name.lower(), 0)),
            "scheduler": {
                "dispatches_total": int(stats.get("dispatches_total", 0)),
                "failures_total": int(stats.get("failures_total", 0)),
                "consecutive_failures": int(stats.get("consecutive_failures", 0)),
                "avg_latency_ms": stats.get("avg_latency_ms"),
                "last_latency_ms": stats.get("last_latency_ms"),
                "last_dispatch_at": stats.get("last_dispatch_at"),
                "last_error": stats.get("last_error"),
                "last_score": stats.get("last_score"),
            },
        })
    _refresh_node_runtime_metrics()
    return {"ok": True, "nodes": nodes, "count": len(nodes), "control_plane_enabled": bool(NODE_CONTROL_PLANE_ENABLED)}


def tool_run_command_node(
    node_name: str,
    command: str,
    timeout: int = 30,
    cwd: str | None = None,
    capability: str | None = None,
) -> dict:
    node = (node_name or "local").strip().lower()
    timeout = clamp_int(timeout, 1, 300, 30)
    required_capability = str(capability or NODE_AUTO_CAPABILITY_DEFAULT).strip().lower() or NODE_AUTO_CAPABILITY_DEFAULT
    policy_ok, policy_reason = enforce_node_command_policy(node, command, capability=required_capability)
    if not policy_ok:
        return {"ok": False, "error": policy_reason, "node": node, "required_capability": required_capability}

    if node in {"auto", "any"}:
        selected = select_remote_node_for_capability(required_capability)
        if selected:
            node = selected
        else:
            node = "local"

    if node in {"", "local"}:
        result = tool_run_command(command, timeout=timeout, cwd=cwd)
        if isinstance(result, dict):
            result["node"] = "local"
        return result

    cfg = REMOTE_NODE_REGISTRY.get(node)
    if not cfg or not bool(cfg.get("enabled", True)):
        return {"ok": False, "error": f"Remote node '{node}' is not available.", "node": node}
    cfg_caps = _normalize_capability_list(cfg.get("capabilities", []))
    if required_capability not in cfg_caps and "general" not in cfg_caps:
        return {
            "ok": False,
            "error": f"Remote node '{node}' does not expose capability '{required_capability}'.",
            "node": node,
            "required_capability": required_capability,
            "available_capabilities": cfg_caps,
        }

    command_path = str(cfg.get("command_path") or "/run_command")
    if not command_path.startswith("/"):
        command_path = "/" + command_path
    endpoint = str(cfg.get("base_url", "")).rstrip("/") + command_path
    safe_ok, safe_reason = apply_url_safety_guard(endpoint, source=f"node:{node}")
    if not safe_ok:
        return {"ok": False, "error": safe_reason, "node": node, "endpoint": endpoint}
    headers = {"Content-Type": "application/json"}
    token = str(cfg.get("token") or "").strip()
    if token:
        headers["Authorization"] = f"Bearer {token}"

    allowed, reason = circuit_allow_call("web_fetch")
    if not allowed:
        return {"ok": False, "error": reason, "node": node}

    started = time.perf_counter()
    try:
        response = REQUESTS_SESSION.post(
            endpoint,
            headers=headers,
            json={"command": command, "timeout": timeout, "cwd": str(cwd or "")},
            timeout=min(max(timeout + 5, 10), REMOTE_NODE_TIMEOUT_SECONDS),
        )
        status_code = int(response.status_code)
        payload: dict = {}
        text_body = ""
        try:
            parsed = response.json()
            if isinstance(parsed, dict):
                payload = parsed
            else:
                text_body = str(parsed)
        except Exception:
            text_body = response.text or ""

        if status_code >= 400:
            circuit_record_failure("web_fetch", f"remote node {node} returned status={status_code}")
            err = str(payload.get("error") or text_body or f"HTTP {status_code}")
            _record_node_dispatch(
                node,
                success=False,
                latency_ms=(time.perf_counter() - started) * 1000.0,
                error=err,
            )
            return {
                "ok": False,
                "error": err[:500],
                "node": node,
                "status_code": status_code,
                "endpoint": endpoint,
            }

        circuit_record_success("web_fetch")
        if NODE_CONTROL_PLANE_ENABLED:
            with NODE_CONTROL_LOCK:
                NODE_HEARTBEAT_MAP[node] = {
                    "last_heartbeat_at": utc_now_iso(),
                    "healthy": True,
                }
        _record_node_dispatch(
            node,
            success=True,
            latency_ms=(time.perf_counter() - started) * 1000.0,
        )
        if payload:
            payload = dict(payload)
            payload["ok"] = bool(payload.get("ok", True))
            payload["node"] = node
            payload["status_code"] = status_code
            payload["endpoint"] = endpoint
            payload["scheduler_score"] = RUNTIME_STATE.get("node_scheduler_last_score")
            return payload
        return {
            "ok": True,
            "node": node,
            "status_code": status_code,
            "endpoint": endpoint,
            "scheduler_score": RUNTIME_STATE.get("node_scheduler_last_score"),
            "stdout": text_body[:10000],
        }
    except Exception as e:
        circuit_record_failure("web_fetch", f"remote node {node} error={str(e)[:160]}")
        with NODE_CONTROL_LOCK:
            NODE_HEARTBEAT_MAP[node] = {
                "last_heartbeat_at": utc_now_iso(),
                "healthy": False,
                "last_error": truncate_text(str(e), 220),
            }
        _record_node_dispatch(
            node,
            success=False,
            latency_ms=(time.perf_counter() - started) * 1000.0,
            error=str(e),
        )
        return {"ok": False, "error": str(e), "node": node, "endpoint": endpoint}


def _validate_required_keys(payload: dict, required_keys: list[str] | None) -> tuple[bool, str | None]:
    if not required_keys:
        return True, None
    for key in required_keys:
        if key not in payload:
            return False, f"Missing required key: {key}"
    return True, None


def call_llm_json_task(
    task_name: str,
    system_prompt: str,
    user_prompt: str,
    required_keys: list[str] | None = None,
    max_attempts: int | None = None,
) -> dict:
    attempts = clamp_int(max_attempts, 1, 6, LLM_STRUCTURED_TASK_MAX_ATTEMPTS)
    last_error = "Unknown structured-task failure."
    raw_content = ""

    for _ in range(attempts):
        RUNTIME_STATE["structured_task_calls"] = int(RUNTIME_STATE.get("structured_task_calls", 0)) + 1
        response = call_llm(
            [
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": user_prompt},
            ],
            source_type="structured_task",
            source_ref=task_name,
        )
        if "error" in response:
            last_error = str(response["error"])
            continue
        try:
            raw_content = response["choices"][0]["message"].get("content", "") or ""
        except Exception:
            raw_content = ""
        parsed = parse_json_from_text(raw_content)
        if isinstance(parsed, dict):
            ok, error = _validate_required_keys(parsed, required_keys)
            if ok:
                return {"ok": True, "data": parsed, "raw": raw_content}
            last_error = error or "Structured JSON missing required fields."
        else:
            last_error = "Model did not return valid JSON object."

    RUNTIME_STATE["structured_task_failures"] = int(RUNTIME_STATE.get("structured_task_failures", 0)) + 1
    return {"ok": False, "error": last_error, "raw": raw_content}


def tool_llm_structured_task(instruction: str, schema: dict | None = None, max_attempts: int = 2) -> dict:
    if not LLM_STRUCTURED_TASK_ENABLED:
        return {"ok": False, "error": "Structured task mode is disabled by configuration."}
    instruction = (instruction or "").strip()
    if not instruction:
        return {"ok": False, "error": "instruction is required."}

    schema_obj = _safe_json_dict(schema, fallback={})
    required_keys = []
    raw_required = schema_obj.get("required")
    if isinstance(raw_required, list):
        required_keys = [str(x).strip() for x in raw_required if str(x).strip()][:20]

    schema_hint = json.dumps(schema_obj, ensure_ascii=False) if schema_obj else "{}"
    result = call_llm_json_task(
        task_name="tool_llm_structured_task",
        system_prompt=(
            "You are a strict JSON engine. Return only one JSON object and no markdown. "
            "Do not include prose outside JSON."
        ),
        user_prompt=(
            f"Instruction:\n{instruction}\n\n"
            f"Desired JSON schema hint:\n{schema_hint}\n\n"
            "Return JSON now."
        ),
        required_keys=required_keys,
        max_attempts=max_attempts,
    )
    if result.get("ok"):
        return {"ok": True, "data": result.get("data", {}), "raw": result.get("raw", "")}
    return {"ok": False, "error": result.get("error", "Structured task failed."), "raw": result.get("raw", "")}


def _normalize_schedule_lane(raw_lane: str) -> str:
    lane = (raw_lane or "cron").strip().lower()
    if not lane:
        return "cron"
    if not re.fullmatch(r"[a-z0-9_-]{1,32}", lane):
        return "cron"
    return lane


def _compute_next_run_at_time(run_at_time: str) -> datetime:
    """Compute next UTC datetime for a 'HH:MM' daily schedule."""
    parts = run_at_time.strip().split(":")
    hour = int(parts[0])
    minute = int(parts[1]) if len(parts) > 1 else 0
    now = datetime.now(timezone.utc)
    today_target = now.replace(hour=hour, minute=minute, second=0, microsecond=0)
    if today_target <= now:
        return today_target + timedelta(days=1)
    return today_target


def tool_schedule_job(owner_id: int | None, name: str, message: str, interval_seconds: int = 300, lane: str = "cron", run_at_time: str | None = None) -> dict:
    if not owner_id or int(owner_id) <= 0:
        return {"ok": False, "error": "Owner context missing for schedule_job."}
    name = (name or "").strip()
    message = (message or "").strip()
    if not name or not message:
        return {"ok": False, "error": "Both name and message are required."}

    lane = _normalize_schedule_lane(lane)
    now = datetime.now(timezone.utc)

    # Clock-time scheduling: run_at_time="HH:MM" (UTC) for daily jobs
    stored_run_at_time = None
    if run_at_time and run_at_time.strip():
        run_at_time = run_at_time.strip()
        if not re.match(r"^\d{1,2}:\d{2}$", run_at_time):
            return {"ok": False, "error": "run_at_time must be 'HH:MM' format (UTC time)"}
        stored_run_at_time = run_at_time
        interval_seconds = 86400  # daily
        next_run = _compute_next_run_at_time(run_at_time)
    else:
        interval_seconds = clamp_int(interval_seconds, CRON_MIN_INTERVAL_SECONDS, 604800, 300)
        next_run = now + timedelta(seconds=interval_seconds)

    db = SessionLocal()
    try:
        row = ScheduledJob(
            owner_id=int(owner_id),
            name=truncate_text(name, 120),
            message=truncate_text(message, 4000),
            lane=lane,
            interval_seconds=interval_seconds,
            enabled=1,
            run_at_time=stored_run_at_time,
            next_run_at=next_run,
            run_count=0,
        )
        db.add(row)
        db.commit()
        db.refresh(row)
        return {
            "ok": True,
            "job_id": row.id,
            "name": row.name,
            "interval_seconds": row.interval_seconds,
            "run_at_time": row.run_at_time,
            "next_run_at": row.next_run_at.isoformat() if row.next_run_at else None,
            "lane": row.lane,
        }
    except Exception as e:
        db.rollback()
        return {"ok": False, "error": str(e)}
    finally:
        db.close()


def tool_list_scheduled_jobs(owner_id: int | None, include_disabled: bool = False, limit: int = 20) -> dict:
    if not owner_id or int(owner_id) <= 0:
        return {"ok": False, "error": "Owner context missing for list_scheduled_jobs."}
    limit = clamp_int(limit, 1, 100, 20)
    db = SessionLocal()
    try:
        q = db.query(ScheduledJob).filter(ScheduledJob.owner_id == int(owner_id))
        if not include_disabled:
            q = q.filter(ScheduledJob.enabled == 1)
        rows = q.order_by(ScheduledJob.id.desc()).limit(limit).all()
        jobs = []
        for row in rows:
            jobs.append({
                "job_id": row.id,
                "name": row.name,
                "message": truncate_text(row.message, 300),
                "lane": row.lane,
                "interval_seconds": row.interval_seconds,
                "enabled": bool(row.enabled),
                "run_count": int(row.run_count or 0),
                "next_run_at": row.next_run_at.isoformat() if row.next_run_at else None,
                "last_run_at": row.last_run_at.isoformat() if row.last_run_at else None,
                "last_error": row.last_error,
            })
        return {"ok": True, "jobs": jobs}
    except Exception as e:
        return {"ok": False, "error": str(e)}
    finally:
        db.close()


def tool_disable_scheduled_job(owner_id: int | None, job_id: int) -> dict:
    if not owner_id or int(owner_id) <= 0:
        return {"ok": False, "error": "Owner context missing for disable_scheduled_job."}
    job_id = clamp_int(job_id, 1, 10**9, 0)
    if job_id <= 0:
        return {"ok": False, "error": "Valid job_id is required."}
    db = SessionLocal()
    try:
        row = (
            db.query(ScheduledJob)
            .filter(ScheduledJob.id == job_id, ScheduledJob.owner_id == int(owner_id))
            .first()
        )
        if not row:
            return {"ok": False, "error": f"Job #{job_id} not found."}
        row.enabled = 0
        db.commit()
        return {"ok": True, "job_id": row.id, "enabled": False}
    except Exception as e:
        db.rollback()
        return {"ok": False, "error": str(e)}
    finally:
        db.close()


def _resolve_owner_runtime_context(db: Session, owner_id: int) -> tuple[User | None, User | None, str, str, str]:
    owner = db.query(User).filter(User.id == int(owner_id)).first()
    if owner is None:
        return None, None, "", "", TEAM_AGENT_DEFAULT_KEY
    root_owner_id = resolve_root_owner_id(db, int(owner_id))
    root_owner = db.query(User).filter(User.id == int(root_owner_id)).first() or owner
    root_chat_id = str(root_owner.telegram_chat_id or f"user_{root_owner.id}")
    root_username = str(root_owner.username or f"user_{root_owner.id}")
    row = (
        db.query(TeamAgent)
        .filter(TeamAgent.agent_owner_id == int(owner_id))
        .order_by(TeamAgent.id.desc())
        .first()
    )
    caller_key = str(row.agent_key or TEAM_AGENT_DEFAULT_KEY).strip().lower() if row else TEAM_AGENT_DEFAULT_KEY
    return owner, root_owner, root_chat_id, root_username, caller_key


def team_spawn_policy_allows(caller_key: str, target_key: str) -> bool:
    caller = normalize_agent_key(caller_key)
    target = normalize_agent_key(target_key)
    if target == TEAM_AGENT_DEFAULT_KEY:
        return False
    if TEAM_AGENT_SPAWN_POLICY == "allow_all":
        return True
    if TEAM_AGENT_SPAWN_POLICY == "main_only":
        return caller == TEAM_AGENT_DEFAULT_KEY
    matrix = TEAM_AGENT_SPAWN_MATRIX
    if not matrix:
        return caller == TEAM_AGENT_DEFAULT_KEY
    direct = f"{caller}>{target}"
    wildcard_target = f"{caller}>*"
    wildcard_caller = f"*>{target}"
    wildcard_all = "*>*"
    return direct in matrix or wildcard_target in matrix or wildcard_caller in matrix or wildcard_all in matrix


def tool_sessions_spawn(owner_id: int | None, agent_key: str, display_name: str | None = None) -> dict:
    if not owner_id or int(owner_id) <= 0:
        return {"ok": False, "error": "Owner context missing for sessions_spawn."}
    db = SessionLocal()
    try:
        owner, root_owner, _, _, caller_key = _resolve_owner_runtime_context(db, int(owner_id))
        if owner is None or root_owner is None:
            return {"ok": False, "error": "Owner not found."}
        key = normalize_agent_key(agent_key)
        if key == TEAM_AGENT_DEFAULT_KEY:
            return {"ok": False, "error": f"'{TEAM_AGENT_DEFAULT_KEY}' is reserved."}
        if not team_spawn_policy_allows(caller_key, key):
            return {"ok": False, "error": f"Spawn policy blocked caller '{caller_key}' -> '{key}'."}
        user = _ensure_team_agent_owner(db, root_owner, key, display_name=display_name)
        row, _ = get_team_agent_with_user(db, int(root_owner.id), key)
        if row is None:
            return {"ok": False, "error": "Failed to create subagent session."}
        row.status = "active"
        row.last_seen_at = datetime.utcnow()
        if display_name:
            row.display_name = truncate_text(str(display_name), 80)
        db.commit()
        return {"ok": True, "agent": serialize_team_agent(row, user)}
    except Exception as e:
        db.rollback()
        return {"ok": False, "error": truncate_text(str(e), 220)}
    finally:
        db.close()


def tool_sessions_send(
    owner_id: int | None,
    agent_key: str,
    message: str,
    expect_response: bool = True,
) -> dict:
    if not owner_id or int(owner_id) <= 0:
        return {"ok": False, "error": "Owner context missing for sessions_send."}
    text = truncate_text(str(message or "").strip(), 6000)
    if not text:
        return {"ok": False, "error": "message is required."}
    db = SessionLocal()
    try:
        _, _, root_chat_id, root_username, _ = _resolve_owner_runtime_context(db, int(owner_id))
        _, agent_user, _, _ = resolve_team_agent_owner_for_request(
            db=db,
            chat_id=root_chat_id,
            username=root_username,
            agent_key=agent_key,
            create_if_missing=False,
            require_active=True,
        )
        agent_owner_id = int(agent_user.id)
    except Exception as e:
        return {"ok": False, "error": truncate_text(str(e), 220)}
    finally:
        db.close()

    if expect_response:
        response = run_agent_loop_serialized(agent_owner_id, text)
        return {"ok": True, "agent_key": normalize_agent_key(agent_key), "owner_id": agent_owner_id, "response": response}

    def _run_background():
        try:
            run_agent_loop_serialized(agent_owner_id, text)
        except Exception:
            return

    threading.Thread(target=_run_background, daemon=True).start()
    return {"ok": True, "queued": True, "agent_key": normalize_agent_key(agent_key), "owner_id": agent_owner_id}


def tool_sessions_list(owner_id: int | None, include_stopped: bool = True) -> dict:
    if not owner_id or int(owner_id) <= 0:
        return {"ok": False, "error": "Owner context missing for sessions_list."}
