def _hash_file_sha256(path: Path) -> str:
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(65536), b""):
            h.update(chunk)
    return h.hexdigest()


def _json_type_matches(value, expected_type: str) -> bool:
    t = str(expected_type or "").strip().lower()
    if t == "string":
        return isinstance(value, str)
    if t == "integer":
        return isinstance(value, int) and not isinstance(value, bool)
    if t == "number":
        return (isinstance(value, int) and not isinstance(value, bool)) or isinstance(value, float)
    if t == "boolean":
        return isinstance(value, bool)
    if t == "array":
        return isinstance(value, list)
    if t == "object":
        return isinstance(value, dict)
    if t in {"", "any"}:
        return True
    return True


def validate_object_schema_payload(payload: dict, schema: dict) -> tuple[bool, str]:
    if not isinstance(payload, dict):
        return False, "Payload must be a JSON object."
    schema_obj = schema if isinstance(schema, dict) else {}
    properties = schema_obj.get("properties")
    required = schema_obj.get("required")
    additional = schema_obj.get("additionalProperties")
    if not isinstance(properties, dict):
        properties = {}
    if not isinstance(required, list):
        required = []

    for key in required:
        k = str(key or "").strip()
        if k and k not in payload:
            return False, f"Missing required field '{k}'."

    for key, value in payload.items():
        spec = properties.get(key)
        if spec is None:
            if additional is False:
                return False, f"Field '{key}' is not allowed by plugin schema."
            continue
        if not isinstance(spec, dict):
            continue
        expected_type = str(spec.get("type") or "").strip().lower()
        if expected_type and not _json_type_matches(value, expected_type):
            return False, f"Field '{key}' must be of type '{expected_type}'."
    return True, ""


def _validate_plugin_parameters_schema(schema: dict) -> tuple[bool, str]:
    if not isinstance(schema, dict):
        return False, "parameters must be a JSON object."
    if str(schema.get("type") or "").strip().lower() != "object":
        return False, "parameters.type must be 'object'."
    properties = schema.get("properties")
    if properties is None:
        return False, "parameters.properties is required."
    if not isinstance(properties, dict):
        return False, "parameters.properties must be an object."
    required = schema.get("required")
    if required is not None and not isinstance(required, list):
        return False, "parameters.required must be an array."
    if isinstance(required, list):
        for raw in required:
            key = str(raw or "").strip()
            if key and key not in properties:
                return False, f"required field '{key}' is missing from properties."
    for key, item in properties.items():
        if not isinstance(item, dict):
            return False, f"property '{key}' must be an object schema."
        prop_type = str(item.get("type") or "").strip().lower()
        if prop_type and prop_type not in {"string", "integer", "number", "boolean", "array", "object"}:
            return False, f"property '{key}' has unsupported type '{prop_type}'."
    return True, ""


def _plugin_allowed_by_policy(plugin_id: str, manifest: dict, digest: str) -> tuple[bool, str]:
    pid = (plugin_id or "").strip().lower()
    if PLUGIN_ALLOWLIST and pid not in PLUGIN_ALLOWLIST:
        return False, "not_in_allowlist"

    pinned_version = PLUGIN_PINNED_VERSIONS.get(pid)
    manifest_version = str(manifest.get("version") or "").strip()
    if pinned_version and manifest_version != pinned_version:
        return False, "version_mismatch"

    trusted_hash = PLUGIN_TRUSTED_HASHES.get(pid)
    if trusted_hash and digest.lower() != trusted_hash.lower():
        return False, "sha256_mismatch"
    if PLUGIN_ENFORCE_TRUST and (not trusted_hash):
        return False, "missing_trusted_hash"
    return True, ""


def load_plugin_tools_registry() -> dict[str, dict]:
    with PLUGIN_LOCK:
        PLUGIN_TOOL_REGISTRY.clear()
        blocked = 0
        if not PLUGIN_ENABLE_DYNAMIC_TOOLS:
            RUNTIME_STATE["plugin_tools_loaded"] = 0
            RUNTIME_STATE["plugin_tools_blocked"] = 0
            return {}

        try:
            PLUGIN_DIR.mkdir(parents=True, exist_ok=True)
        except Exception as e:
            log.warning("PLUGIN_DIR_INIT_FAIL path=%s error=%s", PLUGIN_DIR, str(e)[:220])
            RUNTIME_STATE["plugin_tools_loaded"] = 0
            RUNTIME_STATE["plugin_tools_blocked"] = 1
            return {}

        for manifest_path in sorted(PLUGIN_DIR.glob("*.json")):
            try:
                if manifest_path.stat().st_size > PLUGIN_MAX_MANIFEST_BYTES:
                    blocked += 1
                    log.warning("PLUGIN_SKIP file=%s reason=manifest_too_large", manifest_path)
                    continue
                digest = _hash_file_sha256(manifest_path)
                manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
                if not isinstance(manifest, dict):
                    blocked += 1
                    continue
                plugin_id = str(manifest.get("id") or "").strip().lower()
                tool_name = str(manifest.get("tool_name") or "").strip()
                if not plugin_id or not tool_name:
                    blocked += 1
                    continue
                if not tool_name.startswith("plugin__"):
                    blocked += 1
                    log.warning("PLUGIN_SKIP id=%s reason=tool_name_prefix_required", plugin_id)
                    continue
                allowed, reason = _plugin_allowed_by_policy(plugin_id, manifest, digest)
                if not allowed:
                    blocked += 1
                    log.warning("PLUGIN_SKIP id=%s reason=%s", plugin_id, reason)
                    continue

                params_schema = manifest.get("parameters")
                if not isinstance(params_schema, dict):
                    params_schema = {"type": "object", "properties": {}}
                valid_schema, schema_error = _validate_plugin_parameters_schema(params_schema)
                if not valid_schema:
                    blocked += 1
                    log.warning("PLUGIN_SKIP id=%s reason=invalid_schema detail=%s", plugin_id, truncate_text(schema_error, 220))
                    continue

                PLUGIN_TOOL_REGISTRY[tool_name] = {
                    "id": plugin_id,
                    "name": str(manifest.get("name") or plugin_id),
                    "version": str(manifest.get("version") or "0.0.0"),
                    "tool_name": tool_name,
                    "description": str(manifest.get("description") or f"Plugin tool: {plugin_id}"),
                    "type": str(manifest.get("type") or "http_request"),
                    "method": str(manifest.get("method") or "POST").upper(),
                    "url": str(manifest.get("url") or "").strip(),
                    "headers": _safe_json_dict(manifest.get("headers"), {}),
                    "timeout_sec": clamp_int(manifest.get("timeout_sec"), 2, 300, 30),
                    "forward_args": bool(manifest.get("forward_args", True)),
                    "safe_mode": bool(manifest.get("safe_mode", False)),
                    "parameters_schema": params_schema,
                    "sha256": digest,
                    "manifest_path": str(manifest_path),
                }
            except Exception as e:
                blocked += 1
                log.warning("PLUGIN_SKIP file=%s reason=%s", manifest_path, str(e)[:220])

        RUNTIME_STATE["plugin_tools_loaded"] = len(PLUGIN_TOOL_REGISTRY)
        RUNTIME_STATE["plugin_tools_blocked"] = blocked
        return dict(PLUGIN_TOOL_REGISTRY)


def plugin_tool_definitions() -> list[dict]:
    defs = []
    for tool_name, meta in sorted(PLUGIN_TOOL_REGISTRY.items(), key=lambda x: x[0]):
        params_schema = meta.get("parameters_schema")
        if not isinstance(params_schema, dict) or str(params_schema.get("type", "object")) != "object":
            params_schema = {"type": "object", "properties": {}}
        defs.append({
            "type": "function",
            "function": {
                "name": tool_name,
                "description": meta.get("description", f"Plugin tool {tool_name}"),
                "parameters": params_schema,
            },
        })
    return defs


def tool_list_plugin_tools() -> dict:
    tools = []
    for tool_name, meta in sorted(PLUGIN_TOOL_REGISTRY.items(), key=lambda x: x[0]):
        tools.append({
            "tool_name": tool_name,
            "id": meta.get("id"),
            "name": meta.get("name"),
            "version": meta.get("version"),
            "type": meta.get("type"),
            "safe_mode": bool(meta.get("safe_mode", False)),
            "sha256": meta.get("sha256"),
        })
    return {"ok": True, "count": len(tools), "tools": tools}


def execute_plugin_tool(tool_name: str, args: dict) -> dict:
    meta = PLUGIN_TOOL_REGISTRY.get(tool_name)
    if not meta:
        return {"ok": False, "error": f"Plugin tool not found: {tool_name}"}

    plugin_type = str(meta.get("type") or "http_request")
    if plugin_type != "http_request":
        return {"ok": False, "error": f"Unsupported plugin type: {plugin_type}"}

    url = str(meta.get("url") or "").strip()
    if not url:
        return {"ok": False, "error": f"Plugin {meta.get('id')} missing url."}
    safe_ok, safe_reason = apply_url_safety_guard(url, source=f"plugin:{meta.get('id')}")
    if not safe_ok:
        return {"ok": False, "error": safe_reason, "plugin_id": meta.get("id")}
    method = str(meta.get("method") or "POST").upper()
    timeout = clamp_int(meta.get("timeout_sec"), 2, 300, 30)
    headers = dict(meta.get("headers") or {})
    schema_ok, schema_error = validate_object_schema_payload(_safe_json_dict(args, {}), _safe_json_dict(meta.get("parameters_schema"), {}))
    if not schema_ok:
        return {"ok": False, "error": f"Plugin args validation failed: {schema_error}", "plugin_id": meta.get("id")}

    allowed, reason = circuit_allow_call("web_fetch")
    if not allowed:
        return {"ok": False, "error": reason}

    try:
        if method == "GET":
            response = REQUESTS_SESSION.get(url, params=args if bool(meta.get("forward_args", True)) else None, headers=headers, timeout=timeout)
        else:
            payload = args if bool(meta.get("forward_args", True)) else {}
            response = REQUESTS_SESSION.post(url, json=payload, headers=headers, timeout=timeout)
        status_code = int(response.status_code)
        if status_code >= 400:
            circuit_record_failure("web_fetch", f"plugin {meta.get('id')} status={status_code}")
            return {"ok": False, "error": f"Plugin HTTP {status_code}", "status_code": status_code}
        circuit_record_success("web_fetch")
        try:
            body = response.json()
        except Exception:
            body = {"text": truncate_text(response.text or "", 12000)}
        return {"ok": True, "plugin_id": meta.get("id"), "status_code": status_code, "result": body}
    except Exception as e:
        circuit_record_failure("web_fetch", f"plugin {meta.get('id')} error={str(e)[:160]}")
        return {"ok": False, "error": str(e), "plugin_id": meta.get("id")}


# ---------------------------------------------------------------------------
# CUSTOM (SELF-GENERATED) TOOL SYSTEM
# ---------------------------------------------------------------------------

def _custom_tool_code_safety_check(code: str) -> tuple[bool, str]:
    """Validate custom tool code for safety. Returns (ok, reason)."""
    if not code or not code.strip():
        return False, "Empty code"
    if len(code) > CUSTOM_TOOL_MAX_CODE_SIZE and not custom_tool_trust_full():
        return False, f"Code exceeds max size ({len(code)} > {CUSTOM_TOOL_MAX_CODE_SIZE})"
    try:
        tree = ast.parse(code)
    except SyntaxError as e:
        return False, f"Syntax error: {e}"
    if not custom_tool_trust_full():
        for node in ast.walk(tree):
            if isinstance(node, ast.Import):
                for alias in node.names:
                    mod = str(alias.name).split(".")[0]
                    if mod in CUSTOM_TOOL_FORBIDDEN_IMPORTS:
                        return False, f"Forbidden import: {mod}"
            elif isinstance(node, ast.ImportFrom):
                if node.module:
                    mod = str(node.module).split(".")[0]
                    if mod in CUSTOM_TOOL_FORBIDDEN_IMPORTS:
                        return False, f"Forbidden import: {mod}"
        for pattern in CUSTOM_TOOL_FORBIDDEN_PATTERNS:
            if re.search(pattern, code):
                return False, f"Forbidden pattern detected: {pattern}"
    has_tool_main = False
    for node in ast.walk(tree):
        if isinstance(node, ast.FunctionDef) and node.name == "tool_main":
            has_tool_main = True
            break
    if not has_tool_main:
        return False, "Code must define a 'def tool_main(args: dict) -> dict:' function"
    return True, "ok"


def _create_custom_tool_executor(code: str) -> callable:
    """Compile custom tool code and extract tool_main function."""
    if custom_tool_trust_full():
        namespace = {"__builtins__": builtins.__dict__}
        exec(code, namespace)
        func = namespace.get("tool_main")
        if not callable(func):
            raise ValueError("tool_main is not callable after exec")
        return func

    namespace = {
        "__builtins__": {
            k: getattr(builtins, k)
            for k in [
                "abs", "all", "any", "bool", "bytes", "chr", "dict", "dir",
                "divmod", "enumerate", "filter", "float", "format", "frozenset",
                "getattr", "hasattr", "hash", "hex", "id", "int", "isinstance",
                "issubclass", "iter", "len", "list", "map", "max", "min", "next",
                "oct", "ord", "pow", "print", "range", "repr", "reversed",
                "round", "set", "slice", "sorted", "str", "sum", "tuple",
                "type", "zip", "True", "False", "None", "ValueError",
                "TypeError", "KeyError", "IndexError", "RuntimeError",
                "Exception", "StopIteration", "AttributeError",
            ]
            if hasattr(builtins, k)
        },
    }
    safe_modules = {
        "math": __import__("math"),
        "json": __import__("json"),
        "re": __import__("re"),
        "datetime": __import__("datetime"),
        "hashlib": __import__("hashlib"),
        "base64": __import__("base64"),
        "urllib.parse": __import__("urllib.parse"),
        "collections": __import__("collections"),
        "itertools": __import__("itertools"),
        "functools": __import__("functools"),
        "string": __import__("string"),
        "textwrap": __import__("textwrap"),
        "csv": __import__("csv"),
        "io": __import__("io"),
        "statistics": __import__("statistics"),
    }
    namespace.update(safe_modules)
    exec(code, namespace)
    func = namespace.get("tool_main")
    if not callable(func):
        raise ValueError("tool_main is not callable after exec")
    return func


def register_custom_tool(owner_id: int, tool_name: str, description: str,
                         parameters_json: str, code: str,
                         requirements: str | None = None) -> dict:
    """Validate, test, persist, and register a custom tool."""
    tool_name = str(tool_name).strip().lower()
    if not re.match(r"^[a-z][a-z0-9_]{2,40}$", tool_name):
        return {"ok": False, "error": "Tool name must be 3-41 chars, lowercase alphanumeric+underscore, start with letter"}
    if tool_name in TOOL_DISPATCH or tool_name in PLUGIN_TOOL_REGISTRY:
        return {"ok": False, "error": f"Tool name '{tool_name}' conflicts with a built-in or plugin tool"}
    safe, reason = _custom_tool_code_safety_check(code)
    if not safe:
        return {"ok": False, "error": f"Safety check failed: {reason}"}
    db = SessionLocal()
    try:
        existing_count = db.query(GeneratedTool).filter(
            GeneratedTool.owner_id == int(owner_id),
            GeneratedTool.enabled == 1,
        ).count()
        if existing_count >= CUSTOM_TOOL_MAX_PER_USER and not custom_tool_trust_full():
            return {"ok": False, "error": f"Max custom tools per user reached ({CUSTOM_TOOL_MAX_PER_USER})"}
        if requirements and requirements.strip():
            try:
                req_list = [r.strip() for r in requirements.split(",") if r.strip()]
                if req_list:
                    result = subprocess.run(
                        ["pip", "install"] + req_list,
                        capture_output=True, text=True, timeout=60,
                    )
                    if result.returncode != 0:
                        return {"ok": False, "error": f"pip install failed: {result.stderr[:300]}"}
            except Exception as e:
                return {"ok": False, "error": f"Failed to install requirements: {str(e)[:200]}"}
        test_code = code + "\n\n# Self-test\n_test_result = tool_main({})\nprint('TOOL_TEST_OK:', type(_test_result).__name__)"
        test_result = tool_execute_python(test_code, timeout=CUSTOM_TOOL_SANDBOX_TIMEOUT)
        test_out = str(test_result.get("stdout", ""))
        test_err = str(test_result.get("stderr", ""))
        if "TOOL_TEST_OK:" not in test_out:
            return {"ok": False, "error": f"Sandbox test failed. stdout={test_out[:300]} stderr={test_err[:300]}"}
        try:
            func = _create_custom_tool_executor(code)
        except Exception as e:
            return {"ok": False, "error": f"Failed to create executor: {str(e)[:200]}"}
        try:
            params = json.loads(parameters_json) if parameters_json else {"type": "object", "properties": {}}
        except json.JSONDecodeError:
            params = {"type": "object", "properties": {}}
        existing = db.query(GeneratedTool).filter(GeneratedTool.tool_name == tool_name).first()
        if existing:
            existing.description = description
            existing.parameters_json = json.dumps(params)
            existing.code = code
            existing.requirements = requirements
            existing.enabled = 1
            existing.test_passed = 1
            existing.last_error = None
        else:
            existing = GeneratedTool(
                owner_id=int(owner_id),
                tool_name=tool_name,
                description=description,
                parameters_json=json.dumps(params),
                code=code,
                requirements=requirements,
                enabled=1,
                test_passed=1,
            )
            db.add(existing)
        db.commit()
        CUSTOM_TOOL_REGISTRY[tool_name] = {
            "func": func,
            "definition": {
                "type": "function",
                "function": {
                    "name": tool_name,
                    "description": description,
                    "parameters": params,
                },
            },
            "owner_id": int(owner_id),
            "created_at": datetime.utcnow().isoformat(),
        }
        RUNTIME_STATE["custom_tools_created"] = int(RUNTIME_STATE.get("custom_tools_created", 0)) + 1
        log.info("CUSTOM_TOOL_REGISTERED name=%s owner=%d", tool_name, int(owner_id))
        return {"ok": True, "tool_name": tool_name, "message": f"Tool '{tool_name}' created and registered successfully"}
    finally:
        db.close()


def load_custom_tools_from_db():
    """Load all enabled, tested custom tools from DB into CUSTOM_TOOL_REGISTRY."""
    if not CUSTOM_TOOL_ENABLED:
        return
    db = SessionLocal()
    try:
        tools = db.query(GeneratedTool).filter(
            GeneratedTool.enabled == 1,
            GeneratedTool.test_passed == 1,
        ).all()
        loaded = 0
        for t in tools:
            try:
                func = _create_custom_tool_executor(t.code)
                params = json.loads(t.parameters_json) if t.parameters_json else {"type": "object", "properties": {}}
                CUSTOM_TOOL_REGISTRY[t.tool_name] = {
                    "func": func,
                    "definition": {
                        "type": "function",
                        "function": {
                            "name": t.tool_name,
                            "description": t.description,
                            "parameters": params,
                        },
                    },
                    "owner_id": t.owner_id,
                    "created_at": t.created_at.isoformat() if t.created_at else "",
                }
                loaded += 1
            except Exception as e:
                log.warning("CUSTOM_TOOL_LOAD_FAIL name=%s error=%s", t.tool_name, str(e)[:200])
        RUNTIME_STATE["custom_tools_loaded"] = loaded
        log.info("CUSTOM_TOOLS_LOADED count=%d", loaded)
    finally:
        db.close()


def custom_tool_definitions() -> list[dict]:
    """Return OpenAI function-calling format definitions for all custom tools."""
    return [entry["definition"] for entry in CUSTOM_TOOL_REGISTRY.values()]


def _increment_custom_tool_usage(tool_name: str):
    """Increment usage count for a custom tool in DB."""
    try:
        db = SessionLocal()
        try:
            row = db.query(GeneratedTool).filter(GeneratedTool.tool_name == tool_name).first()
            if row:
                row.usage_count = int(row.usage_count or 0) + 1
                db.commit()
        finally:
            db.close()
    except Exception:
        pass


def _record_custom_tool_error(tool_name: str, error: str):
    """Record error for a custom tool in DB."""
    try:
        db = SessionLocal()
        try:
            row = db.query(GeneratedTool).filter(GeneratedTool.tool_name == tool_name).first()
            if row:
                row.last_error = str(error)[:2000]
                db.commit()
        finally:
            db.close()
    except Exception:
        pass


def tool_create_tool(args: dict) -> dict:
    """Built-in tool: LLM creates a new custom tool."""
    if not CUSTOM_TOOL_ENABLED:
        return {"ok": False, "error": "Custom tool creation is disabled"}
    name = str(args.get("name", "")).strip()
    description = str(args.get("description", "")).strip()
    code = str(args.get("code", "")).strip()
    parameters = str(args.get("parameters", "{}")).strip()
    requirements = args.get("requirements")
    if requirements:
        requirements = str(requirements).strip()
    if not name or not description or not code:
        return {"ok": False, "error": "Missing required fields: name, description, code"}
    owner_id = int(args.get("_owner_id", 0))
    return register_custom_tool(owner_id, name, description, parameters, code, requirements)


def tool_list_custom_tools(args: dict) -> dict:
    """Built-in tool: list all custom tools."""
    tools = []
    db = SessionLocal()
    try:
        rows = db.query(GeneratedTool).order_by(GeneratedTool.tool_name).all()
        for r in rows:
            tools.append({
                "tool_name": r.tool_name,
                "description": r.description[:100],
                "enabled": bool(r.enabled),
                "test_passed": bool(r.test_passed),
                "usage_count": int(r.usage_count or 0),
                "last_error": r.last_error[:100] if r.last_error else None,
                "owner_id": r.owner_id,
            })
    finally:
        db.close()
    in_registry = list(CUSTOM_TOOL_REGISTRY.keys())
    return {"ok": True, "count": len(tools), "tools": tools, "active_in_registry": in_registry}


def tool_disable_custom_tool(args: dict) -> dict:
    """Built-in tool: disable a custom tool."""
    name = str(args.get("name", "")).strip()
    if not name:
        return {"ok": False, "error": "Missing tool name"}
    db = SessionLocal()
    try:
        row = db.query(GeneratedTool).filter(GeneratedTool.tool_name == name).first()
        if not row:
            return {"ok": False, "error": f"Custom tool '{name}' not found"}
        row.enabled = 0
        db.commit()
        CUSTOM_TOOL_REGISTRY.pop(name, None)
        log.info("CUSTOM_TOOL_DISABLED name=%s", name)
        return {"ok": True, "message": f"Tool '{name}' disabled"}
    finally:
        db.close()


def prune_custom_tools():
    """Remove unused custom tools older than 30 days."""
    cutoff = datetime.now(timezone.utc) - timedelta(days=30)
    db = SessionLocal()
    try:
        old_unused = db.query(GeneratedTool).filter(
            GeneratedTool.usage_count == 0,
            GeneratedTool.created_at < cutoff,
        ).all()
        for t in old_unused:
            CUSTOM_TOOL_REGISTRY.pop(t.tool_name, None)
            db.delete(t)
            log.info("CUSTOM_TOOL_PRUNED name=%s", t.tool_name)
        db.commit()
    finally:
        db.close()


