def classify_tool_intent(user_message: str) -> set[str]:
    """Classify which tool categories are relevant to a user message.
    Always includes 'core'. Uses keyword matching only — no LLM call."""
    text = (user_message or "").strip().lower()
    categories: set[str] = {"core"}
    if not text or len(text) < 3:
        return categories
    for category, keywords in _INTENT_KEYWORDS.items():
        if any(kw in text for kw in keywords):
            categories.add(category)
    return categories


def _select_tools_for_intent(
    all_tools: list[dict],
    categories: set[str],
    also_include: set[str] | None = None,
) -> list[dict]:
    """Filter tool definitions to only those in the given categories."""
    allowed = set()
    for cat in categories:
        allowed.update(TOOL_CATEGORIES.get(cat, set()))
    if also_include:
        allowed.update(also_include)
    return [
        t for t in all_tools
        if (t.get("function") or {}).get("name", "") in allowed
    ]


def effective_tool_definitions(
    owner_id: int | None = None,
    user_message: str | None = None,
    also_include: set[str] | None = None,
) -> list[dict]:
    base_defs = list(TOOL_DEFINITIONS)
    if PLUGIN_ENABLE_DYNAMIC_TOOLS:
        base_defs.extend(plugin_tool_definitions())
    if CUSTOM_TOOL_ENABLED and CUSTOM_TOOL_REGISTRY:
        base_defs.extend(custom_tool_definitions())
    # Skip desktop/session tools when desktop control is disabled entirely.
    if not DESKTOP_CONTROL_ENABLED:
        _skip = {"desktop_", "sessions_"}
        base_defs = [
            t for t in base_defs
            if not any(str((t.get("function") or {}).get("name", "")).startswith(p) for p in _skip)
        ]
    # Closed Loop 1+6: Filter/warn/reorder tools by performance
    base_defs = cl_filter_tools_by_performance(base_defs, owner_id)
    # OpenClaw-style intent filtering — only send relevant tools
    if user_message is not None:
        categories = classify_tool_intent(user_message)
        base_defs = _select_tools_for_intent(base_defs, categories, also_include)
        RUNTIME_STATE["tools_intent_categories"] = ",".join(sorted(categories))
        RUNTIME_STATE["tools_intent_filtered_count"] = len(base_defs)
    return base_defs


