# ============================================================================
# SECTION 4: IDENTITY LOADER
# ============================================================================

def load_identity(db: Session, owner_id: int) -> dict:
    """Load the IdentityKernel for a user. Returns a dict or None."""
    kernel = db.query(IdentityKernel).filter(IdentityKernel.owner_id == owner_id).first()
    if not kernel:
        return None
    return {
        "agent_uuid": kernel.agent_uuid,
        "origin_statement": kernel.origin_statement,
        "core_values": kernel.core_values,
        "authority_bounds": kernel.authority_bounds,
    }


# ============================================================================
# SELF-REFLECTION ENGINE (AGI Pillar â€” Learning)
# After each conversation, the agent reflects on what happened and stores
# lessons learned. Before new conversations, relevant lessons are retrieved
# and injected into the system prompt so the agent improves over time.
# ============================================================================

REFLECTION_PROMPT = (
    "You just finished a conversation. Reflect briefly on what happened.\n"
    "Extract 0-2 lessons worth remembering for future conversations.\n"
    "A lesson is worth saving ONLY if it's a reusable insight â€” NOT trivial observations.\n"
    "Examples of good lessons:\n"
    '- "When the user asks about X, they usually want Y approach"\n'
    '- "Tool Z fails when given input like W â€” use alternative approach"\n'
    '- "This user prefers detailed explanations over brief answers"\n'
    "Examples of NOT worth saving:\n"
    '- "The user said hello" (trivial)\n'
    '- "I searched the web" (obvious action)\n'
    "\n"
    "Respond in JSON format ONLY:\n"
    '{"lessons": [{"lesson": "...", "context": "..."}, ...], "reflection": "one sentence summary"}\n'
    "If nothing worth learning, return: {\"lessons\": [], \"reflection\": \"routine interaction\"}\n"
)

REFLECTION_MIN_MESSAGES = 3  # Don't reflect on very short exchanges (e.g., "hi"/"hello")
REFLECTION_COOLDOWN_SECONDS = 120  # Don't reflect more than once every 2 minutes per user

# --- Pillar 1: In-Loop Reflection ---
INLOOP_REFLECTION_ENABLED = _env_flag("INLOOP_REFLECTION_ENABLED", True)
INLOOP_REFLECTION_EVERY_N = max(2, min(5, _env_int("INLOOP_REFLECTION_EVERY_N", 3)))
INLOOP_REFLECTION_PROMPT = (
    "[INTERNAL REFLECTION] Before proceeding, briefly evaluate:\n"
    "1. Are the tool results so far moving toward the user's goal?\n"
    "2. Have any tool calls failed or returned unexpected results?\n"
    "3. Should I change my approach or continue the current strategy?\n"
    "Think in 2-3 sentences, then proceed with your next action."
)

# --- Pillar 4: Task Lesson Extraction ---
TASK_LESSON_EXTRACTION_ENABLED = _env_flag("TASK_LESSON_EXTRACTION_ENABLED", True)
SELF_IMPROVE_LLM_ANALYSIS_ENABLED = _env_flag("SELF_IMPROVE_LLM_ANALYSIS_ENABLED", True)
SELF_IMPROVE_LLM_ANALYSIS_COOLDOWN_HOURS = max(1, min(48, _env_int("SELF_IMPROVE_LLM_ANALYSIS_COOLDOWN_HOURS", 6)))
_self_improve_llm_last_time: dict[int, float] = {}

TASK_REFLECTION_PROMPT = (
    "You just completed (or failed) a task. Reflect on the execution.\n"
    "Extract 0-3 lessons worth remembering for future tasks.\n"
    "Focus on:\n"
    "- What strategies worked well?\n"
    "- What failed and why?\n"
    "- What tool combinations were effective?\n"
    "- What should be done differently next time for similar goals?\n"
    "\n"
    "Respond in JSON format ONLY:\n"
    '{"lessons": [{"lesson": "...", "context": "..."}, ...], "reflection": "one sentence summary"}\n'
    "If nothing worth learning, return: {\"lessons\": [], \"reflection\": \"routine task\"}\n"
)
# Pillar 3: Autonomy — Multi-Day Goal System
GOAL_SYSTEM_ENABLED = _env_flag("GOAL_SYSTEM_ENABLED", True)
