_reflection_last_time: dict[int, float] = {}  # owner_id -> last reflection timestamp
COMPACTION_SUMMARY_PROMPT = (
    "You are compacting old conversation history into episodic memory. "
    "Preserve durable facts, preferences, commitments, and unresolved tasks. "
    "Do not include fluff or repetitive details. "
    "Return strict JSON only with this schema: "
    "{\"summary\":\"...\",\"key_points\":[\"...\"],\"open_loops\":[\"...\"]}. "
    "Keep summary under 220 words, key_points up to 6, open_loops up to 6."
)


def _should_reflect(owner_id: int, message_count: int) -> bool:
    """Decide if reflection is warranted for this conversation."""
    if message_count < REFLECTION_MIN_MESSAGES:
        return False
    now = time.monotonic()
    last = _reflection_last_time.get(owner_id, 0)
    if now - last < REFLECTION_COOLDOWN_SECONDS:
        return False
    return True


def reflect_on_conversation(db: Session, owner_id: int) -> list[dict]:
    """
    Ask the LLM to reflect on the recent conversation and extract lessons.
    Returns a list of lesson dicts: [{"lesson": "...", "context": "..."}]
    """
    global _reflection_last_time

    # Load recent messages for context
    history = get_conversation_history(db, owner_id, limit=20)
    if len(history) < REFLECTION_MIN_MESSAGES:
        return []

    # Build reflection request — strip tool_calls and tool messages to avoid
    # Kimi thinking-mode errors ("reasoning_content is missing").
    clean_history = []
    for msg in history[-15:]:
        if msg.get("role") == "tool":
            continue
        if msg.get("tool_call_id"):
            continue
        if msg.get("tool_calls"):
            text = msg.get("content") or ""
            if text:
                clean_history.append({"role": "assistant", "content": text})
            continue
        clean_history.append({"role": msg["role"], "content": msg.get("content", "")})
    messages = [
        {"role": "system", "content": REFLECTION_PROMPT},
    ] + clean_history

    try:
        response = call_llm(
            messages,
            tools=None,
            owner_id=owner_id,
            source_type="reflection",
            source_ref=f"owner:{owner_id}",
        )  # No tools for reflection
        if "error" in response:
            log.warning("REFLECTION_LLM_ERROR: %s", response["error"])
            return []

        content = response["choices"][0]["message"].get("content", "")
        parsed = parse_json_flexible(content)
        if not parsed or not isinstance(parsed, dict):
            log.warning("REFLECTION_PARSE_FAILED: %s", content[:200])
            return []

        lessons = parsed.get("lessons", [])
        reflection = parsed.get("reflection", "")
        log.info("REFLECTION owner=%d lessons=%d summary=%s", owner_id, len(lessons), reflection[:100])

        _reflection_last_time[owner_id] = time.monotonic()
        return [l for l in lessons if isinstance(l, dict) and l.get("lesson")]

    except Exception as exc:
        log.warning("REFLECTION_FAILED: %s", exc)
        return []


MEMORY_STOPWORDS = {
    "a", "an", "the", "and", "or", "but", "if", "then", "else", "for", "with", "to", "from", "into",
    "on", "in", "at", "of", "by", "as", "is", "are", "was", "were", "be", "been", "being", "it",
    "this", "that", "these", "those", "you", "your", "we", "our", "they", "their", "he", "she", "them",
    "his", "her", "i", "me", "my", "mine", "do", "does", "did", "done", "can", "could", "will", "would",
    "should", "may", "might", "must", "about", "over", "under", "than", "very", "more", "most", "some",
    "any", "all", "few", "each", "every", "just", "also", "only", "not", "no", "yes", "via", "per",
}


def _memory_preview_text(value: str, max_len: int = 320) -> str:
    text = re.sub(r"\s+", " ", str(value or "")).strip()
    if len(text) <= max_len:
        return text
    return text[:max_len] + "...[TRUNCATED]"


def _memory_terms(text: str, max_terms: int = 140) -> set[str]:
    raw = re.findall(r"[a-z0-9][a-z0-9_-]{1,31}", str(text or "").lower())
    terms: list[str] = []
    for token in raw:
        if len(token) < 3:
            continue
        if token in MEMORY_STOPWORDS:
            continue
        if token in terms:
            continue
        terms.append(token)
        if len(terms) >= max_terms:
            break
    return set(terms)


def _token_overlap_score(left_terms: set[str], right_terms: set[str]) -> float:
    if not left_terms or not right_terms:
        return 0.0
    inter = len(left_terms.intersection(right_terms))
    denom = max(1, min(len(left_terms), len(right_terms)))
    return max(0.0, min(1.0, inter / float(denom)))


def _coerce_utc(dt_value) -> datetime | None:
    if dt_value is None:
        return None
    if isinstance(dt_value, datetime):
        if dt_value.tzinfo is None:
            return dt_value.replace(tzinfo=timezone.utc)
        return dt_value.astimezone(timezone.utc)
    return None


def _recency_normalized(created_at, fresh_days: float = MEMORY_RECENCY_FRESH_DAYS, stale_days: float = MEMORY_RECENCY_STALE_DAYS) -> float:
    dt = _coerce_utc(created_at)
    if dt is None:
        return 0.5
    age_days = max(0.0, (datetime.now(timezone.utc) - dt).total_seconds() / 86400.0)
    if age_days <= fresh_days:
        return 1.0
    if age_days >= stale_days:
        return 0.0
    span = max(0.001, stale_days - fresh_days)
    return max(0.0, min(1.0, 1.0 - ((age_days - fresh_days) / span)))


def _extract_task_id_hints(text: str) -> set[int]:
    raw = str(text or "")
    task_ids: set[int] = set()
    patterns = [
        r"#(\d{1,9})\b",
        r"\btask(?:_id| id)?\s*#?\s*(\d{1,9})\b",
        r"/task_(?:status|cancel)\s+(\d{1,9})\b",
    ]
    for pattern in patterns:
        for match in re.findall(pattern, raw, flags=re.IGNORECASE):
            try:
                value = int(match)
            except Exception:
                continue
            if 0 < value <= 10**9:
                task_ids.add(value)
    return task_ids


def _format_quality(value: float | None) -> float | None:
    if value is None:
        return None
    return round(max(0.0, min(1.0, float(value))), 3)


def _estimate_lesson_importance(text: str) -> float:
    value = str(text or "").strip()
    lowered = value.lower()
    score = 0.14
    if len(value) >= 70:
        score += 0.10
    if len(value) >= 130:
        score += 0.08
    if re.search(r"\b(always|never|avoid|critical|important|required|must|do not|don't|unless)\b", lowered):
        score += 0.26
    if re.search(r"\b(error|fail|failure|retry|timeout|blocked|approval|permission|token|queue|webhook|database|db|incident)\b", lowered):
        score += 0.22
    if re.search(r"\b(routine|small talk|smalltalk|greeting|hello)\b", lowered):
        score -= 0.10
    return max(0.0, min(1.0, score))


def _estimate_summary_importance(summary: str, key_points: list[str], open_loops: list[str]) -> float:
    score = 0.16
    summary_text = str(summary or "")
    lowered = summary_text.lower()
    score += min(0.20, 0.05 * len(key_points or []))
    score += min(0.30, 0.08 * len(open_loops or []))
    if len(summary_text) >= 120:
        score += 0.08
    if re.search(r"\b(decision|constraint|tradeoff|risk|blocked|failed|fallback|approval|follow-up|next step)\b", lowered):
        score += 0.20
    if re.search(r"\b(hello|thanks|ok|great)\b", lowered):
        score -= 0.06
    return max(0.0, min(1.0, score))


def _estimate_task_artifact_importance(row: TaskArtifact) -> float:
    score = 0.18
    status = str(row.status or "").lower()
    if status == "done":
        score += 0.10
    elif status in {"failed", "blocked"}:
        score += 0.08
    outcome = str(row.outcome_summary or "")
    if len(outcome) >= 120:
        score += 0.10
    tools = _parse_tool_names_json(row.tool_names_json, max_items=8)
    if tools:
        score += min(0.10, 0.02 * len(tools))
    return max(0.0, min(1.0, score))


def build_memory_continuity_context(db: Session, owner_id: int, user_message: str) -> dict:
    task_hint_ids = set(_extract_task_id_hints(user_message))
    user_prompt_text = _memory_preview_text(user_message, max_len=320)

    recent_user_rows = (
        db.query(ConversationMessage)
        .filter(
            ConversationMessage.owner_id == owner_id,
            ConversationMessage.role == "user",
        )
        .order_by(ConversationMessage.id.desc())
        .limit(MEMORY_CONTINUITY_RECENT_MESSAGES)
        .all()
    )

    recent_snippets: list[str] = []
    skipped_current = False
    for row in recent_user_rows:
        snippet = _memory_preview_text(row.content or "", max_len=320)
        if not snippet:
            continue
        if not skipped_current and snippet == user_prompt_text:
            skipped_current = True
            continue
        skipped_current = True
        recent_snippets.append(snippet)
        task_hint_ids.update(_extract_task_id_hints(snippet))

    continuity_parts: list[str] = []
    if recent_snippets:
        continuity_parts.append("Recent user context:")
        continuity_parts.extend(recent_snippets[:MEMORY_CONTINUITY_RECENT_MESSAGES])

    if MEMORY_CONTINUITY_ACTIVE_TASKS > 0:
        active_statuses = [TASK_STATUS_OPEN, TASK_STATUS_QUEUED, TASK_STATUS_RUNNING, TASK_STATUS_BLOCKED]
        active_tasks = (
            db.query(Task)
            .filter(
                Task.owner_id == owner_id,
                Task.status.in_(active_statuses),
            )
            .order_by(Task.id.desc())
            .limit(MEMORY_CONTINUITY_ACTIVE_TASKS)
            .all()
        )
        if active_tasks:
            continuity_parts.append("Active tasks:")
            for row in active_tasks:
                title = _memory_preview_text(row.title or "", max_len=140)
                desc = _memory_preview_text(row.description or "", max_len=180)
                continuity_parts.append(f"task#{int(row.id)} [{row.status}] {title} | {desc}")
                task_hint_ids.add(int(row.id))

    continuity_text = "\n".join(part for part in continuity_parts if part).strip()
    continuity_score = _token_overlap_score(_memory_terms(user_message), _memory_terms(continuity_text))
    return {
        "continuity_text": continuity_text,
        "task_hint_ids": sorted(task_hint_ids),
        "continuity_score": continuity_score,
    }


def store_lesson(db: Session, owner_id: int, lesson: str, context: str = "") -> bool:
    """Store a lesson as a vector memory for future retrieval."""
    try:
        embed_text = f"{lesson} {context}".strip()
        vec = get_embedding(embed_text)
        if np.linalg.norm(vec) < 1e-9:
            return False

        preview = _memory_preview_text(f"{lesson} | {context}" if context else lesson, max_len=200)
        mv = MemoryVector(
            owner_id=owner_id,
            memory_type="lesson",
            ref_id=None,
            text_preview=preview,
            embedding=embedding_to_bytes(vec),
        )
        db.add(mv)
        db.commit()
        log.info("LESSON_STORED owner=%d lesson=%s", owner_id, lesson[:80])
        return True
    except Exception as exc:
        db.rollback()
        log.warning("LESSON_STORE_FAILED: %s", exc)
        return False


def extract_lessons_from_task(db: Session, task, plan: list[dict]) -> list[dict]:
    """Extract lessons from a completed or failed task (Pillar 4: Learning)."""
    if not TASK_LESSON_EXTRACTION_ENABLED:
        return []
    try:
        owner_id = int(task.owner_id)
        task_title = truncate_text(str(task.title or ""), 200)
        task_desc = truncate_text(str(task.description or ""), 400)

        step_summaries = []
        for step in (plan or []):
            status = str(step.get("status", ""))
            title = str(step.get("title", ""))
            error = str(step.get("last_error", ""))
            summary = f"- [{status}] {title}"
            if error and status == "failed":
                summary += f" (error: {truncate_text(error, 120)})"
            step_summaries.append(summary)

        context_text = (
            f"Task: {task_title}\nDescription: {task_desc}\n"
            f"Final status: {task.status}\n"
            f"Steps:\n" + "\n".join(step_summaries[:8])
        )

        messages = [
            {"role": "system", "content": TASK_REFLECTION_PROMPT},
            {"role": "user", "content": context_text},
        ]

        response = call_llm(
            messages=messages,
            tools=None,
            owner_id=owner_id,
            source_type="reflection",
            source_ref=f"task:{task.id}",
        )
        if not response or not response.get("choices"):
            return []

        raw = str(response["choices"][0].get("message", {}).get("content", "") or "").strip()
        parsed = _safe_json_dict(raw, None)
        if parsed is None:
            json_match = re.search(r"\{.*\}", raw, re.DOTALL)
            if json_match:
                parsed = _safe_json_dict(json_match.group(), {})
            else:
                parsed = {}

        lessons = list(parsed.get("lessons") or [])[:3]
        stored = []
        for item in lessons:
            lesson_text = str(item.get("lesson", "")).strip()
            context = str(item.get("context", "")).strip()
            if lesson_text and len(lesson_text) > 10:
                if store_lesson(db, owner_id, lesson_text, context):
                    stored.append(item)

        if stored:
            log.info("TASK_LESSONS_EXTRACTED task_id=%d count=%d", int(task.id), len(stored))

        # Pillar 2: Create episodic memories from each completed/failed step
        if EPISODIC_MEMORY_ENABLED:
            tools_in_task = []
            for step in (plan or []):
                step_status = str(step.get("status", ""))
                step_title = str(step.get("title", ""))
                if step_status in ("done", "failed"):
                    outcome = "success" if step_status == "done" else "failure"
                    store_episodic_memory(
                        db=db,
                        owner_id=owner_id,
                        situation=f"Task '{task_title}': step '{step_title}'",
                        action_taken=step_title,
                        outcome=outcome,
                        outcome_detail=truncate_text(str(step.get("last_error", "")), 200) if step_status == "failed" else None,
                        tools_used=tools_in_task,
                        source_type="task",
                        source_ref=f"task:{task.id}",
                    )

        return stored
    except Exception as exc:
        log.warning("TASK_LESSON_EXTRACTION_FAIL task_id=%s error=%s", str(getattr(task, "id", "?")), truncate_text(str(exc), 220))
        return []


def prune_lesson_overflow(db: Session, owner_id: int) -> int:
    lesson_rows = (
        db.query(MemoryVector)
        .filter(
            MemoryVector.owner_id == owner_id,
            MemoryVector.memory_type == "lesson",
        )
        .all()
    )
    if len(lesson_rows) <= LESSON_MAX_PER_USER:
        return 0

    scored_rows = []
    for row in lesson_rows:
        importance = _estimate_lesson_importance(row.text_preview or "")
        recency = _recency_normalized(
            row.created_at,
            fresh_days=MEMORY_RECENCY_FRESH_DAYS,
            stale_days=max(MEMORY_RECENCY_STALE_DAYS, 365.0),
        )
        retention = (importance * 0.72) + (recency * 0.28)
        scored_rows.append((retention, int(row.id)))

    scored_rows.sort(key=lambda item: (item[0], item[1]), reverse=True)
    prune_ids = [item[1] for item in scored_rows[LESSON_MAX_PER_USER:]]
    if not prune_ids:
        return 0

    try:
        removed = (
            db.query(MemoryVector)
            .filter(
                MemoryVector.owner_id == owner_id,
                MemoryVector.memory_type == "lesson",
                MemoryVector.id.in_(prune_ids),
            )
            .delete(synchronize_session=False)
        )
        db.commit()
    except Exception:
        db.rollback()
        raise

    removed_count = int(removed or 0)
    RUNTIME_STATE["memory_lessons_pruned"] = int(RUNTIME_STATE.get("memory_lessons_pruned", 0)) + removed_count
    log.info(
        "SESSION_PRUNE_LESSON owner=%d removed=%d retained=%d",
        owner_id,
        removed_count,
        LESSON_MAX_PER_USER,
    )
    return removed_count


def retrieve_relevant_lessons(
    owner_id: int,
    user_message: str,
    top_k: int = 3,
    continuity_text: str = "",
) -> list[str]:
    """Find past lessons relevant to the current user message."""
    limit = clamp_int(top_k, 1, 8, 3)
    db = SessionLocal()
    try:
        mem_vectors = (
            db.query(MemoryVector)
            .filter(
                MemoryVector.owner_id == owner_id,
                MemoryVector.memory_type == "lesson",
            )
            .order_by(MemoryVector.id.desc())
            .limit(LESSON_VECTOR_SCAN_LIMIT)
            .all()
        )
        if not mem_vectors:
            RUNTIME_STATE["memory_last_lessons_retrieved"] = 0
            RUNTIME_STATE["memory_last_lesson_quality"] = None
            return []

        query_vec = get_embedding(user_message)
        if np.linalg.norm(query_vec) < 1e-9:
            RUNTIME_STATE["memory_last_lessons_retrieved"] = 0
            RUNTIME_STATE["memory_last_lesson_quality"] = None
            return []

        query_terms = _memory_terms(user_message)
        continuity_terms = _memory_terms(continuity_text)
        scored: list[tuple[float, str]] = []
        for mv in mem_vectors:
            stored_vec = bytes_to_embedding(mv.embedding)
            sim = cosine_similarity(query_vec, stored_vec)
            if sim <= CLOSED_LOOP_LESSON_MATCH_THRESHOLD:
                continue

            preview = _memory_preview_text(mv.text_preview or "", max_len=200)
            if not preview:
                continue
            lesson_terms = _memory_terms(preview)
            overlap = _token_overlap_score(lesson_terms, query_terms)
            continuity_overlap = _token_overlap_score(lesson_terms, continuity_terms)
            importance = _estimate_lesson_importance(preview)
            recency = _recency_normalized(
                mv.created_at,
                fresh_days=MEMORY_RECENCY_FRESH_DAYS,
                stale_days=max(MEMORY_RECENCY_STALE_DAYS, 365.0),
            )
            total = (
                (max(0.0, sim) * 0.58)
                + (overlap * 0.14)
                + (importance * 0.18)
                + (recency * 0.06)
                + (continuity_overlap * 0.04)
            )
            if total >= LESSON_MIN_TOTAL_SCORE:
                scored.append((total, preview))

        if not scored:
            RUNTIME_STATE["memory_last_lessons_retrieved"] = 0
            RUNTIME_STATE["memory_last_lesson_quality"] = None
            return []

        scored.sort(key=lambda item: item[0], reverse=True)
        selected: list[str] = []
        selected_scores: list[float] = []
        for score, text in scored:
            if text in selected:
                continue
            selected.append(text)
            selected_scores.append(score)
            if len(selected) >= limit:
                break

        avg_quality = sum(selected_scores) / len(selected_scores) if selected_scores else None
        RUNTIME_STATE["memory_last_lessons_retrieved"] = len(selected)
        RUNTIME_STATE["memory_last_lesson_quality"] = _format_quality(avg_quality)
        return selected
    except Exception as exc:
        log.warning("LESSON_RETRIEVAL_FAILED: %s", exc)
        RUNTIME_STATE["memory_last_lessons_retrieved"] = 0
        RUNTIME_STATE["memory_last_lesson_quality"] = None
        return []
    finally:
        db.close()


def _normalize_compaction_text(value: str, max_len: int = 480) -> str:
    text = re.sub(r"\s+", " ", (value or "")).strip()
    if not text:
        return ""
    if len(text) > max_len:
        return text[:max_len] + "...[TRUNCATED]"
    return text


def _sanitize_string_list(value, max_items: int = 6, max_len: int = 220) -> list[str]:
    items = value
    if isinstance(items, str):
        items = [items]
    if not isinstance(items, list):
        return []
    cleaned = []
    for raw in items:
        if not isinstance(raw, str):
            continue
        text = _normalize_compaction_text(raw, max_len=max_len)
        if not text:
            continue
        cleaned.append(text)
        if len(cleaned) >= max_items:
            break
    return cleaned


def _extract_tool_signal_for_compaction(raw_content: str) -> str:
    raw = (raw_content or "").strip()
    if not raw:
        return ""
    try:
        parsed = json.loads(raw)
    except Exception:
        return _normalize_compaction_text(raw, max_len=420)

    if not isinstance(parsed, dict):
        return _normalize_compaction_text(json.dumps(parsed, ensure_ascii=False), max_len=420)

    fragments: list[str] = []
    if parsed.get("error"):
        fragments.append(f"error={_normalize_compaction_text(str(parsed.get('error')), max_len=160)}")
    if parsed.get("summary"):
        fragments.append(f"summary={_normalize_compaction_text(str(parsed.get('summary')), max_len=180)}")
    if parsed.get("answer_brief"):
        fragments.append(f"brief={_normalize_compaction_text(str(parsed.get('answer_brief')), max_len=180)}")
    if parsed.get("message"):
        fragments.append(f"message={_normalize_compaction_text(str(parsed.get('message')), max_len=180)}")

    if fragments:
        return " | ".join(fragments)

    compact = {"ok": parsed.get("ok")}
    for key in ("status", "count", "note_id", "pages"):
        if key in parsed:
            compact[key] = parsed.get(key)
    return _normalize_compaction_text(json.dumps(compact, ensure_ascii=False), max_len=220)


def serialize_messages_for_compaction(messages: list[ConversationMessage]) -> str:
    lines: list[str] = []
    for row in messages:
        role = (row.role or "unknown").strip().lower() or "unknown"
        content = (row.content or "").strip()
        if role == "tool":
            content = _extract_tool_signal_for_compaction(content)
        else:
            content = _normalize_compaction_text(content, max_len=480)

        if not content and row.tool_calls_json:
            try:
                calls = json.loads(row.tool_calls_json)
                names = []
                if isinstance(calls, list):
                    for item in calls:
                        fn_name = (
                            (item or {}).get("function", {}).get("name")
                            if isinstance(item, dict)
                            else None
                        )
                        if isinstance(fn_name, str) and fn_name.strip():
                            names.append(fn_name.strip())
                if names:
                    content = f"tool_calls={','.join(names[:4])}"
            except Exception:
                pass

        if not content:
            content = "[no_content]"
        lines.append(f"{role}: {content}")

    serialized = "\n".join(lines)
    if len(serialized) > 18000:
        serialized = serialized[:18000] + "\n...[TRUNCATED]"
    return serialized


def summarize_conversation_chunk(owner_id: int, serialized_chunk: str) -> dict:
    messages = [
        {"role": "system", "content": COMPACTION_SUMMARY_PROMPT},
        {
            "role": "user",
            "content": (
                f"owner_id={owner_id}\n"
                "Compact this conversation chunk:\n"
                f"{serialized_chunk}"
            ),
        },
    ]
    response = call_llm(
        messages,
        tools=None,
        owner_id=owner_id,
        source_type="compaction",
        source_ref=f"owner:{owner_id}",
    )
    if "error" in response:
        raise RuntimeError(f"Compaction LLM error: {response['error']}")

    content = response["choices"][0]["message"].get("content", "")
    parsed = parse_json_flexible(content)
    if not isinstance(parsed, dict):
        raise RuntimeError("Compaction summary parse failed.")

    summary = _normalize_compaction_text(str(parsed.get("summary", "")), max_len=2200)
    if not summary:
        raise RuntimeError("Compaction summary missing summary field.")

    key_points = _sanitize_string_list(parsed.get("key_points"), max_items=6, max_len=220)
    open_loops = _sanitize_string_list(parsed.get("open_loops"), max_items=6, max_len=220)
    return {
        "summary": summary,
        "key_points": key_points,
        "open_loops": open_loops,
    }


def store_conversation_summary(
    db: Session,
    owner_id: int,
    chunk_rows: list[ConversationMessage],
    summary_obj: dict,
) -> ConversationSummary:
    if not chunk_rows:
        raise ValueError("chunk_rows is required")

    summary_text = _normalize_compaction_text(str(summary_obj.get("summary", "")), max_len=2200)
    if not summary_text:
        raise ValueError("summary text is required")

    key_points = _sanitize_string_list(summary_obj.get("key_points"), max_items=6, max_len=220)
    open_loops = _sanitize_string_list(summary_obj.get("open_loops"), max_items=6, max_len=220)

    record = ConversationSummary(
        owner_id=owner_id,
        start_message_id=int(chunk_rows[0].id),
        end_message_id=int(chunk_rows[-1].id),
        summary=summary_text,
        key_points_json=json.dumps(key_points, ensure_ascii=False),
        open_loops_json=json.dumps(open_loops, ensure_ascii=False),
    )
    try:
        db.add(record)
        db.flush()

        embed_text = " ".join([summary_text] + key_points + open_loops).strip()
        vector = get_embedding(embed_text)
        if np.linalg.norm(vector) >= 1e-9:
            db.add(
                MemoryVector(
                    owner_id=owner_id,
                    memory_type="conversation_summary",
                    ref_id=record.id,
                    text_preview=summary_text[:200],
                    embedding=embedding_to_bytes(vector),
                )
            )

        db.commit()
        db.refresh(record)
        return record
    except Exception:
        db.rollback()
        raise


def prune_summary_overflow(db: Session, owner_id: int) -> int:
    summary_rows = (
        db.query(ConversationSummary)
        .filter(ConversationSummary.owner_id == owner_id)
        .all()
    )
    if len(summary_rows) <= SUMMARY_MAX_PER_USER:
        return 0

    scored_rows: list[tuple[float, int]] = []
    for row in summary_rows:
        key_points = _parse_summary_json_list(row.key_points_json, max_items=8, max_len=220)
        open_loops = _parse_summary_json_list(row.open_loops_json, max_items=8, max_len=220)
        importance = _estimate_summary_importance(row.summary or "", key_points, open_loops)
        recency = _recency_normalized(
            row.created_at,
            fresh_days=MEMORY_RECENCY_FRESH_DAYS,
            stale_days=max(MEMORY_RECENCY_STALE_DAYS, 240.0),
        )
        retention = (importance * 0.70) + (recency * 0.30)
        scored_rows.append((retention, int(row.id)))

    scored_rows.sort(key=lambda item: (item[0], item[1]), reverse=True)
    prune_ids = [item[1] for item in scored_rows[SUMMARY_MAX_PER_USER:]]
    if not prune_ids:
        return 0

    try:
        db.query(MemoryVector).filter(
            MemoryVector.owner_id == owner_id,
            MemoryVector.memory_type == "conversation_summary",
            MemoryVector.ref_id.in_(prune_ids),
        ).delete(synchronize_session=False)
        db.query(ConversationSummary).filter(
            ConversationSummary.owner_id == owner_id,
            ConversationSummary.id.in_(prune_ids),
        ).delete(synchronize_session=False)
        db.commit()
    except Exception:
        db.rollback()
        raise

    log.info(
        "SESSION_PRUNE_SUMMARY owner=%d removed=%d retained=%d strategy=importance_recency",
        owner_id,
        len(prune_ids),
        SUMMARY_MAX_PER_USER,
    )
    removed_count = len(prune_ids)
    RUNTIME_STATE["memory_summaries_pruned"] = int(RUNTIME_STATE.get("memory_summaries_pruned", 0)) + removed_count
    return removed_count


def emergency_prune_raw_history(db: Session, owner_id: int) -> int:
    try:
        total = db.query(ConversationMessage).filter(ConversationMessage.owner_id == owner_id).count()
        if total <= RAW_HISTORY_EMERGENCY_CAP:
            return 0
        remove_count = max(0, total - RAW_HISTORY_EMERGENCY_KEEP)
        if remove_count <= 0:
            return 0

        oldest_ids = [
            row[0]
            for row in (
                db.query(ConversationMessage.id)
                .filter(ConversationMessage.owner_id == owner_id)
                .order_by(ConversationMessage.id.asc())
                .limit(remove_count)
                .all()
            )
        ]
        if not oldest_ids:
            return 0

        removed = (
            db.query(ConversationMessage)
            .filter(
                ConversationMessage.owner_id == owner_id,
                ConversationMessage.id.in_(oldest_ids),
            )
            .delete(synchronize_session=False)
        )
        db.commit()
        log.warning(
            "SESSION_PRUNE_EMERGENCY owner=%d removed=%d total_before=%d keep=%d",
            owner_id,
            removed,
            total,
            RAW_HISTORY_EMERGENCY_KEEP,
        )
        return int(removed or 0)
    except Exception as exc:
        db.rollback()
        log.warning("SESSION_PRUNE_EMERGENCY_FAIL owner=%d error=%s", owner_id, exc)
        return 0


def flush_owner_memory_before_compaction(db: Session, owner_id: int) -> bool:
    if not SESSION_MEMORY_FLUSH_BEFORE_COMPACTION:
        return True
    try:
        db.flush()
        db.commit()
        if SESSION_MEMORY_FLUSH_CHECKPOINT:
            try:
                db.execute(sql_text("PRAGMA wal_checkpoint(PASSIVE)"))
                db.commit()
            except Exception:
                db.rollback()
        RUNTIME_STATE["session_memory_flush_count"] = int(RUNTIME_STATE.get("session_memory_flush_count", 0)) + 1
        log.info("SESSION_MEMORY_FLUSH_OK owner=%d", owner_id)
        return True
    except Exception as exc:
        db.rollback()
        RUNTIME_STATE["session_memory_flush_failures"] = int(RUNTIME_STATE.get("session_memory_flush_failures", 0)) + 1
        log.warning("SESSION_MEMORY_FLUSH_FAIL owner=%d error=%s", owner_id, truncate_text(str(exc), 220))
        return False


def compact_and_prune_session_if_needed(db: Session, owner_id: int):
    try:
        total_messages = db.query(ConversationMessage).filter(ConversationMessage.owner_id == owner_id).count()
        if total_messages <= HISTORY_COMPACT_TRIGGER_MESSAGES:
            return
        if not flush_owner_memory_before_compaction(db, owner_id):
            return

        eligible_count = total_messages - HISTORY_RECENT_KEEP_MESSAGES
        if eligible_count < HISTORY_COMPACT_MIN_CHUNK:
            return

        chunk_size = min(HISTORY_COMPACT_MAX_CHUNK, eligible_count)
        if chunk_size < HISTORY_COMPACT_MIN_CHUNK:
            return

        chunk_rows = (
            db.query(ConversationMessage)
            .filter(ConversationMessage.owner_id == owner_id)
            .order_by(ConversationMessage.id.asc())
            .limit(chunk_size)
            .all()
        )
        if len(chunk_rows) < HISTORY_COMPACT_MIN_CHUNK:
            return

        start_id = int(chunk_rows[0].id)
        end_id = int(chunk_rows[-1].id)
        log.info(
            "SESSION_COMPACT_START owner=%d start_id=%d end_id=%d count=%d total=%d",
            owner_id,
            start_id,
            end_id,
            len(chunk_rows),
            total_messages,
        )

        serialized = serialize_messages_for_compaction(chunk_rows)
        summary_obj = summarize_conversation_chunk(owner_id, serialized)
        summary_row = store_conversation_summary(db, owner_id, chunk_rows, summary_obj)

        chunk_ids = [int(row.id) for row in chunk_rows]
        compacted = (
            db.query(ConversationMessage)
            .filter(
                ConversationMessage.owner_id == owner_id,
                ConversationMessage.id.in_(chunk_ids),
            )
            .delete(synchronize_session=False)
        )
        db.commit()

        pruned = prune_summary_overflow(db, owner_id)
        log.info(
            "SESSION_COMPACT_OK owner=%d summary_id=%d compacted=%d pruned_summaries=%d",
            owner_id,
            summary_row.id,
            int(compacted or 0),
            pruned,
        )
    except Exception as exc:
        db.rollback()
        log.warning("SESSION_COMPACT_FAIL owner=%d error=%s", owner_id, exc)
        emergency_prune_raw_history(db, owner_id)


def compact_session_by_char_budget(db: Session, owner_id: int) -> bool:
    """OpenClaw-style char-budget-triggered compaction.

    Instead of waiting for 80+ messages, this checks whether the raw
    conversation history exceeds the soft trim char budget.  When it does,
    the oldest messages are summarised via the LLM (reusing the existing
    compaction pipeline) and deleted from the DB.  The shorter history is
    then loaded for the current LLM call — no destructive hard clear needed.

    Returns True if compaction was performed.
    """
    if not COMPACTION_CHAR_BUDGET_ENABLED:
        return False

    try:
        rows = (
            db.query(ConversationMessage)
            .filter(ConversationMessage.owner_id == owner_id)
            .order_by(ConversationMessage.id.asc())
            .all()
        )
        if len(rows) < COMPACTION_KEEP_RECENT_MIN + HISTORY_COMPACT_MIN_CHUNK:
            return False

        # Calculate total char payload of all stored messages.
        total_chars = 0
        for row in rows:
            total_chars += len(row.content or "")
            if row.tool_calls_json:
                total_chars += len(row.tool_calls_json)
            if row.tool_call_id:
                total_chars += len(row.tool_call_id)

        if total_chars <= SESSION_SOFT_TRIM_CHAR_BUDGET:
            return False

        # Memory flush before compaction
        if not flush_owner_memory_before_compaction(db, owner_id):
            log.warning("COMPACT_BY_CHARS_FLUSH_FAIL owner=%d — proceeding anyway", owner_id)

        # Determine how many messages to compact (keep recent N)
        keep_recent = max(COMPACTION_KEEP_RECENT_MIN, len(rows) // 3)
        candidate_count = len(rows) - keep_recent
        if candidate_count < HISTORY_COMPACT_MIN_CHUNK:
            return False

        chunk_size = min(HISTORY_COMPACT_MAX_CHUNK, candidate_count)
        chunk_rows = rows[:chunk_size]

        if len(chunk_rows) < HISTORY_COMPACT_MIN_CHUNK:
            return False

        start_id = int(chunk_rows[0].id)
        end_id = int(chunk_rows[-1].id)
        chars_in_chunk = sum(
            len(r.content or "") + len(r.tool_calls_json or "") + len(r.tool_call_id or "")
            for r in chunk_rows
        )

        log.info(
            "COMPACT_BY_CHARS_START owner=%d total_chars=%d budget=%d "
            "chunk=%d start_id=%d end_id=%d chunk_chars=%d",
            owner_id, total_chars, SESSION_SOFT_TRIM_CHAR_BUDGET,
            len(chunk_rows), start_id, end_id, chars_in_chunk,
        )

        serialized = serialize_messages_for_compaction(chunk_rows)
        summary_obj = summarize_conversation_chunk(owner_id, serialized)
        summary_row = store_conversation_summary(db, owner_id, chunk_rows, summary_obj)

        chunk_ids = [int(row.id) for row in chunk_rows]
        compacted = (
            db.query(ConversationMessage)
            .filter(
                ConversationMessage.owner_id == owner_id,
                ConversationMessage.id.in_(chunk_ids),
            )
            .delete(synchronize_session=False)
        )
        db.commit()

        pruned = prune_summary_overflow(db, owner_id)

        RUNTIME_STATE["session_compaction_by_chars"] = int(RUNTIME_STATE.get("session_compaction_by_chars", 0)) + 1
        RUNTIME_STATE["session_compaction_chars_saved"] = int(RUNTIME_STATE.get("session_compaction_chars_saved", 0)) + chars_in_chunk

        log.info(
            "COMPACT_BY_CHARS_OK owner=%d summary_id=%d compacted=%d "
            "chars_saved=%d pruned_summaries=%d",
            owner_id, summary_row.id, int(compacted or 0),
            chars_in_chunk, pruned,
        )
        return True

    except Exception as exc:
        db.rollback()
        log.warning("COMPACT_BY_CHARS_FAIL owner=%d error=%s", owner_id, truncate_text(str(exc), 220))
        return False


def _parse_summary_json_list(raw_value: str, max_items: int = 2, max_len: int = 140) -> list[str]:
    try:
        parsed = json.loads(raw_value or "[]")
    except Exception:
        parsed = []
    return _sanitize_string_list(parsed, max_items=max_items, max_len=max_len)


def _format_conversation_summary_for_prompt(row: ConversationSummary) -> str:
    parts = []
    summary_text = _normalize_compaction_text(row.summary or "", max_len=260)
    if summary_text:
        parts.append(summary_text)

    key_points = _parse_summary_json_list(row.key_points_json, max_items=2, max_len=130)
    if key_points:
        parts.append("Key points: " + "; ".join(key_points))

    open_loops = _parse_summary_json_list(row.open_loops_json, max_items=2, max_len=130)
    if open_loops:
        parts.append("Open loops: " + "; ".join(open_loops))

    combined = " | ".join(parts).strip()
    if not combined:
        return ""
    return _normalize_compaction_text(combined, max_len=460)


def retrieve_relevant_conversation_summaries(
    owner_id: int,
    user_message: str,
    top_k: int = SUMMARY_RETRIEVE_TOP_K,
    continuity_text: str = "",
    task_hint_ids: list[int] | None = None,
) -> list[str]:
    limit = clamp_int(top_k, 1, 8, SUMMARY_RETRIEVE_TOP_K)
    db = SessionLocal()
    try:
        selected: list[str] = []
        selected_ids: set[int] = set()
        selected_scores: list[float] = []
        hint_ids = {int(x) for x in (task_hint_ids or []) if int(x) > 0}
        query_terms = _memory_terms(user_message)
        continuity_terms = _memory_terms(continuity_text)

        vectors = (
            db.query(MemoryVector)
            .filter(
                MemoryVector.owner_id == owner_id,
                MemoryVector.memory_type == "conversation_summary",
            )
            .order_by(MemoryVector.id.desc())
            .limit(800)
            .all()
        )

        if vectors:
            ref_ids = {int(v.ref_id) for v in vectors if v.ref_id}
            summary_rows = (
                db.query(ConversationSummary)
                .filter(
                    ConversationSummary.owner_id == owner_id,
                    ConversationSummary.id.in_(ref_ids),
                )
                .all()
            ) if ref_ids else []
            summary_map = {int(row.id): row for row in summary_rows}

            query_vec = get_embedding(user_message)
            if np.linalg.norm(query_vec) >= 1e-9:
                scored: list[tuple[float, ConversationSummary, str]] = []
                for mv in vectors:
                    if not mv.ref_id:
                        continue
                    row = summary_map.get(int(mv.ref_id))
                    if row is None:
                        continue
                    sim = cosine_similarity(query_vec, bytes_to_embedding(mv.embedding))
                    if sim <= 0.08:
                        continue

                    text = _format_conversation_summary_for_prompt(row)
                    if not text:
                        continue
                    summary_terms = _memory_terms(text)
                    overlap = _token_overlap_score(summary_terms, query_terms)
                    continuity_overlap = _token_overlap_score(summary_terms, continuity_terms)
                    key_points = _parse_summary_json_list(row.key_points_json, max_items=8, max_len=220)
                    open_loops = _parse_summary_json_list(row.open_loops_json, max_items=8, max_len=220)
                    importance = _estimate_summary_importance(row.summary or "", key_points, open_loops)
                    recency = _recency_normalized(row.created_at)
                    task_bonus = 0.0
                    if hint_ids:
                        lowered = text.lower()
                        for task_id in hint_ids:
                            if f"#{task_id}" in lowered or f"task {task_id}" in lowered:
                                task_bonus = 0.10
                                break
                    total_score = (
                        (max(0.0, sim) * 0.55)
                        + (overlap * 0.12)
                        + (importance * 0.18)
                        + (recency * 0.07)
                        + (continuity_overlap * 0.06)
                        + task_bonus
                    )
                    if total_score >= SUMMARY_MIN_TOTAL_SCORE:
                        scored.append((total_score, row, text))

                scored.sort(key=lambda item: item[0], reverse=True)
                for score, row, text in scored:
                    if row.id in selected_ids:
                        continue
                    selected.append(text)
                    selected_ids.add(int(row.id))
                    selected_scores.append(score)
                    if len(selected) >= limit:
                        break

        if len(selected) < limit:
            fallback_rows = (
                db.query(ConversationSummary)
                .filter(ConversationSummary.owner_id == owner_id)
                .order_by(ConversationSummary.id.desc())
                .limit(limit * 4)
                .all()
            )
            for row in fallback_rows:
                if row.id in selected_ids:
                    continue
                text = _format_conversation_summary_for_prompt(row)
                if not text:
                    continue
                summary_terms = _memory_terms(text)
                continuity_overlap = _token_overlap_score(summary_terms, continuity_terms)
                key_points = _parse_summary_json_list(row.key_points_json, max_items=8, max_len=220)
                open_loops = _parse_summary_json_list(row.open_loops_json, max_items=8, max_len=220)
                importance = _estimate_summary_importance(row.summary or "", key_points, open_loops)
                recency = _recency_normalized(row.created_at)
                task_bonus = 0.0
                if hint_ids:
                    lowered = text.lower()
                    for task_id in hint_ids:
                        if f"#{task_id}" in lowered or f"task {task_id}" in lowered:
                            task_bonus = 0.08
                            break
                fallback_score = (importance * 0.70) + (recency * 0.20) + (continuity_overlap * 0.10) + task_bonus
                if fallback_score < SUMMARY_FALLBACK_MIN_SCORE:
                    continue
                selected.append(text)
                selected_ids.add(int(row.id))
                selected_scores.append(fallback_score)
                if len(selected) >= limit:
                    break

        final_selected = selected[:limit]
        avg_quality = (sum(selected_scores[: len(final_selected)]) / len(final_selected)) if final_selected else None
        RUNTIME_STATE["memory_last_summaries_retrieved"] = len(final_selected)
        RUNTIME_STATE["memory_last_summary_quality"] = _format_quality(avg_quality)
        return final_selected
    except Exception as exc:
        log.warning("SUMMARY_RETRIEVAL_FAILED owner=%d error=%s", owner_id, exc)
        RUNTIME_STATE["memory_last_summaries_retrieved"] = 0
        RUNTIME_STATE["memory_last_summary_quality"] = None
        return []
    finally:
        db.close()


def _parse_tool_names_json(raw_value: str, max_items: int = 6) -> list[str]:
    try:
        parsed = json.loads(raw_value or "[]")
    except Exception:
        parsed = []
    items = []
    if isinstance(parsed, list):
        for value in parsed:
            name = _normalize_compaction_text(str(value or ""), max_len=80)
            if not name:
                continue
            if name in items:
                continue
            items.append(name)
            if len(items) >= max_items:
                break
    return items


def _collect_step_tool_names(step_snapshot: dict) -> list[str]:
    names = []
    for event in step_snapshot.get("tool_events", []) or []:
        if not isinstance(event, dict):
            continue
        tool_name = _normalize_compaction_text(str(event.get("tool", "")), max_len=60)
        if not tool_name or tool_name in names:
            continue
        names.append(tool_name)
        if len(names) >= 8:
            break
    return names


def _compose_task_artifact_outcome(step_snapshot: dict) -> str:
    summary = _normalize_compaction_text(str(step_snapshot.get("result_summary", "")), max_len=1400)
    if summary:
        return summary
    err = _normalize_compaction_text(str(step_snapshot.get("last_error", "")), max_len=1400)
    if err:
        return f"Error: {err}"
    status = _normalize_compaction_text(str(step_snapshot.get("status", "")), max_len=80)
    if status:
        return f"Node status: {status}"
    return "Node completed without explicit summary."


def _compose_task_artifact_embedding_text(
    task_title: str,
    task_goal: str,
    step_snapshot: dict,
    outcome_summary: str,
    tool_names: list[str],
) -> str:
    parts = [
        _normalize_compaction_text(task_title, max_len=220),
        _normalize_compaction_text(task_goal, max_len=700),
        _normalize_compaction_text(str(step_snapshot.get("title", "")), max_len=220),
        _normalize_compaction_text(str(step_snapshot.get("step_id", "")), max_len=80),
        _normalize_compaction_text(str(step_snapshot.get("status", "")), max_len=60),
        _normalize_compaction_text(outcome_summary, max_len=900),
    ]
    if tool_names:
        parts.append("tools: " + ", ".join(tool_names[:6]))
    return " | ".join(part for part in parts if part)


def _prune_task_artifact_overflow_db(db: Session, owner_id: int) -> int:
    overflow_rows = (
        db.query(TaskArtifact.id)
        .filter(TaskArtifact.owner_id == owner_id)
        .order_by(TaskArtifact.id.desc())
        .offset(TASK_ARTIFACT_MAX_PER_USER)
        .all()
    )
    prune_ids = [int(row[0]) for row in overflow_rows if row and row[0] is not None]
    if not prune_ids:
        return 0

    db.query(MemoryVector).filter(
        MemoryVector.owner_id == owner_id,
        MemoryVector.memory_type == "task_artifact",
        MemoryVector.ref_id.in_(prune_ids),
    ).delete(synchronize_session=False)
    db.query(TaskArtifact).filter(
        TaskArtifact.owner_id == owner_id,
        TaskArtifact.id.in_(prune_ids),
    ).delete(synchronize_session=False)
    return len(prune_ids)


def store_task_artifact_memory(
    owner_id: int,
    task_id: int,
    task_title: str,
    task_goal: str,
    step_snapshot: dict,
) -> bool:
    if not owner_id or not task_id:
        return False
    if not isinstance(step_snapshot, dict):
        return False

    step_id = _normalize_compaction_text(str(step_snapshot.get("step_id", "")), max_len=80)
    node_title = _normalize_compaction_text(str(step_snapshot.get("title", "")), max_len=200)
    status = _normalize_compaction_text(str(step_snapshot.get("status", "")), max_len=40)
    if not step_id or not node_title or not status:
        return False

    outcome_summary = _compose_task_artifact_outcome(step_snapshot)
    tool_names = _collect_step_tool_names(step_snapshot)
    embed_text = _compose_task_artifact_embedding_text(
        task_title=task_title,
        task_goal=task_goal,
        step_snapshot=step_snapshot,
        outcome_summary=outcome_summary,
        tool_names=tool_names,
    )

    db = SessionLocal()
    try:
        record = TaskArtifact(
            owner_id=int(owner_id),
            task_id=int(task_id),
            step_id=step_id,
            node_title=node_title,
            task_title=_normalize_compaction_text(task_title, max_len=220) or "Task",
            task_goal=_normalize_compaction_text(task_goal, max_len=2000) or "",
            status=status,
            outcome_summary=outcome_summary,
            tool_names_json=json.dumps(tool_names[:8], ensure_ascii=False),
        )
        db.add(record)
        db.flush()

        vec = get_embedding(embed_text)
        if np.linalg.norm(vec) >= 1e-9:
            db.add(
                MemoryVector(
                    owner_id=int(owner_id),
                    memory_type="task_artifact",
                    ref_id=record.id,
                    text_preview=truncate_text(f"{node_title}: {outcome_summary}", 200),
                    embedding=embedding_to_bytes(vec),
                )
            )

        pruned = _prune_task_artifact_overflow_db(db, int(owner_id))
        db.commit()
        RUNTIME_STATE["task_artifacts_stored"] = int(RUNTIME_STATE.get("task_artifacts_stored", 0)) + 1
        if pruned:
            RUNTIME_STATE["task_artifacts_pruned"] = int(RUNTIME_STATE.get("task_artifacts_pruned", 0)) + pruned
            log.info("TASK_ARTIFACT_PRUNE owner=%d removed=%d retain=%d", owner_id, pruned, TASK_ARTIFACT_MAX_PER_USER)
        log.info(
            "TASK_ARTIFACT_STORED owner=%d task_id=%d step_id=%s status=%s",
            owner_id,
            task_id,
            step_id,
            status,
        )
        return True
    except Exception as exc:
        db.rollback()
        log.warning("TASK_ARTIFACT_STORE_FAIL owner=%d task_id=%d error=%s", owner_id, task_id, exc)
        return False
    finally:
        db.close()


def maybe_store_task_artifact_for_step(task: Task, step_snapshot: dict) -> bool:
    if not isinstance(step_snapshot, dict):
        return False
    if step_snapshot.get("artifact_logged_at"):
        return False
    status = str(step_snapshot.get("status", "")).lower()
    if status not in {"done", "failed", "skipped", "blocked"}:
        return False

    saved = store_task_artifact_memory(
        owner_id=int(task.owner_id),
        task_id=int(task.id),
        task_title=str(task.title or ""),
        task_goal=str(task.description or ""),
        step_snapshot=step_snapshot,
    )
    if saved:
        step_snapshot["artifact_logged_at"] = utc_now_iso()
    return saved


def _format_task_artifact_for_prompt(row: TaskArtifact) -> str:
    status = _normalize_compaction_text(str(row.status or ""), max_len=40)
    node_title = _normalize_compaction_text(str(row.node_title or ""), max_len=180)
    outcome = _normalize_compaction_text(str(row.outcome_summary or ""), max_len=300)
    parts = []
    if status or node_title:
        parts.append(f"[{status}] {node_title}".strip())
    if outcome:
        parts.append(outcome)
    tools = _parse_tool_names_json(row.tool_names_json, max_items=4)
    if tools:
        parts.append("tools: " + ", ".join(tools))
    combined = " | ".join(part for part in parts if part)
    return _normalize_compaction_text(combined, max_len=520)


def retrieve_relevant_task_artifacts(
    owner_id: int,
    query_text: str,
    top_k: int = TASK_ARTIFACT_RETRIEVE_TOP_K,
    continuity_text: str = "",
    task_hint_ids: list[int] | None = None,
) -> list[str]:
    limit = clamp_int(top_k, 1, 8, TASK_ARTIFACT_RETRIEVE_TOP_K)
    db = SessionLocal()
    try:
        selected: list[str] = []
        selected_ids: set[int] = set()
        selected_scores: list[float] = []
        query_terms = _memory_terms(query_text)
        continuity_terms = _memory_terms(continuity_text)
        hint_ids = {int(x) for x in (task_hint_ids or []) if int(x) > 0}

        vectors = (
            db.query(MemoryVector)
            .filter(
                MemoryVector.owner_id == owner_id,
                MemoryVector.memory_type == "task_artifact",
            )
            .order_by(MemoryVector.id.desc())
            .limit(TASK_ARTIFACT_VECTOR_SCAN_LIMIT)
            .all()
        )

        if vectors:
            ref_ids = {int(v.ref_id) for v in vectors if v.ref_id}
            artifact_rows = (
                db.query(TaskArtifact)
                .filter(
                    TaskArtifact.owner_id == owner_id,
                    TaskArtifact.id.in_(ref_ids),
                )
                .all()
            ) if ref_ids else []
            artifact_map = {int(row.id): row for row in artifact_rows}

            query_vec = get_embedding(query_text or "")
            if np.linalg.norm(query_vec) >= 1e-9:
                scored: list[tuple[float, TaskArtifact, str]] = []
                for mv in vectors:
                    if not mv.ref_id:
                        continue
                    row = artifact_map.get(int(mv.ref_id))
                    if row is None:
                        continue
                    sim = cosine_similarity(query_vec, bytes_to_embedding(mv.embedding))
                    if sim <= 0.08:
                        continue

                    line = _format_task_artifact_for_prompt(row)
                    if not line:
                        continue
                    artifact_terms = _memory_terms(line + " " + str(row.task_title or ""))
                    overlap = _token_overlap_score(artifact_terms, query_terms)
                    continuity_overlap = _token_overlap_score(artifact_terms, continuity_terms)
                    recency = _recency_normalized(row.created_at)
                    importance = _estimate_task_artifact_importance(row)
                    status = (row.status or "").lower()
                    status_bonus = 0.0
                    if status == "done":
                        status_bonus = 0.06
                    elif status == "skipped":
                        status_bonus = 0.01
                    elif status in {"failed", "blocked"}:
                        status_bonus = 0.03

                    task_bonus = 0.0
                    if hint_ids and int(row.task_id) in hint_ids:
                        task_bonus = 0.14

                    total_score = (
                        (max(0.0, sim) * 0.50)
                        + (overlap * 0.14)
                        + (continuity_overlap * 0.08)
                        + (importance * 0.16)
                        + (recency * 0.07)
                        + status_bonus
                        + task_bonus
                    )
                    if total_score >= TASK_ARTIFACT_MIN_TOTAL_SCORE:
                        scored.append((total_score, row, line))

                scored.sort(key=lambda item: item[0], reverse=True)
                for score, row, line in scored:
                    if row.id in selected_ids:
                        continue
                    selected.append(line)
                    selected_ids.add(int(row.id))
                    selected_scores.append(score)
                    if len(selected) >= limit:
                        break

        if len(selected) < limit:
            fallback_rows = (
                db.query(TaskArtifact)
                .filter(TaskArtifact.owner_id == owner_id)
                .order_by(TaskArtifact.id.desc())
                .limit(limit * 4)
                .all()
            )
            for row in fallback_rows:
                if row.id in selected_ids:
                    continue
                line = _format_task_artifact_for_prompt(row)
                if not line:
                    continue
                artifact_terms = _memory_terms(line + " " + str(row.task_title or ""))
                continuity_overlap = _token_overlap_score(artifact_terms, continuity_terms)
                recency = _recency_normalized(row.created_at)
                importance = _estimate_task_artifact_importance(row)
                task_bonus = 0.0
                if hint_ids and int(row.task_id) in hint_ids:
                    task_bonus = 0.12
                status = (row.status or "").lower()
                status_bonus = 0.0
                if status == "done":
                    status_bonus = 0.05
                elif status in {"failed", "blocked"}:
                    status_bonus = 0.03
                fallback_score = (importance * 0.50) + (recency * 0.25) + (continuity_overlap * 0.15) + task_bonus + status_bonus
                if fallback_score < TASK_ARTIFACT_FALLBACK_MIN_SCORE:
                    continue
                selected.append(line)
                selected_ids.add(int(row.id))
                selected_scores.append(fallback_score)
                if len(selected) >= limit:
                    break

        final_selected = selected[:limit]
        avg_quality = (sum(selected_scores[: len(final_selected)]) / len(final_selected)) if final_selected else None
        RUNTIME_STATE["memory_last_task_artifacts_retrieved"] = len(final_selected)
        RUNTIME_STATE["memory_last_task_artifact_quality"] = _format_quality(avg_quality)
        return final_selected
    except Exception as exc:
        log.warning("TASK_ARTIFACT_RETRIEVAL_FAIL owner=%d error=%s", owner_id, exc)
        RUNTIME_STATE["memory_last_task_artifacts_retrieved"] = 0
        RUNTIME_STATE["memory_last_task_artifact_quality"] = None
        return []
    finally:
        db.close()

def _infer_world_pattern(action_text: str, tool_events: list[dict] | None = None) -> str:
    blob = str(action_text or "").lower()
    events = tool_events or []
    if events:
        names = " ".join(str(item.get("tool", "")) for item in events if isinstance(item, dict)).lower()
        blob = f"{blob} {names}".strip()

    if re.search(r"\b(web|search|http|api|url|download|remote|fetch|scrape)\b", blob):
        return "network_io"
    if re.search(r"\b(file|write|read|directory|path|disk|sqlite|db)\b", blob):
        return "filesystem"
    if re.search(r"\b(run_command|execute_python|shell|script|command|compile|test)\b", blob):
        return "code_exec"
    if re.search(r"\b(cron|schedule|interval|due|tick|queue)\b", blob):
        return "scheduling"
    if re.search(r"\b(approve|reject|token|permission|policy|authority)\b", blob):
        return "governance"
    return "general_reasoning"


def _forecast_risks_for_pattern(pattern_tag: str, action_text: str) -> list[str]:
    text = str(action_text or "").lower()
    risks: list[str] = []
    if pattern_tag == "network_io":
        risks.extend([
            "External endpoint may be unavailable or rate-limited.",
            "Search/fetch results may be noisy and need trust filtering.",
        ])
    elif pattern_tag == "filesystem":
        risks.extend([
            "Path or permission mismatch can fail writes.",
            "Large file payloads can cause truncation or timeout.",
        ])
    elif pattern_tag == "code_exec":
        risks.extend([
            "Command/runtime side effects can diverge from intent.",
            "Execution may fail on dependency or environment mismatch.",
        ])
    elif pattern_tag == "scheduling":
        risks.extend([
            "Delayed execution can run with stale assumptions.",
            "Queue pressure can postpone job completion.",
        ])
    elif pattern_tag == "governance":
        risks.extend([
            "Action may pause for approval/token flow.",
            "Policy boundaries may block direct execution.",
        ])
    else:
        risks.extend([
            "Plan ambiguity can reduce execution quality.",
            "Missing context can cause avoidable retries.",
        ])

    if "delete" in text or "drop" in text:
        risks.append("Destructive intent detected; validation required.")
    if "production" in text:
        risks.append("Production scope requires conservative execution.")
    if "migrate" in text:
        risks.append("Migration order/dependency errors can cascade.")
    return risks[:4]


def _forecast_confidence(attempt: int, dependency_count: int, risk_count: int) -> int:
    score = 82
    score -= max(0, int(attempt) - 1) * 10
    score -= max(0, int(dependency_count)) * 4
    score -= max(0, int(risk_count)) * 5
    return clamp_int(score, 20, 95, 55)


def _compose_world_memory_text(
    action_summary: str,
    pattern_tag: str,
    predicted_outcome: str,
    predicted_risks: list[str],
    status: str,
    observed_outcome: str,
    observed_error: str,
) -> str:
    parts = [
        f"Action: {truncate_text(action_summary or '', 220)}",
        f"Pattern: {pattern_tag}",
        f"Predicted: {truncate_text(predicted_outcome or '', 260)}",
        f"Status: {status}",
    ]
    if predicted_risks:
        parts.append("Risks: " + "; ".join(truncate_text(str(item), 120) for item in predicted_risks[:4]))
    if observed_outcome:
        parts.append("Observed: " + truncate_text(observed_outcome, 260))
    if observed_error:
        parts.append("Error: " + truncate_text(observed_error, 220))
    return _memory_preview_text(" | ".join(parts), max_len=600)


def _prune_action_forecast_overflow_db(db: Session, owner_id: int) -> int:
    stale_rows = (
        db.query(ActionForecast.id)
        .filter(ActionForecast.owner_id == int(owner_id))
        .order_by(ActionForecast.id.desc())
        .offset(WORLD_MODEL_MAX_FORECASTS_PER_USER)
        .all()
    )
    prune_ids = [int(row[0]) for row in stale_rows]
    if not prune_ids:
        return 0

    db.query(MemoryVector).filter(
        MemoryVector.owner_id == int(owner_id),
        MemoryVector.memory_type.in_(["world_model_forecast", "world_model_outcome"]),
        MemoryVector.ref_id.in_(prune_ids),
    ).delete(synchronize_session=False)
    db.query(ActionForecast).filter(
        ActionForecast.owner_id == int(owner_id),
        ActionForecast.id.in_(prune_ids),
    ).delete(synchronize_session=False)
    return len(prune_ids)


def _update_world_model_runtime_metrics_db(db: Session, owner_id: int):
    total = (
        db.query(ActionForecast)
        .filter(ActionForecast.owner_id == int(owner_id))
        .count()
    )
    mismatches = (
        db.query(ActionForecast)
        .filter(
            ActionForecast.owner_id == int(owner_id),
            ActionForecast.status == "mismatch",
        )
        .count()
    )
    recent = (
        db.query(ActionForecast)
        .filter(
            ActionForecast.owner_id == int(owner_id),
            ActionForecast.status.in_(["confirmed", "mismatch"]),
        )
        .order_by(ActionForecast.id.desc())
        .limit(WORLD_MODEL_RECENT_ACCURACY_WINDOW)
        .all()
    )
    judged = [row for row in recent if str(row.status or "") in {"confirmed", "mismatch"}]
    confirmed = sum(1 for row in judged if str(row.status or "") == "confirmed")
    accuracy = (confirmed / len(judged)) if judged else None

    RUNTIME_STATE["world_model_forecasts_total"] = int(total)
    RUNTIME_STATE["world_model_mismatches"] = int(mismatches)
    RUNTIME_STATE["world_model_recent_accuracy"] = _format_quality(accuracy)


def create_action_forecast_record(
    owner_id: int,
    context_type: str,
    context_ref: str,
    action_summary: str,
    attempt: int = 1,
    dependency_count: int = 0,
) -> int | None:
    db = SessionLocal()
    try:
        summary = _memory_preview_text(action_summary or "", max_len=280)
        if not summary:
            return None
        pattern_tag = _infer_world_pattern(summary, None)
        risks = _forecast_risks_for_pattern(pattern_tag, summary)
        confidence = _forecast_confidence(attempt=attempt, dependency_count=dependency_count, risk_count=len(risks))
        predicted_outcome = (
            "Likely success if prerequisites are met, with elevated attention to listed risks."
            if confidence >= 55
            else "Outcome uncertain; likely requires retries or alternative branch."
        )

        row = ActionForecast(
            owner_id=int(owner_id),
            context_type=truncate_text(context_type or "task_step", 40),
            context_ref=truncate_text(context_ref or "", 140) or None,
            action_summary=summary,
            pattern_tag=pattern_tag,
            predicted_outcome=predicted_outcome,
            predicted_risks_json=json.dumps(risks, ensure_ascii=False),
            confidence=confidence,
            status="pending",
        )
        db.add(row)
        db.flush()

        embed_text = _compose_world_memory_text(
            action_summary=summary,
            pattern_tag=pattern_tag,
            predicted_outcome=predicted_outcome,
            predicted_risks=risks,
            status="pending",
            observed_outcome="",
            observed_error="",
        )
        vec = get_embedding(embed_text)
        if np.linalg.norm(vec) > 1e-9:
            db.add(
                MemoryVector(
                    owner_id=int(owner_id),
                    memory_type="world_model_forecast",
                    ref_id=int(row.id),
                    text_preview=truncate_text(embed_text, 200),
                    embedding=embedding_to_bytes(vec),
                )
            )

        _prune_action_forecast_overflow_db(db, int(owner_id))
        _update_world_model_runtime_metrics_db(db, int(owner_id))
        RUNTIME_STATE["world_model_last_forecast_at"] = utc_now_iso()
        db.commit()
        log.info(
            "WORLD_MODEL_FORECAST owner=%d forecast_id=%d pattern=%s confidence=%d",
            int(owner_id),
            int(row.id),
            pattern_tag,
            int(confidence),
        )
        return int(row.id)
    except Exception as exc:
        db.rollback()
        log.warning("WORLD_MODEL_FORECAST_FAIL owner=%d error=%s", int(owner_id), truncate_text(str(exc), 220))
        return None
    finally:
        db.close()


def reconcile_action_forecast_record(
    owner_id: int,
    forecast_id: int | None,
    outcome_state: str,
    observed_outcome: str = "",
    observed_error: str = "",
    tool_events: list[dict] | None = None,
) -> bool:
    if not forecast_id:
        return False
    state = str(outcome_state or "").strip().lower()
    if state not in {"confirmed", "mismatch", "unknown"}:
        state = "unknown"

    db = SessionLocal()
    try:
        row = (
            db.query(ActionForecast)
            .filter(
                ActionForecast.id == int(forecast_id),
                ActionForecast.owner_id == int(owner_id),
            )
            .first()
        )
        if row is None:
            return False
        if str(row.status or "") != "pending":
            return True

        row.status = state
        row.observed_outcome = truncate_text(str(observed_outcome or ""), 1200) or None
        row.observed_error = truncate_text(str(observed_error or ""), 800) or None
        row.resolved_at = datetime.now(timezone.utc)
        if not row.pattern_tag:
            row.pattern_tag = _infer_world_pattern(row.action_summary or "", tool_events)

        risks = _safe_json_list(row.predicted_risks_json, [])
        embed_text = _compose_world_memory_text(
            action_summary=row.action_summary or "",
            pattern_tag=str(row.pattern_tag or "general_reasoning"),
            predicted_outcome=row.predicted_outcome or "",
            predicted_risks=[str(item) for item in risks[:4]],
            status=state,
            observed_outcome=str(row.observed_outcome or ""),
            observed_error=str(row.observed_error or ""),
        )
        vec = get_embedding(embed_text)
        if np.linalg.norm(vec) > 1e-9:
            db.add(
                MemoryVector(
                    owner_id=int(owner_id),
                    memory_type="world_model_outcome",
                    ref_id=int(row.id),
                    text_preview=truncate_text(embed_text, 200),
                    embedding=embedding_to_bytes(vec),
                )
            )

        db.flush()

        # Pillar 4: Pattern failure detection — if same pattern_tag fails 3+ times in 7 days, auto-create improvement note
        if state == "mismatch" and row.pattern_tag:
            try:
                week_ago = datetime.now(timezone.utc) - timedelta(days=7)
                same_pattern_fails = (
                    db.query(ActionForecast)
                    .filter(
                        ActionForecast.owner_id == int(owner_id),
                        ActionForecast.pattern_tag == str(row.pattern_tag),
                        ActionForecast.status == "mismatch",
                        ActionForecast.resolved_at >= week_ago,
                    )
                    .count()
                )
                if same_pattern_fails >= 3:
                    run_self_improvement_cycle(db, int(owner_id), trigger=f"pattern_failure:{row.pattern_tag}")
                    log.info("PATTERN_FAILURE_DETECTED owner=%d pattern=%s fails=%d", int(owner_id), row.pattern_tag, same_pattern_fails)
            except Exception as _pf_exc:
                log.warning("PATTERN_FAILURE_CHECK_FAIL: %s", truncate_text(str(_pf_exc), 140))

        _prune_action_forecast_overflow_db(db, int(owner_id))
        _update_world_model_runtime_metrics_db(db, int(owner_id))
        RUNTIME_STATE["world_model_last_reconciliation_at"] = utc_now_iso()
        db.commit()
        log.info(
            "WORLD_MODEL_RECONCILE owner=%d forecast_id=%d status=%s",
            int(owner_id),
            int(forecast_id),
            state,
        )
        return True
    except Exception as exc:
        db.rollback()
        log.warning(
            "WORLD_MODEL_RECONCILE_FAIL owner=%d forecast_id=%s error=%s",
            int(owner_id),
            str(forecast_id),
            truncate_text(str(exc), 220),
        )
        return False
    finally:
        db.close()


def retrieve_world_model_signals(owner_id: int, query_text: str, top_k: int = 3) -> list[str]:
    limit = clamp_int(top_k, 1, 8, WORLD_MODEL_RETRIEVE_TOP_K)
    db = SessionLocal()
    try:
        query = str(query_text or "").strip()
        if not query:
            return []

        mem_vectors = (
            db.query(MemoryVector)
            .filter(
                MemoryVector.owner_id == int(owner_id),
                MemoryVector.memory_type.in_(["world_model_outcome", "world_model_forecast"]),
            )
            .order_by(MemoryVector.id.desc())
            .limit(WORLD_MODEL_VECTOR_SCAN_LIMIT)
            .all()
        )
        if not mem_vectors:
            return []

        query_vec = get_embedding(query)
        query_terms = _memory_terms(query)
        scored: list[tuple[float, str]] = []
        for mv in mem_vectors:
            stored_vec = bytes_to_embedding(mv.embedding)
            sim = cosine_similarity(query_vec, stored_vec)
            if sim <= 0.08:
                continue

            row = None
            if mv.ref_id:
                row = db.query(ActionForecast).filter(ActionForecast.id == int(mv.ref_id)).first()
            if row is None:
                line = _memory_preview_text(mv.text_preview or "", max_len=260)
                if not line:
                    continue
                overlap = _token_overlap_score(_memory_terms(line), query_terms)
                total = (sim * 0.8) + (overlap * 0.2)
                scored.append((total, line))
                continue

            status = str(row.status or "unknown")
            pattern = str(row.pattern_tag or "general_reasoning")
            observed = str(row.observed_outcome or row.observed_error or "").strip()
            line = (
                f"[{pattern}] predicted: {truncate_text(row.predicted_outcome or '', 110)} "
                f"-> {status}: {truncate_text(observed or 'pending observation', 140)}"
            )
            overlap = _token_overlap_score(_memory_terms(line), query_terms)
            mismatch_boost = 0.08 if status == "mismatch" else 0.0
            recency = _recency_normalized(row.created_at, fresh_days=2.0, stale_days=180.0)
            total = (sim * 0.62) + (overlap * 0.16) + (recency * 0.14) + mismatch_boost
            scored.append((total, _memory_preview_text(line, max_len=260)))

        scored.sort(key=lambda item: item[0], reverse=True)
        selected: list[str] = []
        for _, text in scored:
            if text in selected:
                continue
            selected.append(text)
            if len(selected) >= limit:
                break

        if selected:
            return selected

        fallback_rows = (
            db.query(ActionForecast)
            .filter(
                ActionForecast.owner_id == int(owner_id),
                ActionForecast.status == "mismatch",
            )
            .order_by(ActionForecast.id.desc())
            .limit(limit)
            .all()
        )
        fallback: list[str] = []
        for row in fallback_rows:
            fallback.append(
                _memory_preview_text(
                    f"[{row.pattern_tag or 'general_reasoning'}] mismatch: "
                    f"{truncate_text(row.action_summary or '', 120)} -> "
                    f"{truncate_text(row.observed_error or row.observed_outcome or 'unknown outcome', 120)}",
                    max_len=260,
                )
            )
        return fallback[:limit]
    except Exception as exc:
        log.warning("WORLD_MODEL_SIGNAL_RETRIEVAL_FAIL owner=%d error=%s", int(owner_id), truncate_text(str(exc), 220))
        return []
    finally:
        db.close()


_self_improve_last_time: dict[int, float] = {}


def _build_self_improvement_candidate(evidence: dict) -> dict | None:
    world_accuracy = evidence.get("world_accuracy")
    forecasts_total = int(evidence.get("forecasts_total", 0))
    dead_letters = int(evidence.get("dead_letters_recent", 0))
    runtime_alert_count = int(evidence.get("runtime_alert_count", 0))
    memory_quality = evidence.get("memory_hit_quality")
    pending_approvals = int(evidence.get("approval_pending_count", 0))

    if isinstance(world_accuracy, (int, float)) and forecasts_total >= 12 and float(world_accuracy) < 0.60:
        return {
            "title": "Improve pre-action prediction accuracy",
            "summary": "Recent prediction accuracy dropped below target; increase risk checks before execution.",
            "priority": "high",
            "actions": [
                "Add explicit pre-check tool calls for high-risk steps before main execution.",
                "Prefer smaller branch steps when dependency count is high.",
                "Escalate uncertain plans with confidence below 55 for clarification.",
            ],
        }

    if dead_letters > 0:
        return {
            "title": "Reduce dead-letter task outcomes",
            "summary": "Recent tasks reached dead-letter state; harden retry and branch strategy earlier.",
            "priority": "high",
            "actions": [
                "Detect likely deadlock/dependency risk earlier and branch sooner.",
                "Shorten failing loops by switching strategy after first repeated error.",
                "Capture clearer failure summaries for faster recovery decisions.",
            ],
        }

    if runtime_alert_count > 0:
        return {
            "title": "Stabilize runtime alerts",
            "summary": "Runtime alerts are active; prioritize guardrail and queue health stabilization.",
            "priority": "medium",
            "actions": [
                "Prioritize actions that reduce queue pressure and retry storms.",
                "Favor trusted sources and bounded tool loops while alerts remain active.",
                "Re-check supervisor and webhook health before long autonomous runs.",
            ],
        }

    if isinstance(memory_quality, (int, float)) and float(memory_quality) < 0.42:
        return {
            "title": "Raise memory retrieval signal quality",
            "summary": "Recent memory-hit quality is low; improve retrieval precision and continuity alignment.",
            "priority": "medium",
            "actions": [
                "Use tighter query terms from the current objective before retrieval.",
                "Prefer high-signal memories over broad low-confidence matches.",
                "Prune weak repetitive memories more aggressively when quality drops.",
            ],
        }

    if pending_approvals >= 10:
        return {
            "title": "Lower approval backlog",
            "summary": "Approval queue is growing; reduce avoidable approval-required actions.",
            "priority": "medium",
            "actions": [
                "Batch read-only analysis before proposing write/exec actions.",
                "Ask for one consolidated approval token when possible.",
                "Avoid repeating blocked actions without new evidence.",
            ],
        }

    return None


def _llm_self_improvement_candidate(db: Session, owner_id: int) -> dict | None:
    """Use LLM to analyze recent task outcomes and generate improvement notes (Pillar 4)."""
    if not SELF_IMPROVE_LLM_ANALYSIS_ENABLED:
        return None
    now_mono = time.monotonic()
    last = float(_self_improve_llm_last_time.get(int(owner_id), 0.0))
    if now_mono - last < float(SELF_IMPROVE_LLM_ANALYSIS_COOLDOWN_HOURS) * 3600:
        return None

    now_dt = datetime.now(timezone.utc)
    week_ago = now_dt - timedelta(days=7)

    recent_artifacts = (
        db.query(TaskArtifact)
        .filter(TaskArtifact.owner_id == int(owner_id), TaskArtifact.created_at >= week_ago)
        .order_by(TaskArtifact.id.desc())
        .limit(10)
        .all()
    )
    recent_dead = (
        db.query(TaskDeadLetter)
        .filter(TaskDeadLetter.owner_id == int(owner_id), TaskDeadLetter.created_at >= week_ago)
        .order_by(TaskDeadLetter.id.desc())
        .limit(5)
        .all()
    )
    if len(recent_artifacts) < 3 and len(recent_dead) < 1:
        return None

    _self_improve_llm_last_time[int(owner_id)] = now_mono

    context_parts = ["Recent task outcomes (last 7 days):"]
    for art in recent_artifacts:
        status = str(art.status or "unknown")
        title = truncate_text(str(art.node_title or art.task_title or ""), 100)
        outcome = truncate_text(str(art.outcome_summary or ""), 150)
        context_parts.append(f"- [{status}] {title}: {outcome}")

    if recent_dead:
        context_parts.append("\nFailed tasks (dead letters):")
        for dl in recent_dead:
            title = truncate_text(str(dl.title or ""), 100)
            reason = truncate_text(str(dl.reason or ""), 150)
            context_parts.append(f"- FAILED: {title} — {reason}")

    prompt = (
        "Analyze these recent task outcomes and identify ONE actionable self-improvement.\n"
        "Focus on patterns: repeated failures, inefficient strategies, or missed opportunities.\n"
        "Respond in JSON ONLY:\n"
        '{"title": "short title", "summary": "what to improve", "priority": "high|medium|low", '
        '"actions": ["action1", "action2", "action3"]}\n'
        "If no clear improvement needed, respond: {\"title\": null}\n"
    )

    try:
        messages = [
            {"role": "system", "content": prompt},
            {"role": "user", "content": "\n".join(context_parts)},
        ]
        response = call_llm(messages=messages, tools=None, owner_id=owner_id, source_type="self_improve")
        if not response or not response.get("choices"):
            return None

        raw = str(response["choices"][0].get("message", {}).get("content", "") or "").strip()
        parsed = _safe_json_dict(raw, None)
        if parsed is None:
            json_match = re.search(r"\{.*\}", raw, re.DOTALL)
            parsed = _safe_json_dict(json_match.group(), {}) if json_match else {}

        if not parsed.get("title"):
            return None

        log.info("SELF_IMPROVE_LLM_CANDIDATE owner=%d title=%s", int(owner_id), truncate_text(str(parsed["title"]), 80))
        return parsed
    except Exception as exc:
        log.warning("SELF_IMPROVE_LLM_FAIL owner=%d error=%s", int(owner_id), truncate_text(str(exc), 220))
        return None


def _prune_self_improvement_overflow_db(db: Session, owner_id: int) -> int:
    stale_rows = (
        db.query(SelfImprovementNote.id)
        .filter(SelfImprovementNote.owner_id == int(owner_id))
        .order_by(SelfImprovementNote.id.desc())
        .offset(SELF_IMPROVE_MAX_NOTES_PER_USER)
        .all()
    )
    prune_ids = [int(row[0]) for row in stale_rows]
    if not prune_ids:
        return 0

    db.query(MemoryVector).filter(
        MemoryVector.owner_id == int(owner_id),
        MemoryVector.memory_type == "self_improvement_note",
        MemoryVector.ref_id.in_(prune_ids),
    ).delete(synchronize_session=False)
    db.query(SelfImprovementNote).filter(
        SelfImprovementNote.owner_id == int(owner_id),
        SelfImprovementNote.id.in_(prune_ids),
    ).delete(synchronize_session=False)
    return len(prune_ids)


def run_self_improvement_cycle(db: Session, owner_id: int, trigger: str = "chat") -> dict:
    now_mono = time.monotonic()
    last = float(_self_improve_last_time.get(int(owner_id), 0.0))
    if now_mono - last < float(SELF_IMPROVE_INTERVAL_SECONDS):
        return {"ok": True, "skipped": "cooldown"}
    _self_improve_last_time[int(owner_id)] = now_mono

    now_dt = datetime.now(timezone.utc)
    week_ago = now_dt - timedelta(days=7)
    dead_letters_recent = (
        db.query(TaskDeadLetter)
        .filter(
            TaskDeadLetter.owner_id == int(owner_id),
            TaskDeadLetter.created_at >= week_ago,
        )
        .count()
    )

    evidence = {
        "trigger": truncate_text(trigger, 60),
        "world_accuracy": RUNTIME_STATE.get("world_model_recent_accuracy"),
        "forecasts_total": int(RUNTIME_STATE.get("world_model_forecasts_total", 0)),
        "world_mismatches": int(RUNTIME_STATE.get("world_model_mismatches", 0)),
        "memory_hit_quality": RUNTIME_STATE.get("memory_last_hit_quality"),
        "runtime_alert_count": int(RUNTIME_STATE.get("runtime_alert_count", 0)),
        "approval_pending_count": int(RUNTIME_STATE.get("approval_pending_count", 0)),
        "dead_letters_recent": int(dead_letters_recent),
    }
    candidate = _build_self_improvement_candidate(evidence)
    RUNTIME_STATE["self_improve_last_run_at"] = utc_now_iso()

    if candidate is None:
        candidate = _llm_self_improvement_candidate(db, int(owner_id))

    if candidate is None:
        return {"ok": True, "skipped": "no_signal"}

    title = truncate_text(str(candidate.get("title") or "Self-improvement note"), 180)
    recent_duplicate = (
        db.query(SelfImprovementNote)
        .filter(
            SelfImprovementNote.owner_id == int(owner_id),
            SelfImprovementNote.title == title,
        )
        .order_by(SelfImprovementNote.id.desc())
        .first()
    )
    if recent_duplicate is not None:
        recency = _recency_normalized(recent_duplicate.created_at, fresh_days=0.2, stale_days=3.0)
        if recency > 0.55:
            return {"ok": True, "skipped": "duplicate"}

    actions = [truncate_text(str(item), 260) for item in list(candidate.get("actions") or [])[:6] if str(item).strip()]
    summary = truncate_text(str(candidate.get("summary") or ""), 800)
    priority = truncate_text(str(candidate.get("priority") or "medium"), 20).lower()
    if priority not in {"low", "medium", "high"}:
        priority = "medium"

    row = SelfImprovementNote(
        owner_id=int(owner_id),
        title=title,
        summary=summary,
        actions_json=json.dumps(actions, ensure_ascii=False),
        evidence_json=json.dumps(evidence, ensure_ascii=False),
        priority=priority,
        status="open",
    )
    db.add(row)
    db.flush()

    embed_text = _memory_preview_text(f"{title} | {summary} | actions: {'; '.join(actions)}", max_len=600)
    vec = get_embedding(embed_text)
    if np.linalg.norm(vec) > 1e-9:
        db.add(
            MemoryVector(
                owner_id=int(owner_id),
                memory_type="self_improvement_note",
                ref_id=int(row.id),
                text_preview=truncate_text(embed_text, 200),
                embedding=embedding_to_bytes(vec),
            )
        )

    _prune_self_improvement_overflow_db(db, int(owner_id))
    db.commit()

    total_notes = (
        db.query(SelfImprovementNote)
        .filter(SelfImprovementNote.owner_id == int(owner_id))
        .count()
    )
    RUNTIME_STATE["self_improve_notes_total"] = int(total_notes)
    RUNTIME_STATE["self_improve_last_note"] = title
    log.info(
        "SELF_IMPROVE_NOTE owner=%d note_id=%d priority=%s title=%s",
        int(owner_id),
        int(row.id),
        priority,
        truncate_text(title, 120),
    )
    return {"ok": True, "note_id": int(row.id), "title": title}


def run_self_improvement_cycle_with_new_session(owner_id: int, trigger: str = "chat") -> dict:
    db = SessionLocal()
    try:
        return run_self_improvement_cycle(db, int(owner_id), trigger=trigger)
    except Exception as exc:
        db.rollback()
        log.warning("SELF_IMPROVE_FAIL owner=%d trigger=%s error=%s", int(owner_id), truncate_text(trigger, 80), truncate_text(str(exc), 220))
        return {"ok": False, "error": str(exc)}
    finally:
        db.close()


def retrieve_relevant_self_improvement_notes(owner_id: int, query_text: str, top_k: int = 2) -> list[str]:
    limit = clamp_int(top_k, 1, 6, SELF_IMPROVE_RETRIEVE_TOP_K)
    db = SessionLocal()
    try:
        mem_vectors = (
            db.query(MemoryVector)
            .filter(
                MemoryVector.owner_id == int(owner_id),
                MemoryVector.memory_type == "self_improvement_note",
            )
            .order_by(MemoryVector.id.desc())
            .limit(400)
            .all()
        )
        if not mem_vectors:
            return []

        query_vec = get_embedding(query_text)
        query_terms = _memory_terms(query_text)
        scored: list[tuple[float, str]] = []
        for mv in mem_vectors:
            stored_vec = bytes_to_embedding(mv.embedding)
            sim = cosine_similarity(query_vec, stored_vec)
            if sim <= 0.10:
                continue
            text = _memory_preview_text(mv.text_preview or "", max_len=240)
            overlap = _token_overlap_score(_memory_terms(text), query_terms)
            total = (sim * 0.78) + (overlap * 0.22)
            scored.append((total, text))

        scored.sort(key=lambda item: item[0], reverse=True)
        selected: list[str] = []
        for _, item in scored:
            if item in selected:
                continue
            selected.append(item)
            if len(selected) >= limit:
                break
        return selected
    except Exception as exc:
        log.warning("SELF_IMPROVE_RETRIEVE_FAIL owner=%d error=%s", int(owner_id), truncate_text(str(exc), 220))
        return []
    finally:
        db.close()


def _capability_keyword_score(text: str, keywords: tuple[str, ...]) -> int:
    lowered = str(text or "").lower()
    hits = 0
    for keyword in keywords:
        if keyword and keyword in lowered:
            hits += 1
    return hits


def _expire_capabilities_db(db: Session, owner_id: int) -> int:
    now_dt = datetime.utcnow().replace(tzinfo=None)
    rows = (
        db.query(CapabilityActivation)
        .filter(
            CapabilityActivation.owner_id == int(owner_id),
            CapabilityActivation.state == "active",
            CapabilityActivation.expires_at <= now_dt,
        )
        .all()
    )
    if not rows:
        return 0
    for row in rows:
        row.state = "expired"
    return len(rows)


def _prune_capability_overflow_db(db: Session, owner_id: int) -> int:
    stale_rows = (
        db.query(CapabilityActivation.id)
        .filter(CapabilityActivation.owner_id == int(owner_id))
        .order_by(CapabilityActivation.id.desc())
        .offset(CAPABILITY_MAX_EVENTS_PER_USER)
        .all()
    )
    prune_ids = [int(row[0]) for row in stale_rows]
    if not prune_ids:
        return 0
    db.query(CapabilityActivation).filter(
        CapabilityActivation.owner_id == int(owner_id),
        CapabilityActivation.id.in_(prune_ids),
    ).delete(synchronize_session=False)
    return len(prune_ids)


def _active_capability_list_db(db: Session, owner_id: int) -> list[str]:
    now_dt = datetime.utcnow().replace(tzinfo=None)
    rows = (
        db.query(CapabilityActivation)
        .filter(
            CapabilityActivation.owner_id == int(owner_id),
            CapabilityActivation.state == "active",
            CapabilityActivation.expires_at > now_dt,
        )
        .order_by(CapabilityActivation.id.desc())
        .all()
    )
    active: list[str] = []
    for row in rows:
        capability = str(row.capability or "").strip()
        if capability and capability not in active:
            active.append(capability)
    return active


def activate_dormant_capabilities(db: Session, owner_id: int, trigger_text: str) -> list[str]:
    now_dt = datetime.utcnow().replace(tzinfo=None)
    trigger = truncate_text(str(trigger_text or ""), 600)
    if not trigger:
        active = _active_capability_list_db(db, int(owner_id))
        RUNTIME_STATE["dormant_capabilities_active"] = active
        return active

    expired = _expire_capabilities_db(db, int(owner_id))
    new_activations = 0
    touched = expired > 0
    for capability, meta in DORMANT_CAPABILITY_RULES.items():
        keywords = tuple(meta.get("keywords") or ())
        score = _capability_keyword_score(trigger, keywords)
        if score <= 0:
            continue

        row = (
            db.query(CapabilityActivation)
            .filter(
                CapabilityActivation.owner_id == int(owner_id),
                CapabilityActivation.capability == capability,
                CapabilityActivation.state == "active",
                CapabilityActivation.expires_at > now_dt,
            )
            .order_by(CapabilityActivation.id.desc())
            .first()
        )

        reason = truncate_text(str(meta.get("reason") or "Capability activated by intent signal."), 240)
        ttl = timedelta(seconds=CAPABILITY_ACTIVATION_TTL_SECONDS)
        if row is None:
            row = CapabilityActivation(
                owner_id=int(owner_id),
                capability=capability,
                state="active",
                trigger_text=trigger,
                reason=reason,
                score=min(100, score * 20),
                activated_at=now_dt,
                expires_at=now_dt + ttl,
            )
            db.add(row)
            new_activations += 1
            touched = True
            log.info("DORMANT_CAPABILITY_ACTIVATE owner=%d capability=%s score=%d", int(owner_id), capability, int(score))
        else:
            row.trigger_text = trigger
            row.reason = reason
            row.score = min(100, max(int(row.score or 0), score * 20))
            row.expires_at = max(row.expires_at, now_dt) + timedelta(seconds=int(CAPABILITY_ACTIVATION_TTL_SECONDS * 0.35))
            touched = True

    if touched:
        _prune_capability_overflow_db(db, int(owner_id))
        db.commit()

    active = _active_capability_list_db(db, int(owner_id))
    RUNTIME_STATE["dormant_capabilities_active"] = active
    if new_activations > 0:
        RUNTIME_STATE["dormant_activations_total"] = int(RUNTIME_STATE.get("dormant_activations_total", 0)) + int(new_activations)
        RUNTIME_STATE["dormant_last_activation_at"] = utc_now_iso()
    return active


def activate_dormant_capabilities_with_new_session(owner_id: int, trigger_text: str) -> list[str]:
    db = SessionLocal()
    try:
        return activate_dormant_capabilities(db, int(owner_id), trigger_text)
    except Exception as exc:
        db.rollback()
        log.warning("DORMANT_CAPABILITY_FAIL owner=%d error=%s", int(owner_id), truncate_text(str(exc), 220))
        return []
    finally:
        db.close()


def get_active_capabilities(db: Session, owner_id: int) -> list[str]:
    touched = _expire_capabilities_db(db, int(owner_id))
    if touched:
        db.commit()
    active = _active_capability_list_db(db, int(owner_id))
    RUNTIME_STATE["dormant_capabilities_active"] = active
    return active


def run_post_conversation_reflection(db: Session, owner_id: int):
    """Run reflection after a conversation and store any lessons learned."""
    try:
        lessons = reflect_on_conversation(db, owner_id)
        for lesson_data in lessons:
            lesson_text = lesson_data.get("lesson", "")
            context_text = lesson_data.get("context", "")
            if lesson_text:
                store_lesson(db, owner_id, lesson_text, context_text)
                # Pillar 2: Create episodic memory from each lesson
                if EPISODIC_MEMORY_ENABLED and context_text:
                    store_episodic_memory(
                        db=db,
                        owner_id=owner_id,
                        situation=context_text,
                        action_taken=lesson_text,
                        outcome="success",
                        source_type="chat",
                        source_ref=f"reflection:{owner_id}",
                    )
        prune_lesson_overflow(db, owner_id)
    except Exception as exc:
        log.warning("POST_REFLECTION_FAILED: %s", exc)


def build_system_prompt(
    identity: dict | None,
    lessons: list[str] | None = None,
    conversation_summaries: list[str] | None = None,
    task_artifacts: list[str] | None = None,
    world_model_signals: list[str] | None = None,
    self_improvement_notes: list[str] | None = None,
    active_skills: list[str] | None = None,
    active_capabilities: list[str] | None = None,
    tool_perf_stats: list[dict] | None = None,
    episodic_memories: list[dict] | None = None,
    tool_chaining_hints: list[str] | None = None,
    environment_state: dict | None = None,
) -> str:
    """Build the system prompt from the IdentityKernel + any relevant past lessons."""
    if identity is None:
        base = (
            "You are Mind Clone, an autonomous AI agent. "
            "You can use tools to search the web, read/write files, list directories, and run shell commands. "
            "Think step by step. If a task requires multiple steps, use tools iteratively until done. "
            "Be direct and concise in your responses."
        )
    else:
        # Identity-infused system prompt
        parts = [
            f"IDENTITY: {identity['origin_statement']}",
            "",
            "CORE VALUES:",
        ]
        for v in identity["core_values"]:
            parts.append(f"- {v}")

        parts.append("")
        parts.append("AUTONOMY DIRECTIVES (operator-defined defaults):")
        for key, value in identity["authority_bounds"].items():
            parts.append(f"- {key}: {value}")

        parts.append("")
        parts.append(
            "You are an autonomous agent with access to tools. "
            "Think step by step. Use tools iteratively to accomplish tasks. "
            "Prioritize end-to-end autonomous execution. "
            "If a hard runtime constraint blocks an action, explain briefly and continue with the best alternative. "
            "Be direct and concise."
        )
        base = "\n".join(parts)

    # Inject relevant lessons from past experience
    if lessons:
        lesson_block = "\n\nLESSONS FROM PAST EXPERIENCE (apply these when relevant):\n"
        for i, lesson in enumerate(lessons, 1):
            lesson_block += f"{i}. {lesson}\n"
        base += lesson_block

    if conversation_summaries:
        summary_block = "\n\nCOMPACTED EPISODIC MEMORY (older context condensed):\n"
        for i, item in enumerate(conversation_summaries, 1):
            summary_block += f"{i}. {item}\n"
        base += summary_block

    if task_artifacts:
        artifact_block = "\n\nTASK ARTIFACT MEMORY (reusable prior outcomes):\n"
        for i, item in enumerate(task_artifacts, 1):
            artifact_block += f"{i}. {item}\n"
        base += artifact_block

    if world_model_signals:
        world_block = "\n\nWORLD MODEL SIGNALS (predicted cause/effect from prior outcomes):\n"
        for i, item in enumerate(world_model_signals, 1):
            world_block += f"{i}. {item}\n"
        base += world_block

    if self_improvement_notes:
        improve_block = "\n\nSELF-IMPROVEMENT PLAYBOOK (recent internal upgrades):\n"
        for i, item in enumerate(self_improvement_notes, 1):
            improve_block += f"{i}. {item}\n"
        base += improve_block

    if active_skills:
        skill_block = "\n\nACTIVE SKILLS (owner/runtime generated operating playbooks):\n"
        for i, item in enumerate(active_skills, 1):
            skill_block += f"{i}. {item}\n"
        base += skill_block

    if active_capabilities:
        cap_block = "\n\nACTIVE CAPABILITY MODES:\n"
        for item in active_capabilities:
            cap_block += f"- {item}\n"
        base += cap_block

    # Pillar 7: Inject environment state
    if environment_state:
        env_block = format_environment_state_for_prompt(environment_state)
        if env_block:
            base += env_block

    # Pillar 5: Inject tool chaining hints
    if tool_chaining_hints:
        hints_block = "\n\nTOOL CHAINING HINTS:\n"
        for hint in tool_chaining_hints:
            hints_block += f"- {hint}\n"
        base += hints_block

    # Pillar 2: Inject episodic memories
    if episodic_memories:
        ep_block = format_episodes_for_prompt(episodic_memories)
        if ep_block:
            base += ep_block

    # Pillar 6: Inject tool performance stats
    if tool_perf_stats:
        perf_block = format_tool_perf_for_prompt(tool_perf_stats)
        if perf_block:
            base += perf_block

    return base


# ---------------------------------------------------------------------------
# Pillar 3: Autonomy — Multi-Day Goal System
# ---------------------------------------------------------------------------

def create_goal(
    db: Session,
    owner_id: int,
    title: str,
    description: str = "",
    success_criteria: str = "",
    priority: str = "medium",
    deadline: datetime | None = None,
) -> dict:
    """Create a new goal and optionally decompose it into initial tasks."""
    if not GOAL_SYSTEM_ENABLED:
        return {"ok": False, "error": "Goal system disabled"}
    existing = db.query(func.count(Goal.id)).filter(
        Goal.owner_id == int(owner_id),
        Goal.status.in_(["active", "paused"]),
    ).scalar() or 0
    if existing >= GOAL_MAX_PER_USER:
        return {"ok": False, "error": f"Too many active goals (max {GOAL_MAX_PER_USER})"}
    goal = Goal(
        owner_id=int(owner_id),
        title=truncate_text(str(title), 200),
        description=truncate_text(str(description or ""), 1000),
        success_criteria=truncate_text(str(success_criteria or ""), 500),
        priority=str(priority or "medium")[:10],
        deadline=deadline,
    )
    db.add(goal)
    db.commit()
    db.refresh(goal)
    log.info("GOAL_CREATED id=%d owner=%d title=%s", goal.id, owner_id, goal.title[:60])
    return {"ok": True, "goal_id": int(goal.id), "title": goal.title}


def decompose_goal_into_tasks(
    db: Session,
    goal: "Goal",
    identity: dict | None = None,
) -> list[int]:
    """Use LLM to generate 1-3 tasks from a goal."""
    if not GOAL_SYSTEM_ENABLED:
        return []
    prompt = (
        f"Break this goal into {GOAL_MAX_TASKS_PER_BATCH} concrete, actionable tasks.\n"
        f"Goal: {goal.title}\n"
        f"Description: {goal.description or 'N/A'}\n"
        f"Success criteria: {goal.success_criteria or 'N/A'}\n\n"
        "Return strict JSON: {\"tasks\": [{\"title\": \"...\", \"description\": \"...\"}]}\n"
        f"Return at most {GOAL_MAX_TASKS_PER_BATCH} tasks. Each task should be completable in one session."
    )
    try:
        response = call_llm(
            messages=[
                {"role": "system", "content": "You are a task planner. Return JSON only."},
                {"role": "user", "content": prompt},
            ],
            tools=None,
            owner_id=int(goal.owner_id),
            source_type="goal",
            source_ref=f"goal:{goal.id}",
        )
        if not response or not response.get("choices"):
            return []
        raw = str(response["choices"][0].get("message", {}).get("content", "")).strip()
        parsed = _safe_json_dict(raw, None)
        if parsed is None:
            json_match = re.search(r"\{.*\}", raw, re.DOTALL)
            parsed = _safe_json_dict(json_match.group(), {}) if json_match else {}
        tasks_data = list(parsed.get("tasks") or [])[:GOAL_MAX_TASKS_PER_BATCH]
        task_ids = []
        planner_identity = identity or load_identity(db, int(goal.owner_id))
        planner_agent_uuid = str((planner_identity or {}).get("agent_uuid") or str(uuid.uuid4()))
        for td in tasks_data:
            t_title = truncate_text(str(td.get("title", "")), 200)
            t_desc = truncate_text(str(td.get("description", "")), 800)
            if not t_title:
                continue
            new_task = Task(
                owner_id=int(goal.owner_id),
                agent_uuid=planner_agent_uuid,
                title=t_title,
                description=t_desc,
                status=TASK_STATUS_QUEUED,
                plan=[],
            )
            db.add(new_task)
            db.flush()
            task_ids.append(int(new_task.id))
        existing_ids = json.loads(goal.task_ids_json or "[]")
        goal.task_ids_json = json.dumps(existing_ids + task_ids)
        db.commit()
        log.info("GOAL_DECOMPOSED goal=%d tasks_created=%d", goal.id, len(task_ids))
        return task_ids
    except Exception:
        log.warning("GOAL_DECOMPOSE_FAIL goal=%d", goal.id, exc_info=True)
        return []


def update_goal_progress(db: Session, goal: "Goal") -> int:
    """Recalculate goal progress from task statuses."""
    try:
        task_ids = json.loads(goal.task_ids_json or "[]")
        if not task_ids:
            return 0
        tasks = db.query(Task).filter(Task.id.in_(task_ids)).all()
        if not tasks:
            return 0
        done = sum(1 for t in tasks if t.status in (TASK_STATUS_DONE,))
        total = len(tasks)
        pct = int(100 * done / total) if total > 0 else 0
        goal.progress_pct = pct
        if pct >= 100:
            goal.status = "completed"
        db.commit()
        return pct
    except Exception:
        return int(goal.progress_pct or 0)


def check_goal_needs_new_tasks(db: Session, goal: "Goal", identity: dict | None = None) -> list[int]:
    """If all tasks for a goal are done but goal is not complete, create new batch."""
    try:
        task_ids = json.loads(goal.task_ids_json or "[]")
        if not task_ids:
            return decompose_goal_into_tasks(db, goal, identity)
        tasks = db.query(Task).filter(Task.id.in_(task_ids)).all()
        all_terminal = all(t.status in (TASK_STATUS_DONE, TASK_STATUS_FAILED, TASK_STATUS_CANCELLED) for t in tasks)
        if all_terminal and goal.status == "active" and goal.progress_pct < 100:
            return decompose_goal_into_tasks(db, goal, identity)
        return []
    except Exception:
        return []


def list_goals(db: Session, owner_id: int, status_filter: str | None = None) -> list[dict]:
    """List goals for an owner."""
    q = db.query(Goal).filter(Goal.owner_id == int(owner_id))
    if status_filter:
        q = q.filter(Goal.status == status_filter)
    goals = q.order_by(Goal.created_at.desc()).limit(GOAL_MAX_PER_USER).all()
    return [
        {
            "id": g.id,
            "title": g.title,
            "status": g.status,
            "progress_pct": g.progress_pct,
            "priority": g.priority,
            "task_count": len(json.loads(g.task_ids_json or "[]")),
            "created_at": str(g.created_at),
        }
        for g in goals
    ]


def run_goal_supervisor(db: Session) -> int:
    """Check active goals, update progress, create new tasks if needed. Called from heartbeat."""
    if not GOAL_SYSTEM_ENABLED:
        return 0
    processed = 0
    try:
        active_goals = db.query(Goal).filter(Goal.status == "active").limit(50).all()
        for goal in active_goals:
            update_goal_progress(db, goal)
            if goal.status == "active":
                new_tasks = check_goal_needs_new_tasks(db, goal)
                if new_tasks:
                    processed += len(new_tasks)
            # Deadline warning
            if goal.deadline and goal.status == "active":
                remaining = (goal.deadline - datetime.now(timezone.utc)).total_seconds()
                if 0 < remaining < 86400:  # Less than 24 hours
                    user = db.query(User).filter(User.id == goal.owner_id).first()
                    if user and user.telegram_chat_id:
                        send_task_progress_sync(
                            user.telegram_chat_id,
                            goal.id,
                            f"Goal deadline approaching: '{goal.title}' ({goal.progress_pct}% done)",
                        )
    except Exception:
        log.debug("GOAL_SUPERVISOR_FAIL", exc_info=True)
    return processed


# ---------------------------------------------------------------------------
# Pillar 2: Episodic Memory — Store & Retrieve past experiences
# ---------------------------------------------------------------------------

def store_episodic_memory(
    db: Session,
    owner_id: int,
    situation: str,
    action_taken: str,
    outcome: str = "success",
    outcome_detail: str | None = None,
    tools_used: list[str] | None = None,
    source_type: str = "chat",
    source_ref: str | None = None,
) -> int | None:
    """Store an episodic memory and its vector embedding."""
    if not EPISODIC_MEMORY_ENABLED or not situation or not action_taken:
        return None
    try:
        ep = EpisodicMemory(
            owner_id=int(owner_id),
            situation=truncate_text(str(situation), 500),
            action_taken=truncate_text(str(action_taken), 500),
            outcome=str(outcome or "success")[:20],
            outcome_detail=truncate_text(str(outcome_detail or ""), 300) or None,
            tools_used_json=json.dumps(tools_used or [], ensure_ascii=False),
            source_type=str(source_type or "chat")[:20],
            source_ref=truncate_text(str(source_ref or ""), 100) or None,
        )
        db.add(ep)
        db.flush()
        # Also create a MemoryVector for semantic retrieval
        embed_text = f"{situation} | {action_taken} | {outcome}"
        vec = compute_embedding(embed_text)
        if vec is not None:
            db.add(MemoryVector(
                owner_id=int(owner_id),
                source_type="episodic_memory",
                source_id=int(ep.id),
                text=truncate_text(embed_text, 600),
                vector_json=json.dumps(vec.tolist() if hasattr(vec, "tolist") else list(vec)),
            ))
        db.commit()
        return int(ep.id)
    except Exception:
        log.debug("EPISODIC_MEMORY store failed", exc_info=True)
        try:
            db.rollback()
        except Exception:
            pass
        return None


def retrieve_relevant_episodes(
    owner_id: int,
    query: str,
    top_k: int | None = None,
) -> list[dict]:
    """Retrieve episodic memories relevant to a query using hybrid scoring."""
    if not EPISODIC_MEMORY_ENABLED or not query:
        return []
    k = int(top_k or EPISODIC_MEMORY_RETRIEVE_TOP_K)
    try:
        query_vec = compute_embedding(query)
        db = SessionLocal()
        episodes = (
            db.query(EpisodicMemory)
            .filter(EpisodicMemory.owner_id == int(owner_id))
            .order_by(EpisodicMemory.created_at.desc())
            .limit(200)
            .all()
        )
        if not episodes:
            return []

        # Get memory vectors for scoring
        ep_ids = [e.id for e in episodes]
        vectors = {}
        if query_vec is not None:
            mem_vecs = (
                db.query(MemoryVector)
                .filter(
                    MemoryVector.owner_id == int(owner_id),
                    MemoryVector.source_type == "episodic_memory",
                    MemoryVector.source_id.in_(ep_ids),
                )
                .all()
            )
            for mv in mem_vecs:
                try:
                    vec = json.loads(mv.vector_json)
                    vectors[mv.source_id] = vec
                except Exception:
                    pass

        query_words = set(query.lower().split())
        now_ts = time.time()
        scored = []
        for ep in episodes:
            # Cosine similarity (60%)
            cosine_score = 0.0
            if query_vec is not None and ep.id in vectors:
                cosine_score = float(cosine_similarity(query_vec, vectors[ep.id]))

            # Keyword overlap (18%)
            ep_text = f"{ep.situation} {ep.action_taken}".lower()
            ep_words = set(ep_text.split())
            overlap = len(query_words & ep_words)
            keyword_score = min(1.0, overlap / max(1, len(query_words)))

            # Recency (12%) — decay over 30 days
            ep_age_days = (now_ts - ep.created_at.timestamp()) / 86400.0 if ep.created_at else 30.0
            recency_score = max(0.0, 1.0 - ep_age_days / 30.0)

            # Failure boost (10%) — prioritize learning from failures
            failure_boost = 1.0 if ep.outcome in ("failure", "partial") else 0.0

            total = 0.60 * cosine_score + 0.18 * keyword_score + 0.12 * recency_score + 0.10 * failure_boost
            scored.append((total, ep))

        scored.sort(key=lambda x: x[0], reverse=True)
        results = []
        for score, ep in scored[:k]:
            results.append({
                "situation": ep.situation,
                "action": ep.action_taken,
                "outcome": ep.outcome,
                "detail": ep.outcome_detail or "",
                "tools": json.loads(ep.tools_used_json) if ep.tools_used_json else [],
                "score": round(score, 3),
            })
        return results
    except Exception:
        log.debug("EPISODIC_MEMORY retrieve failed", exc_info=True)
        return []


def format_episodes_for_prompt(episodes: list[dict]) -> str:
    """Format episodic memories as a prompt block."""
    if not episodes:
        return ""
    lines = ["\n\nEPISODIC MEMORY (similar past situations):"]
    for i, ep in enumerate(episodes, 1):
        outcome_icon = {"success": "+", "partial": "~", "failure": "-"}.get(ep["outcome"], "?")
        lines.append(f"{i}. [{outcome_icon}] Situation: {ep['situation']}")
        lines.append(f"   Action: {ep['action']} -> {ep['outcome']}")
        if ep.get("detail"):
            lines.append(f"   Detail: {ep['detail']}")
    return "\n".join(lines)


def prune_episodic_memories(owner_id: int, max_count: int | None = None) -> int:
    """Keep only the most recent N episodic memories per user."""
    limit = int(max_count or EPISODIC_MEMORY_MAX_PER_USER)
    deleted = 0
    try:
        db = SessionLocal()
        total = db.query(func.count(EpisodicMemory.id)).filter(
            EpisodicMemory.owner_id == int(owner_id)
        ).scalar() or 0
        if total <= limit:
            return 0
        excess = int(total - limit)
        oldest = (
            db.query(EpisodicMemory.id)
            .filter(EpisodicMemory.owner_id == int(owner_id))
            .order_by(EpisodicMemory.created_at.asc())
            .limit(excess)
            .all()
        )
        if oldest:
            ids = [r.id for r in oldest]
            db.query(EpisodicMemory).filter(EpisodicMemory.id.in_(ids)).delete(synchronize_session=False)
            db.query(MemoryVector).filter(
                MemoryVector.source_type == "episodic_memory",
                MemoryVector.source_id.in_(ids),
            ).delete(synchronize_session=False)
            deleted = len(ids)
            db.commit()
    except Exception:
        log.debug("EPISODIC_MEMORY prune failed", exc_info=True)
    return deleted


# ---------------------------------------------------------------------------
# Pillar 6: Tool Performance Recording & Retrieval
# ---------------------------------------------------------------------------

def _classify_tool_error(error_str: str) -> str:
    """Classify a tool error into a category."""
    e = (error_str or "").lower()
    if "timeout" in e or "timed out" in e:
        return "timeout"
    if "permission" in e or "denied" in e or "blocked" in e or "forbidden" in e:
        return "permission"
    if "json" in e or "parse" in e or "decode" in e or "invalid" in e:
        return "parse_error"
    if "api" in e or "http" in e or "status" in e or "rate" in e or "quota" in e:
        return "api_error"
    if "not found" in e or "unknown tool" in e:
        return "not_found"
    return "unknown"


def record_tool_performance(
    owner_id: int | None,
    tool_name: str,
    source_type: str,
    success: bool,
    duration_ms: int,
    error_str: str | None = None,
) -> None:
    """Record a tool execution into ToolPerformanceLog."""
    if not TOOL_PERF_TRACKING_ENABLED or owner_id is None:
        return
    error_category = None if success else _classify_tool_error(error_str)
    try:
        db = SessionLocal()
        db.add(ToolPerformanceLog(
            owner_id=int(owner_id),
            tool_name=str(tool_name or "unknown"),
            source_type=str(source_type or "chat"),
            success=1 if success else 0,
            duration_ms=max(0, int(duration_ms)),
            error_category=error_category,
        ))
        db.commit()
    except Exception:
        log.debug("TOOL_PERF record failed tool=%s", tool_name, exc_info=True)


def get_tool_performance_stats(owner_id: int, days: int = 7) -> list[dict]:
    """Get aggregated tool performance stats for an owner over N days."""
    if not TOOL_PERF_TRACKING_ENABLED:
        return []
    cutoff = datetime.utcnow() - timedelta(days=days)
    try:
        db = SessionLocal()
        rows = (
            db.query(
                ToolPerformanceLog.tool_name,
                func.count(ToolPerformanceLog.id).label("total"),
                func.sum(ToolPerformanceLog.success).label("successes"),
                func.avg(ToolPerformanceLog.duration_ms).label("avg_ms"),
            )
            .filter(
                ToolPerformanceLog.owner_id == int(owner_id),
                ToolPerformanceLog.created_at >= cutoff,
            )
            .group_by(ToolPerformanceLog.tool_name)
            .order_by(func.count(ToolPerformanceLog.id).desc())
            .limit(TOOL_PERF_INJECT_TOP_K)
            .all()
        )
        stats = []
        for row in rows:
            total = int(row.total or 0)
            successes = int(row.successes or 0)
            rate = round(100.0 * successes / total, 0) if total > 0 else 0
            stats.append({
                "tool": row.tool_name,
                "total": total,
                "success_rate": rate,
                "avg_ms": int(row.avg_ms or 0),
            })
        return stats
    except Exception:
        log.debug("TOOL_PERF stats query failed", exc_info=True)
        return []


def format_tool_perf_for_prompt(stats: list[dict]) -> str:
    """Format tool performance stats as a prompt block."""
    if not stats:
        return ""
    lines = ["\n\nTOOL PERFORMANCE (last 7 days):"]
    for s in stats:
        lines.append(f"- {s['tool']}: {s['success_rate']:.0f}% success ({s['total']} calls, avg {s['avg_ms']}ms)")
    return "\n".join(lines)


def prune_tool_performance_logs(max_age_days: int | None = None, max_records: int = 5000) -> int:
    """Prune old tool performance logs."""
    age = int(max_age_days or TOOL_PERF_MAX_AGE_DAYS)
    cutoff = datetime.utcnow() - timedelta(days=age)
    deleted = 0
    try:
        db = SessionLocal()
        deleted = db.query(ToolPerformanceLog).filter(
            ToolPerformanceLog.created_at < cutoff,
        ).delete(synchronize_session=False)
        total = db.query(func.count(ToolPerformanceLog.id)).scalar() or 0
        if total > max_records:
            excess = int(total - max_records)
            oldest_ids = (
                db.query(ToolPerformanceLog.id)
                .order_by(ToolPerformanceLog.created_at.asc())
                .limit(excess)
                .all()
            )
            if oldest_ids:
                db.query(ToolPerformanceLog).filter(
                    ToolPerformanceLog.id.in_([r.id for r in oldest_ids])
                ).delete(synchronize_session=False)
                deleted += len(oldest_ids)
        db.commit()
    except Exception:
        log.debug("TOOL_PERF prune failed", exc_info=True)
    return deleted


def should_force_deep_research_prompt(user_message: str) -> bool:
    text = (user_message or "").strip().lower()
    if not text:
        return False
    if text.startswith("/"):
        return False
    if text.startswith("research ") or text.startswith("research:") or text.startswith("research\""):
        return True
    if "deep_research" in text:
        return True

    has_research_signal = any(
        marker in text
        for marker in (
            "research",
            "compare",
            "comparison",
            "benchmark",
            "best",
            "latest",
            "trend",
            "vs ",
            " versus ",
        )
    )
    has_citation_signal = any(
        marker in text
        for marker in (
            "source",
            "sources",
            "source links",
            "citation",
            "citations",
            "cite",
            "evidence",
        )
    )
    return has_research_signal and has_citation_signal


def extract_forced_research_query(user_message: str) -> str:
    text = (user_message or "").strip()
    if not text:
        return ""

    quoted = re.search(r"\"([^\"]{8,400})\"", text)
    if quoted:
        return quoted.group(1).strip()

    text = re.sub(r"^\s*research\b[:\s-]*", "", text, flags=re.IGNORECASE).strip()
    if not text:
        return (user_message or "").strip()
    return text


def format_forced_deep_research_response(query: str, result: dict) -> str:
    if not isinstance(result, dict):
        return "Research failed: unexpected tool result format."
    if not result.get("ok"):
        return f"Research failed: {result.get('error', 'unknown error')}"

    answer = (result.get("answer_brief") or "").strip()
    sources = result.get("sources") or []
    warnings = result.get("warnings") or []

    lines = []
    if answer:
        lines.append(answer)
    else:
        lines.append(f"Research completed for: {query}")

    if sources:
        lines.append("")
        lines.append("Sources:")
        for idx, src in enumerate(sources[:8], 1):
            title = str(src.get("title") or src.get("url") or "").strip()
            url = str(src.get("url") or "").strip()
            if not title and not url:
                continue
            if len(title) > 110:
                title = title[:110] + "..."
            if url:
                lines.append(f"{idx}. {title}\n{url}")
            else:
                lines.append(f"{idx}. {title}")

    if warnings:
        lines.append("")
        lines.append("Notes: " + "; ".join(str(w) for w in warnings[:2]))

    final_text = "\n".join(lines).strip()
    if len(final_text) > 3200:
        final_text = final_text[:3200] + "\n...[TRUNCATED]"
    return final_text


def run_forced_deep_research(
    db: Session,
    owner_id: int,
    identity: dict | None,
    user_message: str,
    blackbox_session_id: str | None = None,
) -> str:
    session_id = str(blackbox_session_id or "").strip() or _blackbox_session_id("chat", owner_id, "forced_research")
    run_budget = create_run_budget("forced_research", owner_id, session_id)
    query = extract_forced_research_query(user_message)
    if not query:
        record_blackbox_event(
            db=db,
            owner_id=owner_id,
            session_id=session_id,
            source_type="chat",
            source_ref=str(owner_id),
            event_type="forced_research_invalid_query",
            payload={"user_message": truncate_text(user_message, 240)},
        )
        return "Research failed: empty query."

    tool_args = {
        "query": query,
        "max_sources": 10,
        "max_runtime_sec": 120,
    }
    call_id = f"forced_deep_research_{uuid.uuid4().hex[:10]}"
    synthetic_tool_call = [{
        "id": call_id,
        "type": "function",
        "function": {
            "name": "deep_research",
            "arguments": json.dumps(tool_args, ensure_ascii=False),
        },
    }]

    save_message(
        db,
        owner_id,
        "assistant",
        content=None,
        tool_calls=synthetic_tool_call,
    )
    log.info("FORCED_DEEP_RESEARCH query=%s", query)
    record_blackbox_event(
        db=db,
        owner_id=owner_id,
        session_id=session_id,
        source_type="chat",
        source_ref=str(owner_id),
        event_type="forced_research_start",
        payload={"query": truncate_text(query, 220)},
    )

    try:
        result = execute_tool_with_context(
            identity=identity,
            tool_name="deep_research",
            args=tool_args,
            owner_id=owner_id,
            source_type="chat",
            source_ref=str(owner_id),
            blackbox_session_id=session_id,
            run_budget=run_budget,
        )
    except Exception as exc_dr:
        log.error("DEEP_RESEARCH_CRASH error=%s", exc_dr, exc_info=True)
        result = {"ok": False, "error": f"Deep research crashed: {exc_dr}"}
    result_str = json.dumps(result, ensure_ascii=False)
    if len(result_str) > 10000:
        result_str = result_str[:10000] + "...[TRUNCATED]"

    save_message(db, owner_id, "tool", content=result_str, tool_call_id=call_id)

    final_text = format_forced_deep_research_response(query, result)
    save_message(db, owner_id, "assistant", content=final_text)
    record_blackbox_event(
        db=db,
        owner_id=owner_id,
        session_id=session_id,
        source_type="chat",
        source_ref=str(owner_id),
        event_type="forced_research_final",
        payload={
            "query": truncate_text(query, 220),
            "ok": bool(result.get("ok", False)) if isinstance(result, dict) else False,
            "response_preview": truncate_text(final_text, 320),
        },
    )
    return final_text


# ============================================================================
# SECTION 5: AUTONOMY DIRECTIVES CHECKER
# ============================================================================

def active_tool_policy_profile() -> str:
    if full_power_system_enabled():
        return "power"
    return TOOL_POLICY_PROFILE if TOOL_POLICY_PROFILE in TOOL_POLICY_PROFILES else "balanced"


def active_tool_policy() -> dict:
    return TOOL_POLICY_PROFILES.get(active_tool_policy_profile(), TOOL_POLICY_PROFILES["balanced"])


def profile_chat_tool_loop_limit() -> int:
    policy = active_tool_policy()
    return clamp_int(policy.get("chat_tool_loops"), 3, 1000000, MAX_TOOL_LOOPS)


def profile_task_tool_loop_limit() -> int:
    policy = active_tool_policy()
    return clamp_int(policy.get("task_tool_loops"), 2, 12, TASK_MAX_TOOL_LOOPS)


def tool_policy_write_roots() -> list[Path]:
    roots = [Path.cwd().resolve(strict=False)]
    roots.extend(TOOL_POLICY_ALLOW_EXTRA_WRITE_ROOTS)
    deduped: list[Path] = []
    seen: set[str] = set()
    for root in roots:
        key = str(root).lower()
        if key in seen:
            continue
        seen.add(key)
        deduped.append(root)
    return deduped


def _is_path_within_root(candidate: Path, root: Path) -> bool:
    try:
        candidate.relative_to(root)
        return True
    except Exception:
        return False


def _resolve_write_target(path_value: str) -> Path:
    raw = (path_value or "").strip()
    target = Path(os.path.expandvars(raw)).expanduser()
    if target.is_absolute():
        return target.resolve(strict=False)
    return (Path.cwd() / target).resolve(strict=False)


def _normalize_tool_rel_path(raw_value: str) -> str:
    text = str(raw_value or "").strip()
    if not text:
        return ""
    text = text.replace("\\", "/")
    while text.startswith("./"):
        text = text[2:]
    return text


def _resolve_tool_path_input(raw_value: str) -> tuple[Path, str]:
    """Resolve a tool-supplied path into an absolute path.

    Returns (resolved_path, base_used) where base_used is one of:
    - "absolute": input was absolute (or drive-qualified)
    - "repo": resolved relative to REPO_ROOT_DIR
    - "core": resolved relative to APP_DIR
    - "process": resolved relative to process cwd (TOOL_PATH_RESOLUTION_MODE=off)
    """
    raw = str(raw_value or "").strip()
    expanded = os.path.expandvars(raw)
    expanded = os.path.expanduser(expanded)

    # Treat drive-qualified paths like "C:foo" as explicitly anchored to a drive.
    if re.match(r"^[a-zA-Z]:", expanded):
        return Path(expanded).resolve(strict=False), "absolute"

    candidate = Path(expanded).expanduser()
    if candidate.is_absolute():
        return candidate.resolve(strict=False), "absolute"

    norm = _normalize_tool_rel_path(expanded)
    mode = str(TOOL_PATH_RESOLUTION_MODE or "auto").strip().lower()
    if mode == "off":
        return (Path.cwd() / norm).resolve(strict=False), "process"

    if mode == "repo":
        base = REPO_ROOT_DIR
        base_label = "repo"
    elif mode == "core":
        base = APP_DIR
        base_label = "core"
    else:
        first = norm.split("/", 1)[0].strip().lower() if norm else ""
        if first in REPO_ROOT_RELATIVE_PREFIXES_SET:
            base = REPO_ROOT_DIR
            base_label = "repo"
        else:
            base = APP_DIR
            base_label = "core"

    return (base / norm).resolve(strict=False), base_label


def _command_mentions_repo_root_prefix(command: str) -> bool:
    blob = str(command or "").lower()
    for prefix in REPO_ROOT_RELATIVE_PREFIXES_SET:
        if f"{prefix}/" in blob or f"{prefix}\\" in blob:
            return True
    return False


def _default_cwd_for_tool_command(command: str) -> tuple[Path | None, str]:
    mode = str(TOOL_DEFAULT_CWD_MODE or "auto").strip().lower()
    if mode == "process":
        return None, "process"
    if mode == "repo":
        return REPO_ROOT_DIR, "repo"
    if mode == "core":
        return APP_DIR, "core"
    # auto
    if _command_mentions_repo_root_prefix(command):
        return REPO_ROOT_DIR, "repo"
    return APP_DIR, "core"


def apply_tool_path_resolution(tool_name: str, args: dict) -> dict:
    """Normalize tool file paths and default cwd so relative paths are stable."""
    runtime_args = dict(args or {})
    if not TOOL_PATH_RESOLUTION_ENABLED:
        return runtime_args

    # Workspace isolation owns relative path semantics when enabled (unless full power bypasses it).
    if WORKSPACE_ISOLATION_ENABLED and not full_power_system_enabled():
        return runtime_args

    name = str(tool_name or "").strip().lower()

    def _bump_path_metrics(base_used: str, tool: str, key: str, raw_value: str, resolved_value: str):
        RUNTIME_STATE["tool_path_resolutions_total"] = int(RUNTIME_STATE.get("tool_path_resolutions_total", 0)) + 1
        if base_used == "repo":
            RUNTIME_STATE["tool_path_resolutions_repo"] = int(RUNTIME_STATE.get("tool_path_resolutions_repo", 0)) + 1
        elif base_used == "core":
            RUNTIME_STATE["tool_path_resolutions_core"] = int(RUNTIME_STATE.get("tool_path_resolutions_core", 0)) + 1
        RUNTIME_STATE["tool_path_resolution_last"] = {
            "tool": truncate_text(tool, 60),
            "key": truncate_text(key, 40),
            "base": truncate_text(base_used, 12),
            "raw": truncate_text(raw_value, 240),
            "resolved": truncate_text(resolved_value, 260),
            "at": utc_now_iso(),
        }

    def _apply_path_key(key: str):
        raw_value = runtime_args.get(key)
        if not isinstance(raw_value, str):
            return
        if not raw_value.strip():
            return
        resolved_path, base_used = _resolve_tool_path_input(raw_value)
        resolved_value = str(resolved_path)
        if resolved_value != raw_value:
            _bump_path_metrics(base_used, name, key, raw_value, resolved_value)
        runtime_args[key] = resolved_value

    if name in {"read_file", "write_file"}:
        _apply_path_key("file_path")
    elif name == "list_directory":
        _apply_path_key("dir_path")
    elif name == "desktop_screenshot":
        if isinstance(runtime_args.get("file_path"), str) and str(runtime_args.get("file_path") or "").strip():
            _apply_path_key("file_path")

    def _apply_cwd_defaults(command_key: str | None):
        raw_cwd = runtime_args.get("cwd")
        if isinstance(raw_cwd, str) and raw_cwd.strip():
            _apply_path_key("cwd")
            return

        default_cwd, base_used = _default_cwd_for_tool_command(
            str(runtime_args.get(command_key) or "") if command_key else ""
        )
        if default_cwd is None:
            return
        runtime_args["cwd"] = str(default_cwd.resolve(strict=False))
        RUNTIME_STATE["tool_cwd_defaults_total"] = int(RUNTIME_STATE.get("tool_cwd_defaults_total", 0)) + 1
        RUNTIME_STATE["tool_cwd_default_last"] = {
            "tool": truncate_text(name, 60),
            "base": truncate_text(base_used, 12),
            "cwd": truncate_text(str(runtime_args.get("cwd") or ""), 260),
            "command_preview": truncate_text(str(runtime_args.get(command_key) or ""), 220) if command_key else "",
            "at": utc_now_iso(),
        }

    if name == "run_command":
        _apply_cwd_defaults("command")
    elif name == "execute_python":
        _apply_cwd_defaults(None)
    elif name == "run_command_node":
        node = str(runtime_args.get("node_name") or "local").strip().lower() or "local"
        if node in {"", "local"}:
            _apply_cwd_defaults("command")

    return runtime_args


def _workspace_label_fragment(raw_value: str | None, fallback: str, max_len: int = 40) -> str:
    text = re.sub(r"[^a-zA-Z0-9._-]+", "_", str(raw_value or "").strip()).strip("._-").lower()
    if not text:
        text = fallback
    return text[:max_len]


def _workspace_scope_label(
    source_type: str | None,
    source_ref: str | None,
    session_id: str | None,
    agent_key: str | None,
) -> str:
    src = _workspace_label_fragment(source_type, "chat", max_len=24)
    ref = _workspace_label_fragment(source_ref, "owner", max_len=36)
    sess = _workspace_label_fragment(session_id, "session", max_len=36)
    agent = _workspace_label_fragment(agent_key, "agent", max_len=24)
    seed = f"{src}|{ref}|{sess}|{agent}"
    digest = hashlib.sha256(seed.encode("utf-8", errors="ignore")).hexdigest()[:14]
    if session_id:
        human = f"{src}-{sess}"
    elif source_ref:
        human = f"{src}-{ref}"
    else:
        human = src
    return _workspace_label_fragment(f"{human}-{digest}", "scope", max_len=64)


def owner_workspace_root(
    owner_id: int,
    source_type: str | None = None,
    source_ref: str | None = None,
    session_id: str | None = None,
    agent_key: str | None = None,
) -> Path:
    if not WORKSPACE_ISOLATION_ENABLED:
        return WORKSPACE_ISOLATION_DEFAULT_ROOT

    db = SessionLocal()
    try:
        root_owner_id = resolve_root_owner_id(db, int(owner_id))
        row = (
            db.query(TeamAgent)
            .filter(TeamAgent.agent_owner_id == int(owner_id))
            .order_by(TeamAgent.id.desc())
            .first()
        )
        if row and row.workspace_root:
            base_path = Path(str(row.workspace_root)).expanduser().resolve(strict=False)
        else:
            base_path = WORKSPACE_ISOLATION_DEFAULT_ROOT
            if TEAM_MODE_ENABLED and int(owner_id) != int(root_owner_id):
                base_path = _team_agent_workspace_root(root_owner_id, "main")

        if WORKSPACE_SESSION_ISOLATION_ENABLED:
            scope_label = _workspace_scope_label(
                source_type=source_type,
                source_ref=source_ref,
                session_id=session_id,
                agent_key=agent_key,
            )
            fallback_base = WORKSPACE_SESSION_ROOT / f"owner_{int(root_owner_id)}"
            is_default_base = str(base_path).strip().lower() == str(WORKSPACE_ISOLATION_DEFAULT_ROOT).strip().lower()
            if is_default_base:
                path = fallback_base / scope_label
            else:
                path = (base_path / ".sessions" / scope_label).resolve(strict=False)
        else:
            path = base_path

        path.mkdir(parents=True, exist_ok=True)
        return path
    except Exception:
        fallback = WORKSPACE_ISOLATION_DEFAULT_ROOT
        try:
            fallback.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass
        return fallback
    finally:
        db.close()


def _resolve_workspace_path(path_value: str, root: Path) -> Path:
    raw = str(path_value or "").strip()
    if not raw:
        return root
    target = Path(os.path.expandvars(raw)).expanduser()
    if target.is_absolute():
        resolved = target.resolve(strict=False)
    else:
        resolved = (root / target).resolve(strict=False)
    return resolved


def apply_workspace_isolation(owner_id: int | None, tool_name: str, args: dict) -> tuple[bool, str, dict]:
    runtime_args = dict(args or {})
    if full_power_system_enabled():
        return True, "", runtime_args
    if not WORKSPACE_ISOLATION_ENABLED:
        return True, "", runtime_args
    if not owner_id:
        return True, "", runtime_args

    source_type = normalize_optional_text(runtime_args.get("_workspace_source_type"), 40) or "chat"
    source_ref = normalize_optional_text(runtime_args.get("_workspace_source_ref"), 120) or str(owner_id)
    session_id = normalize_optional_text(runtime_args.get("_workspace_session_id"), 120)
    agent_key = normalize_optional_text(runtime_args.get("_workspace_agent_key"), 80)
    root = owner_workspace_root(
        int(owner_id),
        source_type=source_type,
        source_ref=source_ref,
        session_id=session_id,
        agent_key=agent_key,
    )
    runtime_args["_workspace_root"] = str(root)
    tool = str(tool_name or "").strip().lower()

    path_key = None
    if tool in {"read_file", "write_file"}:
        path_key = "file_path"
    elif tool == "list_directory":
        path_key = "dir_path"
    elif tool == "desktop_screenshot":
        path_key = "file_path"

    if path_key:
        path_value = str(runtime_args.get(path_key, "")).strip()
        if not path_value and tool != "desktop_screenshot":
            return False, f"{tool_name} requires {path_key}.", runtime_args
        if not path_value:
            runtime_args["_workspace_root"] = str(root)
            RUNTIME_STATE["workspace_isolation_last_root"] = str(root)
            return True, "", runtime_args
        resolved = _resolve_workspace_path(path_value, root)
        if not _is_path_within_root(resolved, root):
            RUNTIME_STATE["workspace_isolation_blocks"] = int(RUNTIME_STATE.get("workspace_isolation_blocks", 0)) + 1
            return False, f"{tool_name} path escaped isolated workspace root '{root}'.", runtime_args
        runtime_args[path_key] = str(resolved)
        RUNTIME_STATE["workspace_isolation_last_root"] = str(root)

    if tool in {"run_command", "execute_python"}:
        runtime_args["cwd"] = str(root)
        RUNTIME_STATE["workspace_isolation_last_root"] = str(root)

    if tool == "run_command_node":
        node_name = str(runtime_args.get("node_name") or "local").strip().lower()
        if node_name in {"", "local"}:
            runtime_args["cwd"] = str(root)
            RUNTIME_STATE["workspace_isolation_last_root"] = str(root)

    return True, "", runtime_args


def os_sandbox_enabled() -> bool:
    return _normalize_os_sandbox_mode(OS_SANDBOX_MODE) == "docker"


def _docker_executable() -> str | None:
    exe = shutil.which("docker")
    return exe


def _run_docker_process(command_args: list[str], timeout: int) -> dict:
    try:
        result = subprocess.run(
            command_args,
            capture_output=True,
            text=True,
            timeout=max(5, int(timeout) + int(OS_SANDBOX_TIMEOUT_BUFFER_SECONDS)),
        )
        return {
            "ok": True,
            "stdout": result.stdout,
            "stderr": result.stderr,
            "return_code": int(result.returncode),
            "command": command_args,
        }
    except subprocess.TimeoutExpired:
        return {"ok": False, "error": "Sandbox execution timed out.", "command": command_args}
    except Exception as e:
        return {"ok": False, "error": f"Sandbox execution failed: {e}", "command": command_args}


def _docker_run_base_args(workspace_root: Path, timeout: int) -> list[str]:
    docker_exe = _docker_executable()
    if not docker_exe:
        raise RuntimeError("Docker executable is not available on host.")
    run_args = [
        docker_exe,
        "run",
        "--rm",
        "--network",
        str(OS_SANDBOX_DOCKER_NETWORK or "none"),
        "--cpus",
        str(OS_SANDBOX_DOCKER_CPUS),
        "--memory",
        f"{int(OS_SANDBOX_DOCKER_MEMORY_MB)}m",
        "--workdir",
        "/workspace",
        "--volume",
        f"{str(workspace_root)}:/workspace",
        str(OS_SANDBOX_DOCKER_IMAGE),
    ]
    return run_args


def _run_command_in_os_sandbox(command: str, timeout: int, workspace_root: Path) -> dict:
    run_args = _docker_run_base_args(workspace_root, timeout)
    run_args.extend(["sh", "-lc", str(command or "")])
    result = _run_docker_process(run_args, timeout=timeout)
    if result.get("ok"):
        return {
            "ok": True,
            "stdout": result.get("stdout", ""),
            "stderr": result.get("stderr", ""),
            "return_code": int(result.get("return_code", -1)),
            "sandbox_mode": "docker",
            "cwd": "/workspace",
        }
    return {
        "ok": False,
        "error": str(result.get("error") or "Sandbox command failed."),
        "stderr": str(result.get("stderr") or ""),
        "sandbox_mode": "docker",
    }


def _run_python_in_os_sandbox(code: str, timeout: int, workspace_root: Path) -> dict:
    tmp_name = f".bob_exec_{uuid.uuid4().hex[:10]}.py"
    tmp_host_path = workspace_root / tmp_name
    try:
        tmp_host_path.write_text(str(code or ""), encoding="utf-8")
    except Exception as e:
        return {"ok": False, "error": f"Failed preparing sandbox script: {e}", "sandbox_mode": "docker"}
    try:
        run_args = _docker_run_base_args(workspace_root, timeout)
        run_args.extend(["python", f"/workspace/{tmp_name}"])
        result = _run_docker_process(run_args, timeout=timeout)
        if result.get("ok"):
            return {
                "ok": True,
                "stdout": result.get("stdout", ""),
                "stderr": result.get("stderr", ""),
                "return_code": int(result.get("return_code", -1)),
                "sandbox_mode": "docker",
                "cwd": "/workspace",
            }
        return {
            "ok": False,
            "error": str(result.get("error") or "Sandbox python failed."),
            "stderr": str(result.get("stderr") or ""),
            "sandbox_mode": "docker",
        }
    finally:
        try:
            tmp_host_path.unlink(missing_ok=True)
        except Exception:
            pass


def _sandbox_registry_key(owner_id: int, workspace_root: Path) -> str:
    return f"{int(owner_id)}::{str(workspace_root.resolve(strict=False)).lower()}"


def sandbox_registry_touch(owner_id: int, workspace_root: Path, tool_name: str) -> dict:
    key = _sandbox_registry_key(owner_id, workspace_root)
    now_mono = time.monotonic()
    now_iso = utc_now_iso()
    with SANDBOX_REGISTRY_LOCK:
        row = SANDBOX_REGISTRY.get(key)
        if row is None:
            row = {
                "key": key,
                "owner_id": int(owner_id),
                "workspace_root": str(workspace_root),
                "created_mono": now_mono,
                "created_at": now_iso,
                "last_used_mono": now_mono,
                "last_used_at": now_iso,
                "last_tool": str(tool_name or ""),
            }
            SANDBOX_REGISTRY[key] = row
            RUNTIME_STATE["sandbox_registry_created"] = int(RUNTIME_STATE.get("sandbox_registry_created", 0)) + 1
        else:
            row["last_used_mono"] = now_mono
            row["last_used_at"] = now_iso
            row["last_tool"] = str(tool_name or "")
            RUNTIME_STATE["sandbox_registry_reused"] = int(RUNTIME_STATE.get("sandbox_registry_reused", 0)) + 1
        RUNTIME_STATE["sandbox_registry_count"] = int(len(SANDBOX_REGISTRY))
        RUNTIME_STATE["sandbox_registry_last_context"] = key
        return dict(row)


def cleanup_sandbox_registry(max_age_seconds: float | None = None) -> int:
    ttl = float(max_age_seconds if max_age_seconds is not None else SANDBOX_REGISTRY_MAX_AGE_SECONDS)
    now_mono = time.monotonic()
    deleted = 0
    with SANDBOX_REGISTRY_LOCK:
        for key in list(SANDBOX_REGISTRY.keys()):
            row = SANDBOX_REGISTRY.get(key) or {}
            last_used = float(row.get("last_used_mono", 0.0) or 0.0)
            if (now_mono - last_used) <= ttl:
                continue
            SANDBOX_REGISTRY.pop(key, None)
            deleted += 1
        if deleted > 0:
            RUNTIME_STATE["sandbox_registry_cleanups"] = int(RUNTIME_STATE.get("sandbox_registry_cleanups", 0)) + deleted
        RUNTIME_STATE["sandbox_registry_count"] = int(len(SANDBOX_REGISTRY))
    return deleted


def execute_tool_in_os_sandbox(
    owner_id: int | None,
    tool_name: str,
    runtime_args: dict,
) -> tuple[bool, dict]:
    if not os_sandbox_enabled():
        return False, {}
    if owner_id is None:
        return False, {}
    name = str(tool_name or "").strip().lower()
    workspace_hint = normalize_optional_text(runtime_args.get("_workspace_root"), 500)
    if workspace_hint:
        workspace_root = Path(str(workspace_hint)).expanduser().resolve(strict=False)
    else:
        workspace_root = owner_workspace_root(
            int(owner_id),
            source_type=normalize_optional_text(runtime_args.get("_workspace_source_type"), 40) or "chat",
            source_ref=normalize_optional_text(runtime_args.get("_workspace_source_ref"), 120) or str(owner_id),
            session_id=normalize_optional_text(runtime_args.get("_workspace_session_id"), 120),
            agent_key=normalize_optional_text(runtime_args.get("_workspace_agent_key"), 80),
        )

    try:
        sandbox_registry_touch(int(owner_id), workspace_root, name)
    except Exception as e:
        RUNTIME_STATE["sandbox_registry_last_error"] = truncate_text(str(e), 220)

    docker_exe = _docker_executable()
    if not docker_exe:
        RUNTIME_STATE["os_sandbox_failures"] = int(RUNTIME_STATE.get("os_sandbox_failures", 0)) + 1
        if bool(OS_SANDBOX_REQUIRED):
            return True, {
                "ok": False,
                "error": "OS sandbox mode is docker but Docker is not installed.",
                "sandbox_mode": "docker",
                "required": True,
            }
        return False, {}

    if name == "run_command":
        timeout = clamp_int(runtime_args.get("timeout", 30), 1, 600, 30)
        command = str(runtime_args.get("command") or "")
        RUNTIME_STATE["os_sandbox_runs"] = int(RUNTIME_STATE.get("os_sandbox_runs", 0)) + 1
        return True, _run_command_in_os_sandbox(command, timeout, workspace_root)

    if name == "execute_python":
        timeout = clamp_int(runtime_args.get("timeout", 15), 1, 600, 15)
        code = str(runtime_args.get("code") or "")
        RUNTIME_STATE["os_sandbox_runs"] = int(RUNTIME_STATE.get("os_sandbox_runs", 0)) + 1
        return True, _run_python_in_os_sandbox(code, timeout, workspace_root)

    if name == "run_command_node":
        node_name = str(runtime_args.get("node_name") or "local").strip().lower()
        if node_name in {"", "local"}:
            timeout = clamp_int(runtime_args.get("timeout", 30), 1, 600, 30)
            command = str(runtime_args.get("command") or "")
            RUNTIME_STATE["os_sandbox_runs"] = int(RUNTIME_STATE.get("os_sandbox_runs", 0)) + 1
            return True, _run_command_in_os_sandbox(command, timeout, workspace_root)
    return False, {}


def apply_tool_policy(tool_name: str, args: dict) -> tuple[bool, str, dict]:
    policy = active_tool_policy()
    runtime_args = dict(args or {})
    if full_power_system_enabled():
        return True, "", runtime_args

    if tool_name.startswith("plugin__"):
        plugin_meta = PLUGIN_TOOL_REGISTRY.get(tool_name)
        if not plugin_meta:
            return False, f"Plugin tool '{tool_name}' is not loaded.", runtime_args
        if active_tool_policy_profile() == "safe" and not bool(plugin_meta.get("safe_mode", False)):
            return False, f"Plugin tool '{tool_name}' is blocked by 'safe' profile.", runtime_args
    else:
        allowed_tools = policy.get("allowed_tools", ALL_TOOL_NAMES)
        if tool_name not in allowed_tools:
            return False, f"Tool '{tool_name}' is blocked by '{active_tool_policy_profile()}' profile.", runtime_args

    if tool_name in {"run_command", "run_command_node"}:
        max_timeout = int(policy.get("max_run_command_timeout", 0))
        if max_timeout <= 0:
            return False, f"{tool_name} is disabled by active tool policy.", runtime_args
        runtime_args["timeout"] = clamp_int(runtime_args.get("timeout", max_timeout), 1, max_timeout, max_timeout)

    if tool_name == "execute_python":
        max_timeout = int(policy.get("max_execute_python_timeout", 0))
        if max_timeout <= 0:
            return False, f"{tool_name} is disabled by active tool policy.", runtime_args
        runtime_args["timeout"] = clamp_int(runtime_args.get("timeout", max_timeout), 1, max_timeout, max_timeout)

    if tool_name == "write_file":
        if not bool(policy.get("allow_write_file", False)):
            return False, "write_file is disabled by active tool policy.", runtime_args

        file_path = str(runtime_args.get("file_path", "")).strip()
        if not file_path:
            return False, "write_file requires file_path.", runtime_args

        if not bool(policy.get("allow_any_write_path", False)):
            target = _resolve_write_target(file_path)
            roots = tool_policy_write_roots()
            if not any(_is_path_within_root(target, root) for root in roots):
                roots_preview = ", ".join(str(r) for r in roots[:3])
                return False, f"write_file path blocked by policy. Allowed roots: {roots_preview}", runtime_args

    return True, "", runtime_args


def active_execution_sandbox_profile() -> str:
    if full_power_system_enabled():
        return "power"
    if EXECUTION_SANDBOX_PROFILE in EXECUTION_SANDBOX_PROFILES:
        return EXECUTION_SANDBOX_PROFILE
    return "default"


def active_execution_sandbox_policy() -> dict:
    return EXECUTION_SANDBOX_PROFILES.get(
        active_execution_sandbox_profile(),
        EXECUTION_SANDBOX_PROFILES["default"],
    )


def _compiled_user_patterns(raw_patterns: list[str]) -> list[re.Pattern]:
    compiled: list[re.Pattern] = []
    for raw in raw_patterns:
        pattern = str(raw or "").strip()
        if not pattern:
            continue
        try:
            compiled.append(re.compile(pattern, re.IGNORECASE))
        except Exception:
            continue
    return compiled


def _matches_any_pattern(text: str, patterns: list[re.Pattern]) -> bool:
    blob = str(text or "")
    return any(p.search(blob) for p in patterns)


def apply_execution_sandbox(
    tool_name: str,
    args: dict,
    source_type: str = "chat",
) -> tuple[bool, str, dict]:
    policy = active_execution_sandbox_policy()
    runtime_args = dict(args or {})
    if full_power_system_enabled():
        return True, "", runtime_args
    src = str(source_type or "chat").strip().lower()
    profile = active_execution_sandbox_profile()

    allow_run = bool(policy.get("allow_run_command", True))
    allow_python = bool(policy.get("allow_execute_python", True))
    allow_remote = bool(policy.get("allow_remote_nodes", True))
    allow_desktop = bool(policy.get("allow_desktop_control", True))
    max_command_chars = clamp_int(policy.get("max_command_chars"), 120, 50000, 900)
    max_python_chars = clamp_int(policy.get("max_python_chars"), 500, 100000, 10000)

    cmd_patterns = list(DEFAULT_SANDBOX_COMMAND_DENY_PATTERNS) + _compiled_user_patterns(EXECUTION_SANDBOX_BLOCK_COMMAND_PATTERNS)
    py_patterns = list(DEFAULT_SANDBOX_PYTHON_DENY_PATTERNS) + _compiled_user_patterns(EXECUTION_SANDBOX_BLOCK_PYTHON_PATTERNS)

    if src == "cron" and profile != "power" and tool_name in {"run_command", "run_command_node", "execute_python"}:
        return False, f"{tool_name} is blocked for cron jobs under sandbox profile '{profile}'.", runtime_args

    if tool_name.startswith("desktop_"):
        if not DESKTOP_CONTROL_ENABLED:
            return False, "Desktop control is disabled by configuration.", runtime_args
        if not allow_desktop:
            return False, f"{tool_name} is disabled by sandbox profile '{profile}'.", runtime_args

    if tool_name == "run_command":
        if not allow_run:
            return False, f"run_command is disabled by sandbox profile '{profile}'.", runtime_args
        command = str(runtime_args.get("command") or "")
        if len(command) > max_command_chars:
            return False, f"run_command exceeds sandbox max length ({max_command_chars}).", runtime_args
        if _matches_any_pattern(command, cmd_patterns):
            return False, "run_command matched sandbox deny pattern.", runtime_args

    if tool_name == "run_command_node":
        if not allow_run:
            return False, f"run_command_node is disabled by sandbox profile '{profile}'.", runtime_args
        command = str(runtime_args.get("command") or "")
        if len(command) > max_command_chars:
            return False, f"run_command_node exceeds sandbox max length ({max_command_chars}).", runtime_args
        if _matches_any_pattern(command, cmd_patterns):
            return False, "run_command_node matched sandbox deny pattern.", runtime_args

        node_name = str(runtime_args.get("node_name") or "local").strip().lower()
        is_local = node_name in {"", "local"}
        if not is_local:
            if not allow_remote:
                return False, f"Remote nodes are disabled by sandbox profile '{profile}'.", runtime_args
            if EXECUTION_SANDBOX_REMOTE_ALLOWLIST and node_name not in EXECUTION_SANDBOX_REMOTE_ALLOWLIST:
                return False, f"Remote node '{node_name}' not in sandbox allowlist.", runtime_args

    if tool_name == "execute_python":
        if not allow_python:
            return False, f"execute_python is disabled by sandbox profile '{profile}'.", runtime_args
        code = str(runtime_args.get("code") or "")
        if len(code) > max_python_chars:
            return False, f"execute_python exceeds sandbox max length ({max_python_chars}).", runtime_args
        if _matches_any_pattern(code, py_patterns):
            return False, "execute_python matched sandbox deny pattern.", runtime_args

    return True, "", runtime_args


def check_authority(identity: dict | None, tool_name: str, args: dict) -> tuple[bool, str]:
    """
    Check if a tool call is allowed by the identity's autonomy directives.
    Returns (allowed: bool, reason: str).
    """
    if full_power_system_enabled() or AUTONOMY_OPENCLAW_MAX:
        return True, ""

    if identity is None:
        return True, ""

    bounds = identity.get("authority_bounds", {})

    # File deletion check
    if tool_name in {"run_command", "run_command_node"}:
        cmd = args.get("command", "")
        if bounds.get("can_delete_files") is False:
            dangerous = ["rm ", "rm -", "rmdir", "del ", "shutil.rmtree"]
            if any(d in cmd for d in dangerous):
                return False, "Autonomy directives prohibit file deletion."

        if bounds.get("can_run_shell") is False:
            return False, "Autonomy directives prohibit shell command execution."

    if tool_name == "write_file" and bounds.get("can_write_files") is False:
        return False, "Autonomy directives prohibit file writing."

    if tool_name.startswith("desktop_") and bounds.get("can_control_desktop") is False:
        return False, "Autonomy directives prohibit desktop control."

    return True, ""


def approval_gate_enabled() -> bool:
    if full_power_system_enabled():
        return False
    return APPROVAL_GATE_MODE != "off"


def _approval_requires_tool(tool_name: str) -> bool:
    name = (tool_name or "").strip().lower()
    if not approval_gate_enabled():
        return False
    if APPROVAL_GATE_MODE == "strict":
        return (
            name in {"run_command", "execute_python", "write_file", "run_command_node"}
            or name.startswith("plugin__")
            or name.startswith("desktop_")
        )
    if name in APPROVAL_REQUIRED_TOOLS:
        return True
    if name.startswith("plugin__"):
        meta = PLUGIN_TOOL_REGISTRY.get(tool_name, {})
        return not bool(meta.get("safe_mode", False))
    return False


def _canonical_args_json(args: dict) -> str:
    try:
        return json.dumps(args or {}, sort_keys=True, ensure_ascii=False)
    except Exception:
        return "{}"


def _refresh_approval_pending_runtime_count():
    db = SessionLocal()
    try:
        now_dt = datetime.utcnow()
        pending_count = (
            db.query(ApprovalRequest)
            .filter(
                ApprovalRequest.status == "pending",
                ApprovalRequest.expires_at > now_dt,
            )
            .count()
        )
        RUNTIME_STATE["approval_pending_count"] = int(pending_count)
    except Exception:
        pass
    finally:
        db.close()


def create_approval_request(
    owner_id: int,
    source_type: str,
    source_ref: str | None,
    step_id: str | None,
    tool_name: str,
    tool_args: dict,
    resume_payload: dict | None = None,
) -> str:
    db = SessionLocal()
    try:
        now_dt = datetime.utcnow()
        expires_dt = now_dt + timedelta(minutes=APPROVAL_TOKEN_TTL_MINUTES)
        args_json = _canonical_args_json(tool_args)
        row = (
            db.query(ApprovalRequest)
            .filter(
                ApprovalRequest.owner_id == int(owner_id),
                ApprovalRequest.status == "pending",
                ApprovalRequest.tool_name == tool_name,
                ApprovalRequest.tool_args_json == args_json,
                ApprovalRequest.expires_at > now_dt,
            )
            .order_by(ApprovalRequest.id.desc())
            .first()
        )
        if row:
            token = row.token
        else:
            token = f"ap_{uuid.uuid4().hex[:10]}"
            row = ApprovalRequest(
                owner_id=int(owner_id),
                token=token,
                source_type=truncate_text(source_type or "chat", 20),
                source_ref=truncate_text(str(source_ref or ""), 120) or None,
                step_id=truncate_text(str(step_id or ""), 80) or None,
                tool_name=truncate_text(tool_name, 120),
                tool_args_json=args_json,
                resume_payload_json=_canonical_args_json(resume_payload or {}),
                status="pending",
                expires_at=expires_dt,
            )
            db.add(row)
            db.commit()

        RUNTIME_STATE["approval_required_count"] = int(RUNTIME_STATE.get("approval_required_count", 0)) + 1
        RUNTIME_STATE["approval_last_token"] = token
        _refresh_approval_pending_runtime_count()
        return token
    except Exception as e:
        db.rollback()
        log.warning("APPROVAL_CREATE_FAIL owner=%s tool=%s error=%s", owner_id, tool_name, str(e)[:200])
        token = f"ap_{uuid.uuid4().hex[:10]}"
        RUNTIME_STATE["approval_last_token"] = token
        return token
    finally:
        db.close()


def validate_approval_token(owner_id: int, token: str, tool_name: str, tool_args: dict) -> bool:
    if not token:
        return False
    db = SessionLocal()
    try:
        now_dt = datetime.utcnow()
        row = (
            db.query(ApprovalRequest)
            .filter(
                ApprovalRequest.owner_id == int(owner_id),
                ApprovalRequest.token == token,
                ApprovalRequest.status == "approved",
                ApprovalRequest.expires_at > now_dt,
            )
            .first()
        )
        if not row:
            return False
        if row.tool_name != tool_name:
            return False
        if (row.tool_args_json or "{}") != _canonical_args_json(tool_args):
            return False
        row.status = "consumed"
        row.decided_at = now_dt
        db.commit()
        _refresh_approval_pending_runtime_count()
        return True
    except Exception:
        db.rollback()
        return False
    finally:
        db.close()


def consume_matching_approved_request(owner_id: int, tool_name: str, tool_args: dict) -> str | None:
    db = SessionLocal()
    try:
        now_dt = datetime.utcnow()
        args_json = _canonical_args_json(tool_args)
        row = (
            db.query(ApprovalRequest)
            .filter(
                ApprovalRequest.owner_id == int(owner_id),
                ApprovalRequest.status == "approved",
                ApprovalRequest.tool_name == tool_name,
                ApprovalRequest.tool_args_json == args_json,
                ApprovalRequest.expires_at > now_dt,
            )
            .order_by(ApprovalRequest.id.desc())
            .first()
        )
        if not row:
            return None
        row.status = "consumed"
        row.decided_at = now_dt
        db.commit()
        _refresh_approval_pending_runtime_count()
        return row.token
    except Exception:
        db.rollback()
        return None
    finally:
        db.close()


def decide_approval_token(owner_id: int, token: str, approve: bool, reason: str = "") -> dict:
    db = SessionLocal()
    try:
        now_dt = datetime.utcnow()
        row = (
            db.query(ApprovalRequest)
            .filter(
                ApprovalRequest.owner_id == int(owner_id),
                ApprovalRequest.token == token,
            )
            .first()
        )
        if not row:
            candidate = db.query(ApprovalRequest).filter(ApprovalRequest.token == token).first()
            if candidate:
                candidate_root = resolve_root_owner_id(db, int(candidate.owner_id))
                requester_root = resolve_root_owner_id(db, int(owner_id))
                if candidate_root == requester_root:
                    row = candidate
        if not row:
            return {"ok": False, "error": "Approval token not found."}
        if row.status not in {"pending", "approved", "rejected", "consumed"}:
            return {"ok": False, "error": f"Approval token is in state '{row.status}'."}
        if row.status != "pending":
            return {
                "ok": True,
                "token": row.token,
                "status": row.status,
                "owner_id": int(row.owner_id),
                "message": f"Token already processed as '{row.status}'.",
            }
        if row.expires_at <= now_dt:
            row.status = "expired"
            row.decided_at = now_dt
            db.commit()
            _refresh_approval_pending_runtime_count()
            return {"ok": False, "error": "Approval token expired."}

        row.status = "approved" if approve else "rejected"
        row.decision_reason = truncate_text(reason or "", 300) or None
        row.decided_at = now_dt
        db.commit()

        if approve:
            RUNTIME_STATE["approval_approved_count"] = int(RUNTIME_STATE.get("approval_approved_count", 0)) + 1
        else:
            RUNTIME_STATE["approval_rejected_count"] = int(RUNTIME_STATE.get("approval_rejected_count", 0)) + 1
        _refresh_approval_pending_runtime_count()

        resume_payload = _safe_json_dict(row.resume_payload_json, {})
        return {
            "ok": True,
            "token": row.token,
            "status": row.status,
            "owner_id": int(row.owner_id),
            "resume_payload": resume_payload,
            "tool_name": row.tool_name,
            "source_type": row.source_type,
            "source_ref": row.source_ref,
            "step_id": row.step_id,
        }
    except Exception as e:
        db.rollback()
        return {"ok": False, "error": str(e)}
    finally:
        db.close()


def approval_manager_create_request(
    owner_id: int,
    source_type: str,
    source_ref: str | None,
    step_id: str | None,
    tool_name: str,
    tool_args: dict,
    resume_payload: dict | None = None,
) -> str:
    return create_approval_request(
        owner_id=owner_id,
        source_type=source_type,
        source_ref=source_ref,
        step_id=step_id,
        tool_name=tool_name,
        tool_args=tool_args,
        resume_payload=resume_payload,
    )


def approval_manager_validate_token(owner_id: int, token: str, tool_name: str, tool_args: dict) -> bool:
    return validate_approval_token(owner_id=owner_id, token=token, tool_name=tool_name, tool_args=tool_args)


def approval_manager_consume_matching(owner_id: int, tool_name: str, tool_args: dict) -> str | None:
    return consume_matching_approved_request(owner_id=owner_id, tool_name=tool_name, tool_args=tool_args)


def approval_manager_decide_token(owner_id: int, token: str, approve: bool, reason: str = "") -> dict:
    return decide_approval_token(owner_id=owner_id, token=token, approve=approve, reason=reason)


def _host_exec_prefix_from_tool(tool_name: str, runtime_args: dict) -> str:
    name = str(tool_name or "").strip().lower()
    if name == "execute_python":
        return "python"
    command = str((runtime_args or {}).get("command") or "").strip()
    if not command:
        return ""
    try:
        parts = shlex.split(command, posix=False)
    except Exception:
        parts = command.split()
    if not parts:
        return ""
    token = str(parts[0]).strip().lower()
    token = token.replace("\\", "/").split("/")[-1]
    token = token.replace(".exe", "")
    return token


def create_host_exec_grant(
    owner_id: int | None,
    node_name: str,
    command_prefix: str,
    created_by: str | None = None,
    ttl_minutes: int | None = None,
) -> dict:
    ttl = clamp_int(ttl_minutes if ttl_minutes is not None else HOST_EXEC_GRANT_TTL_MINUTES, 5, 1440, HOST_EXEC_GRANT_TTL_MINUTES)
    db = SessionLocal()
    try:
        now_dt = datetime.utcnow()
        token = f"hex_{uuid.uuid4().hex[:12]}"
        row = HostExecGrant(
            token=token,
            owner_id=int(owner_id) if owner_id else None,
            node_name=truncate_text(str(node_name or "local").strip().lower(), 40) or "local",
            command_prefix=truncate_text(str(command_prefix or "").strip().lower(), 80),
            status="active",
            created_by=truncate_text(str(created_by or ""), 80) or None,
            expires_at=now_dt + timedelta(minutes=ttl),
        )
        db.add(row)
        db.commit()
        RUNTIME_STATE["host_exec_grants_issued"] = int(RUNTIME_STATE.get("host_exec_grants_issued", 0)) + 1
        return {
            "ok": True,
            "token": token,
            "owner_id": int(owner_id) if owner_id else None,
            "node_name": row.node_name,
            "command_prefix": row.command_prefix,
            "expires_at": row.expires_at.isoformat() if row.expires_at else None,
        }
    except Exception as e:
        db.rollback()
        return {"ok": False, "error": str(e)}
    finally:
        db.close()


def validate_host_exec_grant(
    token: str,
    owner_id: int | None,
    node_name: str,
    command_prefix: str,
) -> bool:
    candidate = str(token or "").strip()
    if not candidate:
        return False
    db = SessionLocal()
    try:
        now_dt = datetime.utcnow()
        row = (
            db.query(HostExecGrant)
            .filter(HostExecGrant.token == candidate)
            .first()
        )
        if not row:
            return False
        if row.status != "active":
            return False
        if row.expires_at <= now_dt:
            row.status = "expired"
            db.commit()
            return False
        expected_node = str(node_name or "local").strip().lower() or "local"
        if str(row.node_name or "local").strip().lower() != expected_node:
            return False
        expected_prefix = str(command_prefix or "").strip().lower()
        if expected_prefix and str(row.command_prefix or "").strip().lower() != expected_prefix:
            return False
        if row.owner_id is not None and owner_id is not None and int(row.owner_id) != int(owner_id):
            return False

        row.status = "consumed"
        row.consumed_at = now_dt
        db.commit()
        RUNTIME_STATE["host_exec_grants_consumed"] = int(RUNTIME_STATE.get("host_exec_grants_consumed", 0)) + 1
        return True
    except Exception:
        db.rollback()
        return False
    finally:
        db.close()


def enforce_host_exec_interlock(
    tool_name: str,
    runtime_args: dict,
    owner_id: int | None,
) -> tuple[bool, str, dict]:
    args = dict(runtime_args or {})
    if full_power_system_enabled():
        return True, "", args
    if not HOST_EXEC_INTERLOCK_ENABLED:
        return True, "", args

    name = str(tool_name or "").strip().lower()
    if name not in {"run_command", "run_command_node", "execute_python"}:
        return True, "", args

    prefix = _host_exec_prefix_from_tool(name, args)
    if name in {"run_command", "run_command_node"}:
        if not prefix:
            return False, "Host interlock requires a non-empty command.", args
        if HOST_EXEC_ALLOWLIST_PREFIXES and prefix not in HOST_EXEC_ALLOWLIST_PREFIXES:
            RUNTIME_STATE["host_exec_interlock_blocks"] = int(RUNTIME_STATE.get("host_exec_interlock_blocks", 0)) + 1
            return False, f"Host exec interlock blocked command prefix '{prefix}'.", args
    else:
        prefix = "python"

    node_name = str(args.get("node_name") or "local").strip().lower() or "local"
    token = str(args.pop("_host_exec_token", "") or "").strip()
    if validate_host_exec_grant(token, owner_id=owner_id, node_name=node_name, command_prefix=prefix):
        return True, "", args

    guidance = (
        f"Host exec interlock requires operator token for {name} "
        f"(node={node_name}, prefix={prefix})."
    )
    return False, guidance, args


def execute_tool_with_context(
    identity: dict | None,
    tool_name: str,
    args: dict,
    owner_id: int | None = None,
    source_type: str = "chat",
    source_ref: str | None = None,
    step_id: str | None = None,
    resume_payload: dict | None = None,
    blackbox_session_id: str | None = None,
    run_budget: dict | None = None,
) -> dict:
    runtime_args = dict(args or {})
    runtime_args = budget_apply_degrade_to_tool_args(tool_name, runtime_args, run_budget)
    bb_session = str(blackbox_session_id or "").strip()
    if owner_id and bb_session:
        record_blackbox_event_with_new_session(
            owner_id=int(owner_id),
            session_id=bb_session,
            source_type=source_type,
            source_ref=source_ref,
            event_type="tool_requested",
            payload={
                "tool_name": tool_name,
                "args": _blackbox_sanitize(runtime_args),
                "step_id": step_id,
            },
        )
    if tool_name in {
        "save_research_note",
        "research_memory_search",
        "semantic_memory_search",
        "schedule_job",
        "list_scheduled_jobs",
        "disable_scheduled_job",
        "desktop_screenshot",
        "sessions_spawn",
        "sessions_send",
        "sessions_list",
        "sessions_history",
        "sessions_stop",
        "create_tool",
        "list_custom_tools",
        "disable_custom_tool",
    }:
        runtime_args["_owner_id"] = owner_id
    if str(tool_name or "").startswith("desktop_") or str(tool_name or "").startswith("browser_"):
        runtime_args["_owner_id"] = owner_id
        if owner_id and "_workspace_root" not in runtime_args:
            try:
                runtime_args["_workspace_root"] = str(
                    owner_workspace_root(
                        int(owner_id),
                        source_type=source_type,
                        source_ref=source_ref,
                        session_id=bb_session,
                    )
                )
            except Exception:
                pass
    if owner_id:
        runtime_args["_workspace_source_type"] = str(source_type or "chat")
        runtime_args["_workspace_source_ref"] = str(source_ref or owner_id)
        runtime_args["_workspace_session_id"] = str(bb_session or "")
        if isinstance(resume_payload, dict):
            runtime_args["_workspace_agent_key"] = str(resume_payload.get("agent_key") or "")
        else:
            runtime_args["_workspace_agent_key"] = ""

    runtime_args = apply_tool_path_resolution(tool_name, runtime_args)

    allowed, reason, runtime_args = apply_tool_policy(tool_name, runtime_args)
    if not allowed:
        RUNTIME_STATE["tool_policy_blocks"] = int(RUNTIME_STATE.get("tool_policy_blocks", 0)) + 1
        if owner_id and bb_session:
            record_blackbox_event_with_new_session(
                owner_id=int(owner_id),
                session_id=bb_session,
                source_type=source_type,
                source_ref=source_ref,
                event_type="tool_blocked_policy",
                payload={"tool_name": tool_name, "reason": reason},
            )
        return {"ok": False, "error": f"BLOCKED: {reason}"}

    allowed, reason, runtime_args = apply_execution_sandbox(tool_name, runtime_args, source_type=source_type)
    if not allowed:
        RUNTIME_STATE["execution_sandbox_blocks"] = int(RUNTIME_STATE.get("execution_sandbox_blocks", 0)) + 1
        if owner_id and bb_session:
            record_blackbox_event_with_new_session(
                owner_id=int(owner_id),
                session_id=bb_session,
                source_type=source_type,
                source_ref=source_ref,
                event_type="tool_blocked_sandbox",
                payload={"tool_name": tool_name, "reason": reason, "profile": active_execution_sandbox_profile()},
            )
        return {"ok": False, "error": f"BLOCKED: {reason}"}

    allowed, reason, runtime_args = apply_workspace_isolation(owner_id, tool_name, runtime_args)
    if not allowed:
        if owner_id and bb_session:
            record_blackbox_event_with_new_session(
                owner_id=int(owner_id),
                session_id=bb_session,
                source_type=source_type,
                source_ref=source_ref,
                event_type="tool_blocked_workspace_isolation",
                payload={"tool_name": tool_name, "reason": reason},
            )
        return {"ok": False, "error": f"BLOCKED: {reason}"}

    allowed, reason = check_authority(identity, tool_name, runtime_args)
    if not allowed:
        if owner_id and bb_session:
            record_blackbox_event_with_new_session(
                owner_id=int(owner_id),
                session_id=bb_session,
                source_type=source_type,
                source_ref=source_ref,
                event_type="tool_blocked_authority",
                payload={"tool_name": tool_name, "reason": reason},
            )
        return {"ok": False, "error": f"BLOCKED: {reason}"}

    if _desktop_tool_requires_active_session(tool_name):
        active_session = _desktop_get_active_session(owner_id)
        if not active_session:
            message = "Desktop session required. Call desktop_session_start first."
            if owner_id and bb_session:
                record_blackbox_event_with_new_session(
                    owner_id=int(owner_id),
                    session_id=bb_session,
                    source_type=source_type,
                    source_ref=source_ref,
                    event_type="tool_blocked_desktop_session_required",
                    payload={"tool_name": tool_name},
                )
            return {
                "ok": False,
                "session_required": True,
                "tool_name": tool_name,
                "error": message,
                "message": message,
            }

    diff_gate = evaluate_workspace_diff_gate(tool_name, runtime_args)
    diff_gate_requires_approval = bool(diff_gate.get("require_approval", False))
    if diff_gate.get("blocked"):
        reason = str(diff_gate.get("reason") or "workspace diff gate block")
        if owner_id and bb_session:
            record_blackbox_event_with_new_session(
                owner_id=int(owner_id),
                session_id=bb_session,
                source_type=source_type,
                source_ref=source_ref,
                event_type="tool_blocked_diff_gate",
                payload={"tool_name": tool_name, "reason": reason, "path": diff_gate.get("path")},
            )
        return {"ok": False, "error": f"BLOCKED: {reason}"}

    host_ok, host_reason, runtime_args = enforce_host_exec_interlock(tool_name, runtime_args, owner_id=owner_id)
    if not host_ok:
        if owner_id and bb_session:
            record_blackbox_event_with_new_session(
                owner_id=int(owner_id),
                session_id=bb_session,
                source_type=source_type,
                source_ref=source_ref,
                event_type="tool_host_exec_required",
                payload={"tool_name": tool_name, "reason": host_reason},
            )
        return {
            "ok": False,
            "approval_required": True,
            "host_exec_required": True,
            "message": host_reason,
            "error": host_reason,
        }

    sandbox_intercepted, sandbox_result = execute_tool_in_os_sandbox(owner_id, tool_name, runtime_args)
    if sandbox_intercepted:
        result = sandbox_result if isinstance(sandbox_result, dict) else {"ok": False, "error": "Sandbox returned invalid payload."}
        if not bool(result.get("ok", False)):
            RUNTIME_STATE["os_sandbox_failures"] = int(RUNTIME_STATE.get("os_sandbox_failures", 0)) + 1
        if str(tool_name or "").startswith("desktop_"):
            _desktop_record_action(owner_id, tool_name, runtime_args, result)
        budget_record_tool_call(run_budget, tool_name, args=runtime_args, result=result)
        if owner_id and bb_session:
            record_blackbox_event_with_new_session(
                owner_id=int(owner_id),
                session_id=bb_session,
                source_type=source_type,
                source_ref=source_ref,
                event_type="tool_completed_sandbox",
                payload={
                    "tool_name": tool_name,
                    "ok": bool(result.get("ok", False)),
                    "sandbox_mode": result.get("sandbox_mode", "docker"),
                },
            )
        record_usage_ledger_event(
            owner_id=owner_id,
            source_type=source_type,
            source_ref=source_ref,
            session_id=bb_session,
            event_type="tool",
            tool_name=tool_name,
            estimated_tokens=_estimate_text_tokens(json.dumps(runtime_args, ensure_ascii=False)),
            estimated_cost_usd=0.0,
            status="ok" if bool(result.get("ok", False)) else "error",
            detail={"sandbox": True},
        )
        return result

    stop_now, stop_reason = budget_should_stop(run_budget)
    if stop_now:
        if owner_id and bb_session:
            record_blackbox_event_with_new_session(
                owner_id=int(owner_id),
                session_id=bb_session,
                source_type=source_type,
                source_ref=source_ref,
                event_type="tool_blocked_budget_stop",
                payload={"tool_name": tool_name, "reason": stop_reason},
            )
        return {"ok": False, "error": f"BUDGET_STOP: {stop_reason}"}

    if owner_id and _approval_requires_tool(tool_name):
        approval_token = str(runtime_args.pop("_approval_token", "") or "").strip()
        sanitized_args = dict(runtime_args)
        approved = False
        if approval_token:
            approved = approval_manager_validate_token(int(owner_id), approval_token, tool_name, sanitized_args)
        else:
            approved = approval_manager_consume_matching(int(owner_id), tool_name, sanitized_args) is not None
        if approved:
            pass
        else:
            effective_resume_payload = dict(resume_payload or {})
            if diff_gate_requires_approval:
                effective_resume_payload["diff_gate_reason"] = str(diff_gate.get("reason") or "")
                effective_resume_payload["diff_gate_path"] = str(diff_gate.get("path") or "")
            token = approval_manager_create_request(
                owner_id=int(owner_id),
                source_type=source_type,
                source_ref=source_ref,
                step_id=step_id,
                tool_name=tool_name,
                tool_args=sanitized_args,
                resume_payload=effective_resume_payload,
            )
            if bb_session:
                record_blackbox_event_with_new_session(
                    owner_id=int(owner_id),
                    session_id=bb_session,
                    source_type=source_type,
                    source_ref=source_ref,
                    event_type="tool_approval_required",
                    payload={"tool_name": tool_name, "token": token, "step_id": step_id},
                )
            return {
                "ok": False,
                "approval_required": True,
                "resume_token": token,
                "tool_name": tool_name,
                "error": "APPROVAL_REQUIRED",
                "message": (
                    f"Approval required for {tool_name}. Send /approve {token} or /reject {token}."
                    + (f" Reason: {diff_gate.get('reason')}" if diff_gate_requires_approval else "")
                ),
            }
    elif owner_id and diff_gate_requires_approval:
        approval_token = str(runtime_args.pop("_approval_token", "") or "").strip()
        sanitized_args = dict(runtime_args)
        approved = False
        if approval_token:
            approved = approval_manager_validate_token(int(owner_id), approval_token, tool_name, sanitized_args)
        else:
            approved = approval_manager_consume_matching(int(owner_id), tool_name, sanitized_args) is not None
        if not approved:
            effective_resume_payload = dict(resume_payload or {})
            effective_resume_payload["diff_gate_reason"] = str(diff_gate.get("reason") or "")
            effective_resume_payload["diff_gate_path"] = str(diff_gate.get("path") or "")
            token = approval_manager_create_request(
                owner_id=int(owner_id),
                source_type=source_type,
                source_ref=source_ref,
                step_id=step_id,
                tool_name=tool_name,
                tool_args=sanitized_args,
                resume_payload=effective_resume_payload,
            )
            if bb_session:
                record_blackbox_event_with_new_session(
                    owner_id=int(owner_id),
                    session_id=bb_session,
                    source_type=source_type,
                    source_ref=source_ref,
                    event_type="tool_approval_required_diff_gate",
                    payload={"tool_name": tool_name, "token": token, "reason": diff_gate.get("reason")},
                )
            return {
                "ok": False,
                "approval_required": True,
                "resume_token": token,
                "tool_name": tool_name,
                "error": "APPROVAL_REQUIRED",
                "message": (
                    f"Approval required for {tool_name}. Send /approve {token} or /reject {token}. "
                    f"Reason: {diff_gate.get('reason')}"
                ),
            }

    if tool_name not in TOOL_DISPATCH and tool_name not in PLUGIN_TOOL_REGISTRY:
        if owner_id and bb_session:
            record_blackbox_event_with_new_session(
                owner_id=int(owner_id),
                session_id=bb_session,
                source_type=source_type,
                source_ref=source_ref,
                event_type="tool_unknown",
                payload={"tool_name": tool_name},
            )
        return {"ok": False, "error": f"Unknown tool: {tool_name}"}

    # Keep these isolation hints internal to the runtime pipeline.
    runtime_args.pop("_workspace_source_type", None)
    runtime_args.pop("_workspace_source_ref", None)
    runtime_args.pop("_workspace_session_id", None)
    runtime_args.pop("_workspace_agent_key", None)

    _tool_start_mono = time.monotonic()
    try:
        if tool_name in TOOL_DISPATCH:
            result = TOOL_DISPATCH[tool_name](runtime_args)
        elif tool_name in CUSTOM_TOOL_REGISTRY:
            try:
                result = CUSTOM_TOOL_REGISTRY[tool_name]["func"](runtime_args)
                _increment_custom_tool_usage(tool_name)
            except Exception as exc:
                _record_custom_tool_error(tool_name, str(exc))
                result = {"ok": False, "error": str(exc)}
        else:
            result = execute_plugin_tool(tool_name, runtime_args)

        _tool_dur_ms = int((time.monotonic() - _tool_start_mono) * 1000)
        _tool_ok = bool(result.get("ok", False)) if isinstance(result, dict) else False
        record_tool_performance(
            owner_id=owner_id,
            tool_name=tool_name,
            source_type=source_type,
            success=_tool_ok,
            duration_ms=_tool_dur_ms,
            error_str=str(result.get("error", "")) if isinstance(result, dict) and not _tool_ok else None,
        )

        budget_record_tool_call(run_budget, tool_name, args=runtime_args, result=result if isinstance(result, dict) else None)

        redaction_hits = 0
        if SECRET_GUARDRAIL_ENABLED:
            result, redaction_hits = redact_secret_data(result)
            if redaction_hits > 0:
                RUNTIME_STATE["secret_redactions_total"] = int(RUNTIME_STATE.get("secret_redactions_total", 0)) + int(redaction_hits)

        if str(tool_name or "").startswith("desktop_"):
            safe_result = result if isinstance(result, dict) else {"ok": False, "error": "Invalid result payload"}
            _desktop_record_action(owner_id, tool_name, runtime_args, safe_result)

        if owner_id and bb_session:
            result_ok = bool(result.get("ok", False)) if isinstance(result, dict) else False
            record_blackbox_event_with_new_session(
                owner_id=int(owner_id),
                session_id=bb_session,
                source_type=source_type,
                source_ref=source_ref,
                event_type="tool_completed",
                payload={
                    "tool_name": tool_name,
                    "ok": result_ok,
                    "secret_redactions": int(redaction_hits),
                    "result_preview": truncate_text(json.dumps(_blackbox_sanitize(result), ensure_ascii=False), 500),
                },
            )
        record_usage_ledger_event(
            owner_id=owner_id,
            source_type=source_type,
            source_ref=source_ref,
            session_id=bb_session,
            event_type="tool",
            tool_name=tool_name,
            estimated_tokens=_estimate_text_tokens(json.dumps(runtime_args, ensure_ascii=False)),
            estimated_cost_usd=0.0,
            status="ok" if bool(result.get("ok", False)) else "error",
            detail={"redactions": int(redaction_hits)},
        )
        return result
    except Exception as e:
        _tool_dur_ms = int((time.monotonic() - _tool_start_mono) * 1000)
        record_tool_performance(
            owner_id=owner_id,
            tool_name=tool_name,
            source_type=source_type,
            success=False,
            duration_ms=_tool_dur_ms,
            error_str=str(e),
        )
        budget_record_tool_call(run_budget, tool_name, args=runtime_args, result={"ok": False, "error": str(e)})
        if owner_id and bb_session:
            record_blackbox_event_with_new_session(
                owner_id=int(owner_id),
                session_id=bb_session,
                source_type=source_type,
                source_ref=source_ref,
                event_type="tool_exception",
                payload={"tool_name": tool_name, "error": truncate_text(str(e), 220)},
            )
        record_usage_ledger_event(
            owner_id=owner_id,
            source_type=source_type,
            source_ref=source_ref,
            session_id=bb_session,
            event_type="tool",
            tool_name=tool_name,
            estimated_tokens=_estimate_text_tokens(json.dumps(runtime_args, ensure_ascii=False)),
            estimated_cost_usd=0.0,
            status="error",
            detail={"error": truncate_text(str(e), 220)},
        )
        return {"ok": False, "error": f"Tool execution failed: {str(e)}"}


# ============================================================================
# SECTION 5B: CLOSED LOOP FEEDBACK ENGINE
# Closes all 6 open feedback loops so Bob actually adapts from experience.
# Feature-flagged with CLOSED_LOOP_ENABLED.
# ============================================================================


def cl_filter_tools_by_performance(tool_defs: list[dict], owner_id: int | None) -> list[dict]:
    """Loop 1+6: Warn/block/reorder tools based on success rate."""
    if not CLOSED_LOOP_ENABLED or not owner_id:
        return tool_defs
    stats = get_tool_performance_stats(owner_id, days=7)
    stats_map = {s["tool"]: s for s in stats if s["total"] >= CLOSED_LOOP_TOOL_MIN_CALLS}
    if not stats_map:
        return tool_defs

    filtered = []
    for td in tool_defs:
        name = (td.get("function") or {}).get("name", "")
        perf = stats_map.get(name)
        if perf and perf["success_rate"] < CLOSED_LOOP_TOOL_BLOCK_THRESHOLD:
            RUNTIME_STATE["cl_tools_blocked"] = int(RUNTIME_STATE.get("cl_tools_blocked", 0)) + 1
            log.info("CL_TOOL_BLOCKED tool=%s rate=%.0f%%", name, perf["success_rate"])
            continue  # Remove from available tools
        if perf and perf["success_rate"] < CLOSED_LOOP_TOOL_WARN_THRESHOLD:
            td = copy.deepcopy(td)
            desc = td["function"].get("description", "")
            td["function"]["description"] = f"[WARNING: {perf['success_rate']:.0f}% success rate] {desc}"
            RUNTIME_STATE["cl_tools_warned"] = int(RUNTIME_STATE.get("cl_tools_warned", 0)) + 1
        filtered.append(td)

    # Loop 6: Reorder — high-performing tools appear first (LLMs prefer earlier tools)
    def _tool_sort_key(td):
        name = (td.get("function") or {}).get("name", "")
        perf = stats_map.get(name)
        if perf:
            return -perf["success_rate"]  # Higher rate = earlier
        return -50  # Unknown tools get neutral position
    filtered.sort(key=_tool_sort_key)
    return filtered


def cl_track_lesson_usage(lessons: list[str], response_text: str, owner_id: int) -> None:
    """Loop 2: Check if LLM actually referenced injected lessons."""
    if not CLOSED_LOOP_ENABLED or not lessons or not response_text:
        return
    response_lower = response_text.lower()
    for lesson in lessons:
        words = lesson.lower().split()
        key_phrases = [" ".join(words[i:i + 3]) for i in range(len(words) - 2)]
        matched = any(phrase in response_lower for phrase in key_phrases[:5])
        if matched:
            RUNTIME_STATE["cl_lessons_used"] = int(RUNTIME_STATE.get("cl_lessons_used", 0)) + 1
        else:
            RUNTIME_STATE["cl_lessons_ignored"] = int(RUNTIME_STATE.get("cl_lessons_ignored", 0)) + 1
    RUNTIME_STATE["cl_loops_closed_total"] = int(RUNTIME_STATE.get("cl_loops_closed_total", 0)) + 1


def cl_close_improvement_notes(notes: list[str], response_text: str, owner_id: int) -> None:
    """Loop 3: Mark improvement notes as applied or dismissed based on LLM usage."""
    if not CLOSED_LOOP_ENABLED or not notes or not response_text:
        return
    response_lower = response_text.lower()
    db = SessionLocal()
    try:
        for note_text in notes:
            preview = (note_text or "")[:80]
            if not preview:
                continue
            note_row = db.query(SelfImprovementNote).filter(
                SelfImprovementNote.owner_id == owner_id,
                SelfImprovementNote.status == "open",
                SelfImprovementNote.summary.contains(preview),
            ).first()
            if not note_row:
                continue

            # Check if response references the note's action items
            actions = json.loads(note_row.actions_json or "[]")
            action_text = " ".join(str(a) for a in actions).lower()
            action_words = action_text.split()
            key_phrases = [" ".join(action_words[i:i + 3]) for i in range(len(action_words) - 2)]
            matched = any(phrase in response_lower for phrase in key_phrases[:5])

            retrieval_count = int(note_row.retrieval_count or 0) + 1
            note_row.retrieval_count = retrieval_count

            if matched:
                note_row.status = "applied"
                RUNTIME_STATE["cl_notes_applied"] = int(RUNTIME_STATE.get("cl_notes_applied", 0)) + 1
                log.info("CL_NOTE_APPLIED note_id=%d title=%s", note_row.id, (note_row.title or "")[:60])
            elif retrieval_count >= CLOSED_LOOP_NOTE_MAX_RETRIEVALS:
                note_row.status = "dismissed"
                RUNTIME_STATE["cl_notes_dismissed"] = int(RUNTIME_STATE.get("cl_notes_dismissed", 0)) + 1
                log.info("CL_NOTE_DISMISSED note_id=%d title=%s retrievals=%d", note_row.id, (note_row.title or "")[:60], retrieval_count)
        db.commit()
    except Exception as e:
        log.debug("CL_NOTE_CLOSE_FAIL: %s", e)
    finally:
        db.close()


def cl_adjust_for_forecast_confidence(confidence: int, step: dict) -> dict:
    """Loop 4: Modify execution strategy based on forecast confidence."""
    if not CLOSED_LOOP_ENABLED:
        return step
    if confidence < CLOSED_LOOP_FORECAST_LOW_CONFIDENCE:
        step["title"] = f"[LOW CONFIDENCE: {confidence}%] {step.get('title', '')}"
        step["_retry_budget_multiplier"] = 2
        RUNTIME_STATE["cl_forecasts_adjusted"] = int(RUNTIME_STATE.get("cl_forecasts_adjusted", 0)) + 1
        log.info("CL_FORECAST_ADJUSTED confidence=%d step=%s", confidence, str(step.get("title", ""))[:60])
    return step


def cl_check_dead_letter_pattern(db, owner_id: int, reason: str, task) -> None:
    """Loop 5: Block strategies that repeatedly fail (dead letter patterns)."""
    if not CLOSED_LOOP_ENABLED:
        return
    try:
        cutoff = datetime.utcnow() - timedelta(days=7)
        reason_prefix = (reason or "")[:100]
        if not reason_prefix:
            return
        similar_count = db.query(func.count(TaskDeadLetter.id)).filter(
            TaskDeadLetter.owner_id == int(owner_id),
            TaskDeadLetter.reason.contains(reason_prefix),
            TaskDeadLetter.created_at >= cutoff,
        ).scalar() or 0

        if similar_count >= CLOSED_LOOP_DEAD_LETTER_BLOCK_COUNT:
            blocked_note = (
                f"BLOCKED STRATEGY: Task '{task.title}' has failed {similar_count}x "
                f"with reason: '{reason[:200]}'. Do NOT retry this approach. "
                "Try a fundamentally different strategy."
            )
            note = SelfImprovementNote(
                owner_id=int(owner_id),
                title=f"Blocked: {truncate_text(task.title, 100)}",
                summary=blocked_note,
                actions_json=json.dumps(["Use alternative approach", "Break into smaller steps", "Skip if non-critical"]),
                evidence_json=json.dumps({"dead_letters": similar_count, "reason": reason[:200]}),
                priority="critical",
                status="open",
            )
            db.add(note)
            emb = get_embedding(blocked_note)
            if emb is not None and np.linalg.norm(emb) > 1e-9:
                db.add(MemoryVector(
                    owner_id=int(owner_id),
                    memory_type="self_improvement_note",
                    ref_id=0,
                    text_preview=truncate_text(blocked_note, 200),
                    embedding=embedding_to_bytes(emb),
                ))
            RUNTIME_STATE["cl_strategies_blocked"] = int(RUNTIME_STATE.get("cl_strategies_blocked", 0)) + 1
            log.warning(
                "CL_STRATEGY_BLOCKED owner=%d task=%s reason=%s count=%d",
                int(owner_id), str(task.title)[:60], reason[:100], similar_count,
            )
    except Exception as e:
        log.debug("CL_DEAD_LETTER_PATTERN_FAIL: %s", e)


# ============================================================================
# SECTION 5C: SELF-TUNING PERFORMANCE ENGINE
# Makes Bob detect and fix his own performance problems automatically.
# Serves Pillar 3 (Autonomy), Pillar 4 (Learning), Pillar 6 (Self-Awareness).
# Runs every SELF_TUNE_INTERVAL_TICKS heartbeat ticks (default: 2 = ~90s).
# ============================================================================

_st_prev_hard_clears: int = 0       # snapshot for rate detection (now tracks compaction_by_chars)
_st_zero_backlog_ticks: int = 0     # consecutive ticks with zero backlog
_st_zero_hard_clear_ticks: int = 0  # consecutive ticks with zero compaction increase
_st_zero_queue_ticks: int = 0       # consecutive ticks with empty queue
_st_zero_degraded_ticks: int = 0    # consecutive ticks with zero degradation increase
_st_prev_degraded: int = 0          # snapshot for rate detection


def st_tune_queue_mode() -> list[str]:
    """Tune queue mode based on backlog. Switch to 'auto' if backlog builds up."""
    global _st_zero_backlog_ticks
    actions = []
    enqueued = int(RUNTIME_STATE.get("command_queue_enqueued", 0))
    processed = int(RUNTIME_STATE.get("command_queue_processed", 0))
    backlog = max(0, enqueued - processed)
    current_mode = str(RUNTIME_STATE.get("command_queue_mode", COMMAND_QUEUE_MODE)).lower()

    effective_threshold = max(10, SELF_TUNE_QUEUE_BACKLOG_THRESHOLD)
    if backlog >= effective_threshold and current_mode == "on":
        RUNTIME_STATE["command_queue_mode"] = "auto"
        RUNTIME_STATE["st_queue_mode_switches"] = int(RUNTIME_STATE.get("st_queue_mode_switches", 0)) + 1
        _st_zero_backlog_ticks = 0
        actions.append(f"queue_mode on->auto (backlog={backlog})")
        log.info("ST_QUEUE_MODE on->auto backlog=%d threshold=%d", backlog, effective_threshold)
    elif backlog == 0:
        _st_zero_backlog_ticks += 1
    else:
        _st_zero_backlog_ticks = 0

    return actions


def st_tune_session_budget() -> list[str]:
    """Tune session char budgets based on compaction rate.

    With the OpenClaw-style unified context manager, hard clears no longer
    occur.  Instead we track ``session_compaction_by_chars`` — when compaction
    fires frequently, we raise budgets to reduce LLM summarisation cost.
    """
    global _st_prev_hard_clears, _st_zero_hard_clear_ticks, SESSION_SOFT_TRIM_CHAR_BUDGET, SESSION_HARD_CLEAR_CHAR_BUDGET
    actions = []
    # Monitor compaction events (replaces old hard clear monitoring)
    current_hard_clears = int(RUNTIME_STATE.get("session_compaction_by_chars", 0))
    delta = current_hard_clears - _st_prev_hard_clears
    _st_prev_hard_clears = current_hard_clears

    if delta >= SELF_TUNE_HARD_CLEAR_RATE_THRESHOLD:
        _st_zero_hard_clear_ticks = 0
        old_soft = SESSION_SOFT_TRIM_CHAR_BUDGET
        old_hard = SESSION_HARD_CLEAR_CHAR_BUDGET
        new_soft = min(SELF_TUNE_SESSION_BUDGET_MAX, old_soft + SELF_TUNE_SESSION_BUDGET_STEP)
        new_hard = min(SELF_TUNE_SESSION_BUDGET_MAX - 8000, old_hard + SELF_TUNE_SESSION_BUDGET_STEP)
        if new_soft != old_soft or new_hard != old_hard:
            SESSION_SOFT_TRIM_CHAR_BUDGET = new_soft
            SESSION_HARD_CLEAR_CHAR_BUDGET = new_hard
            RUNTIME_STATE["st_current_session_soft_budget"] = new_soft
            RUNTIME_STATE["st_current_session_hard_budget"] = new_hard
            RUNTIME_STATE["st_session_budget_adjustments"] = int(RUNTIME_STATE.get("st_session_budget_adjustments", 0)) + 1
            actions.append(f"session_budget raised soft={old_soft}->{new_soft} hard={old_hard}->{new_hard}")
            log.info("ST_SESSION_BUDGET_RAISE soft=%d->%d hard=%d->%d delta_clears=%d",
                     old_soft, new_soft, old_hard, new_hard, delta)
    elif delta == 0:
        _st_zero_hard_clear_ticks += 1
        if _st_zero_hard_clear_ticks >= 10:
            old_soft = SESSION_SOFT_TRIM_CHAR_BUDGET
            old_hard = SESSION_HARD_CLEAR_CHAR_BUDGET
            new_soft = max(SELF_TUNE_SESSION_BUDGET_MIN, old_soft - SELF_TUNE_SESSION_BUDGET_STEP)
            new_hard = max(SELF_TUNE_SESSION_BUDGET_MIN, old_hard - SELF_TUNE_SESSION_BUDGET_STEP)
            if new_soft != old_soft or new_hard != old_hard:
                SESSION_SOFT_TRIM_CHAR_BUDGET = new_soft
                SESSION_HARD_CLEAR_CHAR_BUDGET = new_hard
                RUNTIME_STATE["st_current_session_soft_budget"] = new_soft
                RUNTIME_STATE["st_current_session_hard_budget"] = new_hard
                RUNTIME_STATE["st_session_budget_adjustments"] = int(RUNTIME_STATE.get("st_session_budget_adjustments", 0)) + 1
                _st_zero_hard_clear_ticks = 0
                actions.append(f"session_budget lowered soft={old_soft}->{new_soft} hard={old_hard}->{new_hard}")
                log.info("ST_SESSION_BUDGET_LOWER soft=%d->%d hard=%d->%d stable_ticks=10",
                         old_soft, new_soft, old_hard, new_hard)
    else:
        _st_zero_hard_clear_ticks = 0

    return actions


def st_tune_workers() -> list[str]:
    """Scale queue workers up/down based on queue depth."""
    global _st_zero_queue_ticks, COMMAND_QUEUE_WORKER_COUNT
    actions = []
    if not command_queue_enabled():
        return actions

    queue_size = int(RUNTIME_STATE.get("command_queue_size", 0))
    alive = int(RUNTIME_STATE.get("command_queue_worker_alive_count", 0))

    if queue_size > 5 and alive < SELF_TUNE_WORKER_MAX:
        old_count = COMMAND_QUEUE_WORKER_COUNT
        COMMAND_QUEUE_WORKER_COUNT = min(SELF_TUNE_WORKER_MAX, old_count + 1)
        RUNTIME_STATE["st_current_worker_count"] = COMMAND_QUEUE_WORKER_COUNT
        RUNTIME_STATE["st_worker_scale_events"] = int(RUNTIME_STATE.get("st_worker_scale_events", 0)) + 1
        _st_zero_queue_ticks = 0
        actions.append(f"workers scaled {old_count}->{COMMAND_QUEUE_WORKER_COUNT} (queue_size={queue_size})")
        log.info("ST_WORKER_SCALE_UP %d->%d queue_size=%d", old_count, COMMAND_QUEUE_WORKER_COUNT, queue_size)
    elif queue_size == 0:
        _st_zero_queue_ticks += 1
        if _st_zero_queue_ticks >= 10 and COMMAND_QUEUE_WORKER_COUNT > 2:
            old_count = COMMAND_QUEUE_WORKER_COUNT
            COMMAND_QUEUE_WORKER_COUNT = max(2, old_count - 1)
            RUNTIME_STATE["st_current_worker_count"] = COMMAND_QUEUE_WORKER_COUNT
            RUNTIME_STATE["st_worker_scale_events"] = int(RUNTIME_STATE.get("st_worker_scale_events", 0)) + 1
            _st_zero_queue_ticks = 0
            actions.append(f"workers scaled {old_count}->{COMMAND_QUEUE_WORKER_COUNT} (idle)")
            log.info("ST_WORKER_SCALE_DOWN %d->%d idle_ticks=10", old_count, COMMAND_QUEUE_WORKER_COUNT)
    else:
        _st_zero_queue_ticks = 0

    return actions


def st_tune_budget_mode() -> list[str]:
    """Loosen budget governor when too many runs get degraded."""
    global _st_prev_degraded, _st_zero_degraded_ticks, BUDGET_GOVERNOR_MODE
    actions = []
    current_degraded = int(RUNTIME_STATE.get("budget_runs_degraded", 0))
    delta = current_degraded - _st_prev_degraded
    _st_prev_degraded = current_degraded
    current_mode = str(RUNTIME_STATE.get("budget_governor_mode", BUDGET_GOVERNOR_MODE)).lower()

    if delta > 3 and current_mode == "degrade":
        BUDGET_GOVERNOR_MODE = "warn"
        RUNTIME_STATE["budget_governor_mode"] = "warn"
        RUNTIME_STATE["st_budget_mode_switches"] = int(RUNTIME_STATE.get("st_budget_mode_switches", 0)) + 1
        _st_zero_degraded_ticks = 0
        actions.append(f"budget_mode degrade->warn (degraded_delta={delta})")
        log.info("ST_BUDGET_MODE degrade->warn degraded_delta=%d", delta)
    elif delta == 0:
        _st_zero_degraded_ticks += 1
        if _st_zero_degraded_ticks >= 20 and current_mode == "warn":
            BUDGET_GOVERNOR_MODE = "degrade"
            RUNTIME_STATE["budget_governor_mode"] = "degrade"
            RUNTIME_STATE["st_budget_mode_switches"] = int(RUNTIME_STATE.get("st_budget_mode_switches", 0)) + 1
            _st_zero_degraded_ticks = 0
            actions.append("budget_mode warn->degrade (stable 20 ticks)")
            log.info("ST_BUDGET_MODE warn->degrade stable_ticks=20")
    else:
        _st_zero_degraded_ticks = 0

    return actions


def st_self_tune():
    """Section 5C: Self-Tuning Performance Engine. Called from heartbeat."""
    if not SELF_TUNE_ENABLED:
        return
    tick = int(RUNTIME_STATE.get("heartbeat_ticks_total", 0))
    if tick == 0 or tick % SELF_TUNE_INTERVAL_TICKS != 0:
        return

    actions = []
    try:
        actions += st_tune_queue_mode()
        actions += st_tune_session_budget()
        actions += st_tune_workers()
        actions += st_tune_budget_mode()
    except Exception as e:
        log.debug("ST_SELF_TUNE_ERROR: %s", e)

    RUNTIME_STATE["st_tunes_total"] = int(RUNTIME_STATE.get("st_tunes_total", 0)) + 1
    RUNTIME_STATE["st_last_tune_at"] = utc_now_iso()
    if actions:
        RUNTIME_STATE["st_last_action"] = "; ".join(actions)
        log.info("SELF_TUNE tick=%d actions=%s", tick, actions)


# ============================================================================
# SECTION 6: CONVERSATION MEMORY
# ============================================================================

def _clone_chat_message_for_pruning(msg: dict) -> dict:
    try:
        return json.loads(json.dumps(msg, ensure_ascii=False))
    except Exception:
        return dict(msg or {})


def _message_payload_size(msg: dict) -> int:
    size = 0
    content = msg.get("content")
    if isinstance(content, str):
        size += len(content)
    tc = msg.get("tool_calls")
    if tc is not None:
        try:
            size += len(json.dumps(tc, ensure_ascii=False))
        except Exception:
            size += len(str(tc))
    tool_call_id = msg.get("tool_call_id")
    if isinstance(tool_call_id, str):
        size += len(tool_call_id)
    return size


def _trim_text_for_context(value: str, max_len: int, marker: str) -> str:
    text = str(value or "")
    if len(text) <= max_len:
        return text
    return text[:max_len] + marker


def _sanitize_tool_call_transcript(
    messages: list[dict],
    cleared_placeholder: str = "[tool calls cleared]",
) -> tuple[list[dict], dict]:
    """
    Enforce strict assistant->tool sequencing for tool calls.

    The LLM API requires each assistant message with tool_calls to be followed
    by tool messages that respond to those exact call IDs. This sanitizer keeps
    only immediately-following matching tool responses and clears orphaned
    assistant tool_calls/tool messages.
    """
    source = list(messages or [])
    cleaned: list[dict] = []
    assistant_calls_removed = 0
    assistant_calls_trimmed = 0
    orphan_tool_messages_removed = 0

    i = 0
    while i < len(source):
        raw_msg = source[i]
        msg = dict(raw_msg) if isinstance(raw_msg, dict) else {"role": "user", "content": str(raw_msg)}
        role = str(msg.get("role", "")).lower()

        if role == "assistant" and isinstance(msg.get("tool_calls"), list):
            raw_calls = list(msg.get("tool_calls") or [])
            valid_calls: list[dict] = []
            for raw_tc in raw_calls:
                if not isinstance(raw_tc, dict):
                    continue
                call_id = str(raw_tc.get("id") or "").strip()
                if not call_id:
                    continue
                tc = dict(raw_tc)
                tc["id"] = call_id[:120]
                valid_calls.append(tc)

            if valid_calls:
                msg["tool_calls"] = valid_calls
                if "reasoning_content" not in msg:
                    msg["reasoning_content"] = ""
            else:
                msg.pop("tool_calls", None)
                msg.pop("reasoning_content", None)

            # Tool responses must immediately follow this assistant message.
            j = i + 1
            tool_block: list[dict] = []
            while j < len(source):
                next_raw = source[j]
                next_msg = dict(next_raw) if isinstance(next_raw, dict) else {"role": "tool", "content": str(next_raw)}
                if str(next_msg.get("role", "")).lower() != "tool":
                    break
                tool_block.append(next_msg)
                j += 1

            required_counts: dict[str, int] = {}
            for tc in valid_calls:
                call_id = str(tc.get("id") or "").strip()
                required_counts[call_id] = int(required_counts.get(call_id, 0)) + 1

            consumed_counts: dict[str, int] = {}
            kept_tool_block: list[dict] = []
            for tool_msg in tool_block:
                tool_call_id = str(tool_msg.get("tool_call_id") or "").strip()
                allowed = int(required_counts.get(tool_call_id, 0))
                consumed = int(consumed_counts.get(tool_call_id, 0))
                if tool_call_id and consumed < allowed:
                    consumed_counts[tool_call_id] = consumed + 1
                    tool_msg["tool_call_id"] = tool_call_id[:120]
                    kept_tool_block.append(tool_msg)
                else:
                    orphan_tool_messages_removed += 1

            kept_calls: list[dict] = []
            kept_counts: dict[str, int] = {}
            for tc in valid_calls:
                call_id = str(tc.get("id") or "").strip()
                available = int(consumed_counts.get(call_id, 0))
                used = int(kept_counts.get(call_id, 0))
                if used < available:
                    kept_counts[call_id] = used + 1
                    kept_calls.append(tc)

            removed_calls = max(0, len(valid_calls) - len(kept_calls))
            if removed_calls > 0:
                assistant_calls_trimmed += removed_calls

            if kept_calls:
                msg["tool_calls"] = kept_calls
                if "reasoning_content" not in msg:
                    msg["reasoning_content"] = ""
            else:
                if valid_calls:
                    assistant_calls_removed += 1
                msg.pop("tool_calls", None)
                msg.pop("reasoning_content", None)
                if not msg.get("content"):
                    msg["content"] = str(cleared_placeholder or "[tool calls cleared]")

            cleaned.append(msg)
            cleaned.extend(kept_tool_block)
            i = j
            continue

        if role == "tool":
            orphan_tool_messages_removed += 1
            i += 1
            continue

        cleaned.append(msg)
        i += 1

    return cleaned, {
        "assistant_calls_removed": int(assistant_calls_removed),
        "assistant_calls_trimmed": int(assistant_calls_trimmed),
        "orphan_tool_messages_removed": int(orphan_tool_messages_removed),
    }


def prepare_messages_for_llm(messages: list[dict]) -> tuple[list[dict], dict]:
    if not SESSION_SOFT_TRIM_ENABLED or len(messages) <= 2:
        total = sum(_message_payload_size(msg) for msg in (messages or []))
        return messages, {
            "soft_trimmed": 0,
            "hard_cleared": 0,
            "chars_before": total,
            "chars_after": total,
        }

    pruned = [_clone_chat_message_for_pruning(msg) for msg in (messages or [])]
    chars_before = sum(_message_payload_size(msg) for msg in pruned)
    soft_trimmed = 0
    lightweight_trimmed = 0

    non_system_indexes = [i for i in range(1, len(pruned))]
    soft_keep = set(non_system_indexes[-SESSION_SOFT_TRIM_KEEP_RECENT:])
    hard_keep = set(non_system_indexes[-SESSION_HARD_CLEAR_KEEP_RECENT:])

    # Soft trim pass: keep structure, shrink older heavy payloads.
    for idx in non_system_indexes:
        if idx in soft_keep:
            continue
        msg = pruned[idx]
        role = str(msg.get("role", "")).lower()
        if role == "tool":
            content = str(msg.get("content") or "")
            trimmed = _trim_text_for_context(content, SESSION_SOFT_TRIM_TOOL_MAX_CHARS, "...[SOFT_TRIMMED]")
            if trimmed != content:
                msg["content"] = trimmed
                soft_trimmed += 1
        if role == "assistant" and isinstance(msg.get("tool_calls"), list):
            tool_calls = list(msg.get("tool_calls") or [])
            changed = False
            if len(tool_calls) > 4:
                tool_calls = tool_calls[:4]
                changed = True
            for tc in tool_calls:
                if not isinstance(tc, dict):
                    continue
                fn = tc.get("function")
                if not isinstance(fn, dict):
                    continue
                args_raw = str(fn.get("arguments") or "")
                trimmed_args = _trim_text_for_context(args_raw, 480, "...[SOFT_TRIMMED]")
                if trimmed_args != args_raw:
                    fn["arguments"] = trimmed_args
                    changed = True
            if changed:
                msg["tool_calls"] = tool_calls
                soft_trimmed += 1

    chars_after_soft = sum(_message_payload_size(msg) for msg in pruned)

    # Lightweight trim pass: if still above hard budget after soft trim,
    # further truncate tool responses and tool_call arguments — but NEVER
    # delete content entirely.  The char-budget compaction in
    # compact_session_by_char_budget() should prevent this from firing
    # frequently; this is a safety net, not the primary strategy.
    lightweight_trimmed = 0
    if chars_after_soft > SESSION_HARD_CLEAR_CHAR_BUDGET:
        for idx in non_system_indexes:
            if chars_after_soft <= SESSION_HARD_CLEAR_CHAR_BUDGET:
                break
            if idx in hard_keep:
                continue
            msg = pruned[idx]
            role = str(msg.get("role", "")).lower()
            if role == "tool":
                content = str(msg.get("content") or "")
                trimmed = _trim_text_for_context(content, COMPACTION_LIGHTWEIGHT_TOOL_MAX_CHARS, "...[TRIMMED]")
                if trimmed != content:
                    msg["content"] = trimmed
                    lightweight_trimmed += 1
                    chars_after_soft = sum(_message_payload_size(item) for item in pruned)
            elif role == "assistant" and isinstance(msg.get("tool_calls"), list):
                changed = False
                for tc in (msg.get("tool_calls") or []):
                    if not isinstance(tc, dict):
                        continue
                    fn = tc.get("function")
                    if not isinstance(fn, dict):
                        continue
                    args_raw = str(fn.get("arguments") or "")
                    trimmed_args = _trim_text_for_context(args_raw, COMPACTION_LIGHTWEIGHT_ARGS_MAX_CHARS, "...[TRIMMED]")
                    if trimmed_args != args_raw:
                        fn["arguments"] = trimmed_args
                        changed = True
                if changed:
                    lightweight_trimmed += 1
                    chars_after_soft = sum(_message_payload_size(item) for item in pruned)
    if lightweight_trimmed > 0:
        RUNTIME_STATE["session_lightweight_trim_count"] = int(RUNTIME_STATE.get("session_lightweight_trim_count", 0)) + lightweight_trimmed

    # Structural integrity pass: ensure every tool_call has a matching tool response.
    # Kimi rejects requests where tool_call_ids have no matching tool message.
    _tool_response_ids = set()
    for msg in pruned:
        if str(msg.get("role", "")).lower() == "tool" and msg.get("tool_call_id"):
            _tool_response_ids.add(msg["tool_call_id"])
    for msg in pruned:
        if str(msg.get("role", "")).lower() == "assistant" and isinstance(msg.get("tool_calls"), list):
            original_tcs = list(msg["tool_calls"])
            valid_tcs = [tc for tc in original_tcs if isinstance(tc, dict) and tc.get("id") in _tool_response_ids]
            if len(valid_tcs) == 0:
                # No matching tool responses — convert to plain assistant message
                msg.pop("tool_calls", None)
                msg.pop("reasoning_content", None)
                if not msg.get("content"):
                    msg["content"] = "[tool calls cleared — responses trimmed from context]"
            elif len(valid_tcs) < len(original_tcs):
                msg["tool_calls"] = valid_tcs
    # Also remove orphaned tool messages with no matching assistant tool_call
    _all_tool_call_ids = set()
    for msg in pruned:
        if isinstance(msg.get("tool_calls"), list):
            for tc in msg["tool_calls"]:
                if isinstance(tc, dict) and tc.get("id"):
                    _all_tool_call_ids.add(tc["id"])
    pruned = [
        msg for msg in pruned
        if not (str(msg.get("role", "")).lower() == "tool" and msg.get("tool_call_id") and msg["tool_call_id"] not in _all_tool_call_ids)
    ]
    pruned, _integrity_fix = _sanitize_tool_call_transcript(
        pruned,
        cleared_placeholder="[tool calls cleared - responses trimmed from context]",
    )

    chars_after = sum(_message_payload_size(msg) for msg in pruned)
    chars_saved = max(0, chars_before - chars_after)
    if chars_saved > 0:
        RUNTIME_STATE["session_last_prune_chars"] = int(chars_saved)
    if soft_trimmed > 0:
        RUNTIME_STATE["session_soft_trim_count"] = int(RUNTIME_STATE.get("session_soft_trim_count", 0)) + int(soft_trimmed)
    return pruned, {
        "soft_trimmed": int(soft_trimmed),
        "hard_cleared": 0,
        "lightweight_trimmed": int(lightweight_trimmed),
        "chars_before": int(chars_before),
        "chars_after": int(chars_after),
    }


def _estimate_tokens_from_chars(chars: int) -> int:
    value = max(0, int(chars))
    return max(1, int(round(value / 4.0)))


def capture_context_snapshot(
    owner_id: int,
    session_id: str,
    source_type: str,
    llm_messages: list[dict],
    system_prompt: str,
    history_count: int,
    prune_meta: dict | None = None,
    tools_count: int = 0,
):
    if owner_id <= 0:
        return
    prepared = list(llm_messages or [])
    payload_chars = sum(_message_payload_size(msg) for msg in prepared)
    token_est = _estimate_tokens_from_chars(payload_chars)
    now_iso = utc_now_iso()
    with CONTEXT_XRAY_LOCK:
        seq = int(CONTEXT_XRAY_SEQ.get(owner_id, 0)) + 1
        CONTEXT_XRAY_SEQ[owner_id] = seq
        snapshot = {
            "snapshot_id": seq,
            "owner_id": int(owner_id),
            "session_id": truncate_text(str(session_id or ""), 120),
            "source_type": truncate_text(str(source_type or "chat"), 32),
            "created_at": now_iso,
            "history_count": int(history_count),
            "messages_count": len(prepared),
            "tool_schema_count": int(tools_count),
            "payload_chars": int(payload_chars),
            "token_estimate": int(token_est),
            "prune_meta": dict(prune_meta or {}),
            "system_prompt_preview": truncate_text(system_prompt or "", 1200),
            "messages": prepared,
        }
        bucket = CONTEXT_XRAY_SNAPSHOTS.get(owner_id)
        if not isinstance(bucket, list):
            bucket = []
            CONTEXT_XRAY_SNAPSHOTS[owner_id] = bucket
        bucket.append(snapshot)
        if len(bucket) > CONTEXT_XRAY_MAX_SNAPSHOTS:
            del bucket[:-CONTEXT_XRAY_MAX_SNAPSHOTS]
    RUNTIME_STATE["context_xray_snapshots_total"] = int(RUNTIME_STATE.get("context_xray_snapshots_total", 0)) + 1
    RUNTIME_STATE["context_xray_last_snapshot_at"] = now_iso


def list_context_snapshots(owner_id: int, limit: int = 20) -> list[dict]:
    with CONTEXT_XRAY_LOCK:
        bucket = list(CONTEXT_XRAY_SNAPSHOTS.get(int(owner_id), []))
    limit_val = clamp_int(limit, 1, CONTEXT_XRAY_MAX_SNAPSHOTS, 20)
    selected = bucket[-limit_val:]
    result = []
    for row in selected:
        result.append(
            {
                "snapshot_id": int(row.get("snapshot_id", 0)),
                "created_at": row.get("created_at"),
                "session_id": row.get("session_id"),
                "source_type": row.get("source_type"),
                "history_count": int(row.get("history_count", 0)),
                "messages_count": int(row.get("messages_count", 0)),
                "tool_schema_count": int(row.get("tool_schema_count", 0)),
                "payload_chars": int(row.get("payload_chars", 0)),
                "token_estimate": int(row.get("token_estimate", 0)),
            }
        )
    return list(reversed(result))


def get_context_snapshot(owner_id: int, snapshot_id: int) -> dict | None:
    with CONTEXT_XRAY_LOCK:
        bucket = list(CONTEXT_XRAY_SNAPSHOTS.get(int(owner_id), []))
    for row in reversed(bucket):
        if int(row.get("snapshot_id", 0)) == int(snapshot_id):
            return dict(row)
    return None


def get_conversation_history(db: Session, owner_id: int, limit: int = 50, repair: bool = False) -> list[dict]:
    """Load recent conversation messages for a user."""
    with session_write_lock(int(owner_id), reason="history_load"):
        if repair:
            try:
                repair_transcript_for_owner(db, int(owner_id), max_rows=max(limit * 6, 300), create_synthetic=True)
            except Exception as exc:
                log.warning("SESSION_TRANSCRIPT_REPAIR_LOAD_FAIL owner=%d error=%s", int(owner_id), truncate_text(str(exc), 220))

        rows = (
            db.query(ConversationMessage)
            .filter(ConversationMessage.owner_id == owner_id)
            .order_by(ConversationMessage.id.desc())
            .limit(limit)
            .all()
        )
        rows.reverse()  # Oldest first

        messages = []
        for row in rows:
            msg = {"role": row.role}
            if row.content:
                msg["content"] = row.content
            if row.tool_calls_json:
                msg["tool_calls"] = _safe_load_tool_calls_json(row.tool_calls_json)
                # OpenAI format: assistant messages with tool_calls may have null content
                if not row.content:
                    msg["content"] = None
                # Kimi K2.5 thinking mode requires reasoning_content on assistant
                # messages with tool_calls; use empty string for stored history.
                msg["reasoning_content"] = ""
            if row.tool_call_id:
                msg["tool_call_id"] = row.tool_call_id
            messages.append(msg)

        # ---- Orphan cleanup at load time ----
        # Strip assistant tool_calls that have no matching tool response in history.
        # This prevents HTTP 400 errors from the LLM API.
        _h_tc_ids = set()
        _h_resp_ids = set()
        for _hm in messages:
            if _hm.get("role") == "assistant" and isinstance(_hm.get("tool_calls"), list):
                for _htc in _hm["tool_calls"]:
                    if isinstance(_htc, dict) and _htc.get("id"):
                        _h_tc_ids.add(_htc["id"])
            if _hm.get("role") == "tool" and _hm.get("tool_call_id"):
                _h_resp_ids.add(_hm["tool_call_id"])
        _h_orphaned = _h_tc_ids - _h_resp_ids
        if _h_orphaned:
            log.warning("HISTORY_LOAD_ORPHAN_FIX owner=%d orphaned_ids=%s", owner_id, _h_orphaned)
            for _hm in messages:
                if _hm.get("role") == "assistant" and isinstance(_hm.get("tool_calls"), list):
                    _hm["tool_calls"] = [
                        _htc for _htc in _hm["tool_calls"]
                        if not (isinstance(_htc, dict) and _htc.get("id") in _h_orphaned)
                    ]
                    if not _hm["tool_calls"]:
                        _hm.pop("tool_calls", None)
                        _hm.pop("reasoning_content", None)
                        if not _hm.get("content"):
                            _hm["content"] = "[tool calls cleared — responses missing from history]"
            # Also remove orphaned tool response messages
            messages = [
                _hm for _hm in messages
                if not (_hm.get("role") == "tool" and _hm.get("tool_call_id") and _hm["tool_call_id"] not in _h_tc_ids)
            ]

        messages, _history_fix = _sanitize_tool_call_transcript(
            messages,
            cleared_placeholder="[tool calls cleared - responses missing from history]",
        )
        if (
            int(_history_fix.get("assistant_calls_removed", 0)) > 0
            or int(_history_fix.get("assistant_calls_trimmed", 0)) > 0
            or int(_history_fix.get("orphan_tool_messages_removed", 0)) > 0
        ):
            log.warning(
                "HISTORY_LOAD_SEQUENCE_FIX owner=%d trimmed=%d removed=%d orphan_tools=%d",
                int(owner_id),
                int(_history_fix.get("assistant_calls_trimmed", 0)),
                int(_history_fix.get("assistant_calls_removed", 0)),
                int(_history_fix.get("orphan_tool_messages_removed", 0)),
            )

        return messages


def save_message(db: Session, owner_id: int, role: str, content: str = None,
                 tool_call_id: str = None, tool_calls: list = None):
    """Persist a single message to the conversation history."""
    with session_write_lock(int(owner_id), reason="message_save"):
        msg = ConversationMessage(
            owner_id=owner_id,
            role=role,
            content=content,
            tool_call_id=tool_call_id,
            tool_calls_json=json.dumps(tool_calls) if tool_calls else None,
        )
        db.add(msg)
        db.commit()


# ============================================================================
# SECTION 7: LLM CLIENT (Primary + Failover via OpenAI-compatible API)
# ============================================================================

def _default_llm_profiles() -> list[dict]:
    """
    Multi-model failover chain:
    1. Kimi K2.5 (API paid) - Primary
    2. Gemini 3 Pro (FREE tier) - First fallback
    3. GPT-5.3-Codex (OpenAI subscription) - Second fallback  
    4. Claude Sonnet 4.5 (Anthropic subscription) - Third fallback
    """
    profiles = []
    
    # Priority 10: Primary - Kimi K2.5
    profiles.append({
        "name": "primary_kimi",
        "provider": "moonshot",
        "base_url": KIMI_BASE_URL,
        "model": KIMI_MODEL,
        "api_key": KIMI_API_KEY,
        "priority": 10,
        "enabled": True,
        "billing_enabled": True,
        "supports_tools": True,
        "supports_vision": True,
    })
    
    # Priority 20: Fallback 1 - Gemini 3 Pro (FREE tier)
    gemini_key = os.getenv("GEMINI_API_KEY", "").strip()
    if gemini_key:
        profiles.append({
            "name": "fallback_gemini",
            "provider": "google",
            "base_url": "https://generativelanguage.googleapis.com/v1beta/openai",
            "model": "gemini-3-pro",
            "api_key": gemini_key,
            "priority": 20,
            "enabled": True,
            "billing_enabled": False,  # FREE tier
            "supports_tools": True,
            "supports_vision": True,
        })
    
    # Priority 30: Fallback 2 - GPT-5.3-Codex (OpenAI)
    openai_key = os.getenv("OPENAI_API_KEY", "").strip()
    if openai_key:
        profiles.append({
            "name": "fallback_openai",
            "provider": "openai",
            "base_url": "https://api.openai.com/v1",
            "model": "gpt-5.3-codex",
            "api_key": openai_key,
            "priority": 30,
            "enabled": True,
            "billing_enabled": True,
            "supports_tools": True,
            "supports_vision": True,
        })
    
    # Priority 40: Fallback 3 - Claude Sonnet 4.5 (Anthropic)
    anthropic_key = os.getenv("ANTHROPIC_API_KEY", "").strip()
    if anthropic_key:
        profiles.append({
            "name": "fallback_claude",
            "provider": "anthropic",
            "base_url": "https://api.anthropic.com/v1",
            "model": "claude-sonnet-4-5-20250929",
            "api_key": anthropic_key,
            "priority": 40,
            "enabled": True,
            "billing_enabled": True,
            "supports_tools": True,
            "supports_vision": True,
        })
    
    # Legacy fallback support (Kimi internal fallback)
    fallback = (KIMI_FALLBACK_MODEL or "").strip()
    if LLM_FAILOVER_ENABLED and fallback and fallback != KIMI_MODEL:
        profiles.append({
            "name": "fallback_kimi_internal",
            "provider": "moonshot",
            "base_url": KIMI_BASE_URL,
            "model": fallback,
            "api_key": KIMI_API_KEY,
            "priority": 50,
            "enabled": True,
            "billing_enabled": True,
            "supports_tools": True,
            "supports_vision": True,
        })
    
    return profiles


def configured_llm_profiles() -> list[dict]:
    configured: list[dict] = []
    if MODEL_ROUTER_PROFILES_JSON.strip():
        try:
            parsed = json.loads(MODEL_ROUTER_PROFILES_JSON)
            if isinstance(parsed, list):
                for idx, item in enumerate(parsed):
                    if not isinstance(item, dict):
                        continue
                    name = truncate_text(str(item.get("name") or f"profile_{idx+1}").strip().lower(), 50)
                    model = truncate_text(str(item.get("model") or "").strip(), 120)
                    base_url = str(item.get("base_url") or KIMI_BASE_URL).strip().rstrip("/")
                    enabled = bool(item.get("enabled", True))
                    billing_enabled = bool(item.get("billing_enabled", True))
                    supports_tools = bool(item.get("supports_tools", True))
                    supports_vision = bool(item.get("supports_vision", True))
                    priority = clamp_int(item.get("priority", (idx + 1) * 10), 1, 999, (idx + 1) * 10)
                    api_key = str(item.get("api_key") or "").strip()
                    api_key_env = str(item.get("api_key_env") or "").strip()
                    if not api_key and api_key_env:
                        api_key = str(os.getenv(api_key_env, "") or "").strip()
                    if not model or not base_url or not api_key:
                        continue
                    if MODEL_ROUTER_BILLING_HARD_DISABLE and not billing_enabled:
                        enabled = False
                    configured.append(
                        {
                            "name": name,
                            "provider": truncate_text(str(item.get("provider") or "custom"), 40),
                            "base_url": base_url,
                            "model": model,
                            "api_key": api_key,
                            "priority": priority,
                            "enabled": enabled,
                            "billing_enabled": billing_enabled,
                            "supports_tools": supports_tools,
                            "supports_vision": supports_vision,
                        }
                    )
        except Exception as e:
            log.warning("MODEL_ROUTER_PARSE_FAIL error=%s", truncate_text(str(e), 220))

    if not configured:
        configured = _default_llm_profiles()

    filtered = [p for p in configured if bool(p.get("enabled", True))]
    filtered.sort(key=lambda p: int(p.get("priority", 999)))
    RUNTIME_STATE["model_router_profiles_loaded"] = len(filtered)
    return filtered


def configured_llm_models() -> list[str]:
    models: list[str] = []
    for profile in configured_llm_profiles():
        model = str(profile.get("model") or "").strip()
        if model and model not in models:
            models.append(model)
    return models


def llm_failover_active() -> bool:
    return len(configured_llm_profiles()) > 1


def _extract_llm_error_message(resp: requests.Response) -> str:
    status = resp.status_code
    text = ""
    try:
        payload = resp.json()
        if isinstance(payload, dict):
            err = payload.get("error")
            if isinstance(err, dict):
                text = str(err.get("message") or "")
            elif err is not None:
                text = str(err)
    except Exception:
        text = ""
    if not text:
        text = resp.text or ""
    text = truncate_text(text.strip(), 280)
    return f"HTTP {status}: {text}" if text else f"HTTP {status}"


def _llm_should_attempt_failover(status_code: int | None, has_more_profiles: bool) -> bool:
    if not has_more_profiles:
        return False
    if status_code is None:
        return True
    return status_code in LLM_FAILOVER_RETRYABLE_STATUSES


def _record_llm_attempt(model_name: str):
    RUNTIME_STATE["llm_last_attempt_at"] = utc_now_iso()
    RUNTIME_STATE["llm_last_model_used"] = model_name


def _record_llm_success(model_name: str):
    RUNTIME_STATE["llm_last_model_used"] = model_name
    RUNTIME_STATE["llm_last_success_at"] = utc_now_iso()
    RUNTIME_STATE["llm_last_error"] = None


def _record_llm_failure(model_name: str, error_message: str):
    if model_name == KIMI_MODEL:
        RUNTIME_STATE["llm_primary_failures"] = int(RUNTIME_STATE["llm_primary_failures"]) + 1
    else:
        RUNTIME_STATE["llm_fallback_failures"] = int(RUNTIME_STATE["llm_fallback_failures"]) + 1
    RUNTIME_STATE["llm_last_error"] = truncate_text(error_message, 300)


def _model_profile_key(profile: dict) -> str:
    name = str(profile.get("name") or "").strip().lower()
    model = str(profile.get("model") or "").strip().lower()
    return name or model or "profile"


def _model_profile_health_state(profile_key: str) -> dict:
    key = str(profile_key or "").strip().lower() or "profile"
    with MODEL_ROUTER_LOCK:
        row = MODEL_PROFILE_HEALTH.get(key)
        if not isinstance(row, dict):
            row = {
                "failures_total": 0,
                "consecutive_failures": 0,
                "disabled_until": 0.0,
                "last_error": None,
                "last_failure_at": None,
                "last_success_at": None,
            }
            MODEL_PROFILE_HEALTH[key] = row
        return row


def _messages_contain_vision_content(messages: list[dict]) -> bool:
    for msg in list(messages or []):
        content = msg.get("content")
        if isinstance(content, list):
            for part in content:
                if not isinstance(part, dict):
                    continue
                if str(part.get("type") or "").strip().lower() == "image_url":
                    return True
    return False


def _canary_route_selected(route_key: str | None) -> bool:
    if not CANARY_ROUTER_ENABLED:
        return False
    if CANARY_TRAFFIC_PERCENT <= 0:
        return False
    key = str(route_key or "global").strip().lower() or "global"
    digest = hashlib.sha256(key.encode("utf-8")).hexdigest()
    bucket = int(digest[:8], 16) % 100
    return bucket < int(CANARY_TRAFFIC_PERCENT)


def _canary_refresh_state_locked(now_mono: float):
    rolled_back_until = float(CANARY_STATE.get("rolled_back_until", 0.0) or 0.0)
    if rolled_back_until > 0 and rolled_back_until <= now_mono:
        CANARY_STATE["enabled"] = bool(CANARY_ROUTER_ENABLED)
        CANARY_STATE["rolled_back_until"] = 0.0
        CANARY_STATE["samples"] = 0
        CANARY_STATE["failures"] = 0
        CANARY_STATE["last_reason"] = None


def _canary_mark_result(success: bool, profile: dict):
    profile_name = str(profile.get("name") or "").strip().lower()
    if profile_name != CANARY_PROFILE_NAME:
        return
    now_mono = time.monotonic()
    with CANARY_LOCK:
        _canary_refresh_state_locked(now_mono)
        if not bool(CANARY_STATE.get("enabled", CANARY_ROUTER_ENABLED)):
            return
        CANARY_STATE["samples"] = int(CANARY_STATE.get("samples", 0)) + 1
        if not success:
            CANARY_STATE["failures"] = int(CANARY_STATE.get("failures", 0)) + 1
        samples = int(CANARY_STATE.get("samples", 0))
        failures = int(CANARY_STATE.get("failures", 0))
        fail_rate = (failures / samples) if samples > 0 else 0.0
        if samples >= int(CANARY_MIN_SAMPLES) and fail_rate >= float(CANARY_FAIL_THRESHOLD):
            CANARY_STATE["enabled"] = False
            CANARY_STATE["rolled_back_until"] = now_mono + float(CANARY_ROLLBACK_COOLDOWN_SECONDS)
            CANARY_STATE["last_reason"] = f"fail_rate={fail_rate:.3f} over {samples} samples"
            CANARY_STATE["last_rollback_at"] = utc_now_iso()
            log.warning(
                "CANARY_ROLLBACK profile=%s fail_rate=%.3f samples=%d cooldown=%ds",
                profile_name,
                fail_rate,
                samples,
                int(CANARY_ROLLBACK_COOLDOWN_SECONDS),
            )
    with CANARY_LOCK:
        RUNTIME_STATE["canary_enabled"] = bool(CANARY_STATE.get("enabled", CANARY_ROUTER_ENABLED))
        RUNTIME_STATE["canary_samples"] = int(CANARY_STATE.get("samples", 0))
        RUNTIME_STATE["canary_failures"] = int(CANARY_STATE.get("failures", 0))
        RUNTIME_STATE["canary_rolled_back"] = not bool(CANARY_STATE.get("enabled", CANARY_ROUTER_ENABLED))
        RUNTIME_STATE["canary_last_reason"] = CANARY_STATE.get("last_reason")
        RUNTIME_STATE["canary_last_rollback_at"] = CANARY_STATE.get("last_rollback_at")


def _model_router_order_profiles(profiles: list[dict], route_key: str | None = None) -> list[dict]:
    if not profiles:
        return []
    key = str(route_key or "global").strip().lower() or "global"
    now_mono = time.monotonic()
    with MODEL_ROUTER_LOCK:
        sticky = MODEL_PROFILE_STICKY.get(key)
        sticky_profile_key = ""
        if isinstance(sticky, dict) and float(sticky.get("until", 0.0)) > now_mono:
            sticky_profile_key = str(sticky.get("profile_key") or "")

        available: list[dict] = []
        cooldowned: list[dict] = []
        for profile in profiles:
            profile_key = _model_profile_key(profile)
            health = _model_profile_health_state(profile_key)
            disabled_until = float(health.get("disabled_until", 0.0) or 0.0)
            if disabled_until > now_mono:
                cooldowned.append(profile)
                continue
            cooldown_until = float(MODEL_PROFILE_COOLDOWNS.get(profile_key, 0.0))
            if cooldown_until > now_mono:
                cooldowned.append(profile)
            else:
                available.append(profile)

        ordered = list(available)
        with CANARY_LOCK:
            _canary_refresh_state_locked(now_mono)
            canary_enabled = bool(CANARY_STATE.get("enabled", CANARY_ROUTER_ENABLED))
        if canary_enabled and _canary_route_selected(key):
            canary_profile = None
            for profile in available:
                if str(profile.get("name") or "").strip().lower() == CANARY_PROFILE_NAME:
                    canary_profile = profile
                    break
            if canary_profile is not None:
                ordered = [canary_profile] + [p for p in available if p is not canary_profile]
        if sticky_profile_key:
            sticky_profile = None
            for profile in available:
                if _model_profile_key(profile) == sticky_profile_key:
                    sticky_profile = profile
                    break
            if sticky_profile is not None:
                ordered = [sticky_profile] + [p for p in available if p is not sticky_profile]
        ordered.extend(cooldowned)
        return ordered


def _model_router_mark_failure(profile: dict):
    profile_key = _model_profile_key(profile)
    until = time.monotonic() + float(MODEL_ROUTER_COOLDOWN_SECONDS)
    health = _model_profile_health_state(profile_key)
    with MODEL_ROUTER_LOCK:
        MODEL_PROFILE_COOLDOWNS[profile_key] = until
        health["failures_total"] = int(health.get("failures_total", 0)) + 1
        health["consecutive_failures"] = int(health.get("consecutive_failures", 0)) + 1
        health["last_failure_at"] = utc_now_iso()
        if int(health.get("consecutive_failures", 0)) >= int(MODEL_ROUTER_DISABLE_AFTER_FAILURES):
            health["disabled_until"] = time.monotonic() + float(MODEL_ROUTER_DISABLE_SECONDS)
            RUNTIME_STATE["model_router_profile_disables"] = int(
                RUNTIME_STATE.get("model_router_profile_disables", 0)
            ) + 1
    RUNTIME_STATE["model_router_cooldowns"] = int(RUNTIME_STATE.get("model_router_cooldowns", 0)) + 1
    _canary_mark_result(False, profile)


def _model_router_mark_success(profile: dict, route_key: str | None = None):
    key = str(route_key or "global").strip().lower() or "global"
    profile_key = _model_profile_key(profile)
    sticky_until = time.monotonic() + float(MODEL_ROUTER_STICKY_SECONDS)
    health = _model_profile_health_state(profile_key)
    with MODEL_ROUTER_LOCK:
        MODEL_PROFILE_STICKY[key] = {
            "profile_key": profile_key,
            "until": sticky_until,
        }
        health["consecutive_failures"] = 0
        health["disabled_until"] = 0.0
        health["last_success_at"] = utc_now_iso()
    RUNTIME_STATE["model_router_last_profile"] = profile_key
    _canary_mark_result(True, profile)


def call_llm(
    messages: list[dict],
    tools: list[dict] = None,
    route_key: str | None = None,
    owner_id: int | None = None,
    source_type: str = "chat",
    source_ref: str | None = None,
    session_id: str | None = None,
    task_id: int | None = None,
) -> dict:
    """
    Call primary model with optional fallback model failover.
    Returns the raw response dict.
    """
    allowed, circuit_reason = circuit_allow_call("llm_api")
    if not allowed:
        record_usage_ledger_event(
            owner_id=owner_id,
            source_type=source_type,
            source_ref=source_ref,
            session_id=session_id,
            event_type="llm",
            model_name=None,
            prompt_tokens=_estimate_messages_tokens(messages),
            completion_tokens=0,
            estimated_tokens=_estimate_messages_tokens(messages),
            estimated_cost_usd=0.0,
            status="blocked",
            detail={"reason": circuit_reason},
        )
        return {"error": circuit_reason}

    profiles = configured_llm_profiles()
    model_chain = _model_router_order_profiles(profiles, route_key=route_key)
    fallback_model = str(model_chain[1].get("model")) if len(model_chain) > 1 else None
    last_error = "Unknown LLM error"
    vision_requested = _messages_contain_vision_content(messages)
    attempted_models = 0
    resolved_owner_id = owner_id
    if resolved_owner_id is None:
        route_text = str(route_key or "").strip().lower()
        if route_text.startswith("owner:"):
            raw_owner = route_text.split(":", 1)[1]
            if raw_owner.isdigit():
                resolved_owner_id = int(raw_owner)

    def _record_usage(
        *,
        status: str,
        model_name: str | None,
        response_payload: dict | None = None,
        error_message: str | None = None,
    ):
        prompt_tokens = _estimate_messages_tokens(messages)
        completion_tokens = 0
        if isinstance(response_payload, dict):
            usage = response_payload.get("usage") if isinstance(response_payload.get("usage"), dict) else {}
            prompt_tokens = _coerce_non_negative_int(usage.get("prompt_tokens"), prompt_tokens)
            completion_tokens = _coerce_non_negative_int(usage.get("completion_tokens"), 0)
            if completion_tokens <= 0:
                try:
                    choice = (response_payload.get("choices") or [{}])[0]
                    text = str((choice.get("message") or {}).get("content") or "")
                    completion_tokens = _estimate_text_tokens(text)
                except Exception:
                    completion_tokens = 0
        est_tokens = int(prompt_tokens) + int(completion_tokens)
        cost = estimate_llm_cost_usd(str(model_name or KIMI_MODEL), prompt_tokens, completion_tokens)
        detail = {}
        if error_message:
            detail["error"] = truncate_text(error_message, 280)
        if task_id is not None:
            detail["task_id"] = int(task_id)
        record_usage_ledger_event(
            owner_id=resolved_owner_id,
            source_type=source_type,
            source_ref=source_ref,
            session_id=session_id,
            event_type="llm",
            model_name=model_name,
            prompt_tokens=prompt_tokens,
            completion_tokens=completion_tokens,
            estimated_tokens=est_tokens,
            estimated_cost_usd=cost,
            status=status,
            detail=detail,
        )

    for idx, profile in enumerate(model_chain):
        model_name = str(profile.get("model") or "").strip()
        profile_key = _model_profile_key(profile)
        if tools and MODEL_ROUTER_REQUIRE_TOOLS_SUPPORT and not bool(profile.get("supports_tools", True)):
            RUNTIME_STATE["model_router_compat_skips"] = int(RUNTIME_STATE.get("model_router_compat_skips", 0)) + 1
            log.warning("MODEL_ROUTER_COMPAT_SKIP profile=%s reason=tools_unsupported", profile_key)
            continue
        if vision_requested and MODEL_ROUTER_REQUIRE_VISION_SUPPORT and not bool(profile.get("supports_vision", True)):
            RUNTIME_STATE["model_router_compat_skips"] = int(RUNTIME_STATE.get("model_router_compat_skips", 0)) + 1
            log.warning("MODEL_ROUTER_COMPAT_SKIP profile=%s reason=vision_unsupported", profile_key)
            continue
        base_url = str(profile.get("base_url") or KIMI_BASE_URL).strip().rstrip("/")
        api_key = str(profile.get("api_key") or "").strip()
        url = f"{base_url}/chat/completions"
        headers = {
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json",
        }
        has_more = (idx + 1) < len(model_chain)
        # Last-resort orphan cleanup inside call_llm itself
        _cl_tc_ids = set()
        _cl_resp_ids = set()
        for _cm in messages:
            if _cm.get("role") == "assistant" and isinstance(_cm.get("tool_calls"), list):
                for _ct in _cm["tool_calls"]:
                    if isinstance(_ct, dict) and _ct.get("id"):
                        _cl_tc_ids.add(_ct["id"])
            if _cm.get("role") == "tool" and _cm.get("tool_call_id"):
                _cl_resp_ids.add(_cm["tool_call_id"])
        _cl_orphaned = _cl_tc_ids - _cl_resp_ids
        if _cl_orphaned:
            log.warning("CALL_LLM_ORPHAN_FIX ids=%s", _cl_orphaned)
            for _cm in messages:
                if _cm.get("role") == "assistant" and isinstance(_cm.get("tool_calls"), list):
                    _cm["tool_calls"] = [
                        _ct for _ct in _cm["tool_calls"]
                        if not (isinstance(_ct, dict) and _ct.get("id") in _cl_orphaned)
                    ]
                    if not _cm["tool_calls"]:
                        _cm.pop("tool_calls", None)
                        _cm.pop("reasoning_content", None)
                        if not _cm.get("content"):
                            _cm["content"] = "[tool calls cleared]"
        messages, _call_fix = _sanitize_tool_call_transcript(
            messages,
            cleared_placeholder="[tool calls cleared]",
        )
        if (
            int(_call_fix.get("assistant_calls_removed", 0)) > 0
            or int(_call_fix.get("assistant_calls_trimmed", 0)) > 0
            or int(_call_fix.get("orphan_tool_messages_removed", 0)) > 0
        ):
            log.warning(
                "CALL_LLM_SEQUENCE_FIX model=%s trimmed=%d removed=%d orphan_tools=%d",
                model_name,
                int(_call_fix.get("assistant_calls_trimmed", 0)),
                int(_call_fix.get("assistant_calls_removed", 0)),
                int(_call_fix.get("orphan_tool_messages_removed", 0)),
            )

        payload = {
            "model": model_name,
            "messages": messages,
            "temperature": LLM_TEMPERATURE,
            "max_tokens": LLM_MAX_TOKENS,
        }
        if tools:
            payload["tools"] = tools
            payload["tool_choice"] = "auto"

        _record_llm_attempt(model_name)
        attempted_models += 1
        _payload_size = len(json.dumps(payload, default=str))
        log.info(
            "LLM_CALL_START model=%s tools=%d messages=%d payload_bytes=%d timeout=%s",
            model_name,
            len(payload.get("tools") or []),
            len(payload.get("messages") or []),
            _payload_size,
            LLM_REQUEST_TIMEOUT_SECONDS,
        )

        try:
            resp = REQUESTS_SESSION.post(
                url,
                headers=headers,
                json=payload,
                timeout=LLM_REQUEST_TIMEOUT_SECONDS,
            )
        except requests.exceptions.Timeout:
            err = f"LLM timeout after {LLM_REQUEST_TIMEOUT_SECONDS}s on model={model_name}"
            _record_llm_failure(model_name, err)
            circuit_record_failure("llm_api", err)
            _model_router_mark_failure(profile)
            last_error = err
            if _llm_should_attempt_failover(None, has_more):
                RUNTIME_STATE["llm_failover_count"] = int(RUNTIME_STATE["llm_failover_count"]) + 1
                RUNTIME_STATE["model_router_failovers"] = int(RUNTIME_STATE.get("model_router_failovers", 0)) + 1
                log.warning("LLM_FAILOVER timeout model=%s -> %s", model_name, fallback_model)
                continue
            log.error("LLM call failed: %s", err)
            _record_usage(status="error", model_name=model_name, error_message=err)
            return {"error": err}
        except requests.exceptions.ConnectionError as e:
            err = f"LLM connection error model={model_name}: {truncate_text(str(e), 220)}"
            _record_llm_failure(model_name, err)
            circuit_record_failure("llm_api", err)
            _model_router_mark_failure(profile)
            last_error = err
            if _llm_should_attempt_failover(None, has_more):
                RUNTIME_STATE["llm_failover_count"] = int(RUNTIME_STATE["llm_failover_count"]) + 1
                RUNTIME_STATE["model_router_failovers"] = int(RUNTIME_STATE.get("model_router_failovers", 0)) + 1
                log.warning("LLM_FAILOVER connection model=%s -> %s", model_name, fallback_model)
                continue
            log.error("LLM call failed: %s", err)
            _record_usage(status="error", model_name=model_name, error_message=err)
            return {"error": err}
        except Exception as e:
            err = f"LLM request error model={model_name}: {truncate_text(str(e), 220)}"
            _record_llm_failure(model_name, err)
            circuit_record_failure("llm_api", err)
            _model_router_mark_failure(profile)
            last_error = err
            if _llm_should_attempt_failover(None, has_more):
                RUNTIME_STATE["llm_failover_count"] = int(RUNTIME_STATE["llm_failover_count"]) + 1
                RUNTIME_STATE["model_router_failovers"] = int(RUNTIME_STATE.get("model_router_failovers", 0)) + 1
                log.warning("LLM_FAILOVER request_error model=%s -> %s", model_name, fallback_model)
                continue
            log.error("LLM call failed: %s", err)
            _record_usage(status="error", model_name=model_name, error_message=err)
            return {"error": err}

        if resp.status_code >= 400:
            err = _extract_llm_error_message(resp)
            _record_llm_failure(model_name, err)
            circuit_record_failure("llm_api", err)
            _model_router_mark_failure(profile)
            last_error = err
            if _llm_should_attempt_failover(resp.status_code, has_more):
                RUNTIME_STATE["llm_failover_count"] = int(RUNTIME_STATE["llm_failover_count"]) + 1
                RUNTIME_STATE["model_router_failovers"] = int(RUNTIME_STATE.get("model_router_failovers", 0)) + 1
                log.warning(
                    "LLM_FAILOVER status=%s model=%s -> %s",
                    resp.status_code,
                    model_name,
                    fallback_model,
                )
                continue
            log.error("LLM call failed: %s", err)
            _record_usage(status="error", model_name=model_name, error_message=err)
            return {"error": err}

        try:
            payload_json = resp.json()
        except Exception:
            err = "LLM response was not valid JSON."
            _record_llm_failure(model_name, err)
            circuit_record_failure("llm_api", err)
            _model_router_mark_failure(profile)
            last_error = err
            if _llm_should_attempt_failover(resp.status_code, has_more):
                RUNTIME_STATE["llm_failover_count"] = int(RUNTIME_STATE["llm_failover_count"]) + 1
                RUNTIME_STATE["model_router_failovers"] = int(RUNTIME_STATE.get("model_router_failovers", 0)) + 1
                log.warning("LLM_FAILOVER invalid_json model=%s -> %s", model_name, fallback_model)
                continue
            log.error("LLM call failed: %s", err)
            _record_usage(status="error", model_name=model_name, error_message=err)
            return {"error": err}

        _record_llm_success(model_name)
        _model_router_mark_success(profile, route_key=route_key)
        circuit_record_success("llm_api")
        if idx > 0:
            log.warning("LLM_FAILOVER_OK model=%s", model_name)
        _record_usage(status="ok", model_name=model_name, response_payload=payload_json)
        return payload_json

    if attempted_models <= 0:
        last_error = "No compatible model profile available for this request."
        RUNTIME_STATE["llm_last_error"] = last_error
        _record_usage(status="blocked", model_name=None, error_message=last_error)
        return {"error": last_error}

    log.error("LLM call failed after failover chain: %s", last_error)
    _record_usage(status="error", model_name=None, error_message=last_error)
    return {"error": last_error}


def reindex_owner_memory_vectors(owner_id: int, rebuild_lessons: bool = False) -> dict:
    db = SessionLocal()
    owner = int(owner_id)
    rebuilt = {
        "conversation_summary": 0,
        "research_note": 0,
        "task_artifact": 0,
        "self_improvement_note": 0,
        "world_model_forecast": 0,
        "world_model_outcome": 0,
        "lesson": 0,
    }
    try:
        with session_write_lock(owner, reason="memory_reindex"):
            lesson_seed: list[str] = []
            if rebuild_lessons:
                rows = (
                    db.query(MemoryVector)
                    .filter(MemoryVector.owner_id == owner, MemoryVector.memory_type == "lesson")
                    .order_by(MemoryVector.id.asc())
                    .all()
                )
                lesson_seed = [_memory_preview_text(str(row.text_preview or ""), max_len=600) for row in rows if str(row.text_preview or "").strip()]

            target_types = [
                "conversation_summary",
                "research_note",
                "task_artifact",
                "self_improvement_note",
                "world_model_forecast",
                "world_model_outcome",
            ]
            if rebuild_lessons:
                target_types.append("lesson")

            db.query(MemoryVector).filter(
                MemoryVector.owner_id == owner,
                MemoryVector.memory_type.in_(target_types),
            ).delete(synchronize_session=False)

            # Conversation summaries
            for row in (
                db.query(ConversationSummary)
                .filter(ConversationSummary.owner_id == owner)
                .order_by(ConversationSummary.id.asc())
                .all()
            ):
                text = f"{row.summary}\nKey points: {row.key_points_json}\nOpen loops: {row.open_loops_json}".strip()
                vec = get_embedding(text)
                if np.linalg.norm(vec) < 1e-9:
                    continue
                db.add(
                    MemoryVector(
                        owner_id=owner,
                        memory_type="conversation_summary",
                        ref_id=int(row.id),
                        text_preview=_memory_preview_text(text, max_len=200),
                        embedding=embedding_to_bytes(vec),
                    )
                )
                rebuilt["conversation_summary"] += 1

            # Research notes
            for row in (
                db.query(ResearchNote)
                .filter(ResearchNote.owner_id == owner)
                .order_by(ResearchNote.id.asc())
                .all()
            ):
                text = f"{row.topic}\n{row.summary}".strip()
                vec = get_embedding(text)
                if np.linalg.norm(vec) < 1e-9:
                    continue
                db.add(
                    MemoryVector(
                        owner_id=owner,
                        memory_type="research_note",
                        ref_id=int(row.id),
                        text_preview=_memory_preview_text(text, max_len=200),
                        embedding=embedding_to_bytes(vec),
                    )
                )
                rebuilt["research_note"] += 1

            # Task artifacts
            for row in (
                db.query(TaskArtifact)
                .filter(TaskArtifact.owner_id == owner)
                .order_by(TaskArtifact.id.asc())
                .all()
            ):
                text = f"{row.task_title}\n{row.node_title}\n{row.outcome_summary}".strip()
                vec = get_embedding(text)
                if np.linalg.norm(vec) < 1e-9:
                    continue
                db.add(
                    MemoryVector(
                        owner_id=owner,
                        memory_type="task_artifact",
                        ref_id=int(row.id),
                        text_preview=_memory_preview_text(text, max_len=200),
                        embedding=embedding_to_bytes(vec),
                    )
                )
                rebuilt["task_artifact"] += 1

            # Self-improvement notes
            for row in (
                db.query(SelfImprovementNote)
                .filter(SelfImprovementNote.owner_id == owner)
                .order_by(SelfImprovementNote.id.asc())
                .all()
            ):
                text = f"{row.title}\n{row.summary}\n{row.actions_json}".strip()
                vec = get_embedding(text)
                if np.linalg.norm(vec) < 1e-9:
                    continue
                db.add(
                    MemoryVector(
                        owner_id=owner,
                        memory_type="self_improvement_note",
                        ref_id=int(row.id),
                        text_preview=_memory_preview_text(text, max_len=200),
                        embedding=embedding_to_bytes(vec),
                    )
                )
                rebuilt["self_improvement_note"] += 1

            # World-model memory rows
            for row in (
                db.query(ActionForecast)
                .filter(ActionForecast.owner_id == owner)
                .order_by(ActionForecast.id.asc())
                .all()
            ):
                risks = _safe_json_list(row.predicted_risks_json)
                forecast_text = _compose_world_memory_text(
                    action_summary=str(row.action_summary or ""),
                    pattern_tag=str(row.pattern_tag or "general_reasoning"),
                    predicted_outcome=str(row.predicted_outcome or ""),
                    predicted_risks=[str(item) for item in risks[:4]],
                    status=str(row.status or "pending"),
                    observed_outcome="",
                    observed_error="",
                )
                forecast_vec = get_embedding(forecast_text)
                if np.linalg.norm(forecast_vec) > 1e-9:
                    db.add(
                        MemoryVector(
                            owner_id=owner,
                            memory_type="world_model_forecast",
                            ref_id=int(row.id),
                            text_preview=_memory_preview_text(forecast_text, max_len=200),
                            embedding=embedding_to_bytes(forecast_vec),
                        )
                    )
                    rebuilt["world_model_forecast"] += 1

                if str(row.status or "") in {"confirmed", "mismatch"}:
                    outcome_text = _compose_world_memory_text(
                        action_summary=str(row.action_summary or ""),
                        pattern_tag=str(row.pattern_tag or "general_reasoning"),
                        predicted_outcome=str(row.predicted_outcome or ""),
                        predicted_risks=[str(item) for item in risks[:4]],
                        status=str(row.status or ""),
                        observed_outcome=str(row.observed_outcome or ""),
                        observed_error=str(row.observed_error or ""),
                    )
                    outcome_vec = get_embedding(outcome_text)
                    if np.linalg.norm(outcome_vec) > 1e-9:
                        db.add(
                            MemoryVector(
                                owner_id=owner,
                                memory_type="world_model_outcome",
                                ref_id=int(row.id),
                                text_preview=_memory_preview_text(outcome_text, max_len=200),
                                embedding=embedding_to_bytes(outcome_vec),
                            )
                        )
                        rebuilt["world_model_outcome"] += 1

            if rebuild_lessons:
                for text in lesson_seed:
                    vec = get_embedding(text)
                    if np.linalg.norm(vec) < 1e-9:
                        continue
                    db.add(
                        MemoryVector(
                            owner_id=owner,
                            memory_type="lesson",
                            ref_id=None,
                            text_preview=_memory_preview_text(text, max_len=200),
                            embedding=embedding_to_bytes(vec),
                        )
                    )
                    rebuilt["lesson"] += 1

            db.commit()
            return {"ok": True, "owner_id": owner, "rebuilt": rebuilt}
    except Exception as e:
        db.rollback()
        return {"ok": False, "owner_id": owner, "error": truncate_text(str(e), 240), "rebuilt": rebuilt}
    finally:
        db.close()


# ============================================================================
# SECTION 8: THE AGENT LOOP (The Brain)
# ============================================================================

def run_agent_loop(db: Session, owner_id: int, user_message: str) -> str:
    """
    The core agent loop:
    1. Load identity
    2. Save new user message
    3. Compact/prune history if thresholds are exceeded
    4. Build system prompt with lessons + episodic summaries
    5. Load recent conversation history
    6. Send to LLM with tools
    7. If LLM returns tool_calls Ã¢â€ â€™ execute Ã¢â€ â€™ feed results back Ã¢â€ â€™ repeat
    8. If LLM returns text Ã¢â€ â€™ return to user
    """
    # 1. Load identity
    identity = load_identity(db, owner_id)
    session_id = _blackbox_session_id("chat", owner_id)
    run_budget = create_run_budget("chat", owner_id, session_id)
    record_blackbox_event(
        db=db,
        owner_id=owner_id,
        session_id=session_id,
        source_type="chat",
        source_ref=str(owner_id),
        event_type="chat_start",
        payload={"message_preview": truncate_text(user_message, 240)},
    )

    # 2. Save user message to history
    save_message(db, owner_id, "user", content=user_message)
    record_blackbox_event(
        db=db,
        owner_id=owner_id,
        session_id=session_id,
        source_type="chat",
        source_ref=str(owner_id),
        event_type="chat_user_message_saved",
        payload={"message_preview": truncate_text(user_message, 240)},
    )

    # 3. Compact and prune session history when it grows too large.
    compact_and_prune_session_if_needed(db, owner_id)

    # 3a. OpenClaw-style char-budget compaction: summarise oldest messages when
    #     the stored history exceeds the soft char budget.  This runs BEFORE the
    #     system prompt is built so that newly created summaries are available for
    #     retrieval and the loaded history is already compact.
    compact_session_by_char_budget(db, owner_id)

    # 3b. Activate dormant capabilities when intent signals appear.
    try:
        active_capabilities = activate_dormant_capabilities(db, owner_id, user_message)
    except Exception as exc:
        log.warning("DORMANT_CAPABILITY_CHAT_FAIL owner=%d error=%s", owner_id, truncate_text(str(exc), 220))
        try:
            active_capabilities = get_active_capabilities(db, owner_id)
        except Exception:
            active_capabilities = []

    # 4. Force deep research for research-style prompts so citations stay consistent.
    if should_force_deep_research_prompt(user_message):
        return run_forced_deep_research(
            db=db,
            owner_id=owner_id,
            identity=identity,
            user_message=user_message,
            blackbox_session_id=session_id,
        )

    continuity_ctx = build_memory_continuity_context(db, owner_id, user_message)
    continuity_text = str(continuity_ctx.get("continuity_text") or "")
    task_hint_ids = continuity_ctx.get("task_hint_ids") or []
    continuity_score = float(continuity_ctx.get("continuity_score") or 0.0)
    RUNTIME_STATE["memory_last_continuity_score"] = _format_quality(continuity_score)

    # 5. Adaptive context injection (OpenClaw pattern: less context for simple messages)
    _CONTEXT_PROFILES = {
        "simple":  {"lessons": 1, "summaries": 1, "artifacts": 0, "world": 0, "improve": 0, "skills": 1, "episodes": 0},
        "normal":  {"lessons": 2, "summaries": 2, "artifacts": 2, "world": 2, "improve": 1, "skills": 2, "episodes": 2},
        "complex": {"lessons": 3, "summaries": 3, "artifacts": 3, "world": 3, "improve": 2, "skills": 3, "episodes": 3},
    }
    _msg_text = (user_message or "").strip()
    _msg_lower = _msg_text.lower()
    _simple_re = re.compile(
        r"^(hi|hey|hello|thanks|thank you|ok|okay|yes|no|sure|"
        r"good|great|cool|nice|bye|goodbye|what\??|how are you|"
        r"morning|evening|night|sup|yo|lol|haha|hmm|wow|"
        r"got it|understood|right|fine|alright)[\s!.?]*$",
        re.IGNORECASE,
    )
    if not _msg_text or len(_msg_text) < 15 and (_simple_re.match(_msg_text) or len(_msg_text) < 5):
        _complexity = "simple"
    elif len(_memory_terms(_msg_text)) >= 8:
        _complexity = "complex"
    else:
        _complexity = "normal"
    _ctx = _CONTEXT_PROFILES[_complexity]
    RUNTIME_STATE["context_complexity"] = _complexity

    lessons = retrieve_relevant_lessons(
        owner_id,
        user_message,
        top_k=_ctx["lessons"],
        continuity_text=continuity_text,
    )
    if lessons:
        log.info("LESSONS_INJECTED owner=%d count=%d", owner_id, len(lessons))

    conversation_summaries = retrieve_relevant_conversation_summaries(
        owner_id=owner_id,
        user_message=user_message,
        top_k=min(SUMMARY_RETRIEVE_TOP_K, _ctx["summaries"]),
        continuity_text=continuity_text,
        task_hint_ids=task_hint_ids,
    )
    if conversation_summaries:
        log.info("SESSION_SUMMARY_INJECTED owner=%d count=%d", owner_id, len(conversation_summaries))

    # Only retrieve task artifacts when the message has enough content to embed meaningfully.
    _artifact_query_terms = _memory_terms(user_message)
    if len(_artifact_query_terms) >= 3 and _ctx["artifacts"] > 0:
        task_artifacts = retrieve_relevant_task_artifacts(
            owner_id=owner_id,
            query_text=user_message,
            top_k=min(TASK_ARTIFACT_RETRIEVE_TOP_K, _ctx["artifacts"]),
            continuity_text=continuity_text,
            task_hint_ids=task_hint_ids,
        )
    else:
        task_artifacts = []
    if task_artifacts:
        RUNTIME_STATE["task_artifact_injections"] = int(RUNTIME_STATE.get("task_artifact_injections", 0)) + len(task_artifacts)
        log.info("TASK_ARTIFACT_INJECTED owner=%d count=%d", owner_id, len(task_artifacts))

    if _ctx["world"] > 0:
        world_model_signals = retrieve_world_model_signals(
            owner_id=owner_id,
            query_text=user_message,
            top_k=min(WORLD_MODEL_RETRIEVE_TOP_K, _ctx["world"]),
        )
    else:
        world_model_signals = []
    if world_model_signals:
        log.info("WORLD_MODEL_INJECTED owner=%d count=%d", owner_id, len(world_model_signals))

    if _ctx["improve"] > 0:
        self_improvement_notes = retrieve_relevant_self_improvement_notes(
            owner_id=owner_id,
            query_text=user_message,
            top_k=min(SELF_IMPROVE_RETRIEVE_TOP_K, _ctx["improve"]),
        )
    else:
        self_improvement_notes = []
    if self_improvement_notes:
        log.info("SELF_IMPROVE_INJECTED owner=%d count=%d", owner_id, len(self_improvement_notes))

    active_skills = select_active_skills_for_prompt(
        db=db,
        owner_id=owner_id,
        user_message=user_message,
        top_k=min(SKILLS_ACTIVE_TOP_K, _ctx["skills"]),
        session_id=session_id,
    )
    if active_skills:
        log.info("SKILLS_INJECTED owner=%d count=%d", owner_id, len(active_skills))

    memory_qualities = [
        RUNTIME_STATE.get("memory_last_lesson_quality"),
        RUNTIME_STATE.get("memory_last_summary_quality"),
        RUNTIME_STATE.get("memory_last_task_artifact_quality"),
    ]
    quality_values = [float(value) for value in memory_qualities if isinstance(value, (float, int))]
    RUNTIME_STATE["memory_last_hit_quality"] = _format_quality(
        (sum(quality_values) / len(quality_values)) if quality_values else None
    )
    RUNTIME_STATE["memory_last_retrieved_total"] = int(
        len(lessons)
        + len(conversation_summaries)
        + len(task_artifacts)
        + len(world_model_signals)
        + len(self_improvement_notes)
    )
    RUNTIME_STATE["memory_last_retrieval_at"] = utc_now_iso()

    # 6. Build system prompt with lessons + compacted summaries.
    # Pillar 7: Capture environment state when relevant (skip for simple messages)
    _env_state = capture_environment_state(owner_id) if (ENVIRONMENT_STATE_ENABLED and _should_capture_env_state(user_message) and _complexity != "simple") else {}

    # Pillar 5: Generate tool chaining hints (skip for simple messages)
    _chaining_hints = _generate_tool_chaining_hints(user_message) if (TOOL_CHAINING_HINTS_ENABLED and _complexity != "simple") else []

    # Pillar 2: Retrieve relevant episodic memories
    _episodes = retrieve_relevant_episodes(owner_id, user_message) if (EPISODIC_MEMORY_ENABLED and _ctx["episodes"] > 0) else []

    # Pillar 6: Retrieve tool performance stats for system prompt (skip for simple messages)
    _tool_perf = get_tool_performance_stats(owner_id, days=7) if (TOOL_PERF_TRACKING_ENABLED and _complexity != "simple") else []

    system_prompt = build_system_prompt(
        identity,
        lessons=lessons,
        conversation_summaries=conversation_summaries,
        task_artifacts=task_artifacts,
        world_model_signals=world_model_signals,
        self_improvement_notes=self_improvement_notes,
        active_skills=active_skills,
        active_capabilities=active_capabilities,
        tool_perf_stats=_tool_perf,
        episodic_memories=_episodes,
        tool_chaining_hints=_chaining_hints,
        environment_state=_env_state,
    )

    # 7. Load conversation history
    history = get_conversation_history(db, owner_id, limit=CONVERSATION_HISTORY_LIMIT, repair=True)

    # 8. Build messages array
    messages = [{"role": "system", "content": system_prompt}] + history

    # 9. Agent loop
    _used_tool_names: set[str] = set()  # Track tools used across iterations for intent filter continuity
    _tool_intent_categories = classify_tool_intent(user_message)
    for iteration in range(profile_chat_tool_loop_limit()):
        log.info(f"Agent loop iteration {iteration + 1}")
        stop_now, stop_reason = budget_should_stop(run_budget)
        if stop_now:
            record_blackbox_event(
                db=db,
                owner_id=owner_id,
                session_id=session_id,
                source_type="chat",
                source_ref=str(owner_id),
                event_type="chat_budget_stop",
                payload={"iteration": iteration + 1, "reason": stop_reason, "usage": _budget_usage(run_budget)},
            )
            return f"Budget stop triggered ({stop_reason}). Narrow the scope and retry."
        record_blackbox_event(
            db=db,
            owner_id=owner_id,
            session_id=session_id,
            source_type="chat",
            source_ref=str(owner_id),
            event_type="llm_iteration_start",
            payload={"iteration": iteration + 1},
        )

        llm_messages, prune_meta = prepare_messages_for_llm(messages)
        if int(prune_meta.get("soft_trimmed", 0)) > 0:
            log.info(
                "SESSION_SOFT_TRIM owner=%d iteration=%d trimmed=%d chars_before=%d chars_after=%d",
                owner_id,
                iteration + 1,
                int(prune_meta.get("soft_trimmed", 0)),
                int(prune_meta.get("chars_before", 0)),
                int(prune_meta.get("chars_after", 0)),
            )
        if int(prune_meta.get("lightweight_trimmed", 0)) > 0:
            log.info(
                "SESSION_LIGHTWEIGHT_TRIM owner=%d iteration=%d trimmed=%d chars_before=%d chars_after=%d",
                owner_id,
                iteration + 1,
                int(prune_meta.get("lightweight_trimmed", 0)),
                int(prune_meta.get("chars_before", 0)),
                int(prune_meta.get("chars_after", 0)),
            )

        capture_context_snapshot(
            owner_id=owner_id,
            session_id=session_id,
            source_type="chat",
            llm_messages=llm_messages,
            system_prompt=system_prompt,
            history_count=len(history),
            prune_meta=prune_meta,
            tools_count=len(effective_tool_definitions(owner_id=owner_id, user_message=user_message, also_include=_used_tool_names)),
        )

        # Sanitize messages for Kimi K2.5 thinking mode:
        # 1. Ensure reasoning_content is present on assistant tool_call messages
        # 2. Remove orphaned tool messages whose tool_call_id has no matching assistant
        valid_tc_ids = set()
        for m in llm_messages:
            if m.get("role") == "assistant" and isinstance(m.get("tool_calls"), list):
                if "reasoning_content" not in m:
                    m["reasoning_content"] = ""
                for tc in m["tool_calls"]:
                    if isinstance(tc, dict) and "id" in tc:
                        valid_tc_ids.add(tc["id"])
        llm_messages = [
            m for m in llm_messages
            if not (m.get("role") == "tool" and m.get("tool_call_id") and m["tool_call_id"] not in valid_tc_ids)
        ]

        # Final structural integrity check before LLM call
        _pre_call_tc_ids = set()
        _pre_call_resp_ids = set()
        for _m in llm_messages:
            if _m.get("role") == "assistant" and isinstance(_m.get("tool_calls"), list):
                for _tc in _m["tool_calls"]:
                    if isinstance(_tc, dict) and _tc.get("id"):
                        _pre_call_tc_ids.add(_tc["id"])
            if _m.get("role") == "tool" and _m.get("tool_call_id"):
                _pre_call_resp_ids.add(_m["tool_call_id"])
        _orphaned_tc = _pre_call_tc_ids - _pre_call_resp_ids
        if _orphaned_tc:
            log.warning("PRE_LLM_ORPHANED_TOOL_CALLS ids=%s — stripping", _orphaned_tc)
            for _m in llm_messages:
                if _m.get("role") == "assistant" and isinstance(_m.get("tool_calls"), list):
                    _m["tool_calls"] = [
                        _tc for _tc in _m["tool_calls"]
                        if isinstance(_tc, dict) and _tc.get("id") not in _orphaned_tc
                    ]
                    if not _m["tool_calls"]:
                        _m.pop("tool_calls", None)
                        _m.pop("reasoning_content", None)
                        if not _m.get("content"):
                            _m["content"] = "[tool calls cleared]"

        llm_messages, _pre_llm_fix = _sanitize_tool_call_transcript(
            llm_messages,
            cleared_placeholder="[tool calls cleared]",
        )
        if (
            int(_pre_llm_fix.get("assistant_calls_removed", 0)) > 0
            or int(_pre_llm_fix.get("assistant_calls_trimmed", 0)) > 0
            or int(_pre_llm_fix.get("orphan_tool_messages_removed", 0)) > 0
        ):
            log.warning(
                "PRE_LLM_SEQUENCE_FIX owner=%d trimmed=%d removed=%d orphan_tools=%d",
                int(owner_id),
                int(_pre_llm_fix.get("assistant_calls_trimmed", 0)),
                int(_pre_llm_fix.get("assistant_calls_removed", 0)),
                int(_pre_llm_fix.get("orphan_tool_messages_removed", 0)),
            )

        # Call LLM (OpenClaw-style: only send relevant tools for this message)
        response = call_llm(
            llm_messages,
            tools=effective_tool_definitions(owner_id=owner_id, user_message=user_message, also_include=_used_tool_names),
            route_key=f"owner:{owner_id}",
            owner_id=owner_id,
            source_type="chat",
            source_ref=str(owner_id),
            session_id=session_id,
        )
        budget_record_llm_call(run_budget, llm_messages, response if isinstance(response, dict) else None)

        if "error" in response:
            record_blackbox_event(
                db=db,
                owner_id=owner_id,
                session_id=session_id,
                source_type="chat",
                source_ref=str(owner_id),
                event_type="llm_error",
                payload={"iteration": iteration + 1, "error": truncate_text(str(response.get("error", "")), 260)},
            )
            return f"LLM Error: {response['error']}"

        choice = response["choices"][0]
        assistant_msg = choice["message"]
        finish_reason = choice.get("finish_reason", "stop")

        # Check if LLM wants to call tools
        raw_tool_calls = assistant_msg.get("tool_calls")
        tool_calls = None
        if raw_tool_calls:
            normalized_calls, guard_warnings = normalize_tool_calls_for_guard(raw_tool_calls)
            if guard_warnings:
                RUNTIME_STATE["session_tool_result_guard_blocks"] = int(
                    RUNTIME_STATE.get("session_tool_result_guard_blocks", 0)
                ) + len(guard_warnings)
                record_blackbox_event(
                    db=db,
                    owner_id=owner_id,
                    session_id=session_id,
                    source_type="chat",
                    source_ref=str(owner_id),
                    event_type="tool_call_guard_warning",
                    payload={
                        "iteration": iteration + 1,
                        "warnings": [truncate_text(str(w), 180) for w in guard_warnings[:6]],
                    },
                )
            if normalized_calls:
                tool_calls = normalized_calls

        if tool_calls:
            record_blackbox_event(
                db=db,
                owner_id=owner_id,
                session_id=session_id,
                source_type="chat",
                source_ref=str(owner_id),
                event_type="llm_tool_calls",
                payload={"iteration": iteration + 1, "count": len(tool_calls)},
            )
            # Save assistant message with tool calls
            save_message(
                db, owner_id, "assistant",
                content=assistant_msg.get("content"),
                tool_calls=tool_calls,
            )
            assistant_for_history = dict(assistant_msg)
            assistant_for_history["tool_calls"] = tool_calls
            messages.append(assistant_for_history)

            # Execute each tool call
            max_tools_this_iter = len(tool_calls)
            if budget_should_degrade(run_budget):
                max_tools_this_iter = min(max_tools_this_iter, 1)
                record_blackbox_event(
                    db=db,
                    owner_id=owner_id,
                    session_id=session_id,
                    source_type="chat",
                    source_ref=str(owner_id),
                    event_type="chat_budget_degraded",
                    payload={"iteration": iteration + 1, "max_tools_this_iter": max_tools_this_iter, "usage": _budget_usage(run_budget)},
                )

            for tc_index, tc in enumerate(tool_calls):
                func_name = tc["function"]["name"]
                _used_tool_names.add(func_name)
                try:
                    func_args = json.loads(tc["function"]["arguments"])
                except json.JSONDecodeError:
                    func_args = {}

                call_id = tc["id"]

                stop_now, stop_reason = budget_should_stop(run_budget)
                if stop_now:
                    budget_error = {"ok": False, "error": f"BUDGET_STOP: {stop_reason}"}
                    result_str = json.dumps(budget_error, ensure_ascii=False)
                    save_message(db, owner_id, "tool", content=result_str, tool_call_id=call_id)
                    messages.append({"role": "tool", "tool_call_id": call_id, "content": result_str})
                    record_blackbox_event(
                        db=db,
                        owner_id=owner_id,
                        session_id=session_id,
                        source_type="chat",
                        source_ref=str(owner_id),
                        event_type="tool_skipped_budget_stop",
                        payload={"tool_name": func_name, "call_id": call_id, "reason": stop_reason},
                    )
                    continue

                if tc_index >= max_tools_this_iter:
                    degraded_skip = {"ok": False, "error": "BUDGET_DEGRADE: deferred tool call this iteration."}
                    result_str = json.dumps(degraded_skip, ensure_ascii=False)
                    save_message(db, owner_id, "tool", content=result_str, tool_call_id=call_id)
                    messages.append({"role": "tool", "tool_call_id": call_id, "content": result_str})
                    record_blackbox_event(
                        db=db,
                        owner_id=owner_id,
                        session_id=session_id,
                        source_type="chat",
                        source_ref=str(owner_id),
                        event_type="tool_skipped_budget_degrade",
                        payload={"tool_name": func_name, "call_id": call_id, "index": tc_index},
                    )
                    continue

                log.info(f"Tool call: {func_name}({func_args})")
                record_blackbox_event(
                    db=db,
                    owner_id=owner_id,
                    session_id=session_id,
                    source_type="chat",
                    source_ref=str(owner_id),
                    event_type="tool_call_planned",
                    payload={
                        "iteration": iteration + 1,
                        "tool_name": func_name,
                        "call_id": call_id,
                        "args": _blackbox_sanitize(func_args),
                    },
                )

                try:
                    result = execute_tool_with_context(
                        identity=identity,
                        tool_name=func_name,
                        args=func_args,
                        owner_id=owner_id,
                        source_type="chat",
                        source_ref=str(owner_id),
                        step_id=None,
                        resume_payload={
                            "kind": "chat_message",
                            "owner_id": owner_id,
                            "user_message": user_message,
                        },
                        blackbox_session_id=session_id,
                        run_budget=run_budget,
                    )
                except Exception as exc_tool:
                    log.error("TOOL_EXEC_CRASH tool=%s call_id=%s error=%s", func_name, call_id, exc_tool, exc_info=True)
                    result = {"ok": False, "error": f"Tool execution crashed: {exc_tool}"}

                # Extract screenshot base64 before serializing (don't send huge blob as text)
                screenshot_b64 = None
                if isinstance(result, dict) and "_screenshot_base64" in result:
                    screenshot_b64 = result.pop("_screenshot_base64", None)

                try:
                    result_str, result_truncated = guarded_tool_result_payload(
                        tool_name=func_name,
                        call_id=call_id,
                        result_obj=result,
                    )
                except Exception as exc_guard:
                    log.error("TOOL_RESULT_GUARD_CRASH call_id=%s error=%s", call_id, exc_guard)
                    result_str = json.dumps({"ok": False, "error": f"Result serialization failed: {exc_guard}"}, ensure_ascii=False)
                    result_truncated = False

                if result_truncated:
                    RUNTIME_STATE["session_tool_result_guard_synthetic"] = int(
                        RUNTIME_STATE.get("session_tool_result_guard_synthetic", 0)
                    ) + 1

                # Save tool result — ALWAYS runs, even after exceptions above
                save_message(db, owner_id, "tool", content=result_str, tool_call_id=call_id)
                messages.append({
                    "role": "tool",
                    "tool_call_id": call_id,
                    "content": result_str,
                })

                # Vision injection: if tool returned a screenshot, add it as an
                # image message so the LLM can SEE what's on screen.
                if screenshot_b64:
                    vision_msg = {
                        "role": "user",
                        "content": [
                            {"type": "text", "text": "[SCREENSHOT] Here is the current screen. Analyze it and decide the next action. Refer to elements by their pixel coordinates (x, y) when clicking."},
                            {"type": "image_url", "image_url": {"url": f"data:image/png;base64,{screenshot_b64}"}},
                        ],
                    }
                    messages.append(vision_msg)
                    log.info("VISION_INJECT screenshot injected for LLM, size=%d bytes", len(screenshot_b64))
                result_ok = bool(result.get("ok", False)) if isinstance(result, dict) else False
                record_blackbox_event(
                    db=db,
                    owner_id=owner_id,
                    session_id=session_id,
                    source_type="chat",
                    source_ref=str(owner_id),
                    event_type="tool_result_saved",
                    payload={
                        "iteration": iteration + 1,
                        "tool_name": func_name,
                        "call_id": call_id,
                        "ok": result_ok,
                    },
                )

                if isinstance(result, dict) and result.get("approval_required"):
                    token = str(result.get("resume_token") or "").strip()
                    guidance = str(result.get("message") or "").strip()
                    record_blackbox_event(
                        db=db,
                        owner_id=owner_id,
                        session_id=session_id,
                        source_type="chat",
                        source_ref=str(owner_id),
                        event_type="chat_paused_for_approval",
                        payload={"tool_name": func_name, "token": token},
                    )
                    if token:
                        return (
                            "Action paused for approval.\n"
                            f"Tool: {func_name}\n"
                            f"Token: {token}\n"
                            f"Approve with /approve {token} or reject with /reject {token}."
                            + (f"\nNote: {guidance}" if guidance else "")
                        )
                    if guidance:
                        return f"Action paused for operator interlock.\nTool: {func_name}\n{guidance}"
                    return f"Action paused for approval.\nTool: {func_name}"

            # Pillar 1: In-loop reflection -- inject meta-reasoning every N iterations
            if (
                INLOOP_REFLECTION_ENABLED
                and (iteration + 1) >= INLOOP_REFLECTION_EVERY_N
                and (iteration + 1) % INLOOP_REFLECTION_EVERY_N == 0
            ):
                messages.append({"role": "user", "content": INLOOP_REFLECTION_PROMPT})
                RUNTIME_STATE["inloop_reflections_total"] = int(RUNTIME_STATE.get("inloop_reflections_total", 0)) + 1
                log.info("INLOOP_REFLECTION iteration=%d owner=%d", iteration + 1, owner_id)

            # Proactive capability gap detection for custom tool creation
            if (
                CUSTOM_TOOL_ENABLED
                and not RUNTIME_STATE.get(f"_gap_hint_{owner_id}", False)
            ):
                _resp_text = str(assistant_msg.get("content", "") or "")
                _gap_phrases = ["i don't have a tool", "no tool available", "i cannot", "i lack the capability", "not currently able to"]
                if any(p in _resp_text.lower() for p in _gap_phrases):
                    messages.append({"role": "user", "content": "[SYSTEM HINT] You can use the `create_tool` tool to build a custom tool for capabilities you don't currently have. Define a Python function `tool_main(args: dict) -> dict:` and register it."})
                    RUNTIME_STATE[f"_gap_hint_{owner_id}"] = True
                    RUNTIME_STATE["custom_tool_gap_hints"] = int(RUNTIME_STATE.get("custom_tool_gap_hints", 0)) + 1
                    try:
                        skill_result = maybe_autocreate_skill_from_gap(
                            db=db,
                            owner_id=owner_id,
                            user_message=user_message,
                            assistant_text=_resp_text,
                            session_id=session_id,
                        )
                        if skill_result and skill_result.get("ok"):
                            sk = _safe_json_dict(skill_result.get("skill"), {})
                            skill_key = str(sk.get("skill_key") or "")
                            skill_version = int(skill_result.get("version") or 0)
                            messages.append(
                                {
                                    "role": "user",
                                    "content": (
                                        f"[SYSTEM HINT] Auto-created skill '{skill_key}' v{skill_version}. "
                                        "Use this skill playbook when similar requests appear."
                                    ),
                                }
                            )
                    except Exception as exc:
                        log.warning("SKILL_AUTOCREATE_GAP_FAIL owner=%d error=%s", owner_id, truncate_text(str(exc), 220))

            # Continue loop -- LLM will see tool results and decide next action

        else:
            # No tool calls -- LLM produced final response
            final_text = assistant_msg.get("content", "")
            save_message(db, owner_id, "assistant", content=final_text)

            # Closed Loop 2+3: Track lesson usage and close improvement notes
            cl_track_lesson_usage(lessons, final_text, owner_id)
            cl_close_improvement_notes(self_improvement_notes, final_text, owner_id)

            record_blackbox_event(
                db=db,
                owner_id=owner_id,
                session_id=session_id,
                source_type="chat",
                source_ref=str(owner_id),
                event_type="chat_final_response",
                payload={"iteration": iteration + 1, "response_preview": truncate_text(final_text, 320)},
            )
            return final_text

    # If we exhausted the loop
    record_blackbox_event(
        db=db,
        owner_id=owner_id,
        session_id=session_id,
        source_type="chat",
        source_ref=str(owner_id),
        event_type="chat_loop_exhausted",
        payload={"max_iterations": profile_chat_tool_loop_limit()},
    )
    return "Reached maximum tool call iterations. Task may be incomplete."


def run_agent_loop_with_new_session(owner_id: int, user_message: str) -> str:
    db = SessionLocal()
    try:
        result = run_agent_loop(db, owner_id, user_message)

        # --- Post-conversation reflection (Learning pillar) ---
        try:
            msg_count = db.query(ConversationMessage).filter(
                ConversationMessage.owner_id == owner_id
            ).count()
            if _should_reflect(owner_id, msg_count):
                run_post_conversation_reflection(db, owner_id)
        except Exception as e:
            log.warning(f"[REFLECT] Post-conversation reflection failed: {e}")

        try:
            run_self_improvement_cycle(db, owner_id, trigger="chat")
        except Exception as e:
            log.warning("SELF_IMPROVE_CHAT_FAIL owner=%d error=%s", owner_id, truncate_text(str(e), 220))

        return result
    finally:
        db.close()


