# SECTION 8B: AUTONOMOUS TASK ENGINE
# ============================================================================

def truncate_text(value: str, max_len: int = 500) -> str:
    value = value or ""
    if len(value) <= max_len:
        return value
    return value[:max_len] + "...[TRUNCATED]"


def parse_json_from_text(raw_text: str):
    if not raw_text:
        return None

    candidates = [raw_text.strip()]

    code_blocks = re.findall(r"```(?:json)?\s*([\s\S]*?)```", raw_text, flags=re.IGNORECASE)
    candidates.extend(block.strip() for block in code_blocks if block.strip())

    obj_match = re.search(r"\{[\s\S]*\}", raw_text)
    if obj_match:
        candidates.append(obj_match.group(0).strip())

    arr_match = re.search(r"\[[\s\S]*\]", raw_text)
    if arr_match:
        candidates.append(arr_match.group(0).strip())

    for candidate in candidates:
        try:
            return json.loads(candidate)
        except Exception:
            continue

    return None


def normalize_dependency_list(raw_depends) -> list[str]:
    if isinstance(raw_depends, str):
        raw_items = [raw_depends]
    elif isinstance(raw_depends, list):
        raw_items = raw_depends
    else:
        raw_items = []

    normalized = []
    seen = set()
    for item in raw_items:
        dep = str(item or "").strip()
        if not dep or dep in seen:
            continue
        seen.add(dep)
        normalized.append(dep[:80])
    return normalized[:10]


def normalize_optional_text(value, max_len: int = 200) -> str | None:
    if value is None:
        return None
    text = str(value).strip()
    if not text or text.lower() == "none":
        return None
    return truncate_text(text, max_len)


def normalize_task_plan(raw_plan) -> list[dict]:
    if isinstance(raw_plan, dict):
        raw_steps = raw_plan.get("steps") or raw_plan.get("nodes") or []
    elif isinstance(raw_plan, list):
        raw_steps = raw_plan
    else:
        raw_steps = []

    normalized = []
    seen_ids = set()
    allowed_statuses = {"pending", "running", "done", "failed", "blocked", "skipped"}
    max_nodes = max(TASK_MAX_STEPS, TASK_GRAPH_MAX_NODES)

    for item in raw_steps[:max_nodes]:
        if isinstance(item, str):
            title = item.strip()
            status = "pending"
            attempts = 0
            max_retries = TASK_MAX_STEP_RETRIES
            result_summary = ""
            last_error = None
            tool_events = []
            depends_on = []
            step_id = f"s{len(normalized) + 1}"
            branch_parent_id = None
            branch_reason = None
            checkpoint_at = None
            started_at = None
            completed_at = None
            artifact_logged_at = None
        elif isinstance(item, dict):
            title = str(item.get("title") or item.get("step") or "").strip()
            status = str(item.get("status", "pending")).lower()
            if status not in allowed_statuses:
                status = "pending"
            try:
                attempts = int(item.get("attempts", 0))
            except Exception:
                attempts = 0
            max_retries = clamp_int(item.get("max_retries", TASK_MAX_STEP_RETRIES), 0, 6, TASK_MAX_STEP_RETRIES)
            result_summary = str(item.get("result_summary", ""))
            last_error = item.get("last_error")
            tool_events = item.get("tool_events", [])
            if not isinstance(tool_events, list):
                tool_events = []
            depends_on = normalize_dependency_list(item.get("depends_on", item.get("deps", [])))
            step_id = str(item.get("step_id") or f"s{len(normalized) + 1}").strip()
            branch_parent_id = normalize_optional_text(item.get("branch_parent_id"), 80)
            branch_reason = normalize_optional_text(item.get("branch_reason"), 240)
            checkpoint_at = normalize_optional_text(item.get("checkpoint_at"), 80)
            started_at = normalize_optional_text(item.get("started_at"), 80)
            completed_at = normalize_optional_text(item.get("completed_at"), 80)
            artifact_logged_at = normalize_optional_text(item.get("artifact_logged_at"), 80)
        else:
            continue

        if not title:
            continue

        base_step_id = re.sub(r"[^a-zA-Z0-9_-]", "_", step_id or "")[:60] or f"s{len(normalized) + 1}"
        candidate_step_id = base_step_id
        suffix = 2
        while candidate_step_id in seen_ids:
            candidate_step_id = f"{base_step_id}_{suffix}"
            suffix += 1
        seen_ids.add(candidate_step_id)

        normalized.append({
            "step_id": candidate_step_id,
            "title": title[:200],
            "status": status,
            "attempts": max(attempts, 0),
            "max_retries": max_retries,
            "result_summary": truncate_text(result_summary, 1200),
            "last_error": truncate_text(str(last_error), 600) if last_error else None,
            "tool_events": tool_events,
            "depends_on": depends_on,
            "branch_parent_id": branch_parent_id,
            "branch_reason": branch_reason,
            "checkpoint_at": checkpoint_at,
            "started_at": started_at,
            "completed_at": completed_at,
            "artifact_logged_at": artifact_logged_at,
        })

    valid_ids = {step["step_id"] for step in normalized}
    for idx, step in enumerate(normalized):
        deduped_deps = []
        for dep in step.get("depends_on", []):
            if dep == step["step_id"]:
                continue
            if dep not in valid_ids:
                continue
            if dep not in deduped_deps:
                deduped_deps.append(dep)

        if not deduped_deps and idx > 0 and not step.get("branch_parent_id"):
            deduped_deps = [normalized[idx - 1]["step_id"]]
        step["depends_on"] = deduped_deps

        branch_parent_id = step.get("branch_parent_id")
        if branch_parent_id and branch_parent_id not in valid_ids:
            step["branch_parent_id"] = None

    return normalized


def _stable_json(value) -> str:
    try:
        return json.dumps(value, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
    except Exception:
        return "{}"


def _sha256_text(value: str) -> str:
    return hashlib.sha256(str(value or "").encode("utf-8", errors="ignore")).hexdigest()


def _checkpoint_runtime_signature() -> dict:
    profiles = configured_llm_profiles()
    compact_profiles = []
    for item in profiles[:6]:
        compact_profiles.append({
            "name": str(item.get("name") or ""),
            "model": str(item.get("model") or ""),
            "provider": str(item.get("provider") or ""),
            "enabled": bool(item.get("enabled", True)),
        })
    return {
        "autonomy_mode": AUTONOMY_MODE,
        "bob_full_power_enabled": bool(BOB_FULL_POWER_ENABLED),
        "bob_full_power_scope": BOB_FULL_POWER_SCOPE,
        "bob_full_power_system": bool(full_power_system_enabled()),
        "policy_pack": POLICY_PACK,
        "tool_policy_profile": active_tool_policy_profile(),
        "execution_sandbox_profile": active_execution_sandbox_profile(),
        "custom_tool_trust_mode": CUSTOM_TOOL_TRUST_MODE,
        "custom_tool_trust_full": bool(custom_tool_trust_full()),
        "command_queue_mode": COMMAND_QUEUE_MODE,
        "os_sandbox_mode": _normalize_os_sandbox_mode(OS_SANDBOX_MODE),
        "workspace_isolation_enabled": bool(WORKSPACE_ISOLATION_ENABLED),
        "workspace_session_isolation_enabled": bool(WORKSPACE_SESSION_ISOLATION_ENABLED),
        "model_profiles": compact_profiles,
    }


def _checkpoint_sequence_number(db: Session, task_id: int) -> int:
    last = (
        db.query(TaskCheckpointSnapshot.id)
        .filter(TaskCheckpointSnapshot.task_id == int(task_id))
        .order_by(TaskCheckpointSnapshot.id.desc())
        .first()
    )
    if not last:
        return 1
    return int(last[0]) + 1


def _build_checkpoint_replay_state(
    task: Task,
    source: str,
    normalized_plan: list[dict],
    sequence: int,
) -> dict:
    payload = {
        "schema_version": int(TASK_CHECKPOINT_SCHEMA_VERSION),
        "sequence": int(sequence),
        "created_at": utc_now_iso(),
        "source": truncate_text(str(source or "runtime"), 80),
        "task_id": int(task.id),
        "owner_id": int(task.owner_id),
        "task_status": truncate_text(str(task.status or TASK_STATUS_OPEN), 32),
        "task_title_hash": _sha256_text(truncate_text(str(task.title or ""), 200)),
        "task_description_hash": _sha256_text(truncate_text(str(task.description or ""), 8000)),
        "plan_digest": _sha256_text(_stable_json(normalized_plan)),
        "runtime_signature": _checkpoint_runtime_signature(),
    }
    payload["snapshot_digest"] = _sha256_text(_stable_json(payload))
    return payload


def _validate_checkpoint_replay_state(
    task: Task,
    normalized_plan: list[dict],
    snapshot_extra: dict,
    strict: bool,
) -> tuple[bool, str | None, dict]:
    replay_state = _safe_json_dict(snapshot_extra.get("replay_state"), {})
    if not replay_state:
        if strict:
            return False, "missing replay_state metadata", {}
        return True, None, {}

    try:
        if int(replay_state.get("task_id", -1)) != int(task.id):
            return False, "checkpoint task_id mismatch", replay_state
        if int(replay_state.get("owner_id", -1)) != int(task.owner_id):
            return False, "checkpoint owner_id mismatch", replay_state
    except Exception:
        return False, "invalid replay_state identifiers", replay_state

    expected_plan_digest = _sha256_text(_stable_json(normalized_plan))
    if str(replay_state.get("plan_digest") or "") != expected_plan_digest:
        return False, "checkpoint plan digest mismatch", replay_state

    title_hash = _sha256_text(truncate_text(str(snapshot_extra.get("task_title", task.title or "")), 200))
    if str(replay_state.get("task_title_hash") or "") != title_hash:
        return False, "checkpoint title digest mismatch", replay_state

    desc_hash = _sha256_text(truncate_text(str(snapshot_extra.get("task_description", task.description or "")), 8000))
    if str(replay_state.get("task_description_hash") or "") != desc_hash:
        return False, "checkpoint description digest mismatch", replay_state

    digest = str(replay_state.get("snapshot_digest") or "")
    if digest:
        cloned = dict(replay_state)
        cloned.pop("snapshot_digest", None)
        expected_digest = _sha256_text(_stable_json(cloned))
        if digest != expected_digest:
            return False, "checkpoint envelope digest mismatch", replay_state

    return True, None, replay_state


def restore_task_from_checkpoint_snapshot(
    db: Session,
    task: Task,
    snapshot: TaskCheckpointSnapshot,
    strict: bool | None = None,
) -> bool:
    strict_mode = TASK_CHECKPOINT_REPLAY_STRICT if strict is None else bool(strict)
    try:
        plan = normalize_task_plan(_safe_json_list(snapshot.plan_json, []))
        if not plan:
            RUNTIME_STATE["task_checkpoint_restore_failures"] = int(RUNTIME_STATE.get("task_checkpoint_restore_failures", 0)) + 1
            return False
        extra = _safe_json_dict(snapshot.extra_json, {})
        ok, reason, replay_state = _validate_checkpoint_replay_state(task, plan, extra, strict=strict_mode)
        if not ok:
            RUNTIME_STATE["task_checkpoint_restore_failures"] = int(RUNTIME_STATE.get("task_checkpoint_restore_failures", 0)) + 1
            RUNTIME_STATE["task_checkpoint_restore_drift"] = int(RUNTIME_STATE.get("task_checkpoint_restore_drift", 0)) + 1
            log.warning(
                "TASK_CHECKPOINT_RESTORE_DRIFT task_id=%d snapshot_id=%d reason=%s strict=%s",
                int(task.id),
                int(getattr(snapshot, "id", 0) or 0),
                truncate_text(str(reason or "unknown"), 200),
                strict_mode,
            )
            return False

        task.plan = plan
        restored_title = str(extra.get("task_title") or "").strip()
        restored_description = str(extra.get("task_description") or "").strip()
        if restored_title:
            task.title = truncate_text(restored_title, 200)
        if restored_description:
            task.description = truncate_text(restored_description, 8000)

        restored_status = str(snapshot.task_status or "").strip().lower()
        if restored_status in {
            TASK_STATUS_OPEN,
            TASK_STATUS_QUEUED,
            TASK_STATUS_RUNNING,
            TASK_STATUS_BLOCKED,
            TASK_STATUS_DONE,
            TASK_STATUS_FAILED,
            TASK_STATUS_CANCELLED,
        }:
            task.status = restored_status

        mode = "strict" if strict_mode and replay_state else "legacy"
        RUNTIME_STATE["task_checkpoint_replay_restores"] = int(RUNTIME_STATE.get("task_checkpoint_replay_restores", 0)) + 1
        RUNTIME_STATE["task_checkpoint_last_replay_mode"] = mode
        return True
    except Exception:
        RUNTIME_STATE["task_checkpoint_restore_failures"] = int(RUNTIME_STATE.get("task_checkpoint_restore_failures", 0)) + 1
        return False


def _prune_task_checkpoint_overflow_db(db: Session, task_id: int):
    keep = clamp_int(TASK_CHECKPOINT_MAX_PER_TASK, 10, 1000, 180)
    rows = (
        db.query(TaskCheckpointSnapshot)
        .filter(TaskCheckpointSnapshot.task_id == int(task_id))
        .order_by(TaskCheckpointSnapshot.id.desc())
        .all()
    )
    if len(rows) <= keep:
        return
    prune_ids = [int(row.id) for row in rows[keep:]]
    if not prune_ids:
        return
    db.query(TaskCheckpointSnapshot).filter(TaskCheckpointSnapshot.id.in_(prune_ids)).delete(
        synchronize_session=False
    )


def store_task_checkpoint_snapshot(
    db: Session,
    task: Task,
    source: str,
    extra: dict | None = None,
):
    if not TASK_CHECKPOINT_SNAPSHOT_ENABLED:
        return
    try:
        normalized_plan = normalize_task_plan(task.plan)
        sequence = _checkpoint_sequence_number(db, int(task.id))
        snapshot_extra = _safe_json_dict(extra, {})
        snapshot_extra.setdefault("task_title", truncate_text(str(task.title or ""), 200))
        snapshot_extra.setdefault("task_description", truncate_text(str(task.description or ""), 8000))
        snapshot_extra.setdefault("task_status", truncate_text(str(task.status or TASK_STATUS_OPEN), 32))
        snapshot_extra["replay_state"] = _build_checkpoint_replay_state(
            task=task,
            source=source,
            normalized_plan=normalized_plan,
            sequence=sequence,
        )
        row = TaskCheckpointSnapshot(
            task_id=int(task.id),
            owner_id=int(task.owner_id),
            task_status=truncate_text(str(task.status or TASK_STATUS_OPEN), 32),
            source=truncate_text(str(source or "runtime"), 80),
            plan_json=json.dumps(normalized_plan, ensure_ascii=False),
            extra_json=json.dumps(snapshot_extra, ensure_ascii=False),
        )
        db.add(row)
        db.flush()
        _prune_task_checkpoint_overflow_db(db, int(task.id))
        RUNTIME_STATE["task_checkpoint_snapshots"] = int(RUNTIME_STATE.get("task_checkpoint_snapshots", 0)) + 1
    except Exception as e:
        log.warning(
            "TASK_CHECKPOINT_WRITE_FAIL task_id=%s source=%s error=%s",
            int(getattr(task, "id", 0) or 0),
            truncate_text(source or "", 80),
            truncate_text(str(e), 220),
        )


def latest_task_checkpoint_snapshot(db: Session, task_id: int) -> TaskCheckpointSnapshot | None:
    return (
        db.query(TaskCheckpointSnapshot)
        .filter(TaskCheckpointSnapshot.task_id == int(task_id))
        .order_by(TaskCheckpointSnapshot.id.desc())
        .first()
    )


def restore_task_from_latest_checkpoint(db: Session, task: Task) -> bool:
    if not TASK_CHECKPOINT_SNAPSHOT_ENABLED:
        return False
    snap = latest_task_checkpoint_snapshot(db, int(task.id))
    if snap is None:
        return False
    return restore_task_from_checkpoint_snapshot(db, task, snap, strict=TASK_CHECKPOINT_REPLAY_STRICT)


def fallback_task_plan() -> list[dict]:
    return normalize_task_plan([
        {"title": "Clarify the goal and constraints"},
        {"title": "Gather missing facts using available tools"},
        {"title": "Execute the core work"},
        {"title": "Verify the outcome and summarize results"},
    ])


def generate_task_plan(
    identity: dict | None,
    task_title: str,
    task_goal: str,
    task_artifacts: list[str] | None = None,
) -> list[dict]:
    system_prompt = (
        build_system_prompt(identity, task_artifacts=task_artifacts)
        + "\nYou are generating an execution plan for an autonomous task worker."
        + "\nReturn JSON only. Schema: {\"steps\": [{\"title\": \"...\"}]}"
        + f"\nRules: include 3 to {TASK_MAX_STEPS} concrete steps, concise titles."
    )
    user_prompt = (
        f"Task title: {task_title}\n"
        f"Task goal: {task_goal}\n"
        "Generate the plan now."
    )
    if LLM_STRUCTURED_TASK_ENABLED:
        structured = call_llm_json_task(
            task_name="generate_task_plan",
            system_prompt=system_prompt,
            user_prompt=user_prompt,
            required_keys=["steps"],
            max_attempts=LLM_STRUCTURED_TASK_MAX_ATTEMPTS,
        )
        if structured.get("ok"):
            plan = normalize_task_plan(structured.get("data"))
            if plan:
                return plan[:TASK_MAX_STEPS]
    else:
        response = call_llm(
            [
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": user_prompt},
            ],
            owner_id=identity.get("owner_id") if isinstance(identity, dict) else None,
            source_type="task_plan",
            source_ref=truncate_text(task_title, 80),
        )
        if "error" not in response:
            content = response["choices"][0]["message"].get("content", "")
            parsed = parse_json_from_text(content)
            plan = normalize_task_plan(parsed)
            if plan:
                return plan[:TASK_MAX_STEPS]

    return fallback_task_plan()


def summarize_tool_result(tool_name: str, result: dict) -> str:
    if not isinstance(result, dict):
        return "Tool returned unexpected result format."

    if not result.get("ok", False):
        return truncate_text(str(result.get("error", "Tool failed")), 160)

    if tool_name == "search_web":
        return f"Found {len(result.get('results', []))} results."
    if tool_name == "read_webpage":
        return f"Read {len(result.get('text', ''))} chars from webpage."
    if tool_name == "read_file":
        return f"Read {len(result.get('content', ''))} chars from file."
    if tool_name == "write_file":
        return f"Wrote {result.get('bytes_written', 0)} bytes."
    if tool_name == "list_directory":
        return f"Listed {len(result.get('items', []))} entries."
    if tool_name == "run_command":
        return f"Command finished with code {result.get('return_code')}."
    if tool_name == "execute_python":
        return f"Python execution return code {result.get('return_code')}."
    if tool_name == "deep_research":
        return f"Research returned {len(result.get('sources', []))} sources."
    if tool_name == "read_pdf_url":
        pages = (result.get("metadata") or {}).get("pages")
        return f"PDF parsed with pages={pages}."
    if tool_name == "save_research_note":
        return f"Saved note id={result.get('note_id')}."
    if tool_name == "research_memory_search":
        return f"Found {len(result.get('matches', []))} memory matches."
    if tool_name == "desktop_session_start":
        if result.get("already_active"):
            return f"Desktop session already active: {result.get('session_id')}."
        return f"Desktop session started: {result.get('session_id')}."
    if tool_name == "desktop_session_status":
        return "Desktop session is active." if bool(result.get("active")) else "No active desktop session."
    if tool_name == "desktop_session_stop":
        return f"Desktop session stopped: {result.get('session_id')}."
    if tool_name == "desktop_session_replay":
        return f"Desktop replay executed {result.get('executed', 0)} steps."
    if tool_name == "desktop_screen_state":
        screen = result.get("screen") or {}
        return f"Screen state {screen.get('width')}x{screen.get('height')}."
    if tool_name == "desktop_screenshot":
        return f"Screenshot saved to {result.get('path')}."
    if tool_name == "desktop_list_windows":
        return f"Found {result.get('count', len(result.get('windows', [])))} windows."
    if tool_name == "desktop_uia_tree":
        return f"UI tree returned {result.get('count', len(result.get('nodes', [])))} nodes."
    if tool_name == "desktop_locate_on_screen":
        return "Image found on screen." if bool(result.get("found")) else "Image not found on screen."
    if tool_name == "desktop_click_image":
        return f"Clicked image at ({result.get('clicked_x')}, {result.get('clicked_y')})."
    if tool_name == "desktop_focus_window":
        return f"Focused window: {result.get('matched_title', 'unknown')}."
    if tool_name in {"desktop_move_mouse", "desktop_click", "desktop_drag_mouse"}:
        return f"{tool_name} completed at ({result.get('x')}, {result.get('y')})."
    if tool_name == "desktop_scroll":
        return f"Scrolled {result.get('clicks')}."
    if tool_name == "desktop_type_text":
        return f"Typed {result.get('typed_chars', 0)} chars."
    if tool_name == "desktop_key_press":
        return f"Pressed key {result.get('key')} x{result.get('presses')}."
    if tool_name == "desktop_hotkey":
        return f"Hotkey sent: {','.join(result.get('keys', []))}."
    if tool_name == "desktop_launch_app":
        return f"Launched app pid={result.get('pid')}."
    if tool_name == "desktop_wait":
        return f"Waited {result.get('slept_seconds')}s."
    if tool_name == "desktop_get_clipboard":
        return f"Read {len(result.get('content', ''))} clipboard chars."
    if tool_name == "desktop_set_clipboard":
        return f"Wrote {result.get('chars', 0)} clipboard chars."
    return "Tool call completed."


def task_step_allowed_attempts(step: dict) -> int:
    max_retries = clamp_int(step.get("max_retries", TASK_MAX_STEP_RETRIES), 0, 6, TASK_MAX_STEP_RETRIES)
    return max_retries + 1


def task_status_map(plan: list[dict]) -> dict[str, str]:
    return {step["step_id"]: step["status"] for step in plan}


def build_task_completed_context(plan: list[dict]) -> str:
    completed_lines = []
    for step in plan:
        if step.get("status") != "done":
            continue
        item = step["title"]
        if step.get("result_summary"):
            item += f": {step['result_summary']}"
        completed_lines.append(item)
    return "\n".join(completed_lines)


def find_next_runnable_step_index(plan: list[dict]) -> int | None:
    status_by_id = task_status_map(plan)
    for idx, step in enumerate(plan):
        if step.get("status") != "pending":
            continue
        deps = step.get("depends_on", [])
        if all(status_by_id.get(dep) == "done" for dep in deps):
            return idx
    return None


def recover_running_nodes_for_resume(plan: list[dict]) -> int:
    resumed = 0
    now_iso = utc_now_iso()
    for step in plan:
        if step.get("status") != "running":
            continue
        step["status"] = "pending"
        step["checkpoint_at"] = now_iso
        if not step.get("last_error"):
            step["last_error"] = "Recovered from previous interruption; retrying from checkpoint."
        resumed += 1
    return resumed


def mark_blocked_steps(plan: list[dict]) -> int:
    status_by_id = task_status_map(plan)
    updates = 0
    now_iso = utc_now_iso()
    for step in plan:
        if step.get("status") != "pending":
            continue
        deps = step.get("depends_on", [])
        if not deps:
            continue
        failed_dep = next((dep for dep in deps if status_by_id.get(dep) in {"failed", "blocked"}), None)
        missing_dep = next((dep for dep in deps if dep not in status_by_id), None)
        if not failed_dep and not missing_dep:
            continue
        step["status"] = "blocked"
        if failed_dep:
            step["last_error"] = f"Blocked by failed dependency: {failed_dep}"
        else:
            step["last_error"] = f"Blocked by missing dependency: {missing_dep}"
        step["checkpoint_at"] = now_iso
        updates += 1
    return updates


def count_branches_for_parent(plan: list[dict], parent_step_id: str) -> int:
    return sum(1 for step in plan if step.get("branch_parent_id") == parent_step_id)


def next_branch_step_id(plan: list[dict], parent_step_id: str) -> str:
    existing = {step["step_id"] for step in plan}
    base = re.sub(r"[^a-zA-Z0-9_-]", "_", parent_step_id or "step")[:50] or "step"
    branch_num = 1
    while True:
        candidate = f"{base}_b{branch_num}"
        if candidate not in existing:
            return candidate
        branch_num += 1


def create_recovery_branch_node(plan: list[dict], failed_step: dict, failure_error: str) -> dict | None:
    if not TASK_GRAPH_BRANCHING_ENABLED:
        return None
    if len(plan) >= TASK_GRAPH_MAX_NODES:
        return None

    parent_step_id = failed_step["step_id"]
    if count_branches_for_parent(plan, parent_step_id) >= TASK_GRAPH_MAX_BRANCHES_PER_NODE:
        return None

    # Hard depth limit: count how many "_b" suffixes are already in the step ID.
    # e.g. "s1_b1_b1_b1" has depth 3 — stop branching beyond MAX_BRANCH_DEPTH.
    MAX_BRANCH_DEPTH = 3
    current_depth = parent_step_id.count("_b")
    if current_depth >= MAX_BRANCH_DEPTH:
        log.warning(
            "TASK_GRAPH_BRANCH_DEPTH_LIMIT task step_id=%s depth=%d limit=%d — aborting recovery chain",
            parent_step_id, current_depth, MAX_BRANCH_DEPTH,
        )
        return None

    branch_step_id = next_branch_step_id(plan, parent_step_id)
    now_iso = utc_now_iso()
    title = f"Recovery path for: {truncate_text(failed_step.get('title', 'step'), 120)}"
    deps = [dep for dep in failed_step.get("depends_on", []) if dep != parent_step_id]
    branch_node = {
        "step_id": branch_step_id,
        "title": truncate_text(title, 200),
        "status": "pending",
        "attempts": 0,
        "max_retries": max(1, TASK_MAX_STEP_RETRIES),
        "result_summary": "",
        "last_error": None,
        "tool_events": [],
        "depends_on": deps,
        "branch_parent_id": parent_step_id,
        "branch_reason": truncate_text(failure_error, 240),
        "checkpoint_at": now_iso,
        "started_at": None,
        "completed_at": None,
        "artifact_logged_at": None,
    }
    plan.append(branch_node)

    # Rewire downstream pending/blocked nodes to depend on branch node instead of failed parent.
    for step in plan:
        if step["step_id"] in {parent_step_id, branch_step_id}:
            continue
        deps_before = step.get("depends_on", [])
        if parent_step_id not in deps_before:
            continue
        new_deps = []
        for dep in deps_before:
            next_dep = branch_step_id if dep == parent_step_id else dep
            if next_dep not in new_deps:
                new_deps.append(next_dep)
        step["depends_on"] = new_deps
        if step.get("status") == "blocked":
            step["status"] = "pending"
            step["last_error"] = None
        step["checkpoint_at"] = now_iso

    return branch_node


def run_task_step_loop(
    identity: dict | None,
    task_title: str,
    task_goal: str,
    current_step_title: str,
    completed_context: str,
    task_artifacts: list[str] | None = None,
    world_model_signals: list[str] | None = None,
    self_improvement_notes: list[str] | None = None,
    active_capabilities: list[str] | None = None,
    owner_id: int | None = None,
    task_id: int | None = None,
    step_id: str | None = None,
    blackbox_session_id: str | None = None,
) -> dict:
    base_system_prompt = (
        build_system_prompt(
            identity,
            task_artifacts=task_artifacts,
            world_model_signals=world_model_signals,
            self_improvement_notes=self_improvement_notes,
            active_capabilities=active_capabilities,
        )
        + "\nYou are executing one step of a larger task."
        + "\nUse tools if needed."
        + "\nWhen done, return a concise plain-text summary of this step only."
    )
    user_prompt = (
        f"Task title: {task_title}\n"
        f"Task goal: {task_goal}\n"
        f"Current step: {current_step_title}\n"
        f"Completed steps context:\n{completed_context or 'None'}\n"
        "Execute this step now."
    )

    run_budget = create_run_budget("task_step", owner_id, f"task:{task_id}:{step_id}")
    messages = [
        {"role": "system", "content": base_system_prompt},
        {"role": "user", "content": user_prompt},
    ]
    tool_events = []

    for iteration_index in range(profile_task_tool_loop_limit()):
        role_name = task_role_for_iteration(iteration_index)
        RUNTIME_STATE["task_role_loop_last_role"] = role_name
        RUNTIME_STATE["task_role_loop_runs"] = int(RUNTIME_STATE.get("task_role_loop_runs", 0)) + 1
        role_suffix = ROLE_PROMPT_SUFFIX.get(role_name, ROLE_PROMPT_SUFFIX["executor"])
        messages[0] = {
            "role": "system",
            "content": f"{base_system_prompt}\n{role_suffix}\nCurrent role turn: {role_name}.",
        }

        stop_now, stop_reason = budget_should_stop(run_budget)
        if stop_now:
            return {"ok": False, "error": f"BUDGET_STOP: {stop_reason}", "tool_events": tool_events}

        # Yield to chat if owner is chatting (OpenClaw: user chat gets priority)
        if owner_id and RUNTIME_STATE.get(f"chat_active_{owner_id}"):
            time.sleep(3)

        response = call_llm(
            messages,
            tools=effective_tool_definitions(owner_id=owner_id),
            route_key=f"owner:{owner_id}",
            owner_id=owner_id,
            source_type="task",
            source_ref=str(task_id) if task_id is not None else None,
            session_id=blackbox_session_id,
            task_id=task_id,
        )
        budget_record_llm_call(run_budget, messages, response if isinstance(response, dict) else None)
        if "error" in response:
            return {"ok": False, "error": response["error"], "tool_events": tool_events}

        assistant_msg = response["choices"][0]["message"]
        tool_calls = assistant_msg.get("tool_calls")

        if tool_calls:
            messages.append(assistant_msg)
            max_tools_this_iter = len(tool_calls)
            if budget_should_degrade(run_budget):
                max_tools_this_iter = min(max_tools_this_iter, 1)

            for tc_index, tc in enumerate(tool_calls):
                func_name = tc["function"]["name"]
                try:
                    func_args = json.loads(tc["function"]["arguments"])
                except json.JSONDecodeError:
                    func_args = {}

                stop_now, stop_reason = budget_should_stop(run_budget)
                if stop_now:
                    return {
                        "ok": False,
                        "error": f"BUDGET_STOP: {stop_reason}",
                        "tool_events": tool_events,
                    }

                if tc_index >= max_tools_this_iter:
                    skipped_result = {"ok": False, "error": "BUDGET_DEGRADE: deferred tool call this iteration."}
                    tool_events.append({
                        "tool": func_name,
                        "ok": False,
                        "summary": "Skipped by budget degrade mode.",
                    })
                    messages.append({
                        "role": "tool",
                        "tool_call_id": tc["id"],
                        "content": json.dumps(skipped_result, ensure_ascii=False),
                    })
                    continue

                try:
                    result = execute_tool_with_context(
                        identity=identity,
                        tool_name=func_name,
                        args=func_args,
                        owner_id=owner_id,
                        source_type="task",
                        source_ref=str(task_id) if task_id is not None else None,
                        step_id=step_id,
                        resume_payload={
                            "kind": "task_step",
                            "task_id": task_id,
                            "step_id": step_id,
                        },
                        blackbox_session_id=blackbox_session_id,
                        run_budget=run_budget,
                    )
                except Exception as exc_task_tool:
                    log.error("TASK_TOOL_CRASH tool=%s error=%s", func_name, exc_task_tool, exc_info=True)
                    result = {"ok": False, "error": f"Tool execution crashed: {exc_task_tool}"}

                result_str = json.dumps(result, ensure_ascii=False)
                if len(result_str) > 10000:
                    result_str = result_str[:10000] + "...[TRUNCATED]"

                tool_events.append({
                    "tool": func_name,
                    "ok": bool(result.get("ok", False)) if isinstance(result, dict) else False,
                    "summary": summarize_tool_result(func_name, result),
                })

                if isinstance(result, dict) and result.get("approval_required"):
                    return {
                        "ok": False,
                        "approval_required": True,
                        "resume_token": result.get("resume_token"),
                        "error": result.get("message", "Approval required for tool execution."),
                        "tool_events": tool_events,
                    }

                messages.append({
                    "role": "tool",
                    "tool_call_id": tc["id"],
                    "content": result_str,
                })

            # Pillar 1: In-loop reflection for task steps
            if (
                INLOOP_REFLECTION_ENABLED
                and (iteration_index + 1) >= INLOOP_REFLECTION_EVERY_N
                and (iteration_index + 1) % INLOOP_REFLECTION_EVERY_N == 0
            ):
                messages.append({"role": "user", "content": INLOOP_REFLECTION_PROMPT})
                RUNTIME_STATE["inloop_reflections_total"] = int(RUNTIME_STATE.get("inloop_reflections_total", 0)) + 1
                log.info("INLOOP_REFLECTION task_step iteration=%d task=%s step=%s", iteration_index + 1, task_id, step_id)

            continue

        final_text = (assistant_msg.get("content") or "").strip()
        if not final_text:
            final_text = "Step completed."
        if LLM_STRUCTURED_TASK_ENABLED:
            structured = call_llm_json_task(
                task_name="task_step_finalize",
                system_prompt=(
                    "You normalize task-step completion output to strict JSON. "
                    "Return only JSON with fields: summary (string), confidence (low|medium|high)."
                ),
                user_prompt=f"Raw step output:\n{final_text}\n\nReturn normalized JSON now.",
                required_keys=["summary"],
                max_attempts=LLM_STRUCTURED_TASK_MAX_ATTEMPTS,
            )
            if structured.get("ok"):
                data = _safe_json_dict(structured.get("data"), {})
                maybe_summary = str(data.get("summary") or "").strip()
                if maybe_summary:
                    final_text = truncate_text(maybe_summary, 1400)
        return {"ok": True, "summary": final_text, "tool_events": tool_events}

    return {
        "ok": False,
        "error": "Reached maximum tool iterations for this task step.",
        "tool_events": tool_events,
    }


def execute_task_by_id(task_id: int) -> dict:
    db = SessionLocal()
    task = None
    chat_id = None
    guard_acquired = False
    task_session_id = ""
    try:
        task = db.query(Task).filter(Task.id == task_id).first()
        if not task:
            return {}
        task_session_id = _blackbox_session_id("task", int(task.owner_id), str(task.id))
        record_blackbox_event(
            db=db,
            owner_id=int(task.owner_id),
            session_id=task_session_id,
            source_type="task",
            source_ref=str(task.id),
            event_type="task_execute_start",
            payload={"task_id": int(task.id), "title": truncate_text(task.title or "", 180)},
        )

        if not begin_task_execution(task_id):
            log.warning("TASK_GUARD_SKIP task_id=%d reason=already_active", task_id)
            return {}
        guard_acquired = True

        user = db.query(User).filter(User.id == task.owner_id).first()
        chat_id = user.telegram_chat_id if user else None

        if task.status in {TASK_STATUS_DONE, TASK_STATUS_FAILED, TASK_STATUS_CANCELLED}:
            clear_task_orphan_recovery(task.id)
            record_blackbox_event(
                db=db,
                owner_id=int(task.owner_id),
                session_id=task_session_id,
                source_type="task",
                source_ref=str(task.id),
                event_type="task_already_terminal",
                payload={"status": task.status},
            )
            return {}

        identity = load_identity(db, task.owner_id)
        restored = restore_task_from_latest_checkpoint(db, task)
        if restored:
            log.info("TASK_CHECKPOINT_RESTORE task_id=%d", int(task.id))
        task.status = TASK_STATUS_RUNNING
        db.commit()
        if restored:
            store_task_checkpoint_snapshot(db, task, "resume_restore")
            db.commit()

        plan = normalize_task_plan(task.plan)
        if not plan:
            planning_query = f"{task.title}\n{task.description}"
            planning_artifacts = retrieve_relevant_task_artifacts(
                owner_id=task.owner_id,
                query_text=planning_query,
                top_k=max(1, min(4, TASK_ARTIFACT_RETRIEVE_TOP_K)),
                continuity_text=planning_query,
                task_hint_ids=[int(task.id)],
            )
            if planning_artifacts:
                RUNTIME_STATE["task_artifact_injections"] = int(RUNTIME_STATE.get("task_artifact_injections", 0)) + len(planning_artifacts)
                log.info("TASK_ARTIFACT_PLAN_INJECT task_id=%d count=%d", task.id, len(planning_artifacts))
            plan = generate_task_plan(identity, task.title, task.description, task_artifacts=planning_artifacts)
            log.info("TASK_GRAPH_PLAN_CREATED task_id=%d nodes=%d", task.id, len(plan))
            send_task_progress_sync(chat_id, task.id, f"Planning complete: {len(plan)} steps")
            record_blackbox_event(
                db=db,
                owner_id=int(task.owner_id),
                session_id=task_session_id,
                source_type="task",
                source_ref=str(task.id),
                event_type="task_plan_created",
                payload={"nodes": len(plan)},
            )
        else:
            log.info("TASK_GRAPH_PLAN_RESUME task_id=%d nodes=%d", task.id, len(plan))
            record_blackbox_event(
                db=db,
                owner_id=int(task.owner_id),
                session_id=task_session_id,
                source_type="task",
                source_ref=str(task.id),
                event_type="task_plan_resumed",
                payload={"nodes": len(plan)},
            )

        resumed_nodes = recover_running_nodes_for_resume(plan)
        if resumed_nodes:
            RUNTIME_STATE["task_graph_resume_events"] = int(RUNTIME_STATE.get("task_graph_resume_events", 0)) + resumed_nodes
            log.warning("TASK_GRAPH_RESUME task_id=%d resumed_nodes=%d", task.id, resumed_nodes)

        task.plan = plan
        db.commit()
        store_task_checkpoint_snapshot(db, task, "plan_ready", extra={"nodes": len(plan)})
        db.commit()

        while True:
            db.refresh(task)
            if task.status == TASK_STATUS_CANCELLED:
                clear_task_orphan_recovery(task.id)
                return {"chat_id": chat_id, "message": f"Task #{task.id} cancelled."}

            plan = normalize_task_plan(task.plan)
            if not plan:
                task.status = TASK_STATUS_FAILED
                db.commit()
                return {"chat_id": chat_id, "message": f"Task #{task.id} failed: empty execution graph."}

            if all(step["status"] in {"done", "skipped"} for step in plan):
                task.status = TASK_STATUS_DONE
                task.plan = plan
                db.commit()
                store_task_checkpoint_snapshot(db, task, "task_done")
                db.commit()
                clear_task_orphan_recovery(task.id)
                record_blackbox_event(
                    db=db,
                    owner_id=int(task.owner_id),
                    session_id=task_session_id,
                    source_type="task",
                    source_ref=str(task.id),
                    event_type="task_done",
                    payload={"task_id": int(task.id)},
                )
                try:
                    extract_lessons_from_task(db, task, plan)
                except Exception as _les_exc:
                    log.warning("TASK_LESSON_ON_DONE_FAIL task_id=%d error=%s", int(task.id), truncate_text(str(_les_exc), 140))
                send_task_progress_sync(chat_id, task.id, "Task complete!")
                # Pillar 3: Update goal progress if this task belongs to a goal
                if GOAL_SYSTEM_ENABLED:
                    try:
                        linked_goals = db.query(Goal).filter(
                            Goal.owner_id == int(task.owner_id),
                            Goal.status == "active",
                        ).all()
                        for g in linked_goals:
                            tids = json.loads(g.task_ids_json or "[]")
                            if int(task.id) in tids:
                                update_goal_progress(db, g)
                    except Exception:
                        pass
                return {"chat_id": chat_id, "message": f"Task #{task.id} completed successfully."}

            runnable_idx = find_next_runnable_step_index(plan)
            if runnable_idx is None:
                resumed_nodes = recover_running_nodes_for_resume(plan)
                if resumed_nodes:
                    RUNTIME_STATE["task_graph_resume_events"] = int(RUNTIME_STATE.get("task_graph_resume_events", 0)) + resumed_nodes
                    task.plan = plan
                    db.commit()
                    log.warning("TASK_GRAPH_RESUME task_id=%d resumed_nodes=%d", task.id, resumed_nodes)
                    continue

                blocked_updates = mark_blocked_steps(plan)
                if blocked_updates:
                    task.plan = plan
                    db.commit()
                    continue

                has_pending = any(step["status"] in {"pending", "running"} for step in plan)
                has_failed = any(step["status"] == "failed" for step in plan)
                task.plan = plan
                if has_failed:
                    task.status = TASK_STATUS_FAILED
                    failed_step = next((step for step in plan if step["status"] == "failed"), None)
                    if failed_step is not None:
                        maybe_store_task_artifact_for_step(task, failed_step)
                    create_task_dead_letter(
                        db,
                        task,
                        reason="Task graph ended with failed node(s).",
                        snapshot_plan=plan,
                    )
                    db.commit()
                    clear_task_orphan_recovery(task.id)
                    fail_title = failed_step["title"] if failed_step else "unknown step"
                    record_blackbox_event(
                        db=db,
                        owner_id=int(task.owner_id),
                        session_id=task_session_id,
                        source_type="task",
                        source_ref=str(task.id),
                        event_type="task_failed",
                        payload={"reason": "failed_node", "step_title": truncate_text(fail_title, 140)},
                    )
                    try:
                        extract_lessons_from_task(db, task, plan)
                    except Exception as _les_exc:
                        log.warning("TASK_LESSON_ON_FAIL_FAIL task_id=%d error=%s", int(task.id), truncate_text(str(_les_exc), 140))
                    return {"chat_id": chat_id, "message": f"Task #{task.id} failed at step: {fail_title}"}

                if has_pending:
                    task.status = TASK_STATUS_BLOCKED
                    db.commit()
                    record_blackbox_event(
                        db=db,
                        owner_id=int(task.owner_id),
                        session_id=task_session_id,
                        source_type="task",
                        source_ref=str(task.id),
                        event_type="task_blocked",
                        payload={"reason": "dependency_deadlock"},
                    )
                    return {"chat_id": chat_id, "message": f"Task #{task.id} blocked: no runnable nodes (dependency deadlock)."}

                task.status = TASK_STATUS_FAILED
                create_task_dead_letter(
                    db,
                    task,
                    reason="Task graph entered invalid state (no runnable nodes).",
                    snapshot_plan=plan,
                )
                db.commit()
                clear_task_orphan_recovery(task.id)
                record_blackbox_event(
                    db=db,
                    owner_id=int(task.owner_id),
                    session_id=task_session_id,
                    source_type="task",
                    source_ref=str(task.id),
                    event_type="task_failed",
                    payload={"reason": "invalid_graph_state"},
                )
                return {"chat_id": chat_id, "message": f"Task #{task.id} failed: invalid graph state."}

            step = plan[runnable_idx]
            checkpoint_time = utc_now_iso()
            step["status"] = "running"
            step["attempts"] = int(step.get("attempts", 0)) + 1
            step["last_error"] = None
            step["checkpoint_at"] = checkpoint_time
            step["started_at"] = step.get("started_at") or checkpoint_time
            task.plan = plan
            db.commit()
            store_task_checkpoint_snapshot(
                db,
                task,
                "step_start",
                extra={"step_id": step.get("step_id"), "attempt": int(step.get("attempts", 0))},
            )
            db.commit()
            log.info(
                "TASK_GRAPH_NODE_START task_id=%d step_id=%s attempt=%d",
                task.id,
                step["step_id"],
                step["attempts"],
            )
            record_blackbox_event(
                db=db,
                owner_id=int(task.owner_id),
                session_id=task_session_id,
                source_type="task",
                source_ref=str(task.id),
                event_type="task_node_start",
                payload={
                    "step_id": step["step_id"],
                    "title": truncate_text(step.get("title", ""), 180),
                    "attempt": int(step.get("attempts", 0)),
                    "depends_on": step.get("depends_on", []),
                },
            )

            completed_context = build_task_completed_context(plan)
            artifact_query = "\n".join(
                part for part in [
                    str(task.title or ""),
                    str(task.description or ""),
                    str(step.get("title") or ""),
                    str(step.get("branch_reason") or ""),
                ] if part
            )
            capability_trigger_text = f"{task.title}\n{task.description}\n{step.get('title', '')}\n{step.get('branch_reason', '')}"
            active_step_capabilities = activate_dormant_capabilities_with_new_session(
                owner_id=int(task.owner_id),
                trigger_text=capability_trigger_text,
            )
            step_task_artifacts = retrieve_relevant_task_artifacts(
                owner_id=task.owner_id,
                query_text=artifact_query,
                top_k=max(1, min(4, TASK_ARTIFACT_RETRIEVE_TOP_K)),
                continuity_text=f"task#{task.id} {task.title}\n{artifact_query}",
                task_hint_ids=[int(task.id)],
            )
            if step_task_artifacts:
                RUNTIME_STATE["task_artifact_injections"] = int(RUNTIME_STATE.get("task_artifact_injections", 0)) + len(step_task_artifacts)
                log.info(
                    "TASK_ARTIFACT_STEP_INJECT task_id=%d step_id=%s count=%d",
                    task.id,
                    step["step_id"],
                    len(step_task_artifacts),
                )
            step_world_signals = retrieve_world_model_signals(
                owner_id=int(task.owner_id),
                query_text=artifact_query or str(step.get("title") or ""),
                top_k=max(1, min(4, WORLD_MODEL_RETRIEVE_TOP_K)),
            )
            step_improvement_notes = retrieve_relevant_self_improvement_notes(
                owner_id=int(task.owner_id),
                query_text=artifact_query or str(step.get("title") or ""),
                top_k=max(1, min(3, SELF_IMPROVE_RETRIEVE_TOP_K)),
            )
            forecast_id = create_action_forecast_record(
                owner_id=int(task.owner_id),
                context_type="task_step",
                context_ref=f"task#{int(task.id)}:{step['step_id']}",
                action_summary=artifact_query or str(step.get("title") or ""),
                attempt=int(step.get("attempts", 1)),
                dependency_count=len(step.get("depends_on", [])),
            )
            # Closed Loop 4: Adjust step based on forecast confidence
            if forecast_id:
                _fc_db = SessionLocal()
                try:
                    _fc_row = _fc_db.query(ActionForecast).filter(ActionForecast.id == int(forecast_id)).first()
                    if _fc_row:
                        step = cl_adjust_for_forecast_confidence(int(_fc_row.confidence or 50), step)
                except Exception:
                    pass
                finally:
                    _fc_db.close()
            step_result = run_task_step_loop(
                identity=identity,
                task_title=task.title,
                task_goal=task.description,
                current_step_title=step["title"],
                completed_context=completed_context,
                task_artifacts=step_task_artifacts,
                world_model_signals=step_world_signals,
                self_improvement_notes=step_improvement_notes,
                active_capabilities=active_step_capabilities,
                owner_id=task.owner_id,
                task_id=task.id,
                step_id=step["step_id"],
                blackbox_session_id=task_session_id,
            )

            step["tool_events"] = step_result.get("tool_events", [])
            step["checkpoint_at"] = utc_now_iso()

            if step_result.get("ok"):
                reconcile_action_forecast_record(
                    owner_id=int(task.owner_id),
                    forecast_id=forecast_id,
                    outcome_state="confirmed",
                    observed_outcome=str(step_result.get("summary", "")),
                    observed_error="",
                    tool_events=step_result.get("tool_events", []),
                )
                step["status"] = "done"
                step["result_summary"] = truncate_text(step_result.get("summary", "Step complete."), 1200)
                step["last_error"] = None
                step["completed_at"] = step["checkpoint_at"]
                maybe_store_task_artifact_for_step(task, step)
                task.plan = plan
                db.commit()
                store_task_checkpoint_snapshot(db, task, "step_done", extra={"step_id": step.get("step_id")})
                db.commit()
                log.info("TASK_GRAPH_NODE_DONE task_id=%d step_id=%s", task.id, step["step_id"])
                record_blackbox_event(
                    db=db,
                    owner_id=int(task.owner_id),
                    session_id=task_session_id,
                    source_type="task",
                    source_ref=str(task.id),
                    event_type="task_node_done",
                    payload={
                        "step_id": step["step_id"],
                        "summary": truncate_text(step_result.get("summary", ""), 260),
                    },
                )
                continue

            step["result_summary"] = ""
            step["last_error"] = truncate_text(step_result.get("error", "Step failed."), 600)
            step["completed_at"] = None

            if step_result.get("approval_required"):
                reconcile_action_forecast_record(
                    owner_id=int(task.owner_id),
                    forecast_id=forecast_id,
                    outcome_state="unknown",
                    observed_outcome="Paused for approval before completion.",
                    observed_error=str(step_result.get("error", "")),
                    tool_events=step_result.get("tool_events", []),
                )
                step["status"] = TASK_STATUS_BLOCKED
                step["checkpoint_at"] = utc_now_iso()
                task.status = TASK_STATUS_BLOCKED
                task.plan = plan
                db.commit()
                store_task_checkpoint_snapshot(db, task, "step_blocked_approval", extra={"step_id": step.get("step_id")})
                db.commit()
                token = str(step_result.get("resume_token") or "").strip()
                guidance = str(step_result.get("error") or "").strip()
                log.warning(
                    "TASK_GRAPH_NODE_PAUSED_APPROVAL task_id=%d step_id=%s token=%s",
                    task.id,
                    step["step_id"],
                    token,
                )
                record_blackbox_event(
                    db=db,
                    owner_id=int(task.owner_id),
                    session_id=task_session_id,
                    source_type="task",
                    source_ref=str(task.id),
                    event_type="task_node_paused_approval",
                    payload={"step_id": step["step_id"], "token": token},
                )
                return {
                    "chat_id": chat_id,
                    "message": (
                        (
                            f"Task #{task.id} paused for approval at step '{step['title']}'.\n"
                            f"Token: {token}\n"
                            f"Approve with /approve {token} or reject with /reject {token}."
                        )
                        if token
                        else f"Task #{task.id} paused for operator interlock at step '{step['title']}'.\n{guidance}"
                    ),
                }

            reconcile_action_forecast_record(
                owner_id=int(task.owner_id),
                forecast_id=forecast_id,
                outcome_state="mismatch",
                observed_outcome="Step execution failed.",
                observed_error=str(step.get("last_error") or step_result.get("error") or ""),
                tool_events=step_result.get("tool_events", []),
            )

            allowed_attempts = task_step_allowed_attempts(step)
            if step["attempts"] < allowed_attempts:
                step["status"] = "pending"
                task.plan = plan
                db.commit()
                store_task_checkpoint_snapshot(db, task, "step_retry", extra={"step_id": step.get("step_id")})
                db.commit()
                # Pillar 8: Progress report — step retry (logged only, no Telegram spam)
                log.warning(
                    "TASK_GRAPH_NODE_RETRY task_id=%d step_id=%s attempt=%d max_attempts=%d",
                    task.id,
                    step["step_id"],
                    step["attempts"],
                    allowed_attempts,
                )
                record_blackbox_event(
                    db=db,
                    owner_id=int(task.owner_id),
                    session_id=task_session_id,
                    source_type="task",
                    source_ref=str(task.id),
                    event_type="task_node_retry",
                    payload={
                        "step_id": step["step_id"],
                        "attempt": int(step.get("attempts", 0)),
                        "max_attempts": int(allowed_attempts),
                        "error": truncate_text(step.get("last_error", ""), 200),
                    },
                )
                continue

            step["status"] = "failed"
            branch_node = create_recovery_branch_node(plan, step, step["last_error"])
            if branch_node is not None:
                step["status"] = "skipped"
                step["branch_reason"] = truncate_text(step.get("last_error", "Failed step redirected to recovery branch."), 240)
                step["checkpoint_at"] = utc_now_iso()
                step["completed_at"] = step["checkpoint_at"]
                maybe_store_task_artifact_for_step(task, step)
                RUNTIME_STATE["task_graph_branches_created"] = int(RUNTIME_STATE.get("task_graph_branches_created", 0)) + 1
                task.plan = plan
                db.commit()
                store_task_checkpoint_snapshot(
                    db,
                    task,
                    "branch_created",
                    extra={"parent_step_id": step.get("step_id"), "branch_step_id": branch_node.get("step_id")},
                )
                db.commit()
                log.warning(
                    "TASK_GRAPH_BRANCH_CREATE task_id=%d parent=%s branch=%s",
                    task.id,
                    step["step_id"],
                    branch_node["step_id"],
                )
                record_blackbox_event(
                    db=db,
                    owner_id=int(task.owner_id),
                    session_id=task_session_id,
                    source_type="task",
                    source_ref=str(task.id),
                    event_type="task_branch_created",
                    payload={
                        "parent_step_id": step["step_id"],
                        "branch_step_id": branch_node["step_id"],
                        "reason": truncate_text(step.get("branch_reason", ""), 220),
                    },
                )
                continue

            task.plan = plan
            task.status = TASK_STATUS_FAILED
            maybe_store_task_artifact_for_step(task, step)
            create_task_dead_letter(
                db,
                task,
                reason=f"Node failed without available recovery branch: {step['step_id']}",
                snapshot_plan=plan,
            )
            db.commit()
            store_task_checkpoint_snapshot(db, task, "step_failed_terminal", extra={"step_id": step.get("step_id")})
            db.commit()
            clear_task_orphan_recovery(task.id)
            log.warning("TASK_GRAPH_NODE_FAIL task_id=%d step_id=%s", task.id, step["step_id"])
            record_blackbox_event(
                db=db,
                owner_id=int(task.owner_id),
                session_id=task_session_id,
                source_type="task",
                source_ref=str(task.id),
                event_type="task_failed",
                payload={"reason": "node_fail", "step_id": step["step_id"]},
            )
            return {
                "chat_id": chat_id,
                "message": f"Task #{task.id} failed at step: {step['title']}",
            }

    except Exception as e:
        db.rollback()
        log.exception(f"Task execution failed for task_id={task_id}: {e}")
        if task is not None and task_session_id:
            try:
                record_blackbox_event(
                    db=db,
                    owner_id=int(task.owner_id),
                    session_id=task_session_id,
                    source_type="task",
                    source_ref=str(task.id),
                    event_type="task_exception",
                    payload={"error": truncate_text(str(e), 260)},
                )
            except Exception:
                pass

        if task is not None:
            try:
                plan = normalize_task_plan(task.plan)
                for step in plan:
                    if step.get("status") in {"pending", "running"}:
                        step["status"] = "failed"
                        step["last_error"] = truncate_text(str(e), 600)
                        step["checkpoint_at"] = utc_now_iso()
                        maybe_store_task_artifact_for_step(task, step)
                        break
                task.plan = plan
                task.status = TASK_STATUS_FAILED
                create_task_dead_letter(
                    db,
                    task,
                    reason=f"Unhandled exception during task execution: {truncate_text(str(e), 240)}",
                    snapshot_plan=plan,
                )
                db.commit()
                clear_task_orphan_recovery(task.id)
            except Exception:
                db.rollback()

        return {"chat_id": chat_id, "message": f"Task #{task_id} failed: {truncate_text(str(e), 240)}"}
    finally:
        if guard_acquired:
            end_task_execution(task_id)
        try:
            if task is not None and getattr(task, "owner_id", None):
                final_status = str(getattr(task, "status", "") or "").lower()
                if final_status in {TASK_STATUS_DONE, TASK_STATUS_FAILED, TASK_STATUS_BLOCKED}:
                    run_self_improvement_cycle_with_new_session(
                        owner_id=int(task.owner_id),
                        trigger=f"task_{final_status}",
                    )
        except Exception as exc:
            log.warning("SELF_IMPROVE_TASK_FAIL task_id=%d error=%s", int(task_id), truncate_text(str(exc), 220))
        db.close()


def enqueue_task(task_id: int) -> bool:
    if task_id in TASK_QUEUE_IDS:
        return False
    TASK_QUEUE_IDS.add(task_id)
    TASK_QUEUE.put_nowait(task_id)
    return True


def recover_pending_tasks() -> list[int]:
    db = SessionLocal()
    try:
        rows = (
            db.query(Task)
            .filter(Task.status.in_([TASK_STATUS_OPEN, TASK_STATUS_QUEUED, TASK_STATUS_RUNNING]))
            .all()
        )
        task_ids = []
        for row in rows:
            row.status = TASK_STATUS_QUEUED
            task_ids.append(row.id)
        if rows:
            db.commit()
        return task_ids
    finally:
        db.close()


async def task_worker_loop():
    RUNTIME_STATE["worker_alive"] = True
    log.info("Task worker loop started.")
    try:
        while True:
            task_id = await TASK_QUEUE.get()
            try:
                loop = asyncio.get_running_loop()
                result = await loop.run_in_executor(None, execute_task_by_id, task_id)
                if result and result.get("chat_id") and result.get("message"):
                    await send_telegram_message(result["chat_id"], result["message"])
            except Exception as e:
                log.error(f"Task worker error for task_id={task_id}: {e}")
            finally:
                TASK_QUEUE_IDS.discard(task_id)
                TASK_QUEUE.task_done()
    finally:
        RUNTIME_STATE["worker_alive"] = False
        log.info("Task worker loop stopped.")


def task_progress(plan) -> tuple[int, int]:
    normalized = normalize_task_plan(plan)
    total = len(normalized)
    done = sum(1 for step in normalized if step["status"] in {"done", "skipped"})
    return done, total


def current_task_step(plan) -> str:
    normalized = normalize_task_plan(plan)
    for step in normalized:
        if step["status"] == "running":
            return step["title"]
    for step in normalized:
        if step["status"] == "pending":
            return step["title"]
    return "none"


def format_task_details(task: Task) -> str:
    done, total = task_progress(task.plan)
    current_step = current_task_step(task.plan)
    status_line = f"Task #{task.id} | {task.status} | progress {done}/{total}"
    step_line = f"Current step: {current_step}"
    lines = [
        status_line,
        step_line,
        f"Title: {task.title}",
        f"Goal: {task.description}",
    ]
    for step in normalize_task_plan(task.plan):
        deps = step.get("depends_on", [])
        deps_label = ",".join(deps) if deps else "root"
        step_line = (
            f"- [{step['status']}] {step['step_id']} {step['title']} "
            f"(attempts: {step['attempts']}, deps: {deps_label})"
        )
        lines.append(step_line)
        if step.get("branch_parent_id"):
            lines.append(f"  branch_of: {step['branch_parent_id']}")
        if step.get("last_error"):
            lines.append(f"  last_error: {truncate_text(step['last_error'], 160)}")
    return "\n".join(lines)


def parse_iso_utc(value: str | None) -> datetime | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    if raw.endswith("Z"):
        raw = raw[:-1] + "+00:00"
    try:
        dt = datetime.fromisoformat(raw)
    except Exception:
        return None
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    return dt.astimezone(timezone.utc)


def begin_task_execution(task_id: int) -> bool:
    with TASK_GUARD_LOCK:
        if task_id in ACTIVE_TASK_EXECUTIONS:
            return False
        ACTIVE_TASK_EXECUTIONS.add(task_id)
        return True


def end_task_execution(task_id: int):
    with TASK_GUARD_LOCK:
        ACTIVE_TASK_EXECUTIONS.discard(task_id)


def is_task_execution_active(task_id: int) -> bool:
    with TASK_GUARD_LOCK:
        return task_id in ACTIVE_TASK_EXECUTIONS


def increment_task_orphan_recovery(task_id: int) -> int:
    with TASK_GUARD_LOCK:
        count = int(TASK_GUARD_ORPHAN_RECOVERIES.get(task_id, 0)) + 1
        TASK_GUARD_ORPHAN_RECOVERIES[task_id] = count
        return count


def clear_task_orphan_recovery(task_id: int):
    with TASK_GUARD_LOCK:
        TASK_GUARD_ORPHAN_RECOVERIES.pop(task_id, None)


def latest_plan_checkpoint_dt(plan) -> datetime | None:
    latest_dt = None
    for step in normalize_task_plan(plan):
        for key in ("checkpoint_at", "started_at", "completed_at"):
            dt = parse_iso_utc(step.get(key))
            if dt is None:
                continue
            if latest_dt is None or dt > latest_dt:
                latest_dt = dt
    return latest_dt


def mark_plan_for_orphan_recovery(plan, reason: str) -> list[dict]:
    normalized = normalize_task_plan(plan)
    touched = False
    now_iso = utc_now_iso()
    for step in normalized:
        if step.get("status") == "running":
            step["status"] = "pending"
            step["last_error"] = truncate_text(reason, 600)
            step["checkpoint_at"] = now_iso
            touched = True
    if not touched:
        for step in normalized:
            if step.get("status") == "pending":
                step["last_error"] = truncate_text(reason, 600)
                step["checkpoint_at"] = now_iso
                touched = True
                break
    return normalized


def create_task_dead_letter(db: Session, task: Task, reason: str, snapshot_plan=None):
    try:
        snapshot_payload = {
            "status": task.status,
            "title": task.title,
            "description": task.description,
            "plan": normalize_task_plan(snapshot_plan if snapshot_plan is not None else task.plan),
            "captured_at": utc_now_iso(),
        }
        dl = TaskDeadLetter(
            task_id=task.id,
            owner_id=task.owner_id,
            title=truncate_text(task.title, 200),
            reason=truncate_text(reason, 800),
            snapshot_json=json.dumps(snapshot_payload, ensure_ascii=False),
        )
        db.add(dl)
        RUNTIME_STATE["task_guard_dead_letters"] = int(RUNTIME_STATE.get("task_guard_dead_letters", 0)) + 1
        log.warning("TASK_DEAD_LETTER_CREATE task_id=%d reason=%s", task.id, truncate_text(reason, 180))
        # Closed Loop 5: Check for repeated failure patterns
        cl_check_dead_letter_pattern(db, task.owner_id, reason, task)
    except Exception as e:
        log.error("TASK_DEAD_LETTER_CREATE_FAIL task_id=%s error=%s", task.id, truncate_text(str(e), 180))


def recover_orphan_running_tasks() -> int:
    db = SessionLocal()
    requeue_ids: list[int] = []
    recovered_count = 0
    try:
        rows = db.query(Task).filter(Task.status == TASK_STATUS_RUNNING).all()
        now_utc = datetime.now(timezone.utc)
        for row in rows:
            if row.id in TASK_QUEUE_IDS:
                continue
            if is_task_execution_active(row.id):
                continue

            latest_checkpoint = latest_plan_checkpoint_dt(row.plan)
            if latest_checkpoint is not None:
                age_seconds = (now_utc - latest_checkpoint).total_seconds()
                if age_seconds < TASK_GUARD_ORPHAN_LEASE_SECONDS:
                    continue

            recovery_count = increment_task_orphan_recovery(row.id)
            orphan_reason = (
                f"Recovered orphaned running task after lease timeout "
                f"({TASK_GUARD_ORPHAN_LEASE_SECONDS}s). Recovery #{recovery_count}."
            )
            plan = mark_plan_for_orphan_recovery(row.plan, orphan_reason)

            if recovery_count > TASK_GUARD_MAX_ORPHAN_RECOVERIES:
                row.status = TASK_STATUS_FAILED
                for step in plan:
                    if step.get("status") in {"pending", "running"}:
                        step["status"] = "failed"
                        step["last_error"] = truncate_text(
                            "Exceeded orphan recovery budget. Moved to dead letter.", 600
                        )
                        step["checkpoint_at"] = utc_now_iso()
                        step["completed_at"] = step["checkpoint_at"]
                        break
                row.plan = plan
                create_task_dead_letter(
                    db,
                    row,
                    reason="Exceeded orphan recovery retries.",
                    snapshot_plan=plan,
                )
                clear_task_orphan_recovery(row.id)
                log.warning("TASK_GUARD_ORPHAN_FAIL task_id=%d", row.id)
                continue

            row.status = TASK_STATUS_QUEUED
            row.plan = plan
            requeue_ids.append(row.id)
            recovered_count += 1
            RUNTIME_STATE["task_guard_orphan_requeues"] = int(
                RUNTIME_STATE.get("task_guard_orphan_requeues", 0)
            ) + 1
            log.warning("TASK_GUARD_ORPHAN_REQUEUE task_id=%d recovery=%d", row.id, recovery_count)

        if rows:
            db.commit()
    except Exception as e:
        db.rollback()
        log.error("TASK_GUARD_ORPHAN_CHECK_FAIL error=%s", truncate_text(str(e), 220))
    finally:
        db.close()

    for task_id in requeue_ids:
        enqueue_task(task_id)
    return recovered_count


def normalize_task_text(value: str) -> str:
    text = re.sub(r"\s+", " ", str(value or "").strip().lower())
    return text


def find_duplicate_active_task(db: Session, owner_id: int, title: str, goal: str) -> Task | None:
    title_key = normalize_task_text(title)
    goal_key = normalize_task_text(goal)
    now_utc = datetime.now(timezone.utc)
    rows = (
        db.query(Task)
        .filter(
            Task.owner_id == owner_id,
            Task.status.in_([TASK_STATUS_OPEN, TASK_STATUS_QUEUED, TASK_STATUS_RUNNING, TASK_STATUS_BLOCKED]),
        )
        .order_by(Task.id.desc())
        .limit(40)
        .all()
    )
    for row in rows:
        created_at = row.created_at
        if created_at is not None:
            if created_at.tzinfo is None:
                created_at = created_at.replace(tzinfo=timezone.utc)
            age = (now_utc - created_at.astimezone(timezone.utc)).total_seconds()
            if age > TASK_DEDUPE_WINDOW_SECONDS:
                continue

        if normalize_task_text(row.title) == title_key and normalize_task_text(row.description) == goal_key:
            return row
    return None


