# SECTION 9: USER / IDENTITY MANAGEMENT HELPERS
# ============================================================================

def get_or_create_user(db: Session, telegram_chat_id: str, username: str = None) -> User:
    """Find user by telegram_chat_id, or create one."""
    user = db.query(User).filter(User.telegram_chat_id == telegram_chat_id).first()
    if user:
        return user

    # Create new user
    base_name = (username or f"tg_{telegram_chat_id}").strip() or f"tg_{telegram_chat_id}"
    uname = base_name

    # Avoid username collisions across different chat IDs.
    existing_name = db.query(User).filter(User.username == uname).first()
    if existing_name and existing_name.telegram_chat_id == telegram_chat_id:
        return existing_name
    if existing_name and existing_name.telegram_chat_id != telegram_chat_id:
        uname = f"{base_name}_{telegram_chat_id}"
        suffix = 1
        while db.query(User).filter(User.username == uname).first() and suffix < 100:
            suffix += 1
            uname = f"{base_name}_{telegram_chat_id}_{suffix}"

    user = User(username=uname, telegram_chat_id=telegram_chat_id)
    db.add(user)
    try:
        db.commit()
    except IntegrityError:
        db.rollback()
        # Recover gracefully if another process created user concurrently.
        existing_chat = db.query(User).filter(User.telegram_chat_id == telegram_chat_id).first()
        if existing_chat:
            return existing_chat

        suffix = 1
        uname_retry = f"{base_name}_{telegram_chat_id}_{suffix}"
        while db.query(User).filter(User.username == uname_retry).first() and suffix < 100:
            suffix += 1
            uname_retry = f"{base_name}_{telegram_chat_id}_{suffix}"
        user = User(username=uname_retry, telegram_chat_id=telegram_chat_id)
        db.add(user)
        db.commit()
    db.refresh(user)

    # Create default identity kernel
    kernel = IdentityKernel(
        owner_id=user.id,
        agent_uuid=str(uuid.uuid4()),
        origin_statement="I am Mind Clone, a sovereign AI agent. I think, I act, I learn.",
        core_values=[
            "Be truthful and precise",
            "Protect the user's interests",
            "Be autonomous but accountable",
            "Reason from first principles",
        ],
        authority_bounds={
            "can_delete_files": False,
            "can_run_shell": True,
            "can_write_files": True,
            "can_access_web": True,
            "max_command_timeout": 30,
        },
    )
    db.add(kernel)
    db.commit()

    log.info(f"Created new user: {uname} (id={user.id}) with default identity kernel")
    return user


def parse_task_command_payload(text: str) -> tuple[str, str] | None:
    payload = text[len("/task"):].strip()
    if not payload or "::" not in payload:
        return None

    title, goal = payload.split("::", 1)
    title = title.strip()
    goal = goal.strip()
    if not title or not goal:
        return None

    return title[:140], goal


def parse_cron_add_payload(text: str) -> tuple[int, str] | None:
    payload = text[len("/cron_add"):].strip()
    if not payload or "::" not in payload:
        return None
    interval_raw, message = payload.split("::", 1)
    message = message.strip()
    if not message:
        return None
    try:
        interval_seconds = int(interval_raw.strip())
    except Exception:
        return None
    interval_seconds = clamp_int(interval_seconds, CRON_MIN_INTERVAL_SECONDS, 604800, 300)
    return interval_seconds, truncate_text(message, 3500)


def create_queued_task(db: Session, owner_id: int, title: str, goal: str) -> tuple[Task, bool]:
    duplicate = find_duplicate_active_task(db, owner_id, title, goal)
    if duplicate is not None:
        RUNTIME_STATE["task_dedupe_hits"] = int(RUNTIME_STATE.get("task_dedupe_hits", 0)) + 1
        return duplicate, False

    identity = load_identity(db, owner_id)
    agent_uuid = identity["agent_uuid"] if identity else str(uuid.uuid4())
    task = Task(
        owner_id=owner_id,
        agent_uuid=agent_uuid,
        title=title,
        description=goal,
        status=TASK_STATUS_QUEUED,
        plan=[],
    )
    db.add(task)
    db.commit()
    db.refresh(task)
    return task, True


def list_recent_tasks(db: Session, owner_id: int, limit: int = 10) -> list[Task]:
    return (
        db.query(Task)
        .filter(Task.owner_id == owner_id)
        .order_by(Task.id.desc())
        .limit(limit)
        .all()
    )


def get_user_task_by_id(db: Session, owner_id: int, task_id: int) -> Task | None:
    return (
        db.query(Task)
        .filter(Task.owner_id == owner_id, Task.id == task_id)
        .first()
    )


def cancel_task(db: Session, task: Task) -> tuple[bool, str]:
    if task.status in {TASK_STATUS_DONE, TASK_STATUS_FAILED, TASK_STATUS_CANCELLED}:
        return False, f"Task #{task.id} is already {task.status}."
    task.status = TASK_STATUS_CANCELLED
    db.commit()
    clear_task_orphan_recovery(task.id)
    return True, f"Task #{task.id} cancelled."


def normalize_queue_lane(raw_lane: str) -> str:
    lane = (raw_lane or "default").strip().lower()
    if not lane:
        return "default"
    if not re.fullmatch(r"[a-z0-9_-]{1,32}", lane):
        return "default"
    return lane


def classify_message_lane(source: str, text: str) -> str:
    src = (source or "").strip().lower()
    msg = (text or "").strip().lower()
    if src == "cron":
        return "cron"
    if src == "api":
        if should_force_deep_research_prompt(msg):
            return "research"
        return "api"
    if should_force_deep_research_prompt(msg):
        return "research"
    if msg.startswith("/task"):
        return "task"
    if src == "telegram":
        return "telegram"
    return "default"


def lane_limit(lane: str) -> int:
    lane_key = normalize_queue_lane(lane)
    if lane_key in COMMAND_QUEUE_LANE_LIMITS:
        return int(COMMAND_QUEUE_LANE_LIMITS[lane_key])
    return int(COMMAND_QUEUE_LANE_LIMITS.get("default", max(1, COMMAND_QUEUE_WORKER_COUNT)))


def get_lane_semaphore(lane: str) -> asyncio.Semaphore:
    lane_key = normalize_queue_lane(lane)
    sem = COMMAND_QUEUE_LANE_SEMAPHORES.get(lane_key)
    desired = lane_limit(lane_key)
    if sem is None or getattr(sem, "_mind_clone_limit", None) != desired:
        sem = asyncio.Semaphore(desired)
        setattr(sem, "_mind_clone_limit", desired)
        COMMAND_QUEUE_LANE_SEMAPHORES[lane_key] = sem
    return sem


def active_command_queue_worker_count() -> int:
    alive = 0
    stale_ids = []
    for worker_id, task in COMMAND_QUEUE_WORKER_TASKS.items():
        if task is None or task.done():
            stale_ids.append(worker_id)
        else:
            alive += 1
    for worker_id in stale_ids:
        COMMAND_QUEUE_WORKER_TASKS.pop(worker_id, None)
    return alive


async def ensure_command_queue_workers_running() -> int:
    global COMMAND_QUEUE_WORKER_TASK
    active = active_command_queue_worker_count()
    while active < COMMAND_QUEUE_WORKER_COUNT:
        worker_id = 1
        while worker_id in COMMAND_QUEUE_WORKER_TASKS:
            worker_id += 1
        task = asyncio.create_task(command_queue_worker_loop(worker_id))
        COMMAND_QUEUE_WORKER_TASKS[worker_id] = task
        active += 1
    # Keep compatibility pointer for older code paths
    if COMMAND_QUEUE_WORKER_TASKS:
        first_id = sorted(COMMAND_QUEUE_WORKER_TASKS.keys())[0]
        COMMAND_QUEUE_WORKER_TASK = COMMAND_QUEUE_WORKER_TASKS[first_id]
    else:
        COMMAND_QUEUE_WORKER_TASK = None
    RUNTIME_STATE["command_queue_worker_alive_count"] = active
    RUNTIME_STATE["command_queue_worker_alive"] = active > 0
    return active


async def cancel_command_queue_workers():
    global COMMAND_QUEUE_WORKER_TASK
    for worker_id in sorted(COMMAND_QUEUE_WORKER_TASKS.keys()):
        task = COMMAND_QUEUE_WORKER_TASKS.pop(worker_id, None)
        if task and not task.done():
            task.cancel()
            try:
                await task
            except asyncio.CancelledError:
                pass
            except Exception as e:
                log.error("Failed shutting down command queue worker[%d]: %s", worker_id, e)
    COMMAND_QUEUE_WORKER_TASK = None
    RUNTIME_STATE["command_queue_worker_alive_count"] = 0
    RUNTIME_STATE["command_queue_worker_alive"] = False


def command_queue_enabled() -> bool:
    return COMMAND_QUEUE_MODE in {"on", "auto", "steer", "followup", "collect"}


def get_owner_execution_lock(owner_id: int) -> threading.Lock:
    with OWNER_STATE_LOCK:
        lock = OWNER_EXECUTION_LOCKS.get(owner_id)
        if lock is None:
            lock = threading.Lock()
            OWNER_EXECUTION_LOCKS[owner_id] = lock
        return lock


def mark_owner_active(owner_id: int, active: bool):
    with OWNER_STATE_LOCK:
        if active:
            OWNER_ACTIVE_RUNS.add(owner_id)
        else:
            OWNER_ACTIVE_RUNS.discard(owner_id)


def owner_queue_count(owner_id: int) -> int:
    with OWNER_STATE_LOCK:
        return int(OWNER_QUEUE_COUNTS.get(owner_id, 0))


def increment_owner_queue(owner_id: int):
    with OWNER_STATE_LOCK:
        OWNER_QUEUE_COUNTS[owner_id] = int(OWNER_QUEUE_COUNTS.get(owner_id, 0)) + 1


def decrement_owner_queue(owner_id: int):
    with OWNER_STATE_LOCK:
        current = int(OWNER_QUEUE_COUNTS.get(owner_id, 0))
        if current <= 1:
            OWNER_QUEUE_COUNTS.pop(owner_id, None)
        else:
            OWNER_QUEUE_COUNTS[owner_id] = current - 1


def owner_active_count() -> int:
    with OWNER_STATE_LOCK:
        return len(OWNER_ACTIVE_RUNS)


def owner_backlog_count() -> int:
    with OWNER_STATE_LOCK:
        return sum(int(v) for v in OWNER_QUEUE_COUNTS.values())


def is_owner_busy_or_backlogged(owner_id: int) -> bool:
    with OWNER_STATE_LOCK:
        return owner_id in OWNER_ACTIVE_RUNS or int(OWNER_QUEUE_COUNTS.get(owner_id, 0)) > 0


def normalize_agent_key(raw_value: str | None) -> str:
    value = str(raw_value or TEAM_AGENT_DEFAULT_KEY).strip().lower()
    if not value:
        return TEAM_AGENT_DEFAULT_KEY
    if not re.fullmatch(r"[a-z0-9][a-z0-9_-]{0,31}", value):
        return TEAM_AGENT_DEFAULT_KEY
    return value


def _team_agent_username(base_username: str, agent_key: str) -> str:
    base = re.sub(r"[^a-zA-Z0-9_\\-]", "_", str(base_username or "user")).strip("_") or "user"
    return truncate_text(f"{base}__{agent_key}", 80)


def _team_agent_chat_id(base_chat_id: str, agent_key: str) -> str:
    return truncate_text(f"{str(base_chat_id)}::agent::{agent_key}", 120)


def _team_agent_workspace_root(owner_id: int, agent_key: str) -> Path:
    safe_key = normalize_agent_key(agent_key)
    root = (TEAM_WORKSPACE_ROOT / f"owner_{int(owner_id)}" / safe_key).resolve(strict=False)
    return root


def _upsert_identity_link(
    db: Session,
    canonical_owner_id: int,
    linked_chat_id: str,
    linked_username: str | None,
    scope_mode: str,
):
    chat = str(linked_chat_id or "").strip()
    if not chat:
        return
    row = db.query(IdentityLink).filter(IdentityLink.linked_chat_id == chat).first()
    if row:
        changed = False
        if int(row.canonical_owner_id) != int(canonical_owner_id):
            row.canonical_owner_id = int(canonical_owner_id)
            changed = True
        normalized_user = truncate_text(str(linked_username or "").strip(), 80) or None
        if row.linked_username != normalized_user:
            row.linked_username = normalized_user
            changed = True
        if row.scope_mode != str(scope_mode or "linked_explicit"):
            row.scope_mode = str(scope_mode or "linked_explicit")
            changed = True
        if changed:
            db.commit()
        return

    row = IdentityLink(
        canonical_owner_id=int(canonical_owner_id),
        linked_chat_id=chat,
        linked_username=truncate_text(str(linked_username or "").strip(), 80) or None,
        scope_mode=truncate_text(str(scope_mode or "linked_explicit"), 40),
    )
    db.add(row)
    db.commit()


def resolve_root_owner_id(db: Session, owner_id: int) -> int:
    agent_row = (
        db.query(TeamAgent)
        .filter(TeamAgent.agent_owner_id == int(owner_id))
        .order_by(TeamAgent.id.desc())
        .first()
    )
    if agent_row:
        return int(agent_row.owner_id)
    return int(owner_id)


def _resolve_identity_owner(db: Session, chat_id: str, username: str | None) -> User:
    normalized_chat_id = str(chat_id or "").strip()
    normalized_username = truncate_text(str(username or "").strip(), 80) or None

    if not normalized_chat_id:
        raise ValueError("chat_id is required.")

    link = db.query(IdentityLink).filter(IdentityLink.linked_chat_id == normalized_chat_id).first()
    if link:
        owner = db.query(User).filter(User.id == int(link.canonical_owner_id)).first()
        if owner:
            return owner

    mode = IDENTITY_SCOPE_MODE
    if mode == "strict_chat":
        return get_or_create_user(db, normalized_chat_id, normalized_username)

    if mode == "linked_username" and normalized_username:
        existing = (
            db.query(User)
            .filter(func.lower(User.username) == normalized_username.lower())
            .order_by(User.id.asc())
            .first()
        )
        if existing:
            _upsert_identity_link(
                db=db,
                canonical_owner_id=int(existing.id),
                linked_chat_id=normalized_chat_id,
                linked_username=normalized_username,
                scope_mode="linked_username",
            )
            return existing

    owner = get_or_create_user(db, normalized_chat_id, normalized_username)
    if mode in {"linked_username", "linked_explicit"}:
        _upsert_identity_link(
            db=db,
            canonical_owner_id=int(owner.id),
            linked_chat_id=normalized_chat_id,
            linked_username=normalized_username,
            scope_mode=mode,
        )
    return owner


def _get_team_agent_row(db: Session, root_owner_id: int, agent_key: str) -> TeamAgent | None:
    return (
        db.query(TeamAgent)
        .filter(
            TeamAgent.owner_id == int(root_owner_id),
            TeamAgent.agent_key == normalize_agent_key(agent_key),
        )
        .order_by(TeamAgent.id.desc())
        .first()
    )


def _ensure_team_agent_owner(
    db: Session,
    root_owner: User,
    agent_key: str,
    display_name: str | None = None,
) -> User:
    key = normalize_agent_key(agent_key)
    if key == TEAM_AGENT_DEFAULT_KEY:
        return root_owner

    existing = _get_team_agent_row(db, int(root_owner.id), key)
    if existing:
        agent_user = db.query(User).filter(User.id == int(existing.agent_owner_id)).first()
        if agent_user:
            existing.last_seen_at = datetime.utcnow()
            if existing.status not in {"active", "stopped"}:
                existing.status = "active"
            db.commit()
            return agent_user

    current_count = db.query(TeamAgent).filter(TeamAgent.owner_id == int(root_owner.id)).count()
    if current_count >= TEAM_AGENT_MAX_PER_OWNER:
        raise ValueError(f"Team agent limit reached ({TEAM_AGENT_MAX_PER_OWNER}).")

    base_chat_id = str(root_owner.telegram_chat_id or f"user_{root_owner.id}")
    base_username = str(root_owner.username or f"user_{root_owner.id}")
    agent_chat_id = _team_agent_chat_id(base_chat_id, key)
    agent_username = _team_agent_username(base_username, key)
    agent_user = get_or_create_user(db, agent_chat_id, agent_username)
    workspace_root = _team_agent_workspace_root(int(root_owner.id), key)
    workspace_root.mkdir(parents=True, exist_ok=True)

    row = TeamAgent(
        owner_id=int(root_owner.id),
        agent_owner_id=int(agent_user.id),
        agent_key=key,
        display_name=truncate_text(str(display_name or key), 80),
        workspace_root=str(workspace_root),
        status="active",
        last_seen_at=datetime.utcnow(),
    )
    db.add(row)
    db.commit()

    RUNTIME_STATE["team_agents_total"] = int(RUNTIME_STATE.get("team_agents_total", 0)) + 1
    RUNTIME_STATE["team_last_agent"] = key
    return agent_user


def resolve_owner_context(chat_id: str, username: str | None = None, agent_key: str | None = None) -> dict:
    db = SessionLocal()
    try:
        root_owner = _resolve_identity_owner(db, chat_id, username)
        key = normalize_agent_key(agent_key)
        owner = root_owner
        if TEAM_MODE_ENABLED and key != TEAM_AGENT_DEFAULT_KEY:
            owner = _ensure_team_agent_owner(db, root_owner, key)
        return {
            "owner_id": int(owner.id),
            "root_owner_id": int(root_owner.id),
            "agent_key": key,
            "is_subagent": int(owner.id) != int(root_owner.id),
            "username": str(owner.username or ""),
            "chat_id": str(owner.telegram_chat_id or chat_id),
        }
    finally:
        db.close()


def resolve_owner_id(chat_id: str, username: str = None, agent_key: str | None = None) -> int:
    db = SessionLocal()
    try:
        root_owner = _resolve_identity_owner(db, chat_id, username)
        key = normalize_agent_key(agent_key)
        if TEAM_MODE_ENABLED and key != TEAM_AGENT_DEFAULT_KEY:
            owner = _ensure_team_agent_owner(db, root_owner, key)
            return int(owner.id)
        return int(root_owner.id)
    finally:
        db.close()


