# SECTION 10: TELEGRAM ADAPTER
# ============================================================================

TELEGRAM_API = f"https://api.telegram.org/bot{TELEGRAM_BOT_TOKEN}"


def parse_approval_token(text: str, command_name: str) -> str | None:
    parts = (text or "").strip().split(maxsplit=1)
    if len(parts) != 2:
        return None
    if parts[0].strip().lower() != command_name.strip().lower():
        return None
    token = parts[1].strip()
    if not re.fullmatch(r"[a-zA-Z0-9_-]{4,64}", token):
        return None
    return token


def unpause_task_after_approval(owner_id: int, task_id: int, step_id: str | None) -> tuple[bool, str]:
    db = SessionLocal()
    try:
        task = (
            db.query(Task)
            .filter(Task.id == int(task_id), Task.owner_id == int(owner_id))
            .first()
        )
        if not task:
            return False, f"Task #{task_id} not found for this user."
        plan = normalize_task_plan(task.plan)
        if step_id:
            for step in plan:
                if step.get("step_id") == step_id and step.get("status") == TASK_STATUS_BLOCKED:
                    step["status"] = "pending"
                    step["last_error"] = None
                    step["checkpoint_at"] = utc_now_iso()
                    break
        task.plan = plan
        task.status = TASK_STATUS_QUEUED
        db.commit()
        enqueue_task(task.id)
        return True, f"Task #{task.id} resumed from approval token."
    except Exception as e:
        db.rollback()
        return False, f"Failed to resume task: {truncate_text(str(e), 200)}"
    finally:
        db.close()


async def handle_approval_command(chat_id: str, username: str, token: str, approve: bool):
    owner_id = resolve_owner_id(chat_id, username)
    decision = decide_approval_token(owner_id=owner_id, token=token, approve=approve)
    if not decision.get("ok"):
        await send_telegram_message(chat_id, f"⚠️ {decision.get('error', 'Approval command failed.')}")
        return

    status = str(decision.get("status", "pending"))
    token_owner_id = int(decision.get("owner_id") or owner_id)
    if status != "approved":
        await send_telegram_message(chat_id, f"Approval token {token} set to {status}.")
        return

    payload = _safe_json_dict(decision.get("resume_payload"), {})
    kind = str(payload.get("kind") or "")
    if kind == "task_step":
        task_id = int(payload.get("task_id") or 0)
        step_id = str(payload.get("step_id") or "") or None
        ok, message = unpause_task_after_approval(owner_id=token_owner_id, task_id=task_id, step_id=step_id)
        await send_telegram_message(chat_id, message if ok else f"⚠️ {message}")
        return

    if kind == "chat_message":
        user_message = str(payload.get("user_message") or "").strip()
        if not user_message:
            await send_telegram_message(chat_id, "Approval saved, but no resumable message was found.")
            return
        await send_telegram_message(chat_id, f"Approved {token}. Resuming message execution.")
        await dispatch_incoming_message(
            owner_id=token_owner_id,
            chat_id=chat_id,
            username=username,
            text=user_message,
            source="telegram",
            expect_response=False,
        )
        return

    await send_telegram_message(chat_id, f"Approval token {token} approved.")


def parse_command_id(text: str, command_name: str) -> int | None:
    parts = text.strip().split(maxsplit=1)
    if len(parts) != 2 or parts[0] != command_name:
        return None
    try:
        return int(parts[1].strip())
    except Exception:
        return None


def send_task_progress_sync(chat_id: str | None, task_id: int, message: str) -> None:
    """Send a task progress message to Telegram (sync, rate-limited). Pillar 8."""
    if not TASK_PROGRESS_REPORTING_ENABLED or not chat_id:
        return
    now = time.monotonic()
    last = _task_progress_last_send.get(task_id, 0.0)
    if (now - last) < TASK_PROGRESS_MIN_INTERVAL_SECONDS:
        return
    _task_progress_last_send[task_id] = now
    text = f"[Task #{task_id}] {message}"
    if not telegram_token_configured():
        return
    try:
        url = f"{TELEGRAM_API}/sendMessage"
        import httpx
        with httpx.Client(timeout=15, trust_env=False) as client:
            resp = client.post(url, json={"chat_id": chat_id, "text": text})
            if resp.status_code != 200:
                log.debug("TASK_PROGRESS_SEND_FAIL task=%d status=%d", task_id, resp.status_code)
    except Exception:
        log.debug("TASK_PROGRESS_SEND_ERROR task=%d", task_id, exc_info=True)


async def send_telegram_message(chat_id: str, text: str):
    """Send a message back to Telegram. Splits long messages."""
    text = str(text or "")
    if not text.strip():
        log.warning("TELEGRAM_SEND_SKIP_EMPTY chat_id=%s", chat_id)
        return
    if not telegram_token_configured():
        log.warning("TELEGRAM_SEND_SKIP_UNCONFIGURED_TOKEN chat_id=%s", chat_id)
        return

    url = f"{TELEGRAM_API}/sendMessage"

    # Telegram max message length is 4096
    chunks = [text[i:i+4000] for i in range(0, len(text), 4000)]

    async with httpx.AsyncClient(timeout=30, trust_env=False) as client:
        for chunk in chunks:
            markdown_payload = {
                "chat_id": chat_id,
                "text": chunk,
                "parse_mode": "Markdown",
            }
            try:
                resp = await client.post(url, json=markdown_payload)
                markdown_ok = False
                markdown_err = ""
                if resp.status_code == 200:
                    try:
                        body = resp.json()
                        markdown_ok = bool(body.get("ok", False))
                        if not markdown_ok:
                            markdown_err = truncate_text(str(body), 220)
                    except Exception:
                        markdown_err = truncate_text(resp.text or "Invalid JSON response from Telegram.", 220)
                else:
                    markdown_err = f"status={resp.status_code} body={truncate_text(resp.text, 220)}"

                if markdown_ok:
                    continue

                # Retry in plain text mode for reliability.
                plain_payload = {"chat_id": chat_id, "text": chunk}
                plain_resp = await client.post(url, json=plain_payload)
                plain_ok = False
                plain_err = ""
                if plain_resp.status_code == 200:
                    try:
                        plain_body = plain_resp.json()
                        plain_ok = bool(plain_body.get("ok", False))
                        if not plain_ok:
                            plain_err = truncate_text(str(plain_body), 220)
                    except Exception:
                        plain_err = truncate_text(plain_resp.text or "Invalid JSON response from Telegram.", 220)
                else:
                    plain_err = f"status={plain_resp.status_code} body={truncate_text(plain_resp.text, 220)}"

                if not plain_ok:
                    log.error(
                        "TELEGRAM_SEND_FAIL chat_id=%s markdown_error=%s plain_error=%s text_preview=%s",
                        chat_id,
                        markdown_err,
                        plain_err,
                        truncate_text(chunk, 180),
                    )
            except Exception as e:
                log.error(f"Failed to send telegram message: {e}")


async def send_telegram_placeholder(chat_id: str, text: str = "Thinking...") -> int | None:
    """Send a placeholder message and return its message_id for later editing (OpenClaw edit-streaming)."""
    if not telegram_token_configured():
        return None
    try:
        async with httpx.AsyncClient(timeout=15, trust_env=False) as client:
            resp = await client.post(
                f"{TELEGRAM_API}/sendMessage",
                json={"chat_id": chat_id, "text": text},
            )
            if resp.status_code == 200:
                body = resp.json()
                if body.get("ok"):
                    return body["result"]["message_id"]
    except Exception as e:
        log.warning("TELEGRAM_PLACEHOLDER_FAIL chat_id=%s error=%s", chat_id, truncate_text(str(e), 180))
    return None


async def edit_telegram_message(chat_id: str, message_id: int, text: str):
    """Edit an existing Telegram message with the final response (OpenClaw edit-streaming)."""
    if not telegram_token_configured() or not message_id:
        return
    text = str(text or "")
    if not text.strip():
        return
    url = f"{TELEGRAM_API}/editMessageText"
    first_chunk = text[:4000]
    try:
        async with httpx.AsyncClient(timeout=30, trust_env=False) as client:
            resp = await client.post(url, json={
                "chat_id": chat_id, "message_id": message_id, "text": first_chunk,
            })
            if resp.status_code == 200 and resp.json().get("ok"):
                # If text was longer than 4000 chars, send remainder as new messages
                if len(text) > 4000:
                    remaining = text[4000:]
                    for i in range(0, len(remaining), 4000):
                        await send_telegram_message(chat_id, remaining[i:i+4000])
                return
    except Exception:
        pass
    # Fallback: edit failed, send as new message
    await send_telegram_message(chat_id, text)


def utc_now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


