@app.get("/ops/paths")
def ops_paths_endpoint(_ops=Depends(require_ops_auth)):
    repo_root = str(REPO_ROOT_DIR.resolve(strict=False))
    core_dir = str(APP_DIR.resolve(strict=False))
    process_cwd = str(Path.cwd().resolve(strict=False))

    examples: list[dict] = []
    sample_paths = [
        "mind-clone/mind_clone_agent.py",
        "mind-clone/scripts/release_gate_check.py",
        "mind-clone/persist",
        "persist/skills_vault",
        "README.md",
    ]
    for raw in sample_paths:
        try:
            resolved, base_used = _resolve_tool_path_input(raw)
            examples.append({"raw": raw, "resolved": str(resolved), "base": base_used, "exists": resolved.exists()})
        except Exception as exc:
            examples.append({"raw": raw, "error": truncate_text(str(exc), 220)})

    cmd_examples: list[dict] = []
    sample_cmds = [
        "python -m py_compile mind-clone/mind_clone_agent.py",
        "python mind-clone/scripts/release_gate_check.py",
        "python -m py_compile mind_clone_agent.py",
        "python scripts/release_gate_check.py",
    ]
    for cmd in sample_cmds:
        try:
            default_cwd, base_used = _default_cwd_for_tool_command(cmd)
            cmd_examples.append(
                {
                    "command": cmd,
                    "default_cwd": str(default_cwd.resolve(strict=False)) if default_cwd else None,
                    "base": base_used,
                }
            )
        except Exception as exc:
            cmd_examples.append({"command": cmd, "error": truncate_text(str(exc), 220)})

    payload = {
        "ok": True,
        "repo_root_dir": repo_root,
        "core_dir": core_dir,
        "process_cwd": process_cwd,
        "process_cwd_at_boot": str(PROCESS_CWD_AT_BOOT),
        "tool_path_resolution_enabled": bool(TOOL_PATH_RESOLUTION_ENABLED),
        "tool_path_resolution_mode": str(TOOL_PATH_RESOLUTION_MODE),
        "tool_default_cwd_mode": str(TOOL_DEFAULT_CWD_MODE),
        "repo_root_relative_prefixes": list(REPO_ROOT_RELATIVE_PREFIXES),
        "examples": examples,
        "command_defaults": cmd_examples,
        "runtime_last_path_resolution": RUNTIME_STATE.get("tool_path_resolution_last"),
        "runtime_last_cwd_default": RUNTIME_STATE.get("tool_cwd_default_last"),
        "timestamp": utc_now_iso(),
    }
    return payload


